INSERT INTO `news` VALUES (252, '人形机器人从实验室到产线的最后一里路', 'https://www.oschina.net/news/420634', 'https://www.oschina.net/news/rss', '过去两年，随着越来越多的国产人形机器人登上万众瞩目的大舞台，引发国内外主流媒体争相报道，「具身智能」从学术名词变成了产业热词。但实验室里的 Demo 和工厂里的稳定运行，中间隔着一道工程化的鸿沟。怎么让大模型真正操控机器人舞起来？怎么在真实环境里做强化学习？怎么把成本压到可量产？这些问题，需要一线从业者...', '', '', '', '', '{\'title\': \'人形机器人从实验室到产线的最后一里路\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'人形机器人从实验室到产线的最后一里路\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420634\'}], \'link\': \'https://www.oschina.net/news/420634\', \'tags\': [{\'term\': \'综合新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'过去两年，随着越来越多的国产人形机器人登上万众瞩目的大舞台，引发国内外主流媒体争相报道，「具身智能」从学术名词变成了产业热词。但实验室里的 Demo 和工厂里的稳定运行，中间隔着一道工程化的鸿沟。怎么让大模型真正操控机器人舞起来？怎么在真实环境里做强化学习？怎么把成本压到可量产？这些问题，需要一线从业者...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'过去两年，随着越来越多的国产人形机器人登上万众瞩目的大舞台，引发国内外主流媒体争相报道，「具身智能」从学术名词变成了产业热词。但实验室里的 Demo 和工厂里的稳定运行，中间隔着一道工程化的鸿沟。怎么让大模型真正操控机器人舞起来？怎么在真实环境里做强化学习？怎么把成本压到可量产？这些问题，需要一线从业者...\'}, \'published\': \'Tue, 14 Apr 2026 10:57:59 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=2, tm_min=57, tm_sec=59, tm_wday=1, tm_yday=104, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420634\', \'guidislink\': False}', '2026-04-14 10:57:59', '2026-04-14 03:42:53', 0, '\"\"');
