INSERT INTO `news` VALUES (264, 'Microsoft is officially killing its Outlook Lite app next month', 'https://techcrunch.com/2026/04/13/microsoft-is-officially-killing-its-outlook-lite-app-next-month/', 'https://techcrunch.com/feed/', 'Launched in 2022, Outlook Lite is a lightweight version of the regular Outlook app, designed for Android phones with limited storage and regions with slower internet connections. The app had already been scheduled for retirement.', '', '', '', '', '{\'title\': \'Microsoft is officially killing its Outlook Lite app next month\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://techcrunch.com/feed/\', \'value\': \'Microsoft is officially killing its Outlook Lite app next month\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://techcrunch.com/2026/04/13/microsoft-is-officially-killing-its-outlook-lite-app-next-month/\'}], \'link\': \'https://techcrunch.com/2026/04/13/microsoft-is-officially-killing-its-outlook-lite-app-next-month/\', \'authors\': [{\'name\': \'Aisha Malik\'}], \'author\': \'Aisha Malik\', \'author_detail\': {\'name\': \'Aisha Malik\'}, \'published\': \'Mon, 13 Apr 2026 20:59:12 +0000\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=20, tm_min=59, tm_sec=12, tm_wday=0, tm_yday=103, tm_isdst=0), \'tags\': [{\'term\': \'Apps\', \'scheme\': None, \'label\': None}, {\'term\': \'In Brief\', \'scheme\': None, \'label\': None}, {\'term\': \'Microsoft\', \'scheme\': None, \'label\': None}, {\'term\': \'Outlook\', \'scheme\': None, \'label\': None}, {\'term\': \'Outlook Lite\', \'scheme\': None, \'label\': None}], \'id\': \'https://techcrunch.com/?p=3111969\', \'guidislink\': False, \'summary\': \'Launched in 2022, Outlook Lite is a lightweight version of the regular Outlook app, designed for Android phones with limited storage and regions with slower internet connections.\\xa0The app had already been scheduled for retirement.\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://techcrunch.com/feed/\', \'value\': \'Launched in 2022, Outlook Lite is a lightweight version of the regular Outlook app, designed for Android phones with limited storage and regions with slower internet connections.\\xa0The app had already been scheduled for retirement.\'}}', '2026-04-13 20:59:12', '2026-04-14 03:43:03', 0, '\"\"');
INSERT INTO `news` VALUES (265, 'N-Day-Bench – Can LLMs find real vulnerabilities in real codebases?', 'https://ndaybench.winfunc.com', 'https://hnrss.org/frontpage', '<p>N-Day-Bench tests whether frontier LLMs can find known security vulnerabilities in real repository code. Each month it pulls fresh cases from GitHub security advisories, checks out the repo at the last commit before the patch, and gives models a sandboxed bash shell to explore the codebase.<p>Static vulnerability discovery benchmarks become outdated quickly. Cases leak into training data, and scores start measuring memorization. The monthly refresh keeps the test set ahead of contamination — or at least makes the contamination window honest.<p>Each case runs three agents: a Curator reads the advisory and builds an answer key, a Finder (the model under test) gets 24 shell steps to explore the code and write a structured report, and a Judge scores the blinded submission. The Finder never sees the patch. It starts from sink hints and must trace the bug through actual code.<p>Only repos with 10k+ stars qualify. A diversity pass prevents any single repo from dominating the set. Ambiguous advisories (merge commits, multi-repo references, unresolvable refs) are dropped.<p>Currently evaluating GPT-5.4, Claude Opus 4.6, Gemini 3.1 Pro, GLM-5.1, and Kimi K2.5. All traces are public.<p>Methodology: <a href=\"https://ndaybench.winfunc.com/methodology\">https://ndaybench.winfunc.com/methodology</a><p>Live Leaderboard: <a href=\"https://ndaybench.winfunc.com/leaderboard\">https://ndaybench.winfunc.com/leaderboard</a><p>Live Traces: <a href=\"https://ndaybench.winfunc.com/traces\">https://ndaybench.winfunc.com/traces</a></p>\n<hr />\n<p>Comments URL: <a href=\"https://news.ycombinator.com/item?id=47758347\">https://news.ycombinator.com/item?id=47758347</a></p>\n<p>Points: 41</p>\n<p># Comments: 11</p>', '', '', '', '', '{\'title\': \'N-Day-Bench – Can LLMs find real vulnerabilities in real codebases?\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://hnrss.org/frontpage\', \'value\': \'N-Day-Bench – Can LLMs find real vulnerabilities in real codebases?\'}, \'summary\': \'<p>N-Day-Bench tests whether frontier LLMs can find known security vulnerabilities in real repository code. Each month it pulls fresh cases from GitHub security advisories, checks out the repo at the last commit before the patch, and gives models a sandboxed bash shell to explore the codebase.<p>Static vulnerability discovery benchmarks become outdated quickly. Cases leak into training data, and scores start measuring memorization. The monthly refresh keeps the test set ahead of contamination — or at least makes the contamination window honest.<p>Each case runs three agents: a Curator reads the advisory and builds an answer key, a Finder (the model under test) gets 24 shell steps to explore the code and write a structured report, and a Judge scores the blinded submission. The Finder never sees the patch. It starts from sink hints and must trace the bug through actual code.<p>Only repos with 10k+ stars qualify. A diversity pass prevents any single repo from dominating the set. Ambiguous advisories (merge commits, multi-repo references, unresolvable refs) are dropped.<p>Currently evaluating GPT-5.4, Claude Opus 4.6, Gemini 3.1 Pro, GLM-5.1, and Kimi K2.5. All traces are public.<p>Methodology: <a href=\"https://ndaybench.winfunc.com/methodology\">https://ndaybench.winfunc.com/methodology</a><p>Live Leaderboard: <a href=\"https://ndaybench.winfunc.com/leaderboard\">https://ndaybench.winfunc.com/leaderboard</a><p>Live Traces: <a href=\"https://ndaybench.winfunc.com/traces\">https://ndaybench.winfunc.com/traces</a></p>\\n<hr />\\n<p>Comments URL: <a href=\"https://news.ycombinator.com/item?id=47758347\">https://news.ycombinator.com/item?id=47758347</a></p>\\n<p>Points: 41</p>\\n<p># Comments: 11</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://hnrss.org/frontpage\', \'value\': \'<p>N-Day-Bench tests whether frontier LLMs can find known security vulnerabilities in real repository code. Each month it pulls fresh cases from GitHub security advisories, checks out the repo at the last commit before the patch, and gives models a sandboxed bash shell to explore the codebase.<p>Static vulnerability discovery benchmarks become outdated quickly. Cases leak into training data, and scores start measuring memorization. The monthly refresh keeps the test set ahead of contamination — or at least makes the contamination window honest.<p>Each case runs three agents: a Curator reads the advisory and builds an answer key, a Finder (the model under test) gets 24 shell steps to explore the code and write a structured report, and a Judge scores the blinded submission. The Finder never sees the patch. It starts from sink hints and must trace the bug through actual code.<p>Only repos with 10k+ stars qualify. A diversity pass prevents any single repo from dominating the set. Ambiguous advisories (merge commits, multi-repo references, unresolvable refs) are dropped.<p>Currently evaluating GPT-5.4, Claude Opus 4.6, Gemini 3.1 Pro, GLM-5.1, and Kimi K2.5. All traces are public.<p>Methodology: <a href=\"https://ndaybench.winfunc.com/methodology\">https://ndaybench.winfunc.com/methodology</a><p>Live Leaderboard: <a href=\"https://ndaybench.winfunc.com/leaderboard\">https://ndaybench.winfunc.com/leaderboard</a><p>Live Traces: <a href=\"https://ndaybench.winfunc.com/traces\">https://ndaybench.winfunc.com/traces</a></p>\\n<hr />\\n<p>Comments URL: <a href=\"https://news.ycombinator.com/item?id=47758347\">https://news.ycombinator.com/item?id=47758347</a></p>\\n<p>Points: 41</p>\\n<p># Comments: 11</p>\'}, \'published\': \'Mon, 13 Apr 2026 21:54:03 +0000\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=21, tm_min=54, tm_sec=3, tm_wday=0, tm_yday=103, tm_isdst=0), \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://ndaybench.winfunc.com\'}], \'link\': \'https://ndaybench.winfunc.com\', \'authors\': [{\'name\': \'mufeedvh\'}], \'author\': \'mufeedvh\', \'author_detail\': {\'name\': \'mufeedvh\'}, \'comments\': \'https://news.ycombinator.com/item?id=47758347\', \'id\': \'https://news.ycombinator.com/item?id=47758347\', \'guidislink\': False}', '2026-04-13 21:54:03', '2026-04-14 03:43:05', 0, '\"\"');
