INSERT INTO `news` VALUES (267, 'Thousands of rare concert recordings are landing on the Internet Archive — listen now', 'https://techcrunch.com/2026/04/13/thousands-of-rare-concert-recordings-are-landing-on-the-internet-archive-listen-now/', 'https://techcrunch.com/feed/', 'Chicago-based music superfan Aadam Jacobs has been recording the concerts he goes to since the 1980s, amassing an archive of over 10,000 tapes.', '', '', '', '', '{\'title\': \'Thousands of rare concert recordings are landing on the Internet Archive — listen now\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://techcrunch.com/feed/\', \'value\': \'Thousands of rare concert recordings are landing on the Internet Archive — listen now\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://techcrunch.com/2026/04/13/thousands-of-rare-concert-recordings-are-landing-on-the-internet-archive-listen-now/\'}], \'link\': \'https://techcrunch.com/2026/04/13/thousands-of-rare-concert-recordings-are-landing-on-the-internet-archive-listen-now/\', \'authors\': [{\'name\': \'Amanda Silberling\'}], \'author\': \'Amanda Silberling\', \'author_detail\': {\'name\': \'Amanda Silberling\'}, \'published\': \'Mon, 13 Apr 2026 20:20:47 +0000\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=20, tm_min=20, tm_sec=47, tm_wday=0, tm_yday=103, tm_isdst=0), \'tags\': [{\'term\': \'Media & Entertainment\', \'scheme\': None, \'label\': None}, {\'term\': \'In Brief\', \'scheme\': None, \'label\': None}, {\'term\': \'Internet archive\', \'scheme\': None, \'label\': None}], \'id\': \'https://techcrunch.com/?p=3111913\', \'guidislink\': False, \'summary\': \'Chicago-based music superfan Aadam Jacobs has been recording the concerts he goes to since the 1980s, amassing an archive of over 10,000 tapes.\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://techcrunch.com/feed/\', \'value\': \'Chicago-based music superfan Aadam Jacobs has been recording the concerts he goes to since the 1980s, amassing an archive of over 10,000 tapes.\'}}', '2026-04-13 20:20:47', '2026-04-14 03:43:07', 0, '\"\"');
