INSERT INTO `news` VALUES (269, 'IBM pays $17M fine to end DOJ suit over DEI programs', 'https://techcrunch.com/2026/04/13/ibm-pays-17m-fine-to-end-doj-suit-over-dei-programs/', 'https://techcrunch.com/feed/', 'IBM entered into a $17 million settlement agreement on Friday with the U.S. DOJ over allegations that it engaged in “illegal DEI practices.”', '', '', '', '', '{\'title\': \'IBM pays $17M fine to end DOJ suit over DEI programs\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://techcrunch.com/feed/\', \'value\': \'IBM pays $17M fine to end DOJ suit over DEI programs\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://techcrunch.com/2026/04/13/ibm-pays-17m-fine-to-end-doj-suit-over-dei-programs/\'}], \'link\': \'https://techcrunch.com/2026/04/13/ibm-pays-17m-fine-to-end-doj-suit-over-dei-programs/\', \'authors\': [{\'name\': \'Dominic-Madori Davis\'}], \'author\': \'Dominic-Madori Davis\', \'author_detail\': {\'name\': \'Dominic-Madori Davis\'}, \'published\': \'Mon, 13 Apr 2026 19:11:27 +0000\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=19, tm_min=11, tm_sec=27, tm_wday=0, tm_yday=103, tm_isdst=0), \'tags\': [{\'term\': \'Enterprise\', \'scheme\': None, \'label\': None}, {\'term\': \'Government & Policy\', \'scheme\': None, \'label\': None}, {\'term\': \'IBM\', \'scheme\': None, \'label\': None}, {\'term\': \'doj\', \'scheme\': None, \'label\': None}, {\'term\': \'DEI\', \'scheme\': None, \'label\': None}, {\'term\': \'In Brief\', \'scheme\': None, \'label\': None}], \'id\': \'https://techcrunch.com/?p=3111807\', \'guidislink\': False, \'summary\': \'IBM entered\\xa0into a $17 million settlement agreement on Friday with the U.S. DOJ over allegations that it engaged in “illegal DEI practices.”\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://techcrunch.com/feed/\', \'value\': \'IBM entered\\xa0into a $17 million settlement agreement on Friday with the U.S. DOJ over allegations that it engaged in “illegal DEI practices.”\'}}', '2026-04-13 19:11:27', '2026-04-14 03:43:10', 0, '\"\"');
