INSERT INTO `news` VALUES (275, 'Stanford report highlights growing disconnect between AI insiders and everyone else', 'https://techcrunch.com/2026/04/13/stanford-report-highlights-growing-disconnect-between-ai-insiders-and-everyone-else/', 'https://techcrunch.com/feed/', 'Stanford’s latest AI Index shows a widening gap between experts and the public, with rising anxiety over jobs, healthcare, and the economy.', '', '', '', '', '{\'title\': \'Stanford report highlights growing disconnect between AI insiders and everyone else\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://techcrunch.com/feed/\', \'value\': \'Stanford report highlights growing disconnect between AI insiders and everyone else\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://techcrunch.com/2026/04/13/stanford-report-highlights-growing-disconnect-between-ai-insiders-and-everyone-else/\'}], \'link\': \'https://techcrunch.com/2026/04/13/stanford-report-highlights-growing-disconnect-between-ai-insiders-and-everyone-else/\', \'authors\': [{\'name\': \'Sarah Perez\'}], \'author\': \'Sarah Perez\', \'author_detail\': {\'name\': \'Sarah Perez\'}, \'published\': \'Mon, 13 Apr 2026 18:55:37 +0000\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=18, tm_min=55, tm_sec=37, tm_wday=0, tm_yday=103, tm_isdst=0), \'tags\': [{\'term\': \'AI\', \'scheme\': None, \'label\': None}, {\'term\': \'public sentiment\', \'scheme\': None, \'label\': None}, {\'term\': \'sam altman\', \'scheme\': None, \'label\': None}, {\'term\': \'stanford ai report\', \'scheme\': None, \'label\': None}], \'id\': \'https://techcrunch.com/?p=3111798\', \'guidislink\': False, \'summary\': \'Stanford’s latest AI Index shows a widening gap between experts and the public, with rising anxiety over jobs, healthcare, and the economy.\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://techcrunch.com/feed/\