INSERT INTO `news` VALUES (276, 'Show HN: Ithihāsas – a character explorer for Hindu epics, built in a few hours', 'https://www.ithihasas.in', 'https://hnrss.org/frontpage', '<p>Hi HN!<p>I’ve always found it hard to explore the Mahābhārata and Rāmāyaṇa online. Most content is either long-form or scattered, and understanding a character like Karna or Bhishma usually means opening multiple tabs.<p>I built <a href=\"https://www.ithihasas.in/\" rel=\"nofollow\">https://www.ithihasas.in/</a> to solve that. It is a simple character explorer that lets you navigate the epics through people and their relationships instead of reading everything linearly.<p>This was also an experiment with Claude CLI. I was able to put together the first version in a couple of hours. It helped a lot with generating structured content and speeding up development, but UX and data consistency still needed manual work.<p>Would love feedback on the UX and whether this way of exploring mythology works for you.</p>\n<hr />\n<p>Comments URL: <a href=\"https://news.ycombinator.com/item?id=47756569\">https://news.ycombinator.com/item?id=47756569</a></p>\n<p>Points: 119</p>\n<p># Comments: 28</p>', '', '', '', '', '{\'title\': \'Show HN: Ithihāsas – a character explorer for Hindu epics, built in a few hours\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://hnrss.org/frontpage\', \'value\': \'Show HN: Ithihāsas – a character explorer for Hindu epics, built in a few hours\'}, \'summary\': \'<p>Hi HN!<p>I’ve always found it hard to explore the Mahābhārata and Rāmāyaṇa online. Most content is either long-form or scattered, and understanding a character like Karna or Bhishma usually means opening multiple tabs.<p>I built <a href=\"https://www.ithihasas.in/\" rel=\"nofollow\">https://www.ithihasas.in/</a> to solve that. It is a simple character explorer that lets you navigate the epics through people and their relationships instead of reading everything linearly.<p>This was also an experiment with Claude CLI. I was able to put together the first version in a couple of hours. It helped a lot with generating structured content and speeding up development, but UX and data consistency still needed manual work.<p>Would love feedback on the UX and whether this way of exploring mythology works for you.</p>\\n<hr />\\n<p>Comments URL: <a href=\"https://news.ycombinator.com/item?id=47756569\">https://news.ycombinator.com/item?id=47756569</a></p>\\n<p>Points: 119</p>\\n<p># Comments: 28</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://hnrss.org/frontpage\', \'value\': \'<p>Hi HN!<p>I’ve always found it hard to explore the Mahābhārata and Rāmāyaṇa online. Most content is either long-form or scattered, and understanding a character like Karna or Bhishma usually means opening multiple tabs.<p>I built <a href=\"https://www.ithihasas.in/\" rel=\"nofollow\">https://www.ithihasas.in/</a> to solve that. It is a simple character explorer that lets you navigate the epics through people and their relationships instead of reading everything linearly.<p>This was also an experiment with Claude CLI. I was able to put together the first version in a couple of hours. It helped a lot with generating structured content and speeding up development, but UX and data consistency still needed manual work.<p>Would love feedback on the UX and whether this way of exploring mythology works for you.</p>\\n<hr />\\n<p>Comments URL: <a href=\"https://news.ycombinator.com/item?id=47756569\">https://news.ycombinator.com/item?id=47756569</a></p>\\n<p>Points: 119</p>\\n<p># Comments: 28</p>\'}, \'published\': \'Mon, 13 Apr 2026 19:10:07 +0000\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=19, tm_min=10, tm_sec=7, tm_wday=0, tm_yday=103, tm_isdst=0), \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.ithihasas.in\'}], \'link\': \'https://www.ithihasas.in\', \'authors\': [{\'name\': \'cvrajeesh\'}], \'author\': \'cvrajeesh\', \'author_detail\': {\'name\': \'cvrajeesh\'}, \'comments\': \'https://news.ycombinator.com/item?id=47756569\', \'id\': \'https://news.ycombinator.com/item?id=47756569\', \'guidislink\': False}', '2026-04-13 19:10:07', '2026-04-14 03:43:20', 0, '\"\"');
