INSERT INTO `news` VALUES (290, '加密库 libsodium 1.0.22 发布', 'https://www.oschina.net/news/420378/libsodium-1-0-22-released', 'https://www.oschina.net/news/rss', 'libsodium 1.0.22 现已发布。此版本更新包含了 1.0.21-stable 版本的所有更改，此外还包括： 后量子密钥封装现已可用。ML-KEM768（the NIST-standardized lattice-based KEM）可通过crypto_kem_mlkem768_*()相关函数调用。 X-Wing 是一种混合型 KEM，它结合了 ML-KEM768 和 X25519，可同时抵御经典和量子攻击，可通过cry...', '', '', '', '', '{\'title\': \'加密库 libsodium 1.0.22 发布\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'加密库 libsodium 1.0.22 发布\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420378/libsodium-1-0-22-released\'}], \'link\': \'https://www.oschina.net/news/420378/libsodium-1-0-22-released\', \'tags\': [{\'term\': \'软件更新新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'libsodium 1.0.22 现已发布。此版本更新包含了 1.0.21-stable 版本的所有更改，此外还包括： 后量子密钥封装现已可用。ML-KEM768（the NIST-standardized lattice-based KEM）可通过crypto_kem_mlkem768_*()相关函数调用。 X-Wing 是一种混合型 KEM，它结合了 ML-KEM768 和 X25519，可同时抵御经典和量子攻击，可通过cry...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'libsodium 1.0.22 现已发布。此版本更新包含了 1.0.21-stable 版本的所有更改，此外还包括： 后量子密钥封装现已可用。ML-KEM768（the NIST-standardized lattice-based KEM）可通过crypto_kem_mlkem768_*()相关函数调用。 X-Wing 是一种混合型 KEM，它结合了 ML-KEM768 和 X25519，可同时抵御经典和量子攻击，可通过cry...\'}, \'published\': \'Mon, 13 Apr 2026 17:22:53 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=9, tm_min=22, tm_sec=53, tm_wday=0, tm_yday=103, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420378/libsodium-1-0-22-released\', \'guidislink\': False}', '2026-04-13 17:22:53', '2026-04-14 03:43:35', 0, '\"\"');
