INSERT INTO `news` VALUES (296, 'TIOBE 4 月榜单：Rust 崛起势头放缓', 'https://www.oschina.net/news/420347/tiobe-index-202604', 'https://www.oschina.net/news/rss', 'TIOBE 公布了 2026 年 4 月的编程语言排行榜。 本月榜单主要侧重在 Rust 语言的发展方面。Rust 是 TIOBE 指数前 20 名中最年轻的语言。它于 2020 年 6 月首次进入前 20 名，并被广泛预期将跻身前 10 名，成为 C 和 C++ 的强劲竞争对手。 此后，Rust 的排名稳步提升，甚至在今年年初达到了历史最高点（第 13 位）。然而，...', '', '', '', '', '{\'title\': \'TIOBE 4 月榜单：Rust 崛起势头放缓\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'TIOBE 4 月榜单：Rust 崛起势头放缓\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420347/tiobe-index-202604\'}], \'link\': \'https://www.oschina.net/news/420347/tiobe-index-202604\', \'tags\': [{\'term\': \'综合新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'TIOBE 公布了 2026 年 4 月的编程语言排行榜。 本月榜单主要侧重在 Rust 语言的发展方面。Rust 是 TIOBE 指数前 20 名中最年轻的语言。它于 2020 年 6 月首次进入前 20 名，并被广泛预期将跻身前 10 名，成为 C 和 C++ 的强劲竞争对手。 此后，Rust 的排名稳步提升，甚至在今年年初达到了历史最高点（第 13 位）。然而，...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'TIOBE 公布了 2026 年 4 月的编程语言排行榜。 本月榜单主要侧重在 Rust 语言的发展方面。Rust 是 TIOBE 指数前 20 名中最年轻的语言。它于 2020 年 6 月首次进入前 20 名，并被广泛预期将跻身前 10 名，成为 C 和 C++ 的强劲竞争对手。 此后，Rust 的排名稳步提升，甚至在今年年初达到了历史最高点（第 13 位）。然而，...\'}, \'published\': \'Mon, 13 Apr 2026 16:14:44 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=8, tm_min=14, tm_sec=44, tm_wday=0, tm_yday=103, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420347/tiobe-index-202604\', \'guidislink\': False}', '2026-04-13 16:14:44', '2026-04-14 03:43:40', 0, '\"\"');
