INSERT INTO `news` VALUES (298, 'VirtualEnv 21.2.1 发布，Python 虚拟环境', 'https://www.oschina.net/news/420333/virtualenv-21-2-1-released', 'https://www.oschina.net/news/rss', 'VirtualEnv 21.2.1 现已发布，VirtualEnv 用于在一台机器上创建多个独立的 Python 运行环境，可隔离项目之间的第三方包依赖，为部署应用提供方便，把开发环境的虚拟环境打包到生产环境即可，不需要在服务器上再折腾一翻。 新版更新内容如下： 升级嵌入式 pip/setuptools/wheel #3093 增强升级工作流：age check, dedup,...', '', '', '', '', '{\'title\': \'VirtualEnv 21.2.1 发布，Python 虚拟环境\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'VirtualEnv 21.2.1 发布，Python 虚拟环境\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420333/virtualenv-21-2-1-released\'}], \'link\': \'https://www.oschina.net/news/420333/virtualenv-21-2-1-released\', \'tags\': [{\'term\': \'软件更新新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'VirtualEnv 21.2.1 现已发布，VirtualEnv 用于在一台机器上创建多个独立的 Python 运行环境，可隔离项目之间的第三方包依赖，为部署应用提供方便，把开发环境的虚拟环境打包到生产环境即可，不需要在服务器上再折腾一翻。 新版更新内容如下： 升级嵌入式 pip/setuptools/wheel #3093 增强升级工作流：age check, dedup,...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'VirtualEnv 21.2.1 现已发布，VirtualEnv 用于在一台机器上创建多个独立的 Python 运行环境，可隔离项目之间的第三方包依赖，为部署应用提供方便，把开发环境的虚拟环境打包到生产环境即可，不需要在服务器上再折腾一翻。 新版更新内容如下： 升级嵌入式 pip/setuptools/wheel #3093 增强升级工作流：age check, dedup,...\'}, \'published\': \'Mon, 13 Apr 2026 15:52:45 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=7, tm_min=52, tm_sec=45, tm_wday=0, tm_yday=103, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420333/virtualenv-21-2-1-released\', \'guidislink\': False}', '2026-04-13 15:52:45', '2026-04-14 03:43:42', 0, '\"\"');
