INSERT INTO `news` VALUES (308, 'MiniMax M2.7 开源', 'https://www.oschina.net/news/420305', 'https://www.oschina.net/news/rss', 'MiniMax M2.7 宣布已正式开源。并在开源首日完成了和华为昇腾、摩尔线程、沐曦、昆仑芯、NVIDIA，以及 Together AI、Fireworks、Ollama 等海内外芯片厂商、推理平台的模型接入与推理适配工作。 昇腾 AI 基础软硬件实现首日适配，基于 vllm-Ascend 推理引擎在 Atlas 800 A3、Atlas 800I A2 系列产品上为模型的推理部署提供...', '', '', '', '', '{\'title\': \'MiniMax M2.7 开源\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'MiniMax M2.7 开源\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420305\'}], \'link\': \'https://www.oschina.net/news/420305\', \'tags\': [{\'term\': \'综合新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'MiniMax M2.7 宣布已正式开源。并在开源首日完成了和华为昇腾、摩尔线程、沐曦、昆仑芯、NVIDIA，以及 Together AI、Fireworks、Ollama 等海内外芯片厂商、推理平台的模型接入与推理适配工作。 昇腾 AI 基础软硬件实现首日适配，基于 vllm-Ascend 推理引擎在 Atlas 800 A3、Atlas 800I A2 系列产品上为模型的推理部署提供...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'MiniMax M2.7 宣布已正式开源。并在开源首日完成了和华为昇腾、摩尔线程、沐曦、昆仑芯、NVIDIA，以及 Together AI、Fireworks、Ollama 等海内外芯片厂商、推理平台的模型接入与推理适配工作。 昇腾 AI 基础软硬件实现首日适配，基于 vllm-Ascend 推理引擎在 Atlas 800 A3、Atlas 800I A2 系列产品上为模型的推理部署提供...\'}, \'published\': \'Mon, 13 Apr 2026 14:28:45 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=6, tm_min=28, tm_sec=45, tm_wday=0, tm_yday=103, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420305\', \'guidislink\': False}', '2026-04-13 14:28:45', '2026-04-14 03:43:56', 0, '\"\"');
INSERT INTO `news` VALUES (309, 'From LLMs to hallucinations, here’s a simple guide to common AI terms', 'https://techcrunch.com/2026/04/12/artificial-intelligence-definition-glossary-hallucinations-guide-to-common-ai-terms/', 'https://techcrunch.com/feed/', 'The rise of AI has brought an avalanche of new terms and slang. Here is a glossary with definitions of some of the most important words and phrases you might encounter.', '', '', '', '', '{\'title\': \'From LLMs to hallucinations, here’s a simple guide to common AI terms\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://techcrunch.com/feed/\', \'value\': \'From LLMs to hallucinations, here’s a simple guide to common AI terms\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://techcrunch.com/2026/04/12/artificial-intelligence-definition-glossary-hallucinations-guide-to-common-ai-terms/\'}], \'link\': \'https://techcrunch.com/2026/04/12/artificial-intelligence-definition-glossary-hallucinations-guide-to-common-ai-terms/\', \'authors\': [{\'name\': \'Natasha Lomas, Romain Dillet, Kyle Wiggers, Lucas Ropek\'}], \'author\': \'Natasha Lomas, Romain Dillet, Kyle Wiggers, Lucas Ropek\', \'author_detail\': {\'name\': \'Natasha Lomas, Romain Dillet, Kyle Wiggers, Lucas Ropek\'}, \'published\': \'Sun, 12 Apr 2026 15:07:08 +0000\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=12, tm_hour=15, tm_min=7, tm_sec=8, tm_wday=6, tm_yday=102, tm_isdst=0), \'tags\': [{\'term\': \'AI\', \'scheme\': None, \'label\': None}, {\'term\': \'artificial intelligence\', \'scheme\': None, \'label\': None}, {\'term\': \'evergreens\', \'scheme\': None, \'label\': None}, {\'term\': \'Glossary\', \'scheme\': None, \'label\': None}], \'id\': \'https://techcrunch.com/?p=2973217\', \'guidislink\': False, \'summary\': \'The rise of AI has brought an avalanche of new terms and slang. Here is a glossary with definitions of some of the most important words and phrases you might encounter.\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://techcrunch.com/feed/\', \'value\': \'The rise of AI has brought an avalanche of new terms and slang. Here is a glossary with definitions of some of the most important words and phrases you might encounter.\'}}', '2026-04-12 15:07:08', '2026-04-14 03:43:56', 0, '\"\"');
