INSERT INTO `news` VALUES (317, 'Cilium 庆祝十周年', 'https://www.oschina.net/news/420224', 'https://www.oschina.net/news/rss', 'Cilium 项目庆祝成立 10 周年，社区团队在庆祝的同事也围绕未来十年的工作负载需求对路线图进行了对齐。近期项目的一些进展包括：发布 Cilium 1.19、推出项目完整指南《Cilium Up and Running》、发布一本新的儿童读物，以及来自 OVHcloud 和 Zynga 的最新生产案例研究。 “十年过去，Cilium 不仅在跟上云原生基础设施不...', '', '', '', '', '{\'title\': \'Cilium 庆祝十周年\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'Cilium 庆祝十周年\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420224\'}], \'link\': \'https://www.oschina.net/news/420224\', \'tags\': [{\'term\': \'综合新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'Cilium 项目庆祝成立 10 周年，社区团队在庆祝的同事也围绕未来十年的工作负载需求对路线图进行了对齐。近期项目的一些进展包括：发布 Cilium 1.19、推出项目完整指南《Cilium Up and Running》、发布一本新的儿童读物，以及来自 OVHcloud 和 Zynga 的最新生产案例研究。 “十年过去，Cilium 不仅在跟上云原生基础设施不...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'Cilium 项目庆祝成立 10 周年，社区团队在庆祝的同事也围绕未来十年的工作负载需求对路线图进行了对齐。近期项目的一些进展包括：发布 Cilium 1.19、推出项目完整指南《Cilium Up and Running》、发布一本新的儿童读物，以及来自 OVHcloud 和 Zynga 的最新生产案例研究。 “十年过去，Cilium 不仅在跟上云原生基础设施不...\'}, \'published\': \'Mon, 13 Apr 2026 10:06:37 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=2, tm_min=6, tm_sec=37, tm_wday=0, tm_yday=103, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420224\', \'guidislink\': False}', '2026-04-13 10:06:37', '2026-04-14 03:44:24', 0, '\"\"');
INSERT INTO `news` VALUES (318, '优化兼容性 | gpress v1.2.4 发布', 'https://www.oschina.net/news/420223/gpress-1-2-4-released', 'https://www.oschina.net/news/rss', 'gpress 是 Web3 内容平台，Hertz + Go template + FTS5 全文检索，支持以太坊和百度超级链，兼容 Hugo、WordPress 生态，使用 Wasm 扩展插件，只需 200M 内存. 作为静态站点： gpress 生成的静态文件和 Hugo 一致，也可以简单认为 gpress 是 Hugo 的后台管理，兼容 Hugo 主题生态，已迁移多款 Hugo 主题:even、doks、boo...', '', '', '', '', '{\'title\': \'优化兼容性 | gpress v1.2.4 发布\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'优化兼容性 | gpress v1.2.4 发布\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420223/gpress-1-2-4-released\'}], \'link\': \'https://www.oschina.net/news/420223/gpress-1-2-4-released\', \'tags\': [{\'term\': \'软件更新新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'gpress 是 Web3 内容平台，Hertz + Go template + FTS5 全文检索，支持以太坊和百度超级链，兼容 Hugo、WordPress 生态，使用 Wasm 扩展插件，只需 200M 内存. 作为静态站点： gpress 生成的静态文件和 Hugo 一致，也可以简单认为 gpress 是 Hugo 的后台管理，兼容 Hugo 主题生态，已迁移多款 Hugo 主题:even、doks、boo...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'gpress 是 Web3 内容平台，Hertz + Go template + FTS5 全文检索，支持以太坊和百度超级链，兼容 Hugo、WordPress 生态，使用 Wasm 扩展插件，只需 200M 内存. 作为静态站点： gpress 生成的静态文件和 Hugo 一致，也可以简单认为 gpress 是 Hugo 的后台管理，兼容 Hugo 主题生态，已迁移多款 Hugo 主题:even、doks、boo...\'}, \'published\': \'Mon, 13 Apr 2026 10:05:12 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=2, tm_min=5, tm_sec=12, tm_wday=0, tm_yday=103, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420223/gpress-1-2-4-released\', \'guidislink\': False}', '2026-04-13 10:05:12', '2026-04-14 03:44:27', 0, '\"\"');
