INSERT INTO `news` VALUES (324, 'MacState v1.8.2 发布', 'https://www.oschina.net/news/419566', 'https://www.oschina.net/news/rss', 'MacState v1.8.2 已发布。轻量级 macOS 菜单栏系统监控工具，纯 Swift 开发，零第三方依赖，所有指标合并显示在单个状态栏项中，资源占用极低。 状态栏 设置面板 充电信息 优化 / Improved 线程数优化 — 消除 3 个进程面板独立定时器和队列，合并到 MonitorManager 统一调度；移除能耗 tooltip 独立 5s Timer，改用回调...', '', '', '', '', '{\'title\': \'MacState v1.8.2 发布\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'MacState v1.8.2 发布\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/419566\'}], \'link\': \'https://www.oschina.net/news/419566\', \'tags\': [{\'term\': \'软件更新新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'MacState v1.8.2 已发布。轻量级 macOS 菜单栏系统监控工具，纯 Swift 开发，零第三方依赖，所有指标合并显示在单个状态栏项中，资源占用极低。 状态栏 设置面板 充电信息 优化 / Improved 线程数优化 — 消除 3 个进程面板独立定时器和队列，合并到 MonitorManager 统一调度；移除能耗 tooltip 独立 5s Timer，改用回调...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'MacState v1.8.2 已发布。轻量级 macOS 菜单栏系统监控工具，纯 Swift 开发，零第三方依赖，所有指标合并显示在单个状态栏项中，资源占用极低。 状态栏 设置面板 充电信息 优化 / Improved 线程数优化 — 消除 3 个进程面板独立定时器和队列，合并到 MonitorManager 统一调度；移除能耗 tooltip 独立 5s Timer，改用回调...\'}, \'published\': \'Fri, 10 Apr 2026 23:08:33 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=10, tm_hour=15, tm_min=8, tm_sec=33, tm_wday=4, tm_yday=100, tm_isdst=0), \'id\': \'https://www.oschina.net/news/419566\', \'guidislink\': False}', '2026-04-10 23:08:33', '2026-04-14 03:44:55', 0, '\"\"');
INSERT INTO `news` VALUES (325, '开源中国完成 C+ 轮融资，冲刺“开源AI第一股”', 'https://www.oschina.net/news/419523', 'https://www.oschina.net/news/rss', '4月10日，开源中国宣布完成数亿元C+轮融资，由上海国投先导基金领投，中国互联网投资基金、君联资本、联想创投、苏创投及贝克资本联合跟投。截至目前，开源中国累计融资规模已接近20亿元。 开源中国于2008年8月创立，是国内核心开源与AI基础设施服务商，目前团队超300人，总部在北京市，同时在深圳、广州、郑州设立了研发...', '', '', '', '', '{\'title\': \'开源中国完成 C+ 轮融资，冲刺“开源AI第一股”\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'开源中国完成 C+ 轮融资，冲刺“开源AI第一股”\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/419523\'}], \'link\': \'https://www.oschina.net/news/419523\', \'tags\': [{\'term\': \'综合新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'4月10日，开源中国宣布完成数亿元C+轮融资，由上海国投先导基金领投，中国互联网投资基金、君联资本、联想创投、苏创投及贝克资本联合跟投。截至目前，开源中国累计融资规模已接近20亿元。 开源中国于2008年8月创立，是国内核心开源与AI基础设施服务商，目前团队超300人，总部在北京市，同时在深圳、广州、郑州设立了研发...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'4月10日，开源中国宣布完成数亿元C+轮融资，由上海国投先导基金领投，中国互联网投资基金、君联资本、联想创投、苏创投及贝克资本联合跟投。截至目前，开源中国累计融资规模已接近20亿元。 开源中国于2008年8月创立，是国内核心开源与AI基础设施服务商，目前团队超300人，总部在北京市，同时在深圳、广州、郑州设立了研发...\'}, \'published\': \'Fri, 10 Apr 2026 20:22:44 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=10, tm_hour=12, tm_min=22, tm_sec=44, tm_wday=4, tm_yday=100, tm_isdst=0), \'id\': \'https://www.oschina.net/news/419523\', \'guidislink\': False}', '2026-04-10 20:22:44', '2026-04-14 03:44:58', 0, '\"\"');
