INSERT INTO `news` VALUES (329, 'PHP 8.5.5 发布', 'https://www.oschina.net/news/419485/php-8-5-5-released', 'https://www.oschina.net/news/rss', 'PHP 8.5.5 现已发布，这是一个漏洞修复版本。建议所有 PHP 8.5 用户升级到此版本。 Core： 修复了错误 GH-20672（局部 shadowed 特征属性的 property_info 大小不正确）。 修复了错误 GH-20875、GH-20873、GH-20854（在 get_property_ptr_ptr 中为 lazy 代理传播 IN_GET 保护）。 Bz2： 修复总输出大小截断导致的错误。 ...', '', '', '', '', '{\'title\': \'PHP 8.5.5 发布\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'PHP 8.5.5 发布\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/419485/php-8-5-5-released\'}], \'link\': \'https://www.oschina.net/news/419485/php-8-5-5-released\', \'tags\': [{\'term\': \'软件更新新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'PHP 8.5.5 现已发布，这是一个漏洞修复版本。建议所有 PHP 8.5 用户升级到此版本。 Core： 修复了错误 GH-20672（局部 shadowed 特征属性的 property_info 大小不正确）。 修复了错误 GH-20875、GH-20873、GH-20854（在 get_property_ptr_ptr 中为 lazy 代理传播 IN_GET 保护）。 Bz2： 修复总输出大小截断导致的错误。 ...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'PHP 8.5.5 现已发布，这是一个漏洞修复版本。建议所有 PHP 8.5 用户升级到此版本。 Core： 修复了错误 GH-20672（局部 shadowed 特征属性的 property_info 大小不正确）。 修复了错误 GH-20875、GH-20873、GH-20854（在 get_property_ptr_ptr 中为 lazy 代理传播 IN_GET 保护）。 Bz2： 修复总输出大小截断导致的错误。 ...\'}, \'published\': \'Fri, 10 Apr 2026 18:13:43 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=10, tm_hour=10, tm_min=13, tm_sec=43, tm_wday=4, tm_yday=100, tm_isdst=0), \'id\': \'https://www.oschina.net/news/419485/php-8-5-5-released\', \'guidislink\': False}', '2026-04-10 18:13:43', '2026-04-14 03:45:10', 0, '\"\"');
