INSERT INTO `news` VALUES (332, '浅析分批分页查询场景及方案', 'https://my.oschina.net/u/4090830/blog/19482838', 'https://www.oschina.net/news/rss', '在日常开发中，不可避免的要用到分批查询或分页查询，其中的场景有很多，有的是 WEB 页面的分页查询效果，或移动端向下滑动的分页查询，有的则是因为目标数据量巨大，不得已而分批查询。无论是出于性能考虑，还是大报文考虑，抑或页面的效果，分批或分页查询都是研发的日常。', '', '', '', '', '{\'title\': \'浅析分批分页查询场景及方案\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'浅析分批分页查询场景及方案\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://my.oschina.net/u/4090830/blog/19482838\'}], \'link\': \'https://my.oschina.net/u/4090830/blog/19482838\', \'tags\': [{\'term\': \'综合新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'在日常开发中，不可避免的要用到分批查询或分页查询，其中的场景有很多，有的是 WEB 页面的分页查询效果，或移动端向下滑动的分页查询，有的则是因为目标数据量巨大，不得已而分批查询。无论是出于性能考虑，还是大报文考虑，抑或页面的效果，分批或分页查询都是研发的日常。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'在日常开发中，不可避免的要用到分批查询或分页查询，其中的场景有很多，有的是 WEB 页面的分页查询效果，或移动端向下滑动的分页查询，有的则是因为目标数据量巨大，不得已而分批查询。无论是出于性能考虑，还是大报文考虑，抑或页面的效果，分批或分页查询都是研发的日常。\'}, \'published\': \'Fri, 10 Apr 2026 15:33:12 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=10, tm_hour=7, tm_min=33, tm_sec=12, tm_wday=4, tm_yday=100, tm_isdst=0), \'id\': \'https://my.oschina.net/u/4090830/blog/19482838\', \'guidislink\': False}', '2026-04-10 15:33:12', '2026-04-14 03:45:19', 0, '\"\"');
