INSERT INTO `news` VALUES (335, '红帽撤离中国：一个时代的落幕', 'https://my.oschina.net/u/4487475/blog/19569568', 'https://www.oschina.net/news/rss', '红帽 （ Red Hat ）宣布停止在中国的全部工程活动，仅保留销售和支持职能，裁撤 419 名研发员工，雇佣关系统一于 2026 年 7 月 31 日终止，赔偿方案 N+3 至 N+6，研发职能将转移至亚太地区其他工程枢纽。 公告的措辞很简洁，像一份例行的业务调整声明。但对于国内所有关注开源的朋友们来说，这意味着一个时代的落幕。...', '', '', '', '', '{\'title\': \'红帽撤离中国：一个时代的落幕\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'红帽撤离中国：一个时代的落幕\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://my.oschina.net/u/4487475/blog/19569568\'}], \'link\': \'https://my.oschina.net/u/4487475/blog/19569568\', \'tags\': [{\'term\': \'综合新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'红帽 （ Red Hat ）宣布停止在中国的全部工程活动，仅保留销售和支持职能，裁撤 419 名研发员工，雇佣关系统一于 2026 年 7 月 31 日终止，赔偿方案 N+3 至 N+6，研发职能将转移至亚太地区其他工程枢纽。 公告的措辞很简洁，像一份例行的业务调整声明。但对于国内所有关注开源的朋友们来说，这意味着一个时代的落幕。...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'红帽 （ Red Hat ）宣布停止在中国的全部工程活动，仅保留销售和支持职能，裁撤 419 名研发员工，雇佣关系统一于 2026 年 7 月 31 日终止，赔偿方案 N+3 至 N+6，研发职能将转移至亚太地区其他工程枢纽。 公告的措辞很简洁，像一份例行的业务调整声明。但对于国内所有关注开源的朋友们来说，这意味着一个时代的落幕。...\'}, \'published\': \'Fri, 10 Apr 2026 14:48:22 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=10, tm_hour=6, tm_min=48, tm_sec=22, tm_wday=4, tm_yday=100, tm_isdst=0), \'id\': \'https://my.oschina.net/u/4487475/blog/19569568\', \'guidislink\': False}', '2026-04-10 14:48:22', '2026-04-14 03:46:56', 0, '\"\"');
