INSERT INTO `news` VALUES (360, 'ng-zorro-antd 21.2.2 发布，基于 Angular 的 UI 组件', 'https://www.oschina.net/news/420702/ng-zorro-antd-21-2-2-released', 'https://www.oschina.net/news/rss', 'ng-zorro-antd 是 Ant Design 的 Angular 实现，主要用于研发企业级中后台产品。全部代码开源并遵循 MIT 协议，任何企业、组织及个人均可免费使用。 ng-zorro-antd 21.2.2 正式发布，更新内容如下： Bug Fixes input: 使用 ng control 值初始化 value (#9748) (c650b8a) input: 修复使用 ngModel 时值不正确的问题 (#97...', '', '', '', '', '{\'title\': \'ng-zorro-antd 21.2.2 发布，基于 Angular 的 UI 组件\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'ng-zorro-antd 21.2.2 发布，基于 Angular 的 UI 组件\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420702/ng-zorro-antd-21-2-2-released\'}], \'link\': \'https://www.oschina.net/news/420702/ng-zorro-antd-21-2-2-released\', \'tags\': [{\'term\': \'软件更新新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'ng-zorro-antd 是 Ant Design 的 Angular 实现，主要用于研发企业级中后台产品。全部代码开源并遵循 MIT 协议，任何企业、组织及个人均可免费使用。 ng-zorro-antd 21.2.2 正式发布，更新内容如下： Bug Fixes input: 使用 ng control 值初始化 value (#9748) (c650b8a) input: 修复使用 ngModel 时值不正确的问题 (#97...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'ng-zorro-antd 是 Ant Design 的 Angular 实现，主要用于研发企业级中后台产品。全部代码开源并遵循 MIT 协议，任何企业、组织及个人均可免费使用。 ng-zorro-antd 21.2.2 正式发布，更新内容如下： Bug Fixes input: 使用 ng control 值初始化 value (#9748) (c650b8a) input: 修复使用 ngModel 时值不正确的问题 (#97...\'}, \'published\': \'Tue, 14 Apr 2026 13:55:02 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=5, tm_min=55, tm_sec=2, tm_wday=1, tm_yday=104, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420702/ng-zorro-antd-21-2-2-released\', \'guidislink\': False}', '2026-04-14 13:55:02', '2026-04-14 14:03:44', 0, '\"\"');
