INSERT INTO `news` VALUES (370, '国务院关于同意在海南省暂时调整实施有关行政法规规定的批复', 'http://www.gov.cn/zhengce/content/2023-03/21/content_5747668.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院关于同意在海南省暂时调整实施有关行政法规规定的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意在海南省暂时调整实施有关行政法规规定的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2023-03/21/content_5747668.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2023-03/21/content_5747668.htm\', \'published\': \'Fri, 02 Dec 2022 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2022, tm_mon=12, tm_mday=2, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=4, tm_yday=336, tm_isdst=0)}', '2022-12-02 16:00:00', '2026-04-14 14:04:31', 1, '{\"summary\": \"本文公布国务院对海南调整行政法规的批复，可为布局海南的出海企业提供政策方向参考\", \"abstract\": \"本文是国务院发布的批复文件，核心为同意海南省暂时调整实施有关行政法规规定。当前公开内容未披露具体调整事项的细节。本次规则调整或对出海企业在海南的布局运营产生影响\", \"keywords\": [\"国务院批复\", \"海南省\", \"行政法规调整\", \"政策调整\", \"出海政策\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"同意海南省暂时调整实施有关行政法规，具体调整内容未公开披露\"}, \"topic_cluster\": \"政策合规\", \"industry_category\": \"综合出海赛道\"}');
