INSERT INTO `news` VALUES (379, '国务院关于同意设立中国—菲律宾经贸创新发展示范园区的批复', 'http://www.gov.cn/zhengce/content/2023-01/19/content_5737967.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院关于同意设立中国—菲律宾经贸创新发展示范园区的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意设立中国—菲律宾经贸创新发展示范园区的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2023-01/19/content_5737967.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2023-01/19/content_5737967.htm\', \'published\': \'Wed, 30 Nov 2022 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2022, tm_mon=11, tm_mday=30, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=2, tm_yday=334, tm_isdst=0)}', '2022-11-30 16:00:00', '2026-04-14 14:05:28', 1, '{\"summary\": \"本文公布国务院设立中菲经贸创新发展示范园区的批复，为计划出海菲律宾的中国企业提供政策利好参考\", \"abstract\": \"国务院批复同意设立中国—菲律宾经贸创新发展示范园区，该园区将推动中菲双方经贸创新发展合作。它为中国企业出海布局菲律宾市场打造了官方认可的合作新平台，有意拓展菲律宾市场的出海企业可关注该园区后续配套落地政策，抢抓合作机遇。\", \"keywords\": [\"中菲经贸\", \"创新发展示范园区\", \"国务院批复\", \"企业出海\", \"菲律宾市场\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"国务院同意设立中国—菲律宾经贸创新发展示范园区，为中资企业出海菲律宾提供官方政策支持\"}, \"topic_cluster\": \"海外市场政策与拓展\", \"industry_category\": \"跨境经贸\"}');
INSERT INTO `news` VALUES (380, '国务院关于同意设立中国—印度尼西亚经贸创新发展示范园区的批复', 'http://www.gov.cn/zhengce/content/2023-01/19/content_5737964.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院关于同意设立中国—印度尼西亚经贸创新发展示范园区的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意设立中国—印度尼西亚经贸创新发展示范园区的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2023-01/19/content_5737964.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2023-01/19/content_5737964.htm\', \'published\': \'Wed, 30 Nov 2022 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2022, tm_mon=11, tm_mday=30, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=2, tm_yday=334, tm_isdst=0)}', '2022-11-30 16:00:00', '2026-04-14 14:05:56', 1, '{\"summary\": \"本文公布国务院批复设立中印尼经贸创新发展示范园区，为中国出海企业布局印尼提供新的官方合作平台参考\", \"abstract\": \"国务院正式批复同意设立中国—印度尼西亚经贸创新发展示范园区。该园区将成为中印尼双边经贸创新合作的核心载体。它为中国企业出海布局印尼市场提供了政策支持与合作平台。将进一步推动中印尼两国经贸往来与产业合作升级。\", \"keywords\": [\"中印尼经贸创新发展示范园区\", \"国务院批复\", \"出海布局\", \"双边经贸\", \"印尼市场\", \"境外园区\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"国务院同意设立中国—印度尼西亚经贸创新发展示范园区，为中企出海印尼搭建官方认可的经贸合作平台\"}, \"topic_cluster\": \"海外经贸园区建设\", \"industry_category\": \"综合性跨境经贸\"}');
