INSERT INTO `news` VALUES (388, '国务院关于同意在沈阳等6个城市开展服务业扩大开放综合试点的批复', 'http://www.gov.cn/zhengce/content/2022-12/20/content_5732723.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院关于同意在沈阳等6个城市开展服务业扩大开放综合试点的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意在沈阳等6个城市开展服务业扩大开放综合试点的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-12/20/content_5732723.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-12/20/content_5732723.htm\', \'published\': \'Mon, 01 Nov 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=11, tm_mday=1, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=0, tm_yday=305, tm_isdst=0)}', '2021-11-01 16:00:00', '2026-04-14 14:07:00', 1, '{\"summary\": \"本文公布国务院服务业扩大开放试点批复，帮助出海服务业企业了解国内开放政策动向\", \"abstract\": \"国务院发布批复，同意在沈阳等6个城市开展服务业扩大开放综合试点。该试点是我国推进服务业对外开放的重要布局。相关出海服务业企业可依托试点政策获得更好的发展支持。\", \"keywords\": [\"服务业扩大开放\", \"综合试点\", \"国务院批复\", \"对外开放\", \"城市试点\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"国务院同意在沈阳等6个城市开展服务业扩大开放综合试点，推进服务业领域对外开放\"}, \"topic_cluster\": \"政策研究\", \"industry_category\": \"服务业\"}');
INSERT INTO `news` VALUES (389, '国务院办公厅关于印发“十四五”现代物流发展规划的通知', 'http://www.gov.cn/zhengce/content/2022-12/15/content_5732092.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院办公厅关于印发“十四五”现代物流发展规划的通知\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院办公厅关于印发“十四五”现代物流发展规划的通知\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-12/15/content_5732092.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-12/15/content_5732092.htm\', \'published\': \'Mon, 01 Nov 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=11, tm_mday=1, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=0, tm_yday=305, tm_isdst=0)}', '2021-11-01 16:00:00', '2026-04-14 14:07:23', 1, '{\"summary\": \"本文为国务院印发的“十四五”现代物流发展规划官方通知，可为出海物流相关企业提供政策方向参考\", \"abstract\": \"本文是国务院办公厅印发“十四五”现代物流发展规划的官方通知。该通知针对我国现代物流领域明确了“十四五”阶段的发展框架。这份规划对国内物流企业出海布局具备政策指导价值。相关出海主体可参考规划要求调整自身发展战略。\", \"keywords\": [\"十四五规划\", \"现代物流\", \"供应链物流\", \"企业出海\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"国务院办公厅印发“十四五”现代物流发展规划，明确我国现代物流行业十四五阶段发展方向\"}, \"topic_cluster\": \"供应链物流\", \"industry_category\": \"物流\"}');
