6krcdn.com/hsossms/20260413/v2_1d166f48f3ea47fb9290f6ac2dbd1a3b@6221844_oswg4511313oswg4000oswg2667_img_jpg?x-oss-process=image/quality,q_80/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">图匠® LumiCraft具身打磨机器人进行现场演示（图源/企业）</p>\\n  <p>图速科技成立于2016年，总部位于上海松江，2025年在浙江湖州南浔落成3000平方米工程中心。公司核心业务聚焦轨道交通、航空航天、风力发电、汽车制造四大行业，目前已与多家头部客户形成深度合作。</p>\\n  <p>目前，公司已在华东、华南、西南、西北、华北及东北布局服务网络，具备全国快速响应能力。公司方面表示，未来将进一步拓展船舶、低空经济、装备制造及汽车后市场等新兴增长领域。</p>\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-13 20:07:37', '2026-04-14 14:09:21', 0, '\"\"');
INSERT INTO `news` VALUES (398, '国务院关于同意在廊坊等33个城市和地区设立跨境电子商务综合试验区的批复', 'http://www.gov.cn/zhengce/content/2022-11/24/content_5728554.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院关于同意在廊坊等33个城市和地区设立跨境电子商务综合试验区的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意在廊坊等33个城市和地区设立跨境电子商务综合试验区的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-11/24/content_5728554.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-11/24/content_5728554.htm\', \'published\': \'Sun, 31 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=31, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=6, tm_yday=304, tm_isdst=0)}', '2021-10-31 16:00:00', '2026-04-14 14:09:26', 1, '{\"summary\": \"帮助跨境电商出海企业了解国内最新跨境电商综试区设立政策，把握政策红利\", \"abstract\": \"本文是国务院关于设立跨境电子商务综合试验区的批复文件。批复明确同意在廊坊等33个城市和地区设立新的跨境电子商务综合试验区。新综试区的设立将为跨境电商企业出海提供更多政策支持与发展便利。此举将进一步推动我国跨境电商产业开放发展，助力企业出海\", \"keywords\": [\"跨境电子商务综合试验区\", \"跨境电商\", \"企业出海\", \"国务院批复\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"国务院批复同意在廊坊等33个城市和地区设立跨境电子商务综合试验区，为跨境电商出海提供政策支持\"}, \"topic_cluster\": \"政策服务\", \"industry_category\": \"跨境电商\"}');
INSERT INTO `news` VALUES (399, '国务院关于同意嘉兴秀洲高新技术产业开发区更名为嘉兴高新技术产业开发区的批复', 'http://www.gov.cn/zhengce/content/2022-11/22/content_5728246.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院关于同意嘉兴秀洲高新技术产业开发区更名为嘉兴高新技术产业开发区的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意嘉兴秀洲高新技术产业开发区更名为嘉兴高新技术产业开发区的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-11/22/content_5728246.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-11/22/content_5728246.htm\', \'published\': \'Sun, 31 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=31, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=6, tm_yday=304, tm_isdst=0)}', '2021-10-31 16:00:00', '2026-04-14 14:09:28', 0, '\"\"');
INSERT INTO `news` VALUES (400, '氪星晚报｜“马斯克版微信”或在本周五上线；Meta押注AI数字人，正打造AI版扎克伯格；AI潮玩品牌“MOMOTOY”完成数千万元融资', 'https://36kr.com/p/3765146768376326?f=rss', 'https://36kr.com/feed', '<h2>大公司：</h2>\n  <p><strong>金山办公：一季度净利同比预增402%-473%</strong></p>\n  <p>36氪获悉，金山办公公告，预计2026年第一季度实现归属于上市公司股东的净利润20.22亿元-23.07亿元，同比增长401.89%-472.81%。</p>\n  <p><strong>沪电股份：一季度净利同比预增54.76%-65.25%</strong></p>\n  <p>36氪获悉，沪电股份公告，预计2026年第一季度归属于上市公司股东的净利润为11.8亿元-12.6亿元，比上年同期增长54.76%-65.25%。</p>\n  <p><strong>Meta押注AI数字人，正打造AI版扎克伯格</strong></p>\n  <p>Meta正在打造人工智能版马克・扎克伯格，可代他与员工互动，这是这家科技巨头全面向AI转型的重要举措之一。据四位知情人士透露，这家市值1.6万亿美元的集团一直在研发照片级逼真、可实时交互的AI 3D数字人。其中三位人士称，公司近期已将AI版扎克伯格列为优先项目。（新浪财经）</p>\n  <p><strong>小红书跨境电商平台Redshop将于今年6月正式上线</strong></p>\n  <p>4月13日上午消息，今日，接近小红书的相关人士向媒体透露，其跨境电商平台Redshop将于2026年6月正式上线，标志着小红书从“商家出海”的测试阶段，全面迈入“平台出海”的战略新阶段，进一步完善其全球化商业布局。对此，接近小红书的人士表示，“Redshop将于2026年6月正式上线，首期计划定向邀请部分种子商家，重点覆盖非遗手工、特色手工艺品等品类，后续将逐步拓展至更多类目。”（新浪科技）</p>\n  <p><strong>王石回应被抓传闻：一切安好，造谣者交给法律</strong></p>\n  <p>36氪获悉，4月12日，网传万科创始人王石被抓。王石个人微博回应：“看来大家比我本人还关心我的动态。一切安好，造谣者交给法律。”</p>\n  <p><strong>荣耀机器人“闪电”“元气仔”出征北京亦庄马拉松</strong></p>\n  <p>4月19日，机器人马拉松将在北京亦庄举行。荣耀自研机器人“闪电”“元气仔”正式报名参赛，成为全球首个由终端大厂派出选手的机器人马拉松挑战者。据荣耀技术团队介绍，荣耀机器人“闪电”集成了荣耀在智能制造与具身AI领域的最新成果，高性能高爆发稳定的本体、高动态运控算法、实时感知理解与自主决策能力。</p>\n  <h2>投融资：</h2>\n  <p><strong>AI潮玩品牌“MOMOTOY”完成数千万元融资</strong></p>\n  <p>36氪获悉，AI潮玩品牌“MOMOTOY”已完成数千万元融资，由翼朴基金投资，投后估值2.5亿。品牌负责人透露，本轮融资资金，会重点投向AI技术迭代、高端产品矩阵落地、全球渠道拓展及核心商圈旗舰店铺设四大核心领域。</p>\n  <h2>新产品：</h2>\n  <p><strong>百度Duclaw推出小龙虾生活助手</strong></p>\n  <p>36氪获悉，近日，百度智能云旗下DuClaw公布了新一轮升级，在此前打通小度硬件的基础上，进一步打通百度地图，用户现在通过DuClaw部署小龙虾，只需一条出行指令，就可同步调起小度与百度地图，完成包括日程查询，天气路况及出行规划建议，并通过小度硬件语音交互实时反馈给用户。</p>\n  <p><strong>荷兰汽车电动化进程加速</strong></p>\n  <p>荷兰国家统计局近日公布的数据显示，该国传统燃油车销量逐步萎缩，汽车电动化进程呈加速趋势。这一现象背后既有荷兰汽车产业政策长期引导因素，也受近期国际油价快速上涨的显著影响。数据显示，2026年初荷兰乘用车总量约为940万辆，比一年前增长近2%，新增部分几乎全部为电动化车型。目前，荷兰全部或部分以电为动力的汽车数量已超过200万辆，较一年前增长近6%，约占汽车总保有量的五分之一。（财联社）</p>\n  <p><strong>WPS 365发布东南亚三大生态战略</strong></p>\n  <p>36氪获悉，近日，WPS 365亮相新加坡GITEX ASIA 2026，展示了其作为全球一站式AI协同办公平台的解决方案。目前，WPS 365在东南亚正加速推进三大生态战略：搭建本地渠道网络、深化与全球云厂商融合、为企业提供定制化数字化支持。WPS 365已与华为云、亚马逊云科技（AWS）、谷歌云（Google Cloud）达成战略合作，将应用能力与基础设施深度融合，提供更适配本地算力环境与监管框架的解决方案。</p>\n  <p><strong>“马斯克版微信”或在本周五上线</strong></p>\n  <p>马斯克宣传已久的通讯软件XChat预计4月17日上架苹果App Store。XChat据介绍将采用端到端加密，支持音频/视频通话、编辑/删除消息、屏蔽截图、阅后即焚等功能，并允许创建最多481人的大型群聊。但XChat也存在一些问题，比如可能解密用户讯息的隐私性担忧。（财联社）</p>\n  <h2>今日观点：</h2>\n  <p><strong>机构：预估苹果将于今年取得折叠手机市场近20%的市占</strong></p>\n  <p>36氪获悉，根据TrendForce集邦咨询最新显示产业研究，折叠手机市场最快将于2026下半年迎来苹果入局，引发外界关注相关技术革新。其中，面板折痕的优化，正从以往依赖铰链与支撑结构的“机械对抗”，转向以材料堆叠为核心的“应力管理工程”，折痕处理已成为衡量品牌显示技术整合能力的核心指标。该机构预估，苹果凭借品牌形象与消费者的期待，将于2026年取得折叠手机市场近20%的市占。（财联社）</p>\n  <h2>其他值得关注的新闻：</h2>\n  <p><strong>中办、国办：推动行业协会商会深化改革</strong></p>\n  <p>中共中央办公厅，国务院办公厅发布关于推动行业协会商会深化改革的意见。意见提出，按照协同高效的原则，优化整合业务交叉重叠、机构规模过小、领域划分过细、功能作用较弱的行业协会商会。依法加快运转失灵、扰乱秩序、行业萎缩、宗旨任务已完成的行业协会商会退出；重点培育和优先发展契合国家重大战略和区域发展定位、适应产业转型升级需要、服务发展新质生产力的行业协会商会；积极支持在战略性新兴产业、未来产业、绿色低碳产业等领域依法设立行业协会商会。（新华社）</p>\n  <p><strong>西班牙首相桑切斯参观小米科技园</strong></p>\n  <p>4月13日，正在中国进行正式访问的西班牙首相桑切斯一行到访位于北京的小米科技园。小米集团创始人、董事长兼CEO雷军陪同桑切斯参观小米科技展厅，并介绍小米的业务布局及在欧洲市场的发展情况。根据Omida数据，小米是西班牙市场份额最大的智能手机品牌，2025年以30%的市占率位居第一。近年来，小米持续拓展欧洲市场布局，与多家西班牙本地企业建立了合作关系。（环球时报）</p>', '', '', '', '', '{\'title\': \'氪星晚报｜“马斯克版微信”或在本周五上线；Meta押注AI数字人，正打造AI版扎克伯格；AI潮玩品牌“MOMOTOY”完成数千万元融资\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'氪星晚报｜“马斯克版微信”或在本周五上线；Meta押注AI数字人，正打造AI版扎克伯格；AI潮玩品牌“MOMOTOY”完成数千万元融资\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3765146768376326?f=rss\'}], \'link\': \'https://36kr.com/p/3765146768376326?f=rss\', \'published\': \'2026-04-13 19:09:12  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=11, tm_min=9, tm_sec=12, tm_wday=0, tm_yday=103, tm_isdst=0), \'summary\': \'<h2>大公司：</h2>\\n  <p><strong>金山办公：一季度净利同比预增402%-473%</strong></p>\\n  <p>36氪获悉，金山办公公告，预计2026年第一季度实现归属于上市公司股东的净利润20.22亿元-23.07亿元，同比增长401.89%-472.81%。</p>\\n  <p><strong>沪电股份：一季度净利同比预增54.76%-65.25%</strong></p>\\n  <p>36氪获悉，沪电股份公告，预计2026年第一季度归属于上市公司股东的净利润为11.8亿元-12.6亿元，比上年同期增长54.76%-65.25%。</p>\\n  <p><strong>Meta押注AI数字人，正打造AI版扎克伯格</strong></p>\\n  <p>Meta正在打造人工智能版马克・扎克伯格，可代他与员工互动，这是这家科技巨头全面向AI转型的重要举措之一。据四位知情人士透露，这家市值1.6万亿美元的集团一直在研发照片级逼真、可实时交互的AI 3D数字人。其中三位人士称，公司近期已将AI版扎克伯格列为优先项目。（新浪财经）</p>\\n  <p><strong>小红书跨境电商平台Redshop将于今年6月正式上线</strong></p>\\n  <p>4月13日上午消息，今日，接近小红书的相关人士向媒体透露，其跨境电商平台Redshop将于2026年6月正式上线，标志着小红书从“商家出海”的测试阶段，全面迈入“平台出海”的战略新阶段，进一步完善其全球化商业布局。对此，接近小红书的人士表示，“Redshop将于2026年6月正式上线，首期计划定向邀请部分种子商家，重点覆盖非遗手工、特色手工艺品等品类，后续将逐步拓展至更多类目。”（新浪科技）</p>\\n  <p><strong>王石回应被抓传闻：一切安好，造谣者交给法律</strong></p>\\n  <p>36氪获悉，4月12日，网传万科创始人王石被抓。王石个人微博回应：“看来大家比我本人还关心我的动态。一切安好，造谣者交给法律。”</p>\\n  <p><strong>荣耀机器人“闪电”“元气仔”出征北京亦庄马拉松</strong></p>\\n  <p>4月19日，机器人马拉松将在北京亦庄举行。荣耀自研机器人“闪电”“元气仔”正式报名参赛，成为全球首个由终端大厂派出选手的机器人马拉松挑战者。据荣耀技术团队介绍，荣耀机器人“闪电”集成了荣耀在智能制造与具身AI领域的最新成果，高性能高爆发稳定的本体、高动态运控算法、实时感知理解与自主决策能力。</p>\\n  <h2>投融资：</h2>\\n  <p><strong>AI潮玩品牌“MOMOTOY”完成数千万元融资</strong></p>\\n  <p>36氪获悉，AI潮玩品牌“MOMOTOY”已完成数千万元融资，由翼朴基金投资，投后估值2.5亿。品牌负责人透露，本轮融资资金，会重点投向AI技术迭代、高端产品矩阵落地、全球渠道拓展及核心商圈旗舰店铺设四大核心领域。</p>\\n  <h2>新产品：</h2>\\n  <p><strong>百度Duclaw推出小龙虾生活助手</strong></p>\\n  <p>36氪获悉，近日，百度智能云旗下DuClaw公布了新一轮升级，在此前打通小度硬件的基础上，进一步打通百度地图，用户现在通过DuClaw部署小龙虾，只需一条出行指令，就可同步调起小度与百度地图，完成包括日程查询，天气路况及出行规划建议，并通过小度硬件语音交互实时反馈给用户。</p>\\n  <p><strong>荷兰汽车电动化进程加速</strong></p>\\n  <p>荷兰国家统计局近日公布的数据显示，该国传统燃油车销量逐步萎缩，汽车电动化进程呈加速趋势。这一现象背后既有荷兰汽车产业政策长期引导因素，也受近期国际油价快速上涨的显著影响。数据显示，2026年初荷兰乘用车总量约为940万辆，比一年前增长近2%，新增部分几乎全部为电动化车型。目前，荷兰全部或部分以电为动力的汽车数量已超过200万辆，较一年前增长近6%，约占汽车总保有量的五分之一。（财联社）</p>\\n  <p><strong>WPS 365发布东南亚三大生态战略</strong></p>\\n  <p>36氪获悉，近日，WPS 365亮相新加坡GITEX ASIA 2026，展示了其作为全球一站式AI协同办公平台的解决方案。目前，WPS 365在东南亚正加速推进三大生态战略：搭建本地渠道网络、深化与全球云厂商融合、为企业提供定制化数字化支持。WPS 365已与华为云、亚马逊云科技（AWS）、谷歌云（Google Cloud）达成战略合作，将应用能力与基础设施深度融合，提供更适配本地算力环境与监管框架的解决方案。</p>\\n  <p><strong>“马斯克版微信”或在本周五上线</strong></p>\\n  <p>马斯克宣传已久的通讯软件XChat预计4月17日上架苹果App Store。XChat据介绍将采用端到端加密，支持音频/视频通话、编辑/删除消息、屏蔽截图、阅后即焚等功能，并允许创建最多481人的大型群聊。但XChat也存在一些问题，比如可能解密用户讯息的隐私性担忧。（财联社）</p>\\n  <h2>今日观点：</h2>\\n  <p><strong>机构：预估苹果将于今年取得折叠手机市场近20%的市占</strong></p>\\n  <p>36氪获悉，根据TrendForce集邦咨询最新显示产业研究，折叠手机市场最快将于2026下半年迎来苹果入局，引发外界关注相关技术革新。其中，面板折痕的优化，正从以往依赖铰链与支撑结构的“机械对抗”，转向以材料堆叠为核心的“应力管理工程”，折痕处理已成为衡量品牌显示技术整合能力的核心指标。该机构预估，苹果凭借品牌形象与消费者的期待，将于2026年取得折叠手机市场近20%的市占。（财联社）</p>\\n  <h2>其他值得关注的新闻：</h2>\\n  <p><strong>中办、国办：推动行业协会商会深化改革</strong></p>\\n  <p>中共中央办公厅，国务院办公厅发布关于推动行业协会商会深化改革的意见。意见提出，按照协同高效的原则，优化整合业务交叉重叠、机构规模过小、领域划分过细、功能作用较弱的行业协会商会。依法加快运转失灵、扰乱秩序、行业萎缩、宗旨任务已完成的行业协会商会退出；重点培育和优先发展契合国家重大战略和区域发展定位、适应产业转型升级需要、服务发展新质生产力的行业协会商会；积极支持在战略性新兴产业、未来产业、绿色低碳产业等领域依法设立行业协会商会。（新华社）</p>\\n  <p><strong>西班牙首相桑切斯参观小米科技园</strong></p>\\n  <p>4月13日，正在中国进行正式访问的西班牙首相桑切斯一行到访位于北京的小米科技园。小米集团创始人、董事长兼CEO雷军陪同桑切斯参观小米科技展厅，并介绍小米的业务布局及在欧洲市场的发展情况。根据Omida数据，小米是西班牙市场份额最大的智能手机品牌，2025年以30%的市占率位居第一。近年来，小米持续拓展欧洲市场布局，与多家西班牙本地企业建立了合作关系。（环球时报）</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'<h2>大公司：</h2>\\n  <p><strong>金山办公：一季度净利同比预增402%-473%</strong></p>\\n  <p>36氪获悉，金山办公公告，预计2026年第一季度实现归属于上市公司股东的净利润20.22亿元-23.07亿元，同比增长401.89%-472.81%。</p>\\n  <p><strong>沪电股份：一季度净利同比预增54.76%-65.25%</strong></p>\\n  <p>36氪获悉，沪电股份公告，预计2026年第一季度归属于上市公司股东的净利润为11.8亿元-12.6亿元，比上年同期增长54.76%-65.25%。</p>\\n  <p><strong>Meta押注AI数字人，正打造AI版扎克伯格</strong></p>\\n  <p>Meta正在打造人工智能版马克・扎克伯格，可代他与员工互动，这是这家科技巨头全面向AI转型的重要举措之一。据四位知情人士透露，这家市值1.6万亿美元的集团一直在研发照片级逼真、可实时交互的AI 3D数字人。其中三位人士称，公司近期已将AI版扎克伯格列为优先项目。（新浪财经）</p>\\n  <p><strong>小红书跨境电商平台Redshop将于今年6月正式上线</strong></p>\\n  <p>4月13日上午消息，今日，接近小红书的相关人士向媒体透露，其跨境电商平台Redshop将于2026年6月正式上线，标志着小红书从“商家出海”的测试阶段，全面迈入“平台出海”的战略新阶段，进一步完善其全球化商业布局。对此，接近小红书的人士表示，“Redshop将于2026年6月正式上线，首期计划定向邀请部分种子商家，重点覆盖非遗手工、特色手工艺品等品类，后续将逐步拓展至更多类目。”（新浪科技）</p>\\n  <p><strong>王石回应被抓传闻：一切安好，造谣者交给法律</strong></p>\\n  <p>36氪获悉，4月12日，网传万科创始人王石被抓。王石个人微博回应：“看来大家比我本人还关心我的动态。一切安好，造谣者交给法律。”</p>\\n  <p><strong>荣耀机器人“闪电”“元气仔”出征北京亦庄马拉松</strong></p>\\n  <p>4月19日，机器人马拉松将在北京亦庄举行。荣耀自研机器人“闪电”“元气仔”正式报名参赛，成为全球首个由终端大厂派出选手的机器人马拉松挑战者。据荣耀技术团队介绍，荣耀机器人“闪电”集成了荣耀在智能制造与具身AI领域的最新成果，高性能高爆发稳定的本体、高动态运控算法、实时感知理解与自主决策能力。</p>\\n  <h2>投融资：</h2>\\n  <p><strong>AI潮玩品牌“MOMOTOY”完成数千万元融资</strong></p>\\n  <p>36氪获悉，AI潮玩品牌“MOMOTOY”已完成数千万元融资，由翼朴基金投资，投后估值2.5亿。品牌负责人透露，本轮融资资金，会重点投向AI技术迭代、高端产品矩阵落地、全球渠道拓展及核心商圈旗舰店铺设四大核心领域。</p>\\n  <h2>新产品：</h2>\\n  <p><strong>百度Duclaw推出小龙虾生活助手</strong></p>\\n  <p>36氪获悉，近日，百度智能云旗下DuClaw公布了新一轮升级，在此前打通小度硬件的基础上，进一步打通百度地图，用户现在通过DuClaw部署小龙虾，只需一条出行指令，就可同步调起小度与百度地图，完成包括日程查询，天气路况及出行规划建议，并通过小度硬件语音交互实时反馈给用户。</p>\\n  <p><strong>荷兰汽车电动化进程加速</strong></p>\\n  <p>荷兰国家统计局近日公布的数据显示，该国传统燃油车销量逐步萎缩，汽车电动化进程呈加速趋势。这一现象背后既有荷兰汽车产业政策长期引导因素，也受近期国际油价快速上涨的显著影响。数据显示，2026年初荷兰乘用车总量约为940万辆，比一年前增长近2%，新增部分几乎全部为电动化车型。目前，荷兰全部或部分以电为动力的汽车数量已超过200万辆，较一年前增长近6%，约占汽车总保有量的五分之一。（财联社）</p>\\n  <p><strong>WPS 365发布东南亚三大生态战略</strong></p>\\n  <p>36氪获悉，近日，WPS 365亮相新加坡GITEX ASIA 2026，展示了其作为全球一站式AI协同办公平台的解决方案。目前，WPS 365在东南亚正加速推进三大生态战略：搭建本地渠道网络、深化与全球云厂商融合、为企业提供定制化数字化支持。WPS 365已与华为云、亚马逊云科技（AWS）、谷歌云（Google Cloud）达成战略合作，将应用能力与基础设施深度融合，提供更适配本地算力环境与监管框架的解决方案。</p>\\n  <p><strong>“马斯克版微信”或在本周五上线</strong></p>\\n  <p>马斯克宣传已久的通讯软件XChat预计4月17日上架苹果App Store。XChat据介绍将采用端到端加密，支持音频/视频通话、编辑/删除消息、屏蔽截图、阅后即焚等功能，并允许创建最多481人的大型群聊。但XChat也存在一些问题，比如可能解密用户讯息的隐私性担忧。（财联社）</p>\\n  <h2>今日观点：</h2>\\n  <p><strong>机构：预估苹果将于今年取得折叠手机市场近20%的市占</strong></p>\\n  <p>36氪获悉，根据TrendForce集邦咨询最新显示产业研究，折叠手机市场最快将于2026下半年迎来苹果入局，引发外界关注相关技术革新。其中，面板折痕的优化，正从以往依赖铰链与支撑结构的“机械对抗”，转向以材料堆叠为核心的“应力管理工程”，折痕处理已成为衡量品牌显示技术整合能力的核心指标。该机构预估，苹果凭借品牌形象与消费者的期待，将于2026年取得折叠手机市场近20%的市占。（财联社）</p>\\n  <h2>其他值得关注的新闻：</h2>\\n  <p><strong>中办、国办：推动行业协会商会深化改革</strong></p>\\n  <p>中共中央办公厅，国务院办公厅发布关于推动行业协会商会深化改革的意见。意见提出，按照协同高效的原则，优化整合业务交叉重叠、机构规模过小、领域划分过细、功能作用较弱的行业协会商会。依法加快运转失灵、扰乱秩序、行业萎缩、宗旨任务已完成的行业协会商会退出；重点培育和优先发展契合国家重大战略和区域发展定位、适应产业转型升级需要、服务发展新质生产力的行业协会商会；积极支持在战略性新兴产业、未来产业、绿色低碳产业等领域依法设立行业协会商会。（新华社）</p>\\n  <p><strong>西班牙首相桑切斯参观小米科技园</strong></p>\\n  <p>4月13日，正在中国进行正式访问的西班牙首相桑切斯一行到访位于北京的小米科技园。小米集团创始人、董事长兼CEO雷军陪同桑切斯参观小米科技展厅，并介绍小米的业务布局及在欧洲市场的发展情况。根据Omida数据，小米是西班牙市场份额最大的智能手机品牌，2025年以30%的市占率位居第一。近年来，小米持续拓展欧洲市场布局，与多家西班牙本地企业建立了合作关系。（环球时报）</p>\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-13 19:09:12', '2026-04-14 14:10:07', 1, '{\"summary\": \"帮助出海企业快速掌握跨境电商平台、办公软件出海等领域的最新行业动态与头部玩家布局信息\", \"abstract\": \"本文是多领域科技行业资讯汇总，涵盖大公司动态、投融资、新产品、行业观点等内容。本文披露小红书将于2026年6月上线跨境电商平台Redshop，标志其从商家出海测试迈入平台出海新阶段。WPS 365在新加坡亮相后，宣布在东南亚加速推进三大出海生态战略，适配本地监管与算力需求。此外还涵盖AI技术布局、企业业绩、荷兰汽车电动化趋势等其他科技行业资讯。\", \"keywords\": [\"平台出海\", \"跨境电商\", \"Redshop\", \"WPS 365\", \"东南亚出海\", \"AI数字人\", \"汽车电动化\"], \"policy_risk\": {\"market_risk\": \"马斯克即将推出的通讯软件XChat存在可能解密用户讯息的隐私风险，未提及其他出海相关市场运营风险\", \"policy_compliance\": \"荷兰通过长期产业政策引导推动本国汽车电动化进程；中办、国办印发意见推动行业协会商会深化改革，重点培育服务国家重大战略、新质生产力的行业协会；WPS 365出海东南亚需适配本地监管框架\"}, \"topic_cluster\": \"海外市场洞察、跨境电商\", \"industry_category\": \"跨境电商、企业服务SaaS\"}');
INSERT INTO `news` VALUES (401, '国务院办公厅关于推广行政备案规范管理改革试点经验的通知', 'http://www.gov.cn/zhengce/content/2022-11/18/content_5727708.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院办公厅关于推广行政备案规范管理改革试点经验的通知\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院办公厅关于推广行政备案规范管理改革试点经验的通知\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-11/18/content_5727708.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-11/18/content_5727708.htm\', \'published\': \'Sun, 31 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=31, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=6, tm_yday=304, tm_isdst=0)}', '2021-10-31 16:00:00', '2026-04-14 14:10:11', 1, '{\"summary\": \"本文发布国务院推广行政备案改革试点经验的通知，帮助出海企业掌握国内备案相关改革动向\", \"abstract\": \"本文是国务院办公厅发布的官方通知，核心主题为推广行政备案规范管理改革试点经验。本次通知未披露具体经验内容，该改革落地后有望优化各类行政备案办理流程，对出海企业办理境外投资相关备案将产生积极影响。\", \"keywords\": [\"行政备案\", \"改革试点\", \"合规备案\", \"ODI备案\", \"政务服务改革\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"仅明确将推广行政备案规范管理改革试点经验，未披露具体政策内容\"}, \"topic_cluster\": \"合规备案\", \"industry_category\": \"全行业\"}');
INSERT INTO `news` VALUES (402, '国务院办公厅关于市场监督管理综合行政执法有关事项的通知', 'http://www.gov.cn/zhengce/content/2022-11/16/content_5727228.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院办公厅关于市场监督管理综合行政执法有关事项的通知\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院办公厅关于市场监督管理综合行政执法有关事项的通知\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-11/16/content_5727228.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-11/16/content_5727228.htm\', \'published\': \'Sun, 31 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=31, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=6, tm_yday=304, tm_isdst=0)}', '2021-10-31 16:00:00', '2026-04-14 14:10:14', 0, '\"\"');
INSERT INTO `news` VALUES (403, '野人先生崔渐为：“网红”标签对我们不公平丨厚雪专访', 'https://36kr.com/p/3765076875117314?f=rss', 'https://36kr.com/feed', '<p>作者&nbsp;|&nbsp;钟艺璇</p>\n  <p>编辑&nbsp;|&nbsp;乔芊</p>\n  <p>如果你在一个意大利人面前，把Gelato等同于ice cream，他一定会难过。</p>\n  <p>16世纪，Gelato诞生于文艺复兴时期的佛罗伦萨，传说中一名炼金术师创造了它。在意大利语中，Gelato本就译为冰淇淋。但它和美式冰淇淋ice cream口感大有不同，Gelato使用口感更密实，也更新鲜、低脂和健康。</p>\n  <p>目前中国冰淇淋市场中，夫妻老婆店冷柜里卖的预制冰淇淋占据75%以上的市场份额，这个品类中的高端玩家是哈根达斯。现制冰淇淋只占约25%，以DQ、波比冰淇淋（原波比艾斯）乃至蜜雪冰城为代表的软冰（Soft Serve）以规模化优势，又占其半壁江山，Gelato由于手工现制、定位高端以及门店成本高，市场份额只有6%左右。</p>\n  <p>在欧洲，数百年来，Gelato都以家族传承、百年老店的形式分散存在——意大利4万家Gelato几乎都是小店，甚至只要10家连锁以上，就能称作大品牌。</p>\n  <p>但在中国，有一家公司却想把堪称“小众”的Gelato连锁化，它就是野人先生。</p>\n  <p>2025年，野人先生突然涌现在大众面前，从300多家到突破千店，这也是它爆发式增长的一年。但创始人崔渐为却说，自己创立野人先生已经15年，只是近期才被大众所看见。</p>\n  <p>15年千店的速度并不快，因为中国消费者对Gelato太陌生。“冰淇淋这个品类似乎20年来没有变化，20年前的哈根达斯、20年前的DQ，和今天都一模一样。每一个行业都在加速迭代，冰淇淋行业没理由停滞不前。”崔渐为说，是野人先生在国内开创了 Gelato 这个赛道。</p>\n  <p>上个时代，哈根达斯是工业化背景下，冰淇淋极度标准化的产物。要做品类升级，和对手拉开差距，野人先生一直在放大自己的现制属性——做试吃，让人们知道现制Gelato究竟是什么；拉丝带尖（员工在冰淇淋出品的最后一刻，拉出个性化的弧度），让人们对现制更感同身受；过去冰淇淋用玻璃柜展示，野人就用独立密封桶，解决串味和温度波动，让冰淇淋更新鲜；冰淇淋易化，顾客的手也容易被沾湿，就用玉米杯代替塑料杯，厚壁的杯具能保留风味。</p>\n  <p>这一切的目标都是让Gelato产品更标准，以放大连锁化的可能性。</p>\n  <p>这个可能性究竟是多大？崔渐为以茶饮行业类比，10年前瓶装饮料市场规模3千亿，现制茶饮只有200亿，10年后，现制茶饮也做到了3000亿。</p>\n  <p>“我觉得现制冰淇淋能做到跟预制冰淇淋平分秋色，达到2000亿规模。”崔渐为说。</p>\n  <p>截至目前，DQ在华门店总数超过1800家，是中国最大的现制冰淇淋连锁品牌，波比冰淇淋门店总数超过1200家，野人先生主打Gelato品类，门店规模超过1300家，在全球Gelato连锁领域规模第一。</p>\n  <p>15年过去，2026年春天之始，野人先生在上海开了一家全球旗舰店，这也是全球最大的Gelato旗舰店。崔渐为告诉36氪，过去野人先生只埋头做产品，品牌端几乎没有系统表达，“全球旗舰店是野人先生15年的里程碑，我们想把‘野自天然’的内核完整呈现出来”。</p>\n  <p>近期，36氪和崔渐为有一次对话，他向我们讲述了在连锁化前野人先生15年漫长的准备，自己又是如何抓住现制冰淇淋品类升级的机会，以及可替代选择那么多，中国人又何以需要一支好的Gelato。</p>\n  <p>以下是对话，经36氪编辑：</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_c3b474a237cb400ba0b6c3eb8ef19f3b@5971123_oswg156264oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">野人先生全球旗舰店，位于上海徐汇区东湖路</p>\n  <h3>冰淇淋有清晰的好坏标准</h3>\n  <p><strong>36氪：这一年来野人受到很多媒体关注和报道，你心态上有变化吗？</strong></p>\n  <p><strong>崔渐为：</strong>变化谈不上，多了一些苦恼，也见到社会险恶（笑）。</p>\n  <p>我们是个理工男团队，连市场部都没有，产品和品牌都由我负责。这两个板块都是创造型的工作，我的灵感更多来自于向内求，去探店、去乡下找食材和农民聊天，或者和行业专业人士交流。15年都是这样。</p>\n  <p>野人火了以后，外界很多声音偏离了本质，“网红”、“割韭菜”、“第二个钟薛高”，这些标签被加注在野人身上，其实对我们不公平。可以说，野人对于冰淇淋行业的思考、理解和探索，在全世界都是领先的。</p>\n  <p><strong>36氪：你最初怎么接触到冰淇淋行业？</strong></p>\n  <p><strong>崔渐为：</strong>大学毕业后，我去了一家意大利主权基金工作，当时我们投了一家85年历史的冰淇淋家族企业，在这个过程中，我深度参与也开始喜欢上冰淇淋行业。</p>\n  <p>几百年来，Gelato一直被公认为是最好吃的冰淇淋，无论是生产方式、原料、设备还是工艺，它都比工业化生产的ice cream更有优势。但意大利有四万家Gelato店，连锁化率却很低。当地很多店都是家族经营，还有不少百年老店，一家Gelato品牌能开10家左右门店，就已经算多了。</p>\n  <p>所以当时我们认为Gelato的全球化一定存在机会，就像曾经的星巴克把意大利咖啡带到全球一样。</p>\n  <p><strong>36氪：在野人先生之前，没人尝试过中国的Gelato连锁化吗？</strong></p>\n  <p><strong>崔渐为：</strong>其实相反，中国最早做加盟的品类就是冰淇淋品牌，甚至比茶饮还早。冰淇淋本身太适合做加盟了，它标准化程度高，从美国的4大冰品品牌能看出来，它们在历史上都取得了很好的成就。</p>\n  <p>大概在世纪初，有一批中国加盟商盯上了冰淇淋品类，他们当然知道Gelato最好，也去意大利找了品牌谈战略合作。但他们做的事却和Gelato无关，只是拿上创始人的授权照片，贴在墙上背书，也不用人家的原料，就卖5块钱3个球的冰淇淋。</p>\n  <p>很快，整个行业对中国加盟商都建立了防火墙，意大利人听到是中国人，就不聊了。甚至有中国人再去意大利学习冰淇淋技术，对方都很排斥。</p>\n  <p>这也是为什么今天中国懂Gelato的人太少，因为关于Gelato底层的知识、技术传播都做得不好。我个人是因为刚好在意大利冰淇淋企业工作，才有机会深入内部，接触到更专业的原料、技术、设备原理等关键环节。</p>\n  <p><strong>36氪：欧洲 Gelato 的连锁化率很低，为什么在中国会有这个机会？</strong></p>\n  <p><strong>崔渐为：</strong>欧洲不只是 Gelato 没连锁，很多品类都没有连锁，真正的连锁模式从美国开始。美国人更追求利益最大化，想把生意做到最大。</p>\n  <p>我们扫描行业时发现有几个长期确定的趋势——第一，有人的地方就有冰淇淋需求，这个品类不可能消亡；第二，冰淇淋消费和人均GDP正相关，经济越发达，人们吃的冰淇淋越多、品质要求越高。</p>\n  <p>再反观中国，单看DQ的规模就知道，DQ全球营业额超300亿，中国市场大概 30 多亿，只占 1/10，它最大的市场在美国，贡献200多亿营业额。这说明 DQ 在美国是很日常、很普遍的消费，而中国的市场空间还很大。</p>\n  <p>大家购物、逛街和闲聊的时候，总想喝点什么，那为什么不能是冰淇淋呢？如果野人不把一个更好的现制冰淇淋放在消费者面前，大家永远不知道自己有这个需求。</p>\n  <p><strong>36氪：这个需求一定是30元的Gelato吗？</strong></p>\n  <p><strong>崔渐为：</strong>好产品需要消费者多体验，才能慢慢建立起标准。就像喝咖啡，只要喝的频次足够多，就能尝出花香、果香这些风味，形成自己的评判标准。</p>\n  <p>从专业角度说，冰淇淋的好坏非常清晰，有色香味、养料、温度等十大标准。只是这些东西对消费者来说，太专业。但消费者是最聪明的人群，没人能骗得过消费者的嘴巴。</p>\n  <p><strong>36氪：需求只是开始，决定中国Gelato得以连锁化的客观条件是什么？</strong></p>\n  <p><strong>崔渐为：</strong>设备国产化是Gelato能在中国连锁化的大前提。意大利进口设备价格在60万，但国产只要6万。除了野人，过去中国没有这个市场，所以我们目前的两个供应商，都是陪伴野人成长起来的，野人是绝对的需求方，也只有我们这些使用者，才懂设备的细节和痛点，帮助上游实现研发迭代。</p>\n  <p>这也是为什么野人13年都不加盟的原因，如果机器还有bug，不够丝滑稳定，我怎么敢放加盟？</p>\n  <p><strong>36氪：为什么叫“野人”这个名字？</strong></p>\n  <p><strong>崔渐为：</strong>“野”是不被世俗规则磨掉的初心。我们想呵护这种 “野”，因为它是野人品牌的核心。</p>\n  <p>从业务层面说，我们先养牛、再开店，自己建了牧场，坚持手工制作，这和天然、自由的感觉很契合；从精神层面说，去年我们和张伟丽联名，叫 “野力全开，为热爱而战”，张伟丽在 UFC凭一己之力拿了 6 条金腰带，过去没有亚洲人能做到，我们也想在西方强势的冰淇淋领域做出中国品牌。</p>\n  <p><strong>36氪：你性格“野”吗？</strong></p>\n  <p><strong>崔渐为：</strong>性格里最大的“野”，是创业第一天就决定要把Gelato 做到极致，并且一辈子做这件事。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_7e5cf7b74bb44fd8abacfd4b8294fbc7@5971123_oswg57589oswg1080oswg720_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\" label=\"图片描述\">野人先生产品图</p>\n  <h3>没有招商部，全靠口碑推荐</h3>\n  <p><strong>36氪：为什么决定在2024年放加盟？</strong></p>\n  <p><strong>崔渐为：</strong>放加盟不是选择，而是必然。</p>\n  <p>全球成熟的餐饮品牌，麦肯是加盟，DQ也是加盟。我们为什么要拒绝加盟？本质上，冰淇淋就是高度标准化的品类，而且是小店，非常适合加盟；对比海底捞这种大店、复杂中餐，就不太适合加盟。</p>\n  <p><strong>36氪：野人的加盟商画像是什么样的？</strong></p>\n  <p><strong>崔渐为：</strong>我们选的是超级加盟商，都是职业选手。</p>\n  <p><strong>36氪：为什么不是小的？</strong></p>\n  <p><strong>崔渐为：</strong>超级加盟商的优势在于，他们在食安、服务和门店一线操作上已经建立了很好的职业素养。让这样的人开店，一定能做好，小白就算再聪明，也得走很多弯路。今天野人选择加盟商时，我们首先会关注他是不是一个专业的门店运营者。</p>\n  <p><strong>36氪：这些超级加盟商，开店规模一般在多少？</strong></p>\n  <p><strong>崔渐为：</strong>主流在5-10家，最多有50家的。我们毕竟开放加盟时间短，很少有加盟商是只开单一家的。</p>\n  <p><strong>36氪：听说野人没有招商部，你会直接面试加盟商，他们和你表达最多的顾虑是什么？</strong></p>\n  <p><strong>崔渐为：</strong>顾虑太多了，核心还是对冰淇淋品类的质疑，冰淇淋能做长久吗？能不能像茶饮一样规模化开店？有季节限制怎么办？消费习惯还没养成，能做起来吗？</p>\n  <p>我们也很直接，摊开来讲我们的创业历史，带他们去看野人8 年、10 年的老店，让他们感受老店的运营状态和产品，也会把我们对行业的思考、消费习惯培养的过程和他们沟通。</p>\n  <p>其实这些超级加盟商能力很强，行业也很透明，我们每家店的销售数据，他们自己就能拿到，甚至比我还熟。他们天天混在行业里，选址、运营的门道都懂。当他们来找我们的时候，已经经过反复对比和考察了，只是需要我们解答最后一些疑问，确认自己的判断。</p>\n  <p>野人之所以没招商部还能开这么快，全靠口碑和推荐。我们从来没做过加盟宣传，连加盟电话都很难找到，我们希望和专业、懂行的人合作——大家匹配度高，反而省了很多事。</p>\n  <p><strong>36氪：不担心超级加盟商话语权太强、不好管理吗？</strong></p>\n  <p><strong>崔渐为：</strong>你有价值，他就追随你；你没价值，他自然会离开，不需要刻意管理。</p>\n  <p><strong>36氪：能否讲述一下野人的选址逻辑？</strong></p>\n  <p><strong>崔渐为：</strong>选址是野人十几年踩坑最多的地方，一旦选错，就是血亏。有很多选址，看起来不错，比如商场负一楼、地铁口，这些地方人流多，但开店一定差。因为大家都在匆忙赶路，只会买奶茶、面包这种刚需快消品，买了就能带走；而Gelato需要坐下来慢慢吃。</p>\n  <p>这种选址哪怕我们一再强调不能开，还是有加盟商执意要开。人的惯性认知太难扭转了，但这就是我们要守的底线。我们踩过的坑，不能让加盟商再踩。</p>\n  <p><strong>36氪：有没有看起来不行，实际却很好的选址？</strong></p>\n  <p><strong>崔渐为：</strong>比如商场二楼、三楼，很多人觉得楼层高、人流少，但实际转化率很高。尤其是女装层——大家是无目的闲逛，逛累了就想歇一歇，和闺蜜聊聊天，这时再看到Gelato，转化率极高。而且二楼租金还比一楼、负一楼便宜很多。</p>\n  <p>反倒商场五楼，看着人多，但大家去五楼是有明确需求的——约了人、或者想吃火锅或炒菜，很少会选择中途吃一支冰淇淋。而且现在人怕胖，吃饭前不会额外吃甜的，我们只能捡漏。</p>\n  <h3>如果不是试吃，野人先生已经死掉了</h3>\n  <p><strong>36氪：从现制冰淇淋品类来看，DQ的规模最大，野人相对于他们做了哪些升级？</strong></p>\n  <p><strong>崔渐为：</strong>虽然都属于现制冰淇淋，但DQ是软冰（soft serve），和Gelato完全是两个门类。</p>\n  <p>软冰的优势是随手可得，只要装一台软冰机，把浆料倒进去，接出来就能卖。今天你看到的麦当劳、肯德基以及蜜雪冰城，他们的冰淇淋都属于软冰，简易化和低成本决定了软冰能成为万店的品类。软冰膨化率通常在100%以上，一半以上都是空气，牛奶本身的香味比较寡淡，所以需要添加香精色素。</p>\n  <p>并不是说软冰不好，产品定位和分类不同而已。只是Gelato走的是另一个极端。真材实料，追求低的膨化率，一切味道都来自于食材本身。</p>\n  <p><strong>36氪：Gelato 的膨化率大概是多少？</strong></p>\n  <p><strong>崔渐为：</strong>大概在20%。对比软冰100%膨化率，Gelato只有1/5，这也意味成本有5倍的差距。</p>\n  <p><strong>36氪：野人的单杯为什么定在130g？比对手要少。</strong></p>\n  <p><strong>崔渐为：</strong>这是反复调研后的结果，我们发现，消费者需要“吃得舒服满足，又不过量”，测试后发现130g最合适。</p>\n  <p><strong>36氪：野人的试吃很有名，时候开始的？</strong></p>\n  <p><strong>崔渐为：</strong>2015年，我们开第一家门店时，就有试吃了。只是早期比较简单，客人到柜台前，我们最多会问一句“要不要尝一尝”“先尝再买”。</p>\n  <p>后来店员主动走出去打招呼，成功率很低，还很尴尬。现在我们就设计了专门的试吃小冰箱，放在门店过道最显眼的位置，上面贴“免费试吃”的标识。客人知道这是专门让人试吃的，会大大方方地尝。</p>\n  <p>这对野人先生来说，是一个关键的转折。餐饮行业没有那么多石破天惊的创新，它是一种每天的精进，在于你能不能把一件繁琐枯燥的事坚持下去。</p>\n  <p><strong>36氪：试吃也需要迭代。</strong></p>\n  <p><strong>崔渐为：</strong>试吃从早期1.0，已经迭代到5.0了。野人的试吃，可能是整个冰品行业做得最彻底、花钱最多的那一个。</p>\n  <p>我的想法很简单，想让客人尝到我们的产品，根本不在乎他买不买。如果不是这种非常积极的试吃，我想野人先生已经死掉了。</p>\n  <h3>开心果是转折点</h3>\n  <p><strong>36氪：很早就有投资人找你们，为什么一直没拿融资？</strong></p>\n  <p><strong>崔渐为：</strong>疫情前就不断有投资人找来，我们做到 50 家店时已经是国内第一，100 家时已是全球第一，资本很容易看到我们。但是拿了钱，前提是让钱真正发挥作用。如果不知道怎么花，或者花了也没有好结果，那反而会是一种灾难。</p>\n  <p><strong>36氪：当时大家都在拿钱，估值被炒得很高，这种氛围里，你怎么保持理性？</strong></p>\n  <p><strong>崔渐为：</strong>和我之前做过投资有一点关系。但这不是主要原因，更核心的是做决策时更看重行业本质和规律，而不是跟风。说白了，当时我很清楚，拿了钱对我们来说是负担，发挥不了太多作用。</p>\n  <p><strong>36氪：接下来有融资计划吗？</strong></p>\n  <p><strong>崔渐为：</strong>我们并不排斥资本，但前提是彼此契合。过去一些不好的惯例，很多投资人要求对赌、要求上市时间，有这些条款我们就不聊。现在投资人更理性，愿意尊重企业发展规律。</p>\n  <p><strong>36氪：现在野人已经超过1300家，未来的扩张节奏上，有什么计划？</strong></p>\n  <p><strong>崔渐为：</strong>我们对规模没有很大的欲望。</p>\n  <p><strong>36氪：为什么？</strong></p>\n  <p><strong>崔渐为：</strong>我当然希望品牌有更大影响力，只是它的排位靠后。假如我今天说要开多少店，各个部门一拆解，大家都会为数字努力，动作就很容易变形。野人的思路是，先把一个区域加密，做好口碑，再慢慢拓展。</p>\n  <p><strong>36氪：但事实是2025年野人门店高速增长，这不是目标带来的结果吗？</strong></p>\n  <p><strong>崔渐为：</strong>完全是自然增长，因为门店生意确实变好了。直到今天，我们都在踩刹车开店。比如找上门的加盟商有一千个，我们会筛掉几百个，门槛很高。</p>\n  <p><strong>36氪：生意变好的转折点是什么？</strong></p>\n  <p><strong>崔渐为：</strong>2023年下半年，开心果口味爆了，它让野人的同店业绩增长30%左右。之前野人许多的门店都在盈亏平衡上。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_d00372b35591425eafdf30575357619b@5971123_oswg74656oswg1080oswg1048_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\" label=\"图片描述\">野人先生产品图</p>\n  <p><strong>36氪：开心果口味是野人先生的里程碑？</strong></p>\n  <p><strong>崔渐为：</strong>一个餐饮品牌火与不火，很大程度上取决于有没有爆款大单品，比如霸王茶姬的伯牙绝弦，喜茶的多肉葡萄。大单品让品牌被记住。</p>\n  <p>对于野人来说，这个大单品就是开心果。现在野人所有的产品都是28元，只有38元的定价为开心果而生，因为原材料实在太贵。</p>\n  <p>当时我们在选择开心果原料的时候也纠结过，到底是选择意大利进口，还是日本（正荣）的原料，前者价格是后者的五倍。今天几乎所有烘焙品牌用的都是正荣开心果，但烘焙有面粉有糖，冰淇淋入口即化，对风味要求高。野人要追求品质，就要坚定选择意大利开心果。</p>\n  <p>其实开心果刚推出前两三年，市场表现并不好，直到2023年下半年，突然有很多人来店里点名要购买，各大平台上也开始有用户自发分享，到 2024 年就更火了，从野人扩散到整个冰淇淋行业，再到烘焙、茶饮行业，开心果口味成了全行业都在推的热门口味。</p>\n  <p><strong>36氪：最早的灵感来自于？</strong></p>\n  <p><strong>崔渐为：</strong>没有特别的灵感，更多是一种预判。做研发时，通过判断它的浓郁度、香味和口感，我们就能感知到这款产品的潜力。</p>\n  <p>我们特别为开心果冰淇淋设计了很多出品仪式感，只有它会撒开心果碎，也只有它拥有独特的小翅膀托盒，如你所见，我们一直在海报上重点突出它，员工推荐时，也永远优先开心果口味。就这么坚持了将近5年，才突然爆发。</p>\n  <p><strong>36氪：如果茶饮品牌都反过来做冰淇淋，你会担心吗？</strong></p>\n  <p><strong>崔渐为：</strong>挺好的，大家一起做。现在冰淇淋行业的上限还不太高，我们也不在乎它的上限在哪里，上限是自己做出来的。</p>\n  <p><strong>36氪：不会是你们的对手？</strong></p>\n  <p><strong>崔渐为：</strong>Gelato的整套系统很复杂，不是在门店加一台机器就能解决的，不仅投入大，对门店的水电条件要求也很高。</p>\n  <p><strong>36氪：野人出品时的“拉丝带尖”很有意思，为什么会有这个设计？</strong></p>\n  <p><strong>崔渐为：</strong>拉丝带尖的壁垒不是技术，是创作感。我们不把打冰淇淋当成重复劳动，而是手艺活——往左歪一点像山，往右歪一点像树，每个冰淇淋都不一样。</p>\n  <p>我早期在门店的时候，就讨厌无趣的工作，所以想让打冰淇淋变得有意思，而不是用挖球器做规整的球。</p>\n  <p class=\"image-wrapper\"></p>', '', '', '', '', '{\'title\': \'野人先生崔渐为：“网红”标签对我们不公平丨厚雪专访\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'野人先生崔渐为：“网红”标签对我们不公平丨厚雪专访\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3765076875117314?f=rss\'}], \'link\': \'https://36kr.com/p/3765076875117314?f=rss\', \'published\': \'2026-04-13 17:58:36  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=9, tm_min=58, tm_sec=36, tm_wday=0, tm_yday=103, tm_isdst=0), \'summary\': \'<p>作者&nbsp;|&nbsp;钟艺璇</p>\\n  <p>编辑&nbsp;|&nbsp;乔芊</p>\\n  <p>如果你在一个意大利人面前，把Gelato等同于ice cream，他一定会难过。</p>\\n  <p>16世纪，Gelato诞生于文艺复兴时期的佛罗伦萨，传说中一名炼金术师创造了它。在意大利语中，Gelato本就译为冰淇淋。但它和美式冰淇淋ice cream口感大有不同，Gelato使用口感更密实，也更新鲜、低脂和健康。</p>\\n  <p>目前中国冰淇淋市场中，夫妻老婆店冷柜里卖的预制冰淇淋占据75%以上的市场份额，这个品类中的高端玩家是哈根达斯。现制冰淇淋只占约25%，以DQ、波比冰淇淋（原波比艾斯）乃至蜜雪冰城为代表的软冰（Soft Serve）以规模化优势，又占其半壁江山，Gelato由于手工现制、定位高端以及门店成本高，市场份额只有6%左右。</p>\\n  <p>在欧洲，数百年来，Gelato都以家族传承、百年老店的形式分散存在——意大利4万家Gelato几乎都是小店，甚至只要10家连锁以上，就能称作大品牌。</p>\\n  <p>但在中国，有一家公司却想把堪称“小众”的Gelato连锁化，它就是野人先生。</p>\\n  <p>2025年，野人先生突然涌现在大众面前，从300多家到突破千店，这也是它爆发式增长的一年。但创始人崔渐为却说，自己创立野人先生已经15年，只是近期才被大众所看见。</p>\\n  <p>15年千店的速度并不快，因为中国消费者对Gelato太陌生。“冰淇淋这个品类似乎20年来没有变化，20年前的哈根达斯、20年前的DQ，和今天都一模一样。每一个行业都在加速迭代，冰淇淋行业没理由停滞不前。”崔渐为说，是野人先生在国内开创了 Gelato 这个赛道。</p>\\n  <p>上个时代，哈根达斯是工业化背景下，冰淇淋极度标准化的产物。要做品类升级，和对手拉开差距，野人先生一直在放大自己的现制属性——做试吃，让人们知道现制Gelato究竟是什么；拉丝带尖（员工在冰淇淋出品的最后一刻，拉出个性化的弧度），让人们对现制更感同身受；过去冰淇淋用玻璃柜展示，野人就用独立密封桶，解决串味和温度波动，让冰淇淋更新鲜；冰淇淋易化，顾客的手也容易被沾湿，就用玉米杯代替塑料杯，厚壁的杯具能保留风味。</p>\\n  <p>这一切的目标都是让Gelato产品更标准，以放大连锁化的可能性。</p>\\n  <p>这个可能性究竟是多大？崔渐为以茶饮行业类比，10年前瓶装饮料市场规模3千亿，现制茶饮只有200亿，10年后，现制茶饮也做到了3000亿。</p>\\n  <p>“我觉得现制冰淇淋能做到跟预制冰淇淋平分秋色，达到2000亿规模。”崔渐为说。</p>\\n  <p>截至目前，DQ在华门店总数超过1800家，是中国最大的现制冰淇淋连锁品牌，波比冰淇淋门店总数超过1200家，野人先生主打Gelato品类，门店规模超过1300家，在全球Gelato连锁领域规模第一。</p>\\n  <p>15年过去，2026年春天之始，野人先生在上海开了一家全球旗舰店，这也是全球最大的Gelato旗舰店。崔渐为告诉36氪，过去野人先生只埋头做产品，品牌端几乎没有系统表达，“全球旗舰店是野人先生15年的里程碑，我们想把‘野自天然’的内核完整呈现出来”。</p>\\n  <p>近期，36氪和崔渐为有一次对话，他向我们讲述了在连锁化前野人先生15年漫长的准备，自己又是如何抓住现制冰淇淋品类升级的机会，以及可替代选择那么多，中国人又何以需要一支好的Gelato。</p>\\n  <p>以下是对话，经36氪编辑：</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_c3b474a237cb400ba0b6c3eb8ef19f3b@5971123_oswg156264oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">野人先生全球旗舰店，位于上海徐汇区东湖路</p>\\n  <h3>冰淇淋有清晰的好坏标准</h3>\\n  <p><strong>36氪：这一年来野人受到很多媒体关注和报道，你心态上有变化吗？</strong></p>\\n  <p><strong>崔渐为：</strong>变化谈不上，多了一些苦恼，也见到社会险恶（笑）。</p>\\n  <p>我们是个理工男团队，连市场部都没有，产品和品牌都由我负责。这两个板块都是创造型的工作，我的灵感更多来自于向内求，去探店、去乡下找食材和农民聊天，或者和行业专业人士交流。15年都是这样。</p>\\n  <p>野人火了以后，外界很多声音偏离了本质，“网红”、“割韭菜”、“第二个钟薛高”，这些标签被加注在野人身上，其实对我们不公平。可以说，野人对于冰淇淋行业的思考、理解和探索，在全世界都是领先的。</p>\\n  <p><strong>36氪：你最初怎么接触到冰淇淋行业？</strong></p>\\n  <p><strong>崔渐为：</strong>大学毕业后，我去了一家意大利主权基金工作，当时我们投了一家85年历史的冰淇淋家族企业，在这个过程中，我深度参与也开始喜欢上冰淇淋行业。</p>\\n  <p>几百年来，Gelato一直被公认为是最好吃的冰淇淋，无论是生产方式、原料、设备还是工艺，它都比工业化生产的ice cream更有优势。但意大利有四万家Gelato店，连锁化率却很低。当地很多店都是家族经营，还有不少百年老店，一家Gelato品牌能开10家左右门店，就已经算多了。</p>\\n  <p>所以当时我们认为Gelato的全球化一定存在机会，就像曾经的星巴克把意大利咖啡带到全球一样。</p>\\n  <p><strong>36氪：在野人先生之前，没人尝试过中国的Gelato连锁化吗？</strong></p>\\n  <p><strong>崔渐为：</strong>其实相反，中国最早做加盟的品类就是冰淇淋品牌，甚至比茶饮还早。冰淇淋本身太适合做加盟了，它标准化程度高，从美国的4大冰品品牌能看出来，它们在历史上都取得了很好的成就。</p>\\n  <p>大概在世纪初，有一批中国加盟商盯上了冰淇淋品类，他们当然知道Gelato最好，也去意大利找了品牌谈战略合作。但他们做的事却和Gelato无关，只是拿上创始人的授权照片，贴在墙上背书，也不用人家的原料，就卖5块钱3个球的冰淇淋。</p>\\n  <p>很快，整个行业对中国加盟商都建立了防火墙，意大利人听到是中国人，就不聊了。甚至有中国人再去意大利学习冰淇淋技术，对方都很排斥。</p>\\n  <p>这也是为什么今天中国懂Gelato的人太少，因为关于Gelato底层的知识、技术传播都做得不好。我个人是因为刚好在意大利冰淇淋企业工作，才有机会深入内部，接触到更专业的原料、技术、设备原理等关键环节。</p>\\n  <p><strong>36氪：欧洲 Gelato 的连锁化率很低，为什么在中国会有这个机会？</strong></p>\\n  <p><strong>崔渐为：</strong>欧洲不只是 Gelato 没连锁，很多品类都没有连锁，真正的连锁模式从美国开始。美国人更追求利益最大化，想把生意做到最大。</p>\\n  <p>我们扫描行业时发现有几个长期确定的趋势——第一，有人的地方就有冰淇淋需求，这个品类不可能消亡；第二，冰淇淋消费和人均GDP正相关，经济越发达，人们吃的冰淇淋越多、品质要求越高。</p>\\n  <p>再反观中国，单看DQ的规模就知道，DQ全球营业额超300亿，中国市场大概 30 多亿，只占 1/10，它最大的市场在美国，贡献200多亿营业额。这说明 DQ 在美国是很日常、很普遍的消费，而中国的市场空间还很大。</p>\\n  <p>大家购物、逛街和闲聊的时候，总想喝点什么，那为什么不能是冰淇淋呢？如果野人不把一个更好的现制冰淇淋放在消费者面前，大家永远不知道自己有这个需求。</p>\\n  <p><strong>36氪：这个需求一定是30元的Gelato吗？</strong></p>\\n  <p><strong>崔渐为：</strong>好产品需要消费者多体验，才能慢慢建立起标准。就像喝咖啡，只要喝的频次足够多，就能尝出花香、果香这些风味，形成自己的评判标准。</p>\\n  <p>从专业角度说，冰淇淋的好坏非常清晰，有色香味、养料、温度等十大标准。只是这些东西对消费者来说，太专业。但消费者是最聪明的人群，没人能骗得过消费者的嘴巴。</p>\\n  <p><strong>36氪：需求只是开始，决定中国Gelato得以连锁化的客观条件是什么？</strong></p>\\n  <p><strong>崔渐为：</strong>设备国产化是Gelato能在中国连锁化的大前提。意大利进口设备价格在60万，但国产只要6万。除了野人，过去中国没有这个市场，所以我们目前的两个供应商，都是陪伴野人成长起来的，野人是绝对的需求方，也只有我们这些使用者，才懂设备的细节和痛点，帮助上游实现研发迭代。</p>\\n  <p>这也是为什么野人13年都不加盟的原因，如果机器还有bug，不够丝滑稳定，我怎么敢放加盟？</p>\\n  <p><strong>36氪：为什么叫“野人”这个名字？</strong></p>\\n  <p><strong>崔渐为：</strong>“野”是不被世俗规则磨掉的初心。我们想呵护这种 “野”，因为它是野人品牌的核心。</p>\\n  <p>从业务层面说，我们先养牛、再开店，自己建了牧场，坚持手工制作，这和天然、自由的感觉很契合；从精神层面说，去年我们和张伟丽联名，叫 “野力全开，为热爱而战”，张伟丽在 UFC凭一己之力拿了 6 条金腰带，过去没有亚洲人能做到，我们也想在西方强势的冰淇淋领域做出中国品牌。</p>\\n  <p><strong>36氪：你性格“野”吗？</strong></p>\\n  <p><strong>崔渐为：</strong>性格里最大的“野”，是创业第一天就决定要把Gelato 做到极致，并且一辈子做这件事。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_7e5cf7b74bb44fd8abacfd4b8294fbc7@5971123_oswg57589oswg1080oswg720_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\" label=\"图片描述\">野人先生产品图</p>\\n  <h3>没有招商部，全靠口碑推荐</h3>\\n  <p><strong>36氪：为什么决定在2024年放加盟？</strong></p>\\n  <p><strong>崔渐为：</strong>放加盟不是选择，而是必然。</p>\\n  <p>全球成熟的餐饮品牌，麦肯是加盟，DQ也是加盟。我们为什么要拒绝加盟？本质上，冰淇淋就是高度标准化的品类，而且是小店，非常适合加盟；对比海底捞这种大店、复杂中餐，就不太适合加盟。</p>\\n  <p><strong>36氪：野人的加盟商画像是什么样的？</strong></p>\\n  <p><strong>崔渐为：</strong>我们选的是超级加盟商，都是职业选手。</p>\\n  <p><strong>36氪：为什么不是小的？</strong></p>\\n  <p><strong>崔渐为：</strong>超级加盟商的优势在于，他们在食安、服务和门店一线操作上已经建立了很好的职业素养。让这样的人开店，一定能做好，小白就算再聪明，也得走很多弯路。今天野人选择加盟商时，我们首先会关注他是不是一个专业的门店运营者。</p>\\n  <p><strong>36氪：这些超级加盟商，开店规模一般在多少？</strong></p>\\n  <p><strong>崔渐为：</strong>主流在5-10家，最多有50家的。我们毕竟开放加盟时间短，很少有加盟商是只开单一家的。</p>\\n  <p><strong>36氪：听说野人没有招商部，你会直接面试加盟商，他们和你表达最多的顾虑是什么？</strong></p>\\n  <p><strong>崔渐为：</strong>顾虑太多了，核心还是对冰淇淋品类的质疑，冰淇淋能做长久吗？能不能像茶饮一样规模化开店？有季节限制怎么办？消费习惯还没养成，能做起来吗？</p>\\n  <p>我们也很直接，摊开来讲我们的创业历史，带他们去看野人8 年、10 年的老店，让他们感受老店的运营状态和产品，也会把我们对行业的思考、消费习惯培养的过程和他们沟通。</p>\\n  <p>其实这些超级加盟商能力很强，行业也很透明，我们每家店的销售数据，他们自己就能拿到，甚至比我还熟。他们天天混在行业里，选址、运营的门道都懂。当他们来找我们的时候，已经经过反复对比和考察了，只是需要我们解答最后一些疑问，确认自己的判断。</p>\\n  <p>野人之所以没招商部还能开这么快，全靠口碑和推荐。我们从来没做过加盟宣传，连加盟电话都很难找到，我们希望和专业、懂行的人合作——大家匹配度高，反而省了很多事。</p>\\n  <p><strong>36氪：不担心超级加盟商话语权太强、不好管理吗？</strong></p>\\n  <p><strong>崔渐为：</strong>你有价值，他就追随你；你没价值，他自然会离开，不需要刻意管理。</p>\\n  <p><strong>36氪：能否讲述一下野人的选址逻辑？</strong></p>\\n  <p><strong>崔渐为：</strong>选址是野人十几年踩坑最多的地方，一旦选错，就是血亏。有很多选址，看起来不错，比如商场负一楼、地铁口，这些地方人流多，但开店一定差。因为大家都在匆忙赶路，只会买奶茶、面包这种刚需快消品，买了就能带走；而Gelato需要坐下来慢慢吃。</p>\\n  <p>这种选址哪怕我们一再强调不能开，还是有加盟商执意要开。人的惯性认知太难扭转了，但这就是我们要守的底线。我们踩过的坑，不能让加盟商再踩。</p>\\n  <p><strong>36氪：有没有看起来不行，实际却很好的选址？</strong></p>\\n  <p><strong>崔渐为：</strong>比如商场二楼、三楼，很多人觉得楼层高、人流少，但实际转化率很高。尤其是女装层——大家是无目的闲逛，逛累了就想歇一歇，和闺蜜聊聊天，这时再看到Gelato，转化率极高。而且二楼租金还比一楼、负一楼便宜很多。</p>\\n  <p>反倒商场五楼，看着人多，但大家去五楼是有明确需求的——约了人、或者想吃火锅或炒菜，很少会选择中途吃一支冰淇淋。而且现在人怕胖，吃饭前不会额外吃甜的，我们只能捡漏。</p>\\n  <h3>如果不是试吃，野人先生已经死掉了</h3>\\n  <p><strong>36氪：从现制冰淇淋品类来看，DQ的规模最大，野人相对于他们做了哪些升级？</strong></p>\\n  <p><strong>崔渐为：</strong>虽然都属于现制冰淇淋，但DQ是软冰（soft serve），和Gelato完全是两个门类。</p>\\n  <p>软冰的优势是随手可得，只要装一台软冰机，把浆料倒进去，接出来就能卖。今天你看到的麦当劳、肯德基以及蜜雪冰城，他们的冰淇淋都属于软冰，简易化和低成本决定了软冰能成为万店的品类。软冰膨化率通常在100%以上，一半以上都是空气，牛奶本身的香味比较寡淡，所以需要添加香精色素。</p>\\n  <p>并不是说软冰不好，产品定位和分类不同而已。只是Gelato走的是另一个极端。真材实料，追求低的膨化率，一切味道都来自于食材本身。</p>\\n  <p><strong>36氪：Gelato 的膨化率大概是多少？</strong></p>\\n  <p><strong>崔渐为：</strong>大概在20%。对比软冰100%膨化率，Gelato只有1/5，这也意味成本有5倍的差距。</p>\\n  <p><strong>36氪：野人的单杯为什么定在130g？比对手要少。</strong></p>\\n  <p><strong>崔渐为：</strong>这是反复调研后的结果，我们发现，消费者需要“吃得舒服满足，又不过量”，测试后发现130g最合适。</p>\\n  <p><strong>36氪：野人的试吃很有名，时候开始的？</strong></p>\\n  <p><strong>崔渐为：</strong>2015年，我们开第一家门店时，就有试吃了。只是早期比较简单，客人到柜台前，我们最多会问一句“要不要尝一尝”“先尝再买”。</p>\\n  <p>后来店员主动走出去打招呼，成功率很低，还很尴尬。现在我们就设计了专门的试吃小冰箱，放在门店过道最显眼的位置，上面贴“免费试吃”的标识。客人知道这是专门让人试吃的，会大大方方地尝。</p>\\n  <p>这对野人先生来说，是一个关键的转折。餐饮行业没有那么多石破天惊的创新，它是一种每天的精进，在于你能不能把一件繁琐枯燥的事坚持下去。</p>\\n  <p><strong>36氪：试吃也需要迭代。</strong></p>\\n  <p><strong>崔渐为：</strong>试吃从早期1.0，已经迭代到5.0了。野人的试吃，可能是整个冰品行业做得最彻底、花钱最多的那一个。</p>\\n  <p>我的想法很简单，想让客人尝到我们的产品，根本不在乎他买不买。如果不是这种非常积极的试吃，我想野人先生已经死掉了。</p>\\n  <h3>开心果是转折点</h3>\\n  <p><strong>36氪：很早就有投资人找你们，为什么一直没拿融资？</strong></p>\\n  <p><strong>崔渐为：</strong>疫情前就不断有投资人找来，我们做到 50 家店时已经是国内第一，100 家时已是全球第一，资本很容易看到我们。但是拿了钱，前提是让钱真正发挥作用。如果不知道怎么花，或者花了也没有好结果，那反而会是一种灾难。</p>\\n  <p><strong>36氪：当时大家都在拿钱，估值被炒得很高，这种氛围里，你怎么保持理性？</strong></p>\\n  <p><strong>崔渐为：</strong>和我之前做过投资有一点关系。但这不是主要原因，更核心的是做决策时更看重行业本质和规律，而不是跟风。说白了，当时我很清楚，拿了钱对我们来说是负担，发挥不了太多作用。</p>\\n  <p><strong>36氪：接下来有融资计划吗？</strong></p>\\n  <p><strong>崔渐为：</strong>我们并不排斥资本，但前提是彼此契合。过去一些不好的惯例，很多投资人要求对赌、要求上市时间，有这些条款我们就不聊。现在投资人更理性，愿意尊重企业发展规律。</p>\\n  <p><strong>36氪：现在野人已经超过1300家，未来的扩张节奏上，有什么计划？</strong></p>\\n  <p><strong>崔渐为：</strong>我们对规模没有很大的欲望。</p>\\n  <p><strong>36氪：为什么？</strong></p>\\n  <p><strong>崔渐为：</strong>我当然希望品牌有更大影响力，只是它的排位靠后。假如我今天说要开多少店，各个部门一拆解，大家都会为数字努力，动作就很容易变形。野人的思路是，先把一个区域加密，做好口碑，再慢慢拓展。</p>\\n  <p><strong>36氪：但事实是2025年野人门店高速增长，这不是目标带来的结果吗？</strong></p>\\n  <p><strong>崔渐为：</strong>完全是自然增长，因为门店生意确实变好了。直到今天，我们都在踩刹车开店。比如找上门的加盟商有一千个，我们会筛掉几百个，门槛很高。</p>\\n  <p><strong>36氪：生意变好的转折点是什么？</strong></p>\\n  <p><strong>崔渐为：</strong>2023年下半年，开心果口味爆了，它让野人的同店业绩增长30%左右。之前野人许多的门店都在盈亏平衡上。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_d00372b35591425eafdf30575357619b@5971123_oswg74656oswg1080oswg1048_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\" label=\"图片描述\">野人先生产品图</p>\\n  <p><strong>36氪：开心果口味是野人先生的里程碑？</strong></p>\\n  <p><strong>崔渐为：</strong>一个餐饮品牌火与不火，很大程度上取决于有没有爆款大单品，比如霸王茶姬的伯牙绝弦，喜茶的多肉葡萄。大单品让品牌被记住。</p>\\n  <p>对于野人来说，这个大单品就是开心果。现在野人所有的产品都是28元，只有38元的定价为开心果而生，因为原材料实在太贵。</p>\\n  <p>当时我们在选择开心果原料的时候也纠结过，到底是选择意大利进口，还是日本（正荣）的原料，前者价格是后者的五倍。今天几乎所有烘焙品牌用的都是正荣开心果，但烘焙有面粉有糖，冰淇淋入口即化，对风味要求高。野人要追求品质，就要坚定选择意大利开心果。</p>\\n  <p>其实开心果刚推出前两三年，市场表现并不好，直到2023年下半年，突然有很多人来店里点名要购买，各大平台上也开始有用户自发分享，到 2024 年就更火了，从野人扩散到整个冰淇淋行业，再到烘焙、茶饮行业，开心果口味成了全行业都在推的热门口味。</p>\\n  <p><strong>36氪：最早的灵感来自于？</strong></p>\\n  <p><strong>崔渐为：</strong>没有特别的灵感，更多是一种预判。做研发时，通过判断它的浓郁度、香味和口感，我们就能感知到这款产品的潜力。</p>\\n  <p>我们特别为开心果冰淇淋设计了很多出品仪式感，只有它会撒开心果碎，也只有它拥有独特的小翅膀托盒，如你所见，我们一直在海报上重点突出它，员工推荐时，也永远优先开心果口味。就这么坚持了将近5年，才突然爆发。</p>\\n  <p><strong>36氪：如果茶饮品牌都反过来做冰淇淋，你会担心吗？</strong></p>\\n  <p><strong>崔渐为：</strong>挺好的，大家一起做。现在冰淇淋行业的上限还不太高，我们也不在乎它的上限在哪里，上限是自己做出来的。</p>\\n  <p><strong>36氪：不会是你们的对手？</strong></p>\\n  <p><strong>崔渐为：</strong>Gelato的整套系统很复杂，不是在门店加一台机器就能解决的，不仅投入大，对门店的水电条件要求也很高。</p>\\n  <p><strong>36氪：野人出品时的“拉丝带尖”很有意思，为什么会有这个设计？</strong></p>\\n  <p><strong>崔渐为：</strong>拉丝带尖的壁垒不是技术，是创作感。我们不把打冰淇淋当成重复劳动，而是手艺活——往左歪一点像山，往右歪一点像树，每个冰淇淋都不一样。</p>\\n  <p>我早期在门店的时候，就讨厌无趣的工作，所以想让打冰淇淋变得有意思，而不是用挖球器做规整的球。</p>\\n  <p class=\"image-wrapper\"></p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'<p>作者&nbsp;|&nbsp;钟艺璇</p>\\n  <p>编辑&nbsp;|&nbsp;乔芊</p>\\n  <p>如果你在一个意大利人面前，把Gelato等同于ice cream，他一定会难过。</p>\\n  <p>16世纪，Gelato诞生于文艺复兴时期的佛罗伦萨，传说中一名炼金术师创造了它。在意大利语中，Gelato本就译为冰淇淋。但它和美式冰淇淋ice cream口感大有不同，Gelato使用口感更密实，也更新鲜、低脂和健康。</p>\\n  <p>目前中国冰淇淋市场中，夫妻老婆店冷柜里卖的预制冰淇淋占据75%以上的市场份额，这个品类中的高端玩家是哈根达斯。现制冰淇淋只占约25%，以DQ、波比冰淇淋（原波比艾斯）乃至蜜雪冰城为代表的软冰（Soft Serve）以规模化优势，又占其半壁江山，Gelato由于手工现制、定位高端以及门店成本高，市场份额只有6%左右。</p>\\n  <p>在欧洲，数百年来，Gelato都以家族传承、百年老店的形式分散存在——意大利4万家Gelato几乎都是小店，甚至只要10家连锁以上，就能称作大品牌。</p>\\n  <p>但在中国，有一家公司却想把堪称“小众”的Gelato连锁化，它就是野人先生。</p>\\n  <p>2025年，野人先生突然涌现在大众面前，从300多家到突破千店，这也是它爆发式增长的一年。但创始人崔渐为却说，自己创立野人先生已经15年，只是近期才被大众所看见。</p>\\n  <p>15年千店的速度并不快，因为中国消费者对Gelato太陌生。“冰淇淋这个品类似乎20年来没有变化，20年前的哈根达斯、20年前的DQ，和今天都一模一样。每一个行业都在加速迭代，冰淇淋行业没理由停滞不前。”崔渐为说，是野人先生在国内开创了 Gelato 这个赛道。</p>\\n  <p>上个时代，哈根达斯是工业化背景下，冰淇淋极度标准化的产物。要做品类升级，和对手拉开差距，野人先生一直在放大自己的现制属性——做试吃，让人们知道现制Gelato究竟是什么；拉丝带尖（员工在冰淇淋出品的最后一刻，拉出个性化的弧度），让人们对现制更感同身受；过去冰淇淋用玻璃柜展示，野人就用独立密封桶，解决串味和温度波动，让冰淇淋更新鲜；冰淇淋易化，顾客的手也容易被沾湿，就用玉米杯代替塑料杯，厚壁的杯具能保留风味。</p>\\n  <p>这一切的目标都是让Gelato产品更标准，以放大连锁化的可能性。</p>\\n  <p>这个可能性究竟是多大？崔渐为以茶饮行业类比，10年前瓶装饮料市场规模3千亿，现制茶饮只有200亿，10年后，现制茶饮也做到了3000亿。</p>\\n  <p>“我觉得现制冰淇淋能做到跟预制冰淇淋平分秋色，达到2000亿规模。”崔渐为说。</p>\\n  <p>截至目前，DQ在华门店总数超过1800家，是中国最大的现制冰淇淋连锁品牌，波比冰淇淋门店总数超过1200家，野人先生主打Gelato品类，门店规模超过1300家，在全球Gelato连锁领域规模第一。</p>\\n  <p>15年过去，2026年春天之始，野人先生在上海开了一家全球旗舰店，这也是全球最大的Gelato旗舰店。崔渐为告诉36氪，过去野人先生只埋头做产品，品牌端几乎没有系统表达，“全球旗舰店是野人先生15年的里程碑，我们想把‘野自天然’的内核完整呈现出来”。</p>\\n  <p>近期，36氪和崔渐为有一次对话，他向我们讲述了在连锁化前野人先生15年漫长的准备，自己又是如何抓住现制冰淇淋品类升级的机会，以及可替代选择那么多，中国人又何以需要一支好的Gelato。</p>\\n  <p>以下是对话，经36氪编辑：</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_c3b474a237cb400ba0b6c3eb8ef19f3b@5971123_oswg156264oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">野人先生全球旗舰店，位于上海徐汇区东湖路</p>\\n  <h3>冰淇淋有清晰的好坏标准</h3>\\n  <p><strong>36氪：这一年来野人受到很多媒体关注和报道，你心态上有变化吗？</strong></p>\\n  <p><strong>崔渐为：</strong>变化谈不上，多了一些苦恼，也见到社会险恶（笑）。</p>\\n  <p>我们是个理工男团队，连市场部都没有，产品和品牌都由我负责。这两个板块都是创造型的工作，我的灵感更多来自于向内求，去探店、去乡下找食材和农民聊天，或者和行业专业人士交流。15年都是这样。</p>\\n  <p>野人火了以后，外界很多声音偏离了本质，“网红”、“割韭菜”、“第二个钟薛高”，这些标签被加注在野人身上，其实对我们不公平。可以说，野人对于冰淇淋行业的思考、理解和探索，在全世界都是领先的。</p>\\n  <p><strong>36氪：你最初怎么接触到冰淇淋行业？</strong></p>\\n  <p><strong>崔渐为：</strong>大学毕业后，我去了一家意大利主权基金工作，当时我们投了一家85年历史的冰淇淋家族企业，在这个过程中，我深度参与也开始喜欢上冰淇淋行业。</p>\\n  <p>几百年来，Gelato一直被公认为是最好吃的冰淇淋，无论是生产方式、原料、设备还是工艺，它都比工业化生产的ice cream更有优势。但意大利有四万家Gelato店，连锁化率却很低。当地很多店都是家族经营，还有不少百年老店，一家Gelato品牌能开10家左右门店，就已经算多了。</p>\\n  <p>所以当时我们认为Gelato的全球化一定存在机会，就像曾经的星巴克把意大利咖啡带到全球一样。</p>\\n  <p><strong>36氪：在野人先生之前，没人尝试过中国的Gelato连锁化吗？</strong></p>\\n  <p><strong>崔渐为：</strong>其实相反，中国最早做加盟的品类就是冰淇淋品牌，甚至比茶饮还早。冰淇淋本身太适合做加盟了，它标准化程度高，从美国的4大冰品品牌能看出来，它们在历史上都取得了很好的成就。</p>\\n  <p>大概在世纪初，有一批中国加盟商盯上了冰淇淋品类，他们当然知道Gelato最好，也去意大利找了品牌谈战略合作。但他们做的事却和Gelato无关，只是拿上创始人的授权照片，贴在墙上背书，也不用人家的原料，就卖5块钱3个球的冰淇淋。</p>\\n  <p>很快，整个行业对中国加盟商都建立了防火墙，意大利人听到是中国人，就不聊了。甚至有中国人再去意大利学习冰淇淋技术，对方都很排斥。</p>\\n  <p>这也是为什么今天中国懂Gelato的人太少，因为关于Gelato底层的知识、技术传播都做得不好。我个人是因为刚好在意大利冰淇淋企业工作，才有机会深入内部，接触到更专业的原料、技术、设备原理等关键环节。</p>\\n  <p><strong>36氪：欧洲 Gelato 的连锁化率很低，为什么在中国会有这个机会？</strong></p>\\n  <p><strong>崔渐为：</strong>欧洲不只是 Gelato 没连锁，很多品类都没有连锁，真正的连锁模式从美国开始。美国人更追求利益最大化，想把生意做到最大。</p>\\n  <p>我们扫描行业时发现有几个长期确定的趋势——第一，有人的地方就有冰淇淋需求，这个品类不可能消亡；第二，冰淇淋消费和人均GDP正相关，经济越发达，人们吃的冰淇淋越多、品质要求越高。</p>\\n  <p>再反观中国，单看DQ的规模就知道，DQ全球营业额超300亿，中国市场大概 30 多亿，只占 1/10，它最大的市场在美国，贡献200多亿营业额。这说明 DQ 在美国是很日常、很普遍的消费，而中国的市场空间还很大。</p>\\n  <p>大家购物、逛街和闲聊的时候，总想喝点什么，那为什么不能是冰淇淋呢？如果野人不把一个更好的现制冰淇淋放在消费者面前，大家永远不知道自己有这个需求。</p>\\n  <p><strong>36氪：这个需求一定是30元的Gelato吗？</strong></p>\\n  <p><strong>崔渐为：</strong>好产品需要消费者多体验，才能慢慢建立起标准。就像喝咖啡，只要喝的频次足够多，就能尝出花香、果香这些风味，形成自己的评判标准。</p>\\n  <p>从专业角度说，冰淇淋的好坏非常清晰，有色香味、养料、温度等十大标准。只是这些东西对消费者来说，太专业。但消费者是最聪明的人群，没人能骗得过消费者的嘴巴。</p>\\n  <p><strong>36氪：需求只是开始，决定中国Gelato得以连锁化的客观条件是什么？</strong></p>\\n  <p><strong>崔渐为：</strong>设备国产化是Gelato能在中国连锁化的大前提。意大利进口设备价格在60万，但国产只要6万。除了野人，过去中国没有这个市场，所以我们目前的两个供应商，都是陪伴野人成长起来的，野人是绝对的需求方，也只有我们这些使用者，才懂设备的细节和痛点，帮助上游实现研发迭代。</p>\\n  <p>这也是为什么野人13年都不加盟的原因，如果机器还有bug，不够丝滑稳定，我怎么敢放加盟？</p>\\n  <p><strong>36氪：为什么叫“野人”这个名字？</strong></p>\\n  <p><strong>崔渐为：</strong>“野”是不被世俗规则磨掉的初心。我们想呵护这种 “野”，因为它是野人品牌的核心。</p>\\n  <p>从业务层面说，我们先养牛、再开店，自己建了牧场，坚持手工制作，这和天然、自由的感觉很契合；从精神层面说，去年我们和张伟丽联名，叫 “野力全开，为热爱而战”，张伟丽在 UFC凭一己之力拿了 6 条金腰带，过去没有亚洲人能做到，我们也想在西方强势的冰淇淋领域做出中国品牌。</p>\\n  <p><strong>36氪：你性格“野”吗？</strong></p>\\n  <p><strong>崔渐为：</strong>性格里最大的“野”，是创业第一天就决定要把Gelato 做到极致，并且一辈子做这件事。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_7e5cf7b74bb44fd8abacfd4b8294fbc7@5971123_oswg57589oswg1080oswg720_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\" label=\"图片描述\">野人先生产品图</p>\\n  <h3>没有招商部，全靠口碑推荐</h3>\\n  <p><strong>36氪：为什么决定在2024年放加盟？</strong></p>\\n  <p><strong>崔渐为：</strong>放加盟不是选择，而是必然。</p>\\n  <p>全球成熟的餐饮品牌，麦肯是加盟，DQ也是加盟。我们为什么要拒绝加盟？本质上，冰淇淋就是高度标准化的品类，而且是小店，非常适合加盟；对比海底捞这种大店、复杂中餐，就不太适合加盟。</p>\\n  <p><strong>36氪：野人的加盟商画像是什么样的？</strong></p>\\n  <p><strong>崔渐为：</strong>我们选的是超级加盟商，都是职业选手。</p>\\n  <p><strong>36氪：为什么不是小的？</strong></p>\\n  <p><strong>崔渐为：</strong>超级加盟商的优势在于，他们在食安、服务和门店一线操作上已经建立了很好的职业素养。让这样的人开店，一定能做好，小白就算再聪明，也得走很多弯路。今天野人选择加盟商时，我们首先会关注他是不是一个专业的门店运营者。</p>\\n  <p><strong>36氪：这些超级加盟商，开店规模一般在多少？</strong></p>\\n  <p><strong>崔渐为：</strong>主流在5-10家，最多有50家的。我们毕竟开放加盟时间短，很少有加盟商是只开单一家的。</p>\\n  <p><strong>36氪：听说野人没有招商部，你会直接面试加盟商，他们和你表达最多的顾虑是什么？</strong></p>\\n  <p><strong>崔渐为：</strong>顾虑太多了，核心还是对冰淇淋品类的质疑，冰淇淋能做长久吗？能不能像茶饮一样规模化开店？有季节限制怎么办？消费习惯还没养成，能做起来吗？</p>\\n  <p>我们也很直接，摊开来讲我们的创业历史，带他们去看野人8 年、10 年的老店，让他们感受老店的运营状态和产品，也会把我们对行业的思考、消费习惯培养的过程和他们沟通。</p>\\n  <p>其实这些超级加盟商能力很强，行业也很透明，我们每家店的销售数据，他们自己就能拿到，甚至比我还熟。他们天天混在行业里，选址、运营的门道都懂。当他们来找我们的时候，已经经过反复对比和考察了，只是需要我们解答最后一些疑问，确认自己的判断。</p>\\n  <p>野人之所以没招商部还能开这么快，全靠口碑和推荐。我们从来没做过加盟宣传，连加盟电话都很难找到，我们希望和专业、懂行的人合作——大家匹配度高，反而省了很多事。</p>\\n  <p><strong>36氪：不担心超级加盟商话语权太强、不好管理吗？</strong></p>\\n  <p><strong>崔渐为：</strong>你有价值，他就追随你；你没价值，他自然会离开，不需要刻意管理。</p>\\n  <p><strong>36氪：能否讲述一下野人的选址逻辑？</strong></p>\\n  <p><strong>崔渐为：</strong>选址是野人十几年踩坑最多的地方，一旦选错，就是血亏。有很多选址，看起来不错，比如商场负一楼、地铁口，这些地方人流多，但开店一定差。因为大家都在匆忙赶路，只会买奶茶、面包这种刚需快消品，买了就能带走；而Gelato需要坐下来慢慢吃。</p>\\n  <p>这种选址哪怕我们一再强调不能开，还是有加盟商执意要开。人的惯性认知太难扭转了，但这就是我们要守的底线。我们踩过的坑，不能让加盟商再踩。</p>\\n  <p><strong>36氪：有没有看起来不行，实际却很好的选址？</strong></p>\\n  <p><strong>崔渐为：</strong>比如商场二楼、三楼，很多人觉得楼层高、人流少，但实际转化率很高。尤其是女装层——大家是无目的闲逛，逛累了就想歇一歇，和闺蜜聊聊天，这时再看到Gelato，转化率极高。而且二楼租金还比一楼、负一楼便宜很多。</p>\\n  <p>反倒商场五楼，看着人多，但大家去五楼是有明确需求的——约了人、或者想吃火锅或炒菜，很少会选择中途吃一支冰淇淋。而且现在人怕胖，吃饭前不会额外吃甜的，我们只能捡漏。</p>\\n  <h3>如果不是试吃，野人先生已经死掉了</h3>\\n  <p><strong>36氪：从现制冰淇淋品类来看，DQ的规模最大，野人相对于他们做了哪些升级？</strong></p>\\n  <p><strong>崔渐为：</strong>虽然都属于现制冰淇淋，但DQ是软冰（soft serve），和Gelato完全是两个门类。</p>\\n  <p>软冰的优势是随手可得，只要装一台软冰机，把浆料倒进去，接出来就能卖。今天你看到的麦当劳、肯德基以及蜜雪冰城，他们的冰淇淋都属于软冰，简易化和低成本决定了软冰能成为万店的品类。软冰膨化率通常在100%以上，一半以上都是空气，牛奶本身的香味比较寡淡，所以需要添加香精色素。</p>\\n  <p>并不是说软冰不好，产品定位和分类不同而已。只是Gelato走的是另一个极端。真材实料，追求低的膨化率，一切味道都来自于食材本身。</p>\\n  <p><strong>36氪：Gelato 的膨化率大概是多少？</strong></p>\\n  <p><strong>崔渐为：</strong>大概在20%。对比软冰100%膨化率，Gelato只有1/5，这也意味成本有5倍的差距。</p>\\n  <p><strong>36氪：野人的单杯为什么定在130g？比对手要少。</strong></p>\\n  <p><strong>崔渐为：</strong>这是反复调研后的结果，我们发现，消费者需要“吃得舒服满足，又不过量”，测试后发现130g最合适。</p>\\n  <p><strong>36氪：野人的试吃很有名，时候开始的？</strong></p>\\n  <p><strong>崔渐为：</strong>2015年，我们开第一家门店时，就有试吃了。只是早期比较简单，客人到柜台前，我们最多会问一句“要不要尝一尝”“先尝再买”。</p>\\n  <p>后来店员主动走出去打招呼，成功率很低，还很尴尬。现在我们就设计了专门的试吃小冰箱，放在门店过道最显眼的位置，上面贴“免费试吃”的标识。客人知道这是专门让人试吃的，会大大方方地尝。</p>\\n  <p>这对野人先生来说，是一个关键的转折。餐饮行业没有那么多石破天惊的创新，它是一种每天的精进，在于你能不能把一件繁琐枯燥的事坚持下去。</p>\\n  <p><strong>36氪：试吃也需要迭代。</strong></p>\\n  <p><strong>崔渐为：</strong>试吃从早期1.0，已经迭代到5.0了。野人的试吃，可能是整个冰品行业做得最彻底、花钱最多的那一个。</p>\\n  <p>我的想法很简单，想让客人尝到我们的产品，根本不在乎他买不买。如果不是这种非常积极的试吃，我想野人先生已经死掉了。</p>\\n  <h3>开心果是转折点</h3>\\n  <p><strong>36氪：很早就有投资人找你们，为什么一直没拿融资？</strong></p>\\n  <p><strong>崔渐为：</strong>疫情前就不断有投资人找来，我们做到 50 家店时已经是国内第一，100 家时已是全球第一，资本很容易看到我们。但是拿了钱，前提是让钱真正发挥作用。如果不知道怎么花，或者花了也没有好结果，那反而会是一种灾难。</p>\\n  <p><strong>36氪：当时大家都在拿钱，估值被炒得很高，这种氛围里，你怎么保持理性？</strong></p>\\n  <p><strong>崔渐为：</strong>和我之前做过投资有一点关系。但这不是主要原因，更核心的是做决策时更看重行业本质和规律，而不是跟风。说白了，当时我很清楚，拿了钱对我们来说是负担，发挥不了太多作用。</p>\\n  <p><strong>36氪：接下来有融资计划吗？</strong></p>\\n  <p><strong>崔渐为：</strong>我们并不排斥资本，但前提是彼此契合。过去一些不好的惯例，很多投资人要求对赌、要求上市时间，有这些条款我们就不聊。现在投资人更理性，愿意尊重企业发展规律。</p>\\n  <p><strong>36氪：现在野人已经超过1300家，未来的扩张节奏上，有什么计划？</strong></p>\\n  <p><strong>崔渐为：</strong>我们对规模没有很大的欲望。</p>\\n  <p><strong>36氪：为什么？</strong></p>\\n  <p><strong>崔渐为：</strong>我当然希望品牌有更大影响力，只是它的排位靠后。假如我今天说要开多少店，各个部门一拆解，大家都会为数字努力，动作就很容易变形。野人的思路是，先把一个区域加密，做好口碑，再慢慢拓展。</p>\\n  <p><strong>36氪：但事实是2025年野人门店高速增长，这不是目标带来的结果吗？</strong></p>\\n  <p><strong>崔渐为：</strong>完全是自然增长，因为门店生意确实变好了。直到今天，我们都在踩刹车开店。比如找上门的加盟商有一千个，我们会筛掉几百个，门槛很高。</p>\\n  <p><strong>36氪：生意变好的转折点是什么？</strong></p>\\n  <p><strong>崔渐为：</strong>2023年下半年，开心果口味爆了，它让野人的同店业绩增长30%左右。之前野人许多的门店都在盈亏平衡上。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_d00372b35591425eafdf30575357619b@5971123_oswg74656oswg1080oswg1048_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\" label=\"图片描述\">野人先生产品图</p>\\n  <p><strong>36氪：开心果口味是野人先生的里程碑？</strong></p>\\n  <p><strong>崔渐为：</strong>一个餐饮品牌火与不火，很大程度上取决于有没有爆款大单品，比如霸王茶姬的伯牙绝弦，喜茶的多肉葡萄。大单品让品牌被记住。</p>\\n  <p>对于野人来说，这个大单品就是开心果。现在野人所有的产品都是28元，只有38元的定价为开心果而生，因为原材料实在太贵。</p>\\n  <p>当时我们在选择开心果原料的时候也纠结过，到底是选择意大利进口，还是日本（正荣）的原料，前者价格是后者的五倍。今天几乎所有烘焙品牌用的都是正荣开心果，但烘焙有面粉有糖，冰淇淋入口即化，对风味要求高。野人要追求品质，就要坚定选择意大利开心果。</p>\\n  <p>其实开心果刚推出前两三年，市场表现并不好，直到2023年下半年，突然有很多人来店里点名要购买，各大平台上也开始有用户自发分享，到 2024 年就更火了，从野人扩散到整个冰淇淋行业，再到烘焙、茶饮行业，开心果口味成了全行业都在推的热门口味。</p>\\n  <p><strong>36氪：最早的灵感来自于？</strong></p>\\n  <p><strong>崔渐为：</strong>没有特别的灵感，更多是一种预判。做研发时，通过判断它的浓郁度、香味和口感，我们就能感知到这款产品的潜力。</p>\\n  <p>我们特别为开心果冰淇淋设计了很多出品仪式感，只有它会撒开心果碎，也只有它拥有独特的小翅膀托盒，如你所见，我们一直在海报上重点突出它，员工推荐时，也永远优先开心果口味。就这么坚持了将近5年，才突然爆发。</p>\\n  <p><strong>36氪：如果茶饮品牌都反过来做冰淇淋，你会担心吗？</strong></p>\\n  <p><strong>崔渐为：</strong>挺好的，大家一起做。现在冰淇淋行业的上限还不太高，我们也不在乎它的上限在哪里，上限是自己做出来的。</p>\\n  <p><strong>36氪：不会是你们的对手？</strong></p>\\n  <p><strong>崔渐为：</strong>Gelato的整套系统很复杂，不是在门店加一台机器就能解决的，不仅投入大，对门店的水电条件要求也很高。</p>\\n  <p><strong>36氪：野人出品时的“拉丝带尖”很有意思，为什么会有这个设计？</strong></p>\\n  <p><strong>崔渐为：</strong>拉丝带尖的壁垒不是技术，是创作感。我们不把打冰淇淋当成重复劳动，而是手艺活——往左歪一点像山，往右歪一点像树，每个冰淇淋都不一样。</p>\\n  <p>我早期在门店的时候，就讨厌无趣的工作，所以想让打冰淇淋变得有意思，而不是用挖球器做规整的球。</p>\\n  <p class=\"image-wrapper\"></p>\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-13 17:58:36', '2026-04-14 14:10:15', 0, '\"\"');
INSERT INTO `news` VALUES (404, '国务院关于国家公园空间布局方案的批复', 'http://www.gov.cn/zhengce/content/2022-11/08/content_5725340.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院关于国家公园空间布局方案的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于国家公园空间布局方案的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-11/08/content_5725340.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-11/08/content_5725340.htm\', \'published\': \'Sun, 31 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=31, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=6, tm_yday=304, tm_isdst=0)}', '2021-10-31 16:00:00', '2026-04-14 14:10:17', 0, '\"\"');
INSERT INTO `news` VALUES (405, '包容 探索 求真 守正｜2026光幕计划终审阵容与年度面孔公布', 'https://36kr.com/p/3764886161048323?f=rss', 'https://36kr.com/feed', '<p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_9829b6380e514568b4857c8a2dec1beb@5889148_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">&nbsp;</p>\n  <p>当短剧成为当下备受关注的叙事形态，当AI不断拓展表达的边界，表演这门古老的艺术，也站在了新的岔路口。效率与流量构筑了可见的赛道，而真正的叩问始终沉在深处：在技术的“巧”与媒介的“快”之外，那些源于血肉之躯的、笨拙而恳切的“真”，是否依然拥有抵达人心的力量？</p>\n  <p>辨识这份真实，需要深耕岁月、敬畏专业的目光。为此，我们荣幸地邀请到李少红导演担任第十六届北京国际电影节BE SEEN 光幕计划终评审主席，赵小丁、吴刚、俞白眉、魏钦涛担任终审评委。他们以多年的创作生命为标尺，为这份最终的年度面孔入选演员名单注入了厚重的公信力与深远的期待。</p>\n  <p>“表演有无数个高山要翻跃。”终审现场，评委俞白眉的这句话，道出了在场者的共同感受。在为期两天的评审中，来自戏剧、影视、短剧等不同背景的青年演员相继登场，他们的创作在评委面前展开了一场坦诚而多元的时代对话。李少红导演不断追问演员是否“走心”，吴刚则反复强调，无论在何种媒介与赛道中，“真听、真看、真判断”永远是表演不可撼动的根基。评审的意义，正是以专业的目光，聚拢并辨认那些真正将表演视为志业的跋涉者，既尊重市场的选择，也尊重专业的信念。</p>\n  <p>2026年，556位青年演员用他们的创作参与了这场对时代的叩问。经过323人初审、89人终审的漫长评议，我们共同确认了25张年度面孔。这份名单，是我们交出的答卷：在拥抱变化与恪守本心之间，在传承积淀与大胆实验之际，我们选择回归最朴素的“土壤”—— 坚信那些对生活的诚实体验、对角色笨拙的靠近，才是表演穿越所有喧嚣的根基。我们珍视这份“拙诚”的底色，因为它源自生命本身的热度，无法被任何算法预设或替代。</p>\n  <p>这份答卷，以<strong>包容</strong>拥抱多元表演形态，不设边界；以<strong>探索</strong>直面时代新命题，建立新标尺；以<strong>求真</strong>回归表演本质，夯实专业功底；以<strong>守正</strong>在奔涌浪潮中，持守公正与关怀。</p>\n  <p><strong>终评审主席：李少红</strong></p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_5144fe74196d4d8b95f843b25dd8bbf7@5889148_oswg446164oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">&nbsp;</p>\n  <p>中国第五代导演的代表人物。从《红粉》《血色清晨》到《大明宫词》，她始终以极致的艺术敏感与人文关怀，淬炼表演中最动人的真实质感，创作了多部兼具作者表达与广泛共鸣的经典作品。评审中，她持续追问演员是否“走心”，警惕任何对生活的简单模仿。她相信，动人的表演在于“想”大于“演”，需要演员将对生活的独到理解与个人气质融合，淬炼出专属于角色的真实质感，让每一次诠释都成为不可复制的创造。</p>\n  <p><strong>终审评委：赵小丁</strong></p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_eaf4994ef4db446ca187e0fa2db87764@5889148_oswg509081oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">&nbsp;</p>\n  <p>中国影视摄影师学会会长，荣获金鸡奖最佳摄影的导演与摄影指导，代表作包括《悬崖之上》《满江红》。他的视角从光影出发，审视表演如何与摄影共同完成视觉叙事。他探讨演员的身体如何在镜头前建立有效的张力，细微的情绪又如何被光影捕捉并赋予力量。他同时谨慎指出，演员的表演设计需有分寸，最理想的境界，是表演与视听语言达成“浑然一体的化学作用”，不露设计的痕迹。</p>\n  <p><strong>终审评委：吴 刚</strong></p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_b1f5d5fa31d34664bf95425b9339be4b@5889148_oswg455313oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">&nbsp;</p>\n  <p>北京人民艺术剧院国家一级演员。凭借“剧抛脸”式的演技在《人民的名义》《狂飙》等作品中深入人心。他的审视深入表演的肌理，追溯演员构建角色的内在逻辑。他引导演员从对手的台词中寻找自己行为的依据，以此构建清晰可信的心理行动线。在他看来，令人信服的表演，其核心是塑造“人物关系”，任何技巧与设计，都必须服务于让一个具体、鲜活的人“立”在台上。</p>\n  <p><strong>终审评委：俞白眉</strong></p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_d78eb991981f4b6ab7f4581ec10b221f@5889148_oswg585353oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">&nbsp;</p>\n  <p>导演及编剧，作品如《中国乒乓之绝地反击》《银河补习班》深谙类型叙事与大众情感连接。他的评审紧扣“故事”与“戏剧博弈”。他极度关注演员对文本潜台词的理解深度，以及能否在有限的篇幅内，通过细腻的层次变化，呈现复杂的人物心理与关系张力。他认为“松弛不是涣散”，演员必须建立宏观的剧本视野与准确的审美判断，方能使表演真正承载并推动叙事，达成与观众的高效共情。</p>\n  <p><strong>终审评委：魏钦涛</strong></p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_c87ce56cabc04a0394c0a1f11a97f9db@5889148_oswg460546oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">&nbsp;</p>\n  <p>红果精品短剧负责人，短剧领域的深度实践者，带领“果燃计划”孵化出品百余部精品短剧。他从产业最前线带来对“竖屏语法”的敏锐洞察。他的评审，聚焦于表演在即时反馈的生态中，如何迅速建立信任、精准传递情绪，在有限的“格子”里完成有效叙事。同时，他也提醒演员警惕陷入“快餐式”的表演惯性，认为短剧表演的未来，在于向更扎实的人物塑造与戏剧张力寻求拓展。</p>\n  <p><strong>第十六届北京国际电影节 BE SEEN 光幕计划年度面孔正式发布！</strong></p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_4d4f2a894efc4816a6a9002b3c25d975@5889148_oswg3258532oswg1080oswg3743_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">&nbsp;</p>\n  <p>五道来自表演、导演、制片、编剧、摄影维度的专业目光，在评审现场交汇、碰撞，乃至激烈辩论。他们共同完成的，远不止于一份名单的选拔，而是一场关于表演本质在当下如何存续的深度校准。</p>\n  <p>山在远处，攀登便有了方向。 而今天横亘于前的，是技术的精密、算法的效率与流量的速度所垒成的新高度。而表演的长路，是一代代人的接续跋涉，每一程都需回应时代的叩问，每一次驻足都在校准前行的路标。最终浮现的25张年度面孔中的成员，将很快进入集训营，投身于经典剧场与实验剧场的实战拍摄，在真实的创作激流中，完成下一次前行的可能。</p>\n  <p>翻越高山，不在于征服，更在于确认。确认沉重的呼吸、脚下的砂石与拂过的山风，它们本身，便是对生命最诚恳的丈量；也确认翻山越岭、满身疲惫后，一个朴素的真理依然清晰：&nbsp;无论媒介与技术如何变迁，表演最动人的，永远源于生命对生命最本真的、笨拙而诚恳的照亮。</p>\n  <p>如此跋涉，只因深信不疑，所有诚恳的丈量，最终都将让我们摘取到那颗属于生命的果实。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_9bfae94b5a35451eb38d9319fa5c0edb@5889148_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">&nbsp;</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_55e32b377d744ad68d6b6361d1d65b0c@5889148_oswg46724oswg1080oswg494_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">&nbsp;</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_2c44806851184f1d90b47b0334e1e99b@5889148_oswg147862oswg1080oswg2134_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">&nbsp;</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_7b3471df3b8f4ae5af5ae9e74964c67f@5889148_oswg41421oswg1080oswg870_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">&nbsp;</p>\n  <p class=\"editor-note\">本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/fseaDTiJzXscOk2bcRk8xg\" rel=\"noopener noreferrer\" target=\"_blank\">“BE SEEN光幕计划”</a>，作者：BE&nbsp;SEEN，36氪经授权发布。</p>', '', '', '', '', '{\'title\': \'包容 探索 求真 守正｜2026光幕计划终审阵容与年度面孔公布\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'包容 探索 求真 守正｜2026光幕计划终审阵容与年度面孔公布\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3764886161048323?f=rss\'}], \'link\': \'https://36kr.com/p/3764886161048323?f=rss\', \'published\': \'2026-04-13 14:59:19  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=6, tm_min=59, tm_sec=19, tm_wday=0, tm_yday=103, tm_isdst=0), \'summary\': \'<p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_9829b6380e514568b4857c8a2dec1beb@5889148_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p>当短剧成为当下备受关注的叙事形态，当AI不断拓展表达的边界，表演这门古老的艺术，也站在了新的岔路口。效率与流量构筑了可见的赛道，而真正的叩问始终沉在深处：在技术的“巧”与媒介的“快”之外，那些源于血肉之躯的、笨拙而恳切的“真”，是否依然拥有抵达人心的力量？</p>\\n  <p>辨识这份真实，需要深耕岁月、敬畏专业的目光。为此，我们荣幸地邀请到李少红导演担任第十六届北京国际电影节BE SEEN 光幕计划终评审主席，赵小丁、吴刚、俞白眉、魏钦涛担任终审评委。他们以多年的创作生命为标尺，为这份最终的年度面孔入选演员名单注入了厚重的公信力与深远的期待。</p>\\n  <p>“表演有无数个高山要翻跃。”终审现场，评委俞白眉的这句话，道出了在场者的共同感受。在为期两天的评审中，来自戏剧、影视、短剧等不同背景的青年演员相继登场，他们的创作在评委面前展开了一场坦诚而多元的时代对话。李少红导演不断追问演员是否“走心”，吴刚则反复强调，无论在何种媒介与赛道中，“真听、真看、真判断”永远是表演不可撼动的根基。评审的意义，正是以专业的目光，聚拢并辨认那些真正将表演视为志业的跋涉者，既尊重市场的选择，也尊重专业的信念。</p>\\n  <p>2026年，556位青年演员用他们的创作参与了这场对时代的叩问。经过323人初审、89人终审的漫长评议，我们共同确认了25张年度面孔。这份名单，是我们交出的答卷：在拥抱变化与恪守本心之间，在传承积淀与大胆实验之际，我们选择回归最朴素的“土壤”—— 坚信那些对生活的诚实体验、对角色笨拙的靠近，才是表演穿越所有喧嚣的根基。我们珍视这份“拙诚”的底色，因为它源自生命本身的热度，无法被任何算法预设或替代。</p>\\n  <p>这份答卷，以<strong>包容</strong>拥抱多元表演形态，不设边界；以<strong>探索</strong>直面时代新命题，建立新标尺；以<strong>求真</strong>回归表演本质，夯实专业功底；以<strong>守正</strong>在奔涌浪潮中，持守公正与关怀。</p>\\n  <p><strong>终评审主席：李少红</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_5144fe74196d4d8b95f843b25dd8bbf7@5889148_oswg446164oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p>中国第五代导演的代表人物。从《红粉》《血色清晨》到《大明宫词》，她始终以极致的艺术敏感与人文关怀，淬炼表演中最动人的真实质感，创作了多部兼具作者表达与广泛共鸣的经典作品。评审中，她持续追问演员是否“走心”，警惕任何对生活的简单模仿。她相信，动人的表演在于“想”大于“演”，需要演员将对生活的独到理解与个人气质融合，淬炼出专属于角色的真实质感，让每一次诠释都成为不可复制的创造。</p>\\n  <p><strong>终审评委：赵小丁</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_eaf4994ef4db446ca187e0fa2db87764@5889148_oswg509081oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p>中国影视摄影师学会会长，荣获金鸡奖最佳摄影的导演与摄影指导，代表作包括《悬崖之上》《满江红》。他的视角从光影出发，审视表演如何与摄影共同完成视觉叙事。他探讨演员的身体如何在镜头前建立有效的张力，细微的情绪又如何被光影捕捉并赋予力量。他同时谨慎指出，演员的表演设计需有分寸，最理想的境界，是表演与视听语言达成“浑然一体的化学作用”，不露设计的痕迹。</p>\\n  <p><strong>终审评委：吴 刚</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_b1f5d5fa31d34664bf95425b9339be4b@5889148_oswg455313oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p>北京人民艺术剧院国家一级演员。凭借“剧抛脸”式的演技在《人民的名义》《狂飙》等作品中深入人心。他的审视深入表演的肌理，追溯演员构建角色的内在逻辑。他引导演员从对手的台词中寻找自己行为的依据，以此构建清晰可信的心理行动线。在他看来，令人信服的表演，其核心是塑造“人物关系”，任何技巧与设计，都必须服务于让一个具体、鲜活的人“立”在台上。</p>\\n  <p><strong>终审评委：俞白眉</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_d78eb991981f4b6ab7f4581ec10b221f@5889148_oswg585353oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p>导演及编剧，作品如《中国乒乓之绝地反击》《银河补习班》深谙类型叙事与大众情感连接。他的评审紧扣“故事”与“戏剧博弈”。他极度关注演员对文本潜台词的理解深度，以及能否在有限的篇幅内，通过细腻的层次变化，呈现复杂的人物心理与关系张力。他认为“松弛不是涣散”，演员必须建立宏观的剧本视野与准确的审美判断，方能使表演真正承载并推动叙事，达成与观众的高效共情。</p>\\n  <p><strong>终审评委：魏钦涛</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_c87ce56cabc04a0394c0a1f11a97f9db@5889148_oswg460546oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p>红果精品短剧负责人，短剧领域的深度实践者，带领“果燃计划”孵化出品百余部精品短剧。他从产业最前线带来对“竖屏语法”的敏锐洞察。他的评审，聚焦于表演在即时反馈的生态中，如何迅速建立信任、精准传递情绪，在有限的“格子”里完成有效叙事。同时，他也提醒演员警惕陷入“快餐式”的表演惯性，认为短剧表演的未来，在于向更扎实的人物塑造与戏剧张力寻求拓展。</p>\\n  <p><strong>第十六届北京国际电影节 BE SEEN 光幕计划年度面孔正式发布！</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_4d4f2a894efc4816a6a9002b3c25d975@5889148_oswg3258532oswg1080oswg3743_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p>五道来自表演、导演、制片、编剧、摄影维度的专业目光，在评审现场交汇、碰撞，乃至激烈辩论。他们共同完成的，远不止于一份名单的选拔，而是一场关于表演本质在当下如何存续的深度校准。</p>\\n  <p>山在远处，攀登便有了方向。 而今天横亘于前的，是技术的精密、算法的效率与流量的速度所垒成的新高度。而表演的长路，是一代代人的接续跋涉，每一程都需回应时代的叩问，每一次驻足都在校准前行的路标。最终浮现的25张年度面孔中的成员，将很快进入集训营，投身于经典剧场与实验剧场的实战拍摄，在真实的创作激流中，完成下一次前行的可能。</p>\\n  <p>翻越高山，不在于征服，更在于确认。确认沉重的呼吸、脚下的砂石与拂过的山风，它们本身，便是对生命最诚恳的丈量；也确认翻山越岭、满身疲惫后，一个朴素的真理依然清晰：&nbsp;无论媒介与技术如何变迁，表演最动人的，永远源于生命对生命最本真的、笨拙而诚恳的照亮。</p>\\n  <p>如此跋涉，只因深信不疑，所有诚恳的丈量，最终都将让我们摘取到那颗属于生命的果实。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_9bfae94b5a35451eb38d9319fa5c0edb@5889148_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_55e32b377d744ad68d6b6361d1d65b0c@5889148_oswg46724oswg1080oswg494_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_2c44806851184f1d90b47b0334e1e99b@5889148_oswg147862oswg1080oswg2134_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_7b3471df3b8f4ae5af5ae9e74964c67f@5889148_oswg41421oswg1080oswg870_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p class=\"editor-note\">本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/fseaDTiJzXscOk2bcRk8xg\" rel=\"noopener noreferrer\" target=\"_blank\">“BE SEEN光幕计划”</a>，作者：BE&nbsp;SEEN，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'<p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_9829b6380e514568b4857c8a2dec1beb@5889148_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p>当短剧成为当下备受关注的叙事形态，当AI不断拓展表达的边界，表演这门古老的艺术，也站在了新的岔路口。效率与流量构筑了可见的赛道，而真正的叩问始终沉在深处：在技术的“巧”与媒介的“快”之外，那些源于血肉之躯的、笨拙而恳切的“真”，是否依然拥有抵达人心的力量？</p>\\n  <p>辨识这份真实，需要深耕岁月、敬畏专业的目光。为此，我们荣幸地邀请到李少红导演担任第十六届北京国际电影节BE SEEN 光幕计划终评审主席，赵小丁、吴刚、俞白眉、魏钦涛担任终审评委。他们以多年的创作生命为标尺，为这份最终的年度面孔入选演员名单注入了厚重的公信力与深远的期待。</p>\\n  <p>“表演有无数个高山要翻跃。”终审现场，评委俞白眉的这句话，道出了在场者的共同感受。在为期两天的评审中，来自戏剧、影视、短剧等不同背景的青年演员相继登场，他们的创作在评委面前展开了一场坦诚而多元的时代对话。李少红导演不断追问演员是否“走心”，吴刚则反复强调，无论在何种媒介与赛道中，“真听、真看、真判断”永远是表演不可撼动的根基。评审的意义，正是以专业的目光，聚拢并辨认那些真正将表演视为志业的跋涉者，既尊重市场的选择，也尊重专业的信念。</p>\\n  <p>2026年，556位青年演员用他们的创作参与了这场对时代的叩问。经过323人初审、89人终审的漫长评议，我们共同确认了25张年度面孔。这份名单，是我们交出的答卷：在拥抱变化与恪守本心之间，在传承积淀与大胆实验之际，我们选择回归最朴素的“土壤”—— 坚信那些对生活的诚实体验、对角色笨拙的靠近，才是表演穿越所有喧嚣的根基。我们珍视这份“拙诚”的底色，因为它源自生命本身的热度，无法被任何算法预设或替代。</p>\\n  <p>这份答卷，以<strong>包容</strong>拥抱多元表演形态，不设边界；以<strong>探索</strong>直面时代新命题，建立新标尺；以<strong>求真</strong>回归表演本质，夯实专业功底；以<strong>守正</strong>在奔涌浪潮中，持守公正与关怀。</p>\\n  <p><strong>终评审主席：李少红</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_5144fe74196d4d8b95f843b25dd8bbf7@5889148_oswg446164oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p>中国第五代导演的代表人物。从《红粉》《血色清晨》到《大明宫词》，她始终以极致的艺术敏感与人文关怀，淬炼表演中最动人的真实质感，创作了多部兼具作者表达与广泛共鸣的经典作品。评审中，她持续追问演员是否“走心”，警惕任何对生活的简单模仿。她相信，动人的表演在于“想”大于“演”，需要演员将对生活的独到理解与个人气质融合，淬炼出专属于角色的真实质感，让每一次诠释都成为不可复制的创造。</p>\\n  <p><strong>终审评委：赵小丁</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_eaf4994ef4db446ca187e0fa2db87764@5889148_oswg509081oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p>中国影视摄影师学会会长，荣获金鸡奖最佳摄影的导演与摄影指导，代表作包括《悬崖之上》《满江红》。他的视角从光影出发，审视表演如何与摄影共同完成视觉叙事。他探讨演员的身体如何在镜头前建立有效的张力，细微的情绪又如何被光影捕捉并赋予力量。他同时谨慎指出，演员的表演设计需有分寸，最理想的境界，是表演与视听语言达成“浑然一体的化学作用”，不露设计的痕迹。</p>\\n  <p><strong>终审评委：吴 刚</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_b1f5d5fa31d34664bf95425b9339be4b@5889148_oswg455313oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p>北京人民艺术剧院国家一级演员。凭借“剧抛脸”式的演技在《人民的名义》《狂飙》等作品中深入人心。他的审视深入表演的肌理，追溯演员构建角色的内在逻辑。他引导演员从对手的台词中寻找自己行为的依据，以此构建清晰可信的心理行动线。在他看来，令人信服的表演，其核心是塑造“人物关系”，任何技巧与设计，都必须服务于让一个具体、鲜活的人“立”在台上。</p>\\n  <p><strong>终审评委：俞白眉</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_d78eb991981f4b6ab7f4581ec10b221f@5889148_oswg585353oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p>导演及编剧，作品如《中国乒乓之绝地反击》《银河补习班》深谙类型叙事与大众情感连接。他的评审紧扣“故事”与“戏剧博弈”。他极度关注演员对文本潜台词的理解深度，以及能否在有限的篇幅内，通过细腻的层次变化，呈现复杂的人物心理与关系张力。他认为“松弛不是涣散”，演员必须建立宏观的剧本视野与准确的审美判断，方能使表演真正承载并推动叙事，达成与观众的高效共情。</p>\\n  <p><strong>终审评委：魏钦涛</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_c87ce56cabc04a0394c0a1f11a97f9db@5889148_oswg460546oswg1080oswg1629_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p>红果精品短剧负责人，短剧领域的深度实践者，带领“果燃计划”孵化出品百余部精品短剧。他从产业最前线带来对“竖屏语法”的敏锐洞察。他的评审，聚焦于表演在即时反馈的生态中，如何迅速建立信任、精准传递情绪，在有限的“格子”里完成有效叙事。同时，他也提醒演员警惕陷入“快餐式”的表演惯性，认为短剧表演的未来，在于向更扎实的人物塑造与戏剧张力寻求拓展。</p>\\n  <p><strong>第十六届北京国际电影节 BE SEEN 光幕计划年度面孔正式发布！</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_4d4f2a894efc4816a6a9002b3c25d975@5889148_oswg3258532oswg1080oswg3743_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p>五道来自表演、导演、制片、编剧、摄影维度的专业目光，在评审现场交汇、碰撞，乃至激烈辩论。他们共同完成的，远不止于一份名单的选拔，而是一场关于表演本质在当下如何存续的深度校准。</p>\\n  <p>山在远处，攀登便有了方向。 而今天横亘于前的，是技术的精密、算法的效率与流量的速度所垒成的新高度。而表演的长路，是一代代人的接续跋涉，每一程都需回应时代的叩问，每一次驻足都在校准前行的路标。最终浮现的25张年度面孔中的成员，将很快进入集训营，投身于经典剧场与实验剧场的实战拍摄，在真实的创作激流中，完成下一次前行的可能。</p>\\n  <p>翻越高山，不在于征服，更在于确认。确认沉重的呼吸、脚下的砂石与拂过的山风，它们本身，便是对生命最诚恳的丈量；也确认翻山越岭、满身疲惫后，一个朴素的真理依然清晰：&nbsp;无论媒介与技术如何变迁，表演最动人的，永远源于生命对生命最本真的、笨拙而诚恳的照亮。</p>\\n  <p>如此跋涉，只因深信不疑，所有诚恳的丈量，最终都将让我们摘取到那颗属于生命的果实。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_9bfae94b5a35451eb38d9319fa5c0edb@5889148_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_55e32b377d744ad68d6b6361d1d65b0c@5889148_oswg46724oswg1080oswg494_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_2c44806851184f1d90b47b0334e1e99b@5889148_oswg147862oswg1080oswg2134_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_7b3471df3b8f4ae5af5ae9e74964c67f@5889148_oswg41421oswg1080oswg870_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">&nbsp;</p>\\n  <p class=\"editor-note\">本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/fseaDTiJzXscOk2bcRk8xg\" rel=\"noopener noreferrer\" target=\"_blank\">“BE SEEN光幕计划”</a>，作者：BE&nbsp;SEEN，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-13 14:59:19', '2026-04-14 14:10:18', 0, '\"\"');
INSERT INTO `news` VALUES (406, '这届留学生，用AI看病省出一辆特斯拉', 'https://36kr.com/p/3764892434711049?f=rss', 'https://36kr.com/feed', '<h2>01. 用AI硬扛20天，省出一辆特斯拉</h2>\n  <p>回国做完四颗牙的根管治疗后，英国留学生土土盯着一万多的账单算了算，<strong>发现自己回国这一趟，竟然省下了一辆二手“特斯拉”。</strong></p>\n  <p>就在20天前，土土的牙痛又犯了，连吃饭都变成了一种酷刑。他迫切需要找点缓解的办法，但脑海里闪过之前在国外的看牙经历——</p>\n  <p>之前一次，同样是牙疼，土土挂了当地的一家私人医院的牙医号。一套检查下来，医生给出的治疗方案是根管治疗，要先磨牙、清洗，价格1900磅，还要做牙冠，1500磅，再加上4、500磅的手术费，治一颗牙至少要花4000磅，折合人民币近40000块。<strong>花了天价不说，效果也一言难尽。治完没多久，土土的牙冠就掉了，技术完全不值这个价。</strong></p>\n  <p>“这钱花得太憋屈了。”土土决定，这次回国治疗。但距离回国还有20天，怎么熬？他拿出手机，打开蚂蚁阿福问，“怎么能在不做根管的情况下，坚持一段时间到回国？”</p>\n  <p>很快，阿福给出了一套缓解方案：冷敷，盐水漱口，并辅助服用些止痛药。土土就靠着这些办法撑了20天，一放假，他就坐上航班，直奔国内的公立医院，用1万多的价格，一口气做了4颗牙的根管。</p>\n  <p>他算了笔账。<strong>如果在国外，这四颗牙至少要16000磅，“省下的这笔钱够买辆二手特斯拉的了。”土土说。</strong></p>\n  <p><strong>看病难、看病贵早就是留学生的共识了。</strong>虽然部分国家会提供免费或平价的医疗服务，但漫长的等待周期，一般只适合自愈型的小毛病。一旦遇到一些非危及生命但又极其折磨人的问题，只能加钱去私立医院，随后面临的便是海外医疗的“天价账单”。</p>\n  <p><strong>于是这种“小病靠AI缓解，大问题靠AI撑到回国治”的操作，正在成为留子圈的新型生存指南。</strong></p>\n  <p>在美国留学的霏霏，前段时间突然浑身过敏，偏偏自己又没带国内常备的氯雷他定。不知道在美国该买什么药的她，果断打开ChatGPT。像在药店问药剂师一样，连抛好几个问题，“美国能买到哪些荨麻疹或过敏药？”“哪个效果更好？”“哪个成分不容易嗜睡？”“里面具体都有什么？”</p>\n  <p>AI不仅给出详细解答，还特意叮嘱她“服药期间需要戒酒”。<strong>对照着AI给的方案，霏霏用几十刀就解决了问题。</strong></p>\n  <p>因为只打算在美国待一年，霏霏并没有购买当地高昂的医疗保险。但就算有保险，价格也不便宜。当地保单只能承担一部分费用，急诊室的病床只要躺上去就是500刀，见了医生就算什么都没诊断出来，1200刀也得照付。</p>\n  <p>一位网友在美国留学时，腿被热油烫伤起泡，等了两个小时才看到医生，只是被涂了药、包了纱布，一周后却收到了1900刀的账单。自媒体博主“逻辑医学”曾分享过美国急诊室的费用构成，包括设施费、医生费、检查和治疗费还有药品费，<strong>普通感冒急诊费500刀起，轻微割伤缝针要1000刀，重症或入院治疗则要上万美金。</strong></p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_9303d0ffb6604cbc892b9583fd83c77b@11416942_oswg41174oswg1024oswg357_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_7c85f4c311b44b13a333609f83b7f5d0@11416942_oswg67961oswg822oswg1024_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">网友收到“天价账单”，图源网络</p>\n  <p>在账单刺客面前，越来越多留学生开始熟练地把AI当成自己的私人健康顾问。</p>\n  <h2><strong>02. 这届留子的看病方法论：先问问AI</strong></h2>\n  <p>数据也证明了这一点。</p>\n  <p>土土曾在留学群里做过一个小调研，<strong>400多人的投票结果显示，近8成留学生承认用AI看过病。</strong>而大家在国外看病的难题，除了觉得价格贵，还有83.8%的留学生都是担心医生水平，怕被误诊，也有73.1%苦于预约太慢，排到号的时候病都好了。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_3c794f1542af483f8c6be645ef0cfaaa@11416942_oswg130409oswg632oswg552_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">土土的调研</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_8408135e1ebd44af84039019277f3e39@11416942_oswg97125oswg1024oswg642_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">网友吐槽国外医疗，图源网络</p>\n  <p><strong>“以前留子看病全靠命硬，现在多了一个AI。”土土总结。</strong></p>\n  <p><strong>像土土一样的“精算型留子”，主打把预算花在刀刃上。</strong>他们不是抠，是拒绝当“冤大头”。他们用AI进行成本核算和风险对冲——用AI给的方法先缓解症状，把大头预算留给国内高效且高性价比的医疗系统。</p>\n  <p>在土土的调研中，7成跟他一样用过蚂蚁阿福的留学生表示自己省下了看病钱，其中，近4成的人省下超2万元。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_d6e4ae3bf3ff43b8a9485e4003cbb10e@11416942_oswg144806oswg680oswg488_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">土土的调研</p>\n  <p><strong>而阿桢是典型的“硬扛型留子”，但在她看来，硬扛不是躺平，而是有准备、有技术含量的自救。</strong>来英国留学前，阿祯从国内背了一大堆肠胃药、感冒药，做好了“小病靠硬扛”的准备。</p>\n  <p>前些日子，她和朋友去西班牙旅游，最后一天突然感觉胃不舒服，四肢酸痛。偏偏手头没带药，不知道怎么异地买药和看病的阿祯，先在社交媒体上搜了搜，但信息乱七八糟，没一个和自己症状完全对上的。</p>\n  <p>她打开ChatGPT，把自己的情况一股脑喂进去。Chat老师追问了几轮后，初步判断是肠胃炎，建议补充电解质。阿桢照做后果然症状好转了一些，回到英国后又吃了从国内带的肠胃药，身体很快恢复。</p>\n  <p><strong>“有了AI，至少不用一个人在异国他乡瞎猜，就医焦虑少了一大半。”阿祯说。</strong></p>\n  <p><strong>同样是在英国留学的杨灿，则已经从单一的AI辅助进阶到用AI交叉验证了。</strong></p>\n  <p>前些日子，她感觉脸有些痛，在社交媒体上对照症状可能是三叉神经痛。但不敢下判断的她，问了问Deepseek，“我的左牙龈有点发炎了，左边额头上有一个大火疖子，导致我的整个左脸都有点酸酸的刺刺的胀胀的疼痛，还有耳朵也痛。”</p>\n  <p>Deepseek追问了些细节，比如症状是谁先出现的？痛是持续的还是一阵一阵的？最终分析可能是面部感染扩散。<strong>为了稳妥些，杨灿又把同样的问题抛给了蚂蚁阿福。</strong>阿福追问得更细：“现在发烧吗？火疖子是硬的还是软的？牙龈除了发炎有没有脓包？”</p>\n  <p>综合判断后，阿福给出了和Deepseek一致的建议，不要用手挤压或热敷额头上的疖子，否则容易引发颅内感染。同时，<strong>两个 AI都给出了关键提醒：一旦出现发烧、视力模糊、疖子快速变大等症状，必须立即去急诊。</strong></p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_5d0c289051a845e0a8ad1007f33fe11c@11416942_oswg227893oswg1080oswg2181_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">阿福给出的就诊建议</p>\n  <p>两边信息一交叉，杨灿心里有底了。至于如果两个AI说法打架怎么办？“那就去医院啊。”杨灿说，<strong>“AI帮我过滤掉90%的恐慌，但如果它们意见不合，那说明这事得让专业的人来。”</strong></p>\n  <p><strong>这届留学生都清楚地知道，AI的边界在哪里。</strong>就像阿桢心里也有条红线，感冒咳嗽这种“初级打怪”的症状，用自己带的药，能扛则扛；肠胃炎这种之前没处理过、但问题不大的情况，找AI问清楚。但如果严重到骨折这种，爬也得爬去医院。</p>\n  <h2><strong>03. 异国他乡的安全感</strong></h2>\n  <p><strong>把AI用得这么溜，不是留子们天生爱折腾，实在是被逼出来的。</strong></p>\n  <p>霏霏至今记得陪过敏的朋友去急诊的那天。她们足足等了8个小时才见到医生。看着朋友呼吸困难，憋的脸都红了，医生只是喂了一颗药，并表示“我知道你很难受，但请你有耐心。在你真的遇到情况的时候我们会立马救治你，但我们判断你现在情况还可以，如果实在不舒服，我们可以给你打一个抗过敏药。”</p>\n  <p><strong>“一般你去急诊，除非你已经有生命危险，否则只是胃痛或是感冒发烧了，基本都排不上的，（医生）只会让你喝凉水。”</strong>杨灿感叹，“网上有个段子，病人和耐心的英文单词都叫 patient。那一刻你才会懂，为什么大家宁愿自己想办法。”</p>\n  <p>在没有AI的年代，土土说自己的生存策略就是“小病靠硬扛，大病买机票”。生病了就吃万能药，在家躺着靠免疫靠自愈。</p>\n  <p>但现在，他会直接打开手机，输入症状，让AI帮忙进行初步的症状分析。AI不会像急诊室那样让你等8小时，也不会在高烧的时候让你来一杯“伏特加”。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_6afca04733864e4a941e9067348f459f@11416942_oswg41663oswg1024oswg349_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">网友吐槽国外医疗，图源网络</p>\n  <p>前不久，土土突发湿疹，他直接拍了张患处的照片发给蚂蚁阿福，说怀疑自己可能过敏了。阿福通过图像识别与一次次的追问，告诉土土是真菌感染。土土又顺嘴问阿福，家里有款药膏能不能直接用，阿福制止，“不行，你那个是治细菌的，你这个是真菌感染。”</p>\n  <p>“那一刻觉得特别安心”，土土说，以前身上起东西，要么瞎猜涂药膏，要么硬扛过去，现在拍张照，30秒就知道怎么回事，还能避免用错药。</p>\n  <p><strong>说到底，这届留子用AI看病，图的不仅是省钱。</strong>更是在那个凌晨三点、举目无亲、身体不适又不知该找谁的脆弱时刻，能有一个24小时在线、不收费、不排队、还能用中文告诉你“暂时没事”或者“该去医院了”的依靠。</p>\n  <p>正如杨灿说的：“AI提醒哪几种情况下必须去医院的时候，我觉得它挺靠谱的。”<strong>以前生病是硬忍，现在是先问问AI，再决定忍不忍。</strong></p>\n  <p>这种随叫随到的安全感，或许就是AI给这届留子，最值钱的定心丸。</p>\n  <p>（文中人物均为化名）</p>', '', '', '', '', '{\'title\': \'这届留学生，用AI看病省出一辆特斯拉\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'这届留学生，用AI看病省出一辆特斯拉\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3764892434711049?f=rss\'}], \'link\': \'https://36kr.com/p/3764892434711049?f=rss\', \'published\': \'2026-04-13 14:50:56  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=6, tm_min=50, tm_sec=56, tm_wday=0, tm_yday=103, tm_isdst=0), \'summary\': \'<h2>01. 用AI硬扛20天，省出一辆特斯拉</h2>\\n  <p>回国做完四颗牙的根管治疗后，英国留学生土土盯着一万多的账单算了算，<strong>发现自己回国这一趟，竟然省下了一辆二手“特斯拉”。</strong></p>\\n  <p>就在20天前，土土的牙痛又犯了，连吃饭都变成了一种酷刑。他迫切需要找点缓解的办法，但脑海里闪过之前在国外的看牙经历——</p>\\n  <p>之前一次，同样是牙疼，土土挂了当地的一家私人医院的牙医号。一套检查下来，医生给出的治疗方案是根管治疗，要先磨牙、清洗，价格1900磅，还要做牙冠，1500磅，再加上4、500磅的手术费，治一颗牙至少要花4000磅，折合人民币近40000块。<strong>花了天价不说，效果也一言难尽。治完没多久，土土的牙冠就掉了，技术完全不值这个价。</strong></p>\\n  <p>“这钱花得太憋屈了。”土土决定，这次回国治疗。但距离回国还有20天，怎么熬？他拿出手机，打开蚂蚁阿福问，“怎么能在不做根管的情况下，坚持一段时间到回国？”</p>\\n  <p>很快，阿福给出了一套缓解方案：冷敷，盐水漱口，并辅助服用些止痛药。土土就靠着这些办法撑了20天，一放假，他就坐上航班，直奔国内的公立医院，用1万多的价格，一口气做了4颗牙的根管。</p>\\n  <p>他算了笔账。<strong>如果在国外，这四颗牙至少要16000磅，“省下的这笔钱够买辆二手特斯拉的了。”土土说。</strong></p>\\n  <p><strong>看病难、看病贵早就是留学生的共识了。</strong>虽然部分国家会提供免费或平价的医疗服务，但漫长的等待周期，一般只适合自愈型的小毛病。一旦遇到一些非危及生命但又极其折磨人的问题，只能加钱去私立医院，随后面临的便是海外医疗的“天价账单”。</p>\\n  <p><strong>于是这种“小病靠AI缓解，大问题靠AI撑到回国治”的操作，正在成为留子圈的新型生存指南。</strong></p>\\n  <p>在美国留学的霏霏，前段时间突然浑身过敏，偏偏自己又没带国内常备的氯雷他定。不知道在美国该买什么药的她，果断打开ChatGPT。像在药店问药剂师一样，连抛好几个问题，“美国能买到哪些荨麻疹或过敏药？”“哪个效果更好？”“哪个成分不容易嗜睡？”“里面具体都有什么？”</p>\\n  <p>AI不仅给出详细解答，还特意叮嘱她“服药期间需要戒酒”。<strong>对照着AI给的方案，霏霏用几十刀就解决了问题。</strong></p>\\n  <p>因为只打算在美国待一年，霏霏并没有购买当地高昂的医疗保险。但就算有保险，价格也不便宜。当地保单只能承担一部分费用，急诊室的病床只要躺上去就是500刀，见了医生就算什么都没诊断出来，1200刀也得照付。</p>\\n  <p>一位网友在美国留学时，腿被热油烫伤起泡，等了两个小时才看到医生，只是被涂了药、包了纱布，一周后却收到了1900刀的账单。自媒体博主“逻辑医学”曾分享过美国急诊室的费用构成，包括设施费、医生费、检查和治疗费还有药品费，<strong>普通感冒急诊费500刀起，轻微割伤缝针要1000刀，重症或入院治疗则要上万美金。</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_9303d0ffb6604cbc892b9583fd83c77b@11416942_oswg41174oswg1024oswg357_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_7c85f4c311b44b13a333609f83b7f5d0@11416942_oswg67961oswg822oswg1024_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">网友收到“天价账单”，图源网络</p>\\n  <p>在账单刺客面前，越来越多留学生开始熟练地把AI当成自己的私人健康顾问。</p>\\n  <h2><strong>02. 这届留子的看病方法论：先问问AI</strong></h2>\\n  <p>数据也证明了这一点。</p>\\n  <p>土土曾在留学群里做过一个小调研，<strong>400多人的投票结果显示，近8成留学生承认用AI看过病。</strong>而大家在国外看病的难题，除了觉得价格贵，还有83.8%的留学生都是担心医生水平，怕被误诊，也有73.1%苦于预约太慢，排到号的时候病都好了。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_3c794f1542af483f8c6be645ef0cfaaa@11416942_oswg130409oswg632oswg552_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">土土的调研</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_8408135e1ebd44af84039019277f3e39@11416942_oswg97125oswg1024oswg642_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">网友吐槽国外医疗，图源网络</p>\\n  <p><strong>“以前留子看病全靠命硬，现在多了一个AI。”土土总结。</strong></p>\\n  <p><strong>像土土一样的“精算型留子”，主打把预算花在刀刃上。</strong>他们不是抠，是拒绝当“冤大头”。他们用AI进行成本核算和风险对冲——用AI给的方法先缓解症状，把大头预算留给国内高效且高性价比的医疗系统。</p>\\n  <p>在土土的调研中，7成跟他一样用过蚂蚁阿福的留学生表示自己省下了看病钱，其中，近4成的人省下超2万元。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_d6e4ae3bf3ff43b8a9485e4003cbb10e@11416942_oswg144806oswg680oswg488_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">土土的调研</p>\\n  <p><strong>而阿桢是典型的“硬扛型留子”，但在她看来，硬扛不是躺平，而是有准备、有技术含量的自救。</strong>来英国留学前，阿祯从国内背了一大堆肠胃药、感冒药，做好了“小病靠硬扛”的准备。</p>\\n  <p>前些日子，她和朋友去西班牙旅游，最后一天突然感觉胃不舒服，四肢酸痛。偏偏手头没带药，不知道怎么异地买药和看病的阿祯，先在社交媒体上搜了搜，但信息乱七八糟，没一个和自己症状完全对上的。</p>\\n  <p>她打开ChatGPT，把自己的情况一股脑喂进去。Chat老师追问了几轮后，初步判断是肠胃炎，建议补充电解质。阿桢照做后果然症状好转了一些，回到英国后又吃了从国内带的肠胃药，身体很快恢复。</p>\\n  <p><strong>“有了AI，至少不用一个人在异国他乡瞎猜，就医焦虑少了一大半。”阿祯说。</strong></p>\\n  <p><strong>同样是在英国留学的杨灿，则已经从单一的AI辅助进阶到用AI交叉验证了。</strong></p>\\n  <p>前些日子，她感觉脸有些痛，在社交媒体上对照症状可能是三叉神经痛。但不敢下判断的她，问了问Deepseek，“我的左牙龈有点发炎了，左边额头上有一个大火疖子，导致我的整个左脸都有点酸酸的刺刺的胀胀的疼痛，还有耳朵也痛。”</p>\\n  <p>Deepseek追问了些细节，比如症状是谁先出现的？痛是持续的还是一阵一阵的？最终分析可能是面部感染扩散。<strong>为了稳妥些，杨灿又把同样的问题抛给了蚂蚁阿福。</strong>阿福追问得更细：“现在发烧吗？火疖子是硬的还是软的？牙龈除了发炎有没有脓包？”</p>\\n  <p>综合判断后，阿福给出了和Deepseek一致的建议，不要用手挤压或热敷额头上的疖子，否则容易引发颅内感染。同时，<strong>两个 AI都给出了关键提醒：一旦出现发烧、视力模糊、疖子快速变大等症状，必须立即去急诊。</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_5d0c289051a845e0a8ad1007f33fe11c@11416942_oswg227893oswg1080oswg2181_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">阿福给出的就诊建议</p>\\n  <p>两边信息一交叉，杨灿心里有底了。至于如果两个AI说法打架怎么办？“那就去医院啊。”杨灿说，<strong>“AI帮我过滤掉90%的恐慌，但如果它们意见不合，那说明这事得让专业的人来。”</strong></p>\\n  <p><strong>这届留学生都清楚地知道，AI的边界在哪里。</strong>就像阿桢心里也有条红线，感冒咳嗽这种“初级打怪”的症状，用自己带的药，能扛则扛；肠胃炎这种之前没处理过、但问题不大的情况，找AI问清楚。但如果严重到骨折这种，爬也得爬去医院。</p>\\n  <h2><strong>03. 异国他乡的安全感</strong></h2>\\n  <p><strong>把AI用得这么溜，不是留子们天生爱折腾，实在是被逼出来的。</strong></p>\\n  <p>霏霏至今记得陪过敏的朋友去急诊的那天。她们足足等了8个小时才见到医生。看着朋友呼吸困难，憋的脸都红了，医生只是喂了一颗药，并表示“我知道你很难受，但请你有耐心。在你真的遇到情况的时候我们会立马救治你，但我们判断你现在情况还可以，如果实在不舒服，我们可以给你打一个抗过敏药。”</p>\\n  <p><strong>“一般你去急诊，除非你已经有生命危险，否则只是胃痛或是感冒发烧了，基本都排不上的，（医生）只会让你喝凉水。”</strong>杨灿感叹，“网上有个段子，病人和耐心的英文单词都叫 patient。那一刻你才会懂，为什么大家宁愿自己想办法。”</p>\\n  <p>在没有AI的年代，土土说自己的生存策略就是“小病靠硬扛，大病买机票”。生病了就吃万能药，在家躺着靠免疫靠自愈。</p>\\n  <p>但现在，他会直接打开手机，输入症状，让AI帮忙进行初步的症状分析。AI不会像急诊室那样让你等8小时，也不会在高烧的时候让你来一杯“伏特加”。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_6afca04733864e4a941e9067348f459f@11416942_oswg41663oswg1024oswg349_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">网友吐槽国外医疗，图源网络</p>\\n  <p>前不久，土土突发湿疹，他直接拍了张患处的照片发给蚂蚁阿福，说怀疑自己可能过敏了。阿福通过图像识别与一次次的追问，告诉土土是真菌感染。土土又顺嘴问阿福，家里有款药膏能不能直接用，阿福制止，“不行，你那个是治细菌的，你这个是真菌感染。”</p>\\n  <p>“那一刻觉得特别安心”，土土说，以前身上起东西，要么瞎猜涂药膏，要么硬扛过去，现在拍张照，30秒就知道怎么回事，还能避免用错药。</p>\\n  <p><strong>说到底，这届留子用AI看病，图的不仅是省钱。</strong>更是在那个凌晨三点、举目无亲、身体不适又不知该找谁的脆弱时刻，能有一个24小时在线、不收费、不排队、还能用中文告诉你“暂时没事”或者“该去医院了”的依靠。</p>\\n  <p>正如杨灿说的：“AI提醒哪几种情况下必须去医院的时候，我觉得它挺靠谱的。”<strong>以前生病是硬忍，现在是先问问AI，再决定忍不忍。</strong></p>\\n  <p>这种随叫随到的安全感，或许就是AI给这届留子，最值钱的定心丸。</p>\\n  <p>（文中人物均为化名）</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'<h2>01. 用AI硬扛20天，省出一辆特斯拉</h2>\\n  <p>回国做完四颗牙的根管治疗后，英国留学生土土盯着一万多的账单算了算，<strong>发现自己回国这一趟，竟然省下了一辆二手“特斯拉”。</strong></p>\\n  <p>就在20天前，土土的牙痛又犯了，连吃饭都变成了一种酷刑。他迫切需要找点缓解的办法，但脑海里闪过之前在国外的看牙经历——</p>\\n  <p>之前一次，同样是牙疼，土土挂了当地的一家私人医院的牙医号。一套检查下来，医生给出的治疗方案是根管治疗，要先磨牙、清洗，价格1900磅，还要做牙冠，1500磅，再加上4、500磅的手术费，治一颗牙至少要花4000磅，折合人民币近40000块。<strong>花了天价不说，效果也一言难尽。治完没多久，土土的牙冠就掉了，技术完全不值这个价。</strong></p>\\n  <p>“这钱花得太憋屈了。”土土决定，这次回国治疗。但距离回国还有20天，怎么熬？他拿出手机，打开蚂蚁阿福问，“怎么能在不做根管的情况下，坚持一段时间到回国？”</p>\\n  <p>很快，阿福给出了一套缓解方案：冷敷，盐水漱口，并辅助服用些止痛药。土土就靠着这些办法撑了20天，一放假，他就坐上航班，直奔国内的公立医院，用1万多的价格，一口气做了4颗牙的根管。</p>\\n  <p>他算了笔账。<strong>如果在国外，这四颗牙至少要16000磅，“省下的这笔钱够买辆二手特斯拉的了。”土土说。</strong></p>\\n  <p><strong>看病难、看病贵早就是留学生的共识了。</strong>虽然部分国家会提供免费或平价的医疗服务，但漫长的等待周期，一般只适合自愈型的小毛病。一旦遇到一些非危及生命但又极其折磨人的问题，只能加钱去私立医院，随后面临的便是海外医疗的“天价账单”。</p>\\n  <p><strong>于是这种“小病靠AI缓解，大问题靠AI撑到回国治”的操作，正在成为留子圈的新型生存指南。</strong></p>\\n  <p>在美国留学的霏霏，前段时间突然浑身过敏，偏偏自己又没带国内常备的氯雷他定。不知道在美国该买什么药的她，果断打开ChatGPT。像在药店问药剂师一样，连抛好几个问题，“美国能买到哪些荨麻疹或过敏药？”“哪个效果更好？”“哪个成分不容易嗜睡？”“里面具体都有什么？”</p>\\n  <p>AI不仅给出详细解答，还特意叮嘱她“服药期间需要戒酒”。<strong>对照着AI给的方案，霏霏用几十刀就解决了问题。</strong></p>\\n  <p>因为只打算在美国待一年，霏霏并没有购买当地高昂的医疗保险。但就算有保险，价格也不便宜。当地保单只能承担一部分费用，急诊室的病床只要躺上去就是500刀，见了医生就算什么都没诊断出来，1200刀也得照付。</p>\\n  <p>一位网友在美国留学时，腿被热油烫伤起泡，等了两个小时才看到医生，只是被涂了药、包了纱布，一周后却收到了1900刀的账单。自媒体博主“逻辑医学”曾分享过美国急诊室的费用构成，包括设施费、医生费、检查和治疗费还有药品费，<strong>普通感冒急诊费500刀起，轻微割伤缝针要1000刀，重症或入院治疗则要上万美金。</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_9303d0ffb6604cbc892b9583fd83c77b@11416942_oswg41174oswg1024oswg357_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_7c85f4c311b44b13a333609f83b7f5d0@11416942_oswg67961oswg822oswg1024_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">网友收到“天价账单”，图源网络</p>\\n  <p>在账单刺客面前，越来越多留学生开始熟练地把AI当成自己的私人健康顾问。</p>\\n  <h2><strong>02. 这届留子的看病方法论：先问问AI</strong></h2>\\n  <p>数据也证明了这一点。</p>\\n  <p>土土曾在留学群里做过一个小调研，<strong>400多人的投票结果显示，近8成留学生承认用AI看过病。</strong>而大家在国外看病的难题，除了觉得价格贵，还有83.8%的留学生都是担心医生水平，怕被误诊，也有73.1%苦于预约太慢，排到号的时候病都好了。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_3c794f1542af483f8c6be645ef0cfaaa@11416942_oswg130409oswg632oswg552_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">土土的调研</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_8408135e1ebd44af84039019277f3e39@11416942_oswg97125oswg1024oswg642_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">网友吐槽国外医疗，图源网络</p>\\n  <p><strong>“以前留子看病全靠命硬，现在多了一个AI。”土土总结。</strong></p>\\n  <p><strong>像土土一样的“精算型留子”，主打把预算花在刀刃上。</strong>他们不是抠，是拒绝当“冤大头”。他们用AI进行成本核算和风险对冲——用AI给的方法先缓解症状，把大头预算留给国内高效且高性价比的医疗系统。</p>\\n  <p>在土土的调研中，7成跟他一样用过蚂蚁阿福的留学生表示自己省下了看病钱，其中，近4成的人省下超2万元。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_d6e4ae3bf3ff43b8a9485e4003cbb10e@11416942_oswg144806oswg680oswg488_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">土土的调研</p>\\n  <p><strong>而阿桢是典型的“硬扛型留子”，但在她看来，硬扛不是躺平，而是有准备、有技术含量的自救。</strong>来英国留学前，阿祯从国内背了一大堆肠胃药、感冒药，做好了“小病靠硬扛”的准备。</p>\\n  <p>前些日子，她和朋友去西班牙旅游，最后一天突然感觉胃不舒服，四肢酸痛。偏偏手头没带药，不知道怎么异地买药和看病的阿祯，先在社交媒体上搜了搜，但信息乱七八糟，没一个和自己症状完全对上的。</p>\\n  <p>她打开ChatGPT，把自己的情况一股脑喂进去。Chat老师追问了几轮后，初步判断是肠胃炎，建议补充电解质。阿桢照做后果然症状好转了一些，回到英国后又吃了从国内带的肠胃药，身体很快恢复。</p>\\n  <p><strong>“有了AI，至少不用一个人在异国他乡瞎猜，就医焦虑少了一大半。”阿祯说。</strong></p>\\n  <p><strong>同样是在英国留学的杨灿，则已经从单一的AI辅助进阶到用AI交叉验证了。</strong></p>\\n  <p>前些日子，她感觉脸有些痛，在社交媒体上对照症状可能是三叉神经痛。但不敢下判断的她，问了问Deepseek，“我的左牙龈有点发炎了，左边额头上有一个大火疖子，导致我的整个左脸都有点酸酸的刺刺的胀胀的疼痛，还有耳朵也痛。”</p>\\n  <p>Deepseek追问了些细节，比如症状是谁先出现的？痛是持续的还是一阵一阵的？最终分析可能是面部感染扩散。<strong>为了稳妥些，杨灿又把同样的问题抛给了蚂蚁阿福。</strong>阿福追问得更细：“现在发烧吗？火疖子是硬的还是软的？牙龈除了发炎有没有脓包？”</p>\\n  <p>综合判断后，阿福给出了和Deepseek一致的建议，不要用手挤压或热敷额头上的疖子，否则容易引发颅内感染。同时，<strong>两个 AI都给出了关键提醒：一旦出现发烧、视力模糊、疖子快速变大等症状，必须立即去急诊。</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_5d0c289051a845e0a8ad1007f33fe11c@11416942_oswg227893oswg1080oswg2181_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">阿福给出的就诊建议</p>\\n  <p>两边信息一交叉，杨灿心里有底了。至于如果两个AI说法打架怎么办？“那就去医院啊。”杨灿说，<strong>“AI帮我过滤掉90%的恐慌，但如果它们意见不合，那说明这事得让专业的人来。”</strong></p>\\n  <p><strong>这届留学生都清楚地知道，AI的边界在哪里。</strong>就像阿桢心里也有条红线，感冒咳嗽这种“初级打怪”的症状，用自己带的药，能扛则扛；肠胃炎这种之前没处理过、但问题不大的情况，找AI问清楚。但如果严重到骨折这种，爬也得爬去医院。</p>\\n  <h2><strong>03. 异国他乡的安全感</strong></h2>\\n  <p><strong>把AI用得这么溜，不是留子们天生爱折腾，实在是被逼出来的。</strong></p>\\n  <p>霏霏至今记得陪过敏的朋友去急诊的那天。她们足足等了8个小时才见到医生。看着朋友呼吸困难，憋的脸都红了，医生只是喂了一颗药，并表示“我知道你很难受，但请你有耐心。在你真的遇到情况的时候我们会立马救治你，但我们判断你现在情况还可以，如果实在不舒服，我们可以给你打一个抗过敏药。”</p>\\n  <p><strong>“一般你去急诊，除非你已经有生命危险，否则只是胃痛或是感冒发烧了，基本都排不上的，（医生）只会让你喝凉水。”</strong>杨灿感叹，“网上有个段子，病人和耐心的英文单词都叫 patient。那一刻你才会懂，为什么大家宁愿自己想办法。”</p>\\n  <p>在没有AI的年代，土土说自己的生存策略就是“小病靠硬扛，大病买机票”。生病了就吃万能药，在家躺着靠免疫靠自愈。</p>\\n  <p>但现在，他会直接打开手机，输入症状，让AI帮忙进行初步的症状分析。AI不会像急诊室那样让你等8小时，也不会在高烧的时候让你来一杯“伏特加”。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_6afca04733864e4a941e9067348f459f@11416942_oswg41663oswg1024oswg349_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">网友吐槽国外医疗，图源网络</p>\\n  <p>前不久，土土突发湿疹，他直接拍了张患处的照片发给蚂蚁阿福，说怀疑自己可能过敏了。阿福通过图像识别与一次次的追问，告诉土土是真菌感染。土土又顺嘴问阿福，家里有款药膏能不能直接用，阿福制止，“不行，你那个是治细菌的，你这个是真菌感染。”</p>\\n  <p>“那一刻觉得特别安心”，土土说，以前身上起东西，要么瞎猜涂药膏，要么硬扛过去，现在拍张照，30秒就知道怎么回事，还能避免用错药。</p>\\n  <p><strong>说到底，这届留子用AI看病，图的不仅是省钱。</strong>更是在那个凌晨三点、举目无亲、身体不适又不知该找谁的脆弱时刻，能有一个24小时在线、不收费、不排队、还能用中文告诉你“暂时没事”或者“该去医院了”的依靠。</p>\\n  <p>正如杨灿说的：“AI提醒哪几种情况下必须去医院的时候，我觉得它挺靠谱的。”<strong>以前生病是硬忍，现在是先问问AI，再决定忍不忍。</strong></p>\\n  <p>这种随叫随到的安全感，或许就是AI给这届留子，最值钱的定心丸。</p>\\n  <p>（文中人物均为化名）</p>\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-13 14:50:56', '2026-04-14 14:10:20', 0, '\"\"');
INSERT INTO `news` VALUES (407, '缔结条约管理办法', 'http://www.gov.cn/zhengce/content/2022-11/07/content_5725135.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'缔结条约管理办法\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'缔结条约管理办法\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-11/07/content_5725135.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-11/07/content_5725135.htm\', \'published\': \'Sun, 31 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=31, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=6, tm_yday=304, tm_isdst=0)}', '2021-10-31 16:00:00', '2026-04-14 14:10:46', 0, '\"\"');
INSERT INTO `news` VALUES (408, '国务院办公厅关于复制推广营商环境创新试点改革举措的通知', 'http://www.gov.cn/zhengce/content/2022-10/31/content_5722748.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院办公厅关于复制推广营商环境创新试点改革举措的通知\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院办公厅关于复制推广营商环境创新试点改革举措的通知\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-10/31/content_5722748.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-10/31/content_5722748.htm\', \'published\': \'Sat, 30 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=30, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=5, tm_yday=303, tm_isdst=0)}', '2021-10-30 16:00:00', '2026-04-14 14:10:56', 0, '\"\"');
INSERT INTO `news` VALUES (409, '国务院办公厅关于印发全国一体化政务大数据体系建设指南的通知', 'http://www.gov.cn/zhengce/content/2022-10/28/content_5722322.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院办公厅关于印发全国一体化政务大数据体系建设指南的通知\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院办公厅关于印发全国一体化政务大数据体系建设指南的通知\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-10/28/content_5722322.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-10/28/content_5722322.htm\', \'published\': \'Sat, 30 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=30, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=5, tm_yday=303, tm_isdst=0)}', '2021-10-30 16:00:00', '2026-04-14 14:11:01', 0, '\"\"');
INSERT INTO `news` VALUES (410, '对话雅诗兰黛集团总裁兼CEO司泰峰：让一家公司变得更敏捷，这是他的第一年｜New Look专访', 'https://36kr.com/p/3756542711120640?f=rss', 'https://36kr.com/feed', '<p>文｜贺哲馨</p>\n  <p>编辑｜乔芊</p>\n  <p>从外表看，司泰峰（Stéphane de La Faverie）并不是那类锋芒毕露的“改革派”。</p>\n  <p>他多数时候带着温和的笑意，步伐与语速都偏慢——或许带着一点法国人特有的松弛感。你也很难想象，在成为父亲之前，司泰峰是“狂热的风帆冲浪和跳伞爱好者”。</p>\n  <p>当下消费环境的惊险程度可能不亚于任何冒险运动。但在日前与36氪的专访中，司泰峰展现出一种从容：<strong>“我们是一家80年历史的公司，30多年前就进入中国市场，波动对我们来说不是什么新鲜事，我们的应对思路始终是一个——尽可能贴近消费者。</strong>”</p>\n  <p>“而且你知道吗，”他接着说，“雅诗兰黛是第一个用中国人作为广告模特的外国美妆品牌。”这句话透露的言外之意是——在市场直觉和动作上，这家公司一向走在前面。</p>\n  <p>司泰峰所有履历都与美妆有关，在2011年加入雅诗兰黛集团之后，从品牌总经理一路做到全球执行总裁。2025年1月，他接替傅懿德 (Fabrizio Freda），正式成为雅诗兰黛集团总裁兼首席执行官。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260407/v2_0bd034e2772445e191dc2e4028064a1d@5922386_oswg631199oswg2232oswg1388_img_png?x-oss-process=image/quality,q_90/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">雅诗兰黛集团总裁兼首席执行官司泰峰</p>\n  <p>这份新职位几乎没有过渡期。上任仅一个月，司泰峰就提出了一项重大改革：<strong>雅诗兰黛集团将区域数量整合为四个，以及将损益表的责任从全球品牌部门下放到各个地区。</strong></p>\n  <p>这一改革让公司的日常运营变得更“精干和快速”，也能最大程度发挥品牌组合在不同地区的优势。而在此之前，雅诗兰黛集团的模式是一个“品牌部门决定全球销售”，对区域市场的灵活响应有所制约。</p>\n  <p>在司泰峰上任之前，这家集团几乎是传统家族企业的经典样本——拥有许多流传至今的经典产品，也有经过反复验证的成功路径，但一切都中规中矩。“我们相比拉新更擅长留存，”连司泰峰本人也承认，“但如今的消费者需要看到更多新事物。”</p>\n  <p>他在上任之初承诺一年内将公司推向市场的新品数量增加两倍，最终将创新产品的占比“从10%提升到30%”，如今这一比例增加到了19%。去年上市的雅诗兰黛冻龄白金蕴能黑钻赋活精华油，成为他经常引用的例子，<strong>“我们中国的研发团队仅仅用了15个月就将其从概念变成了产品，这是一个从公司和行业角度都非常罕见的速度。”</strong></p>\n  <p>与产品节奏同步变化的，是渠道结构。2024年，雅诗兰黛品牌首次登陆Amazon官网，此后一年内，集团已有超过10个品牌入驻这一平台。与此同时，美国百货渠道的占比下降至约30%，这一数字已经低于不少同行。线上渠道的权重被系统性抬升，并进一步延伸至Shopify和TikTok Shop等新兴电商生态，尤其是后者，在北美市场展现出极高的增长率，被视为美容市场下一阶段的重要变量。</p>\n  <p>敏捷、创新以及以消费者为中心，可以最精简地概括司泰峰上任以来推进的一系列变革。这三个词背后，指向的是一套系统性的逻辑重构：<strong>从品牌驱动转向市场驱动，从全球指令转向区域决策，从守护经典转向主动创造。</strong></p>\n  <p>自2026财年开始，雅诗兰黛集团对中国大陆市场业绩进行单独披露。Q2中国大陆市场净销售额达9.28亿美元，同比增长13%，增速在集团四大区域市场中位居第一，对集团的营收贡献占比超过20%。</p>\n  <p>速度更快、电商环境更完善的中国大陆市场，也理所应当成了全新运营体系的前线实验场。</p>\n  <p>3月26日，位于上海闵行的雅诗兰黛中国供应链智能运营中心正式启用。活动现场，一架无人机悬吊着一件缎带装饰的纸箱落在观礼台旁，象征着第一件由该中心打包的包裹。</p>\n  <p>过去企业在接到订单后，需先拣货打包包裹，快递公司揽收后集中转运至其中转场按目的地或者线路分拨。如今，该中心将订单履约与快递包裹分拨两大环节打通，订单再完成分拣打包包裹后直接目的地或者线路发运，提升了整体流转效率，消费者可以更快收到所购产品。</p>\n  <p>对于正在经历调整期的雅诗兰黛集团来说，这类基础设施的变化未必显眼，却直接关系到效率、成本以及对市场变化的反应速度。</p>\n  <p><strong>“我可以在飞行的同时修理飞机，”司泰峰曾如此形容这份工作，“以当今消费者变化的速度，你必须能够承担一定的风险，而这正是我试图教给这家公司的。”</strong></p>\n  <p>以下是36氪与司泰峰的专访内容，在保留原意的基础上经过删减。</p>\n  <h3>谈转型：一次结构性的变革</h3>\n  <p><strong>36氪：你担任雅诗兰黛集团总裁兼首席执行官已经满一年了，你会如何总结过去一年的工作？</strong></p>\n  <p>司泰峰：在我一年前出任CEO时，我就意识到要在当下的高端美妆行业中保持竞争力，我们必须更快行动，并以更差异化的方式运营。行业正在变化——消费者连接更紧密，市场节奏明显加快，我们也必须随之调整。</p>\n  <p>我的首要任务，是在集团长期积累的基础上，优化工作方式、重新聚焦消费者，同时搭建一套支撑下一阶段增长的运营体系。</p>\n  <p>基于这一思考，我们提出了“Beauty Reimagined（重塑美妆新境）”，希望让公司回到可持续增长轨道，并真正把“以消费者为中心”落到实处。这一战略围绕五个重点展开：扩大消费者覆盖、推动创新、加大消费者投入、实现可持续增长，以及重塑工作方式。</p>\n  <p>经过一年的推进，无论在工作方式、创新能力还是业绩表现上，我们都已经看到一些积极变化。当然，这仍在过程中，转型不会一蹴而就。</p>\n  <p><strong>36氪：雅诗兰黛集团的业绩2026财年恢复增长，背后发生了什么？</strong></p>\n  <p>司泰峰：我们在本财年上半年就已经回到正轨了——第一季度增长了3%，第二季度增长了4%。这次恢复增长其实是一次非常深层的、结构性的变革，我把它定义为公司历史上规模最大的一次运营与领导力转型。</p>\n  <p>一是我们让组织架构变得更精简了，过去一年做了很多领导层的调整，这些都在我们\'重塑美妆新境\'（Beauty Reimagined）这个大战略框架下推进的。二是我们给公司每一个人都讲清楚了：我们要做什么样的公司——做全球最好的、以消费者为中心的美妆企业。</p>\n  <p>我们还做了一个很重要的调整——把盈亏责任从品牌层面放到了区域层面。这样一来，哪个市场有增长机会，我们就能更快去抓住它。中国就是一个很好的例子。过去这一年，我们看到中国明显在复苏，美妆行业势头很好，中国团队也能更快地做出反应。</p>\n  <p><strong>36氪：PRGP（Profit Recovery and Growth Plan）包含了很多削减成本的内容，可以说削减成本也是复苏关键原因吗？</strong></p>\n  <p>司泰峰：PRGP不是简单的成本削减。核心是让组织变得更精简、更灵活，从而把更多的钱和精力用在直接面向消费者的地方。这是我们能够加速的一个重要原因——在恢复盈利的同时，我们加大了对消费者的投入。</p>\n  <p>我们还在推一个东西，我叫它\'一个运营模式\'（one operating model）——一个团队，一种文化，一套做法。同时我们和全球很多合作伙伴建立了深度合作，比如Shopify、埃森哲、谷歌等等，这些都帮助我们更敏捷、更快速，把更多精力放在创意和创新上——最终，就是推动增长、恢复盈利。</p>\n  <p>具体说到中国——从宏观层面，我们看到了明显的加速复苏。上一个自然年最后一个季度，我们在中国增长了13%，而且已经连续两个季度在提升市场份额。</p>\n  <h3>谈中国：在‘第二主场’，敏捷是关键词</h3>\n  <p><strong>36氪： 你说过\"中国消费者信心仍然低迷\"，但同期中国业务又实现了双位数增长——怎么理解这个矛盾？</strong></p>\n  <p>司泰峰：我们确实看到中国消费者信心在逐步改善。同时，我们的表现优于高端美妆行业整体。<strong>增长主要来自几个方面：一是持续推出符合消费者需求的创新产品；二是更精准地触达目标人群；三是加大面向消费者的投入，从而带动新客获取。</strong></p>\n  <p>品牌层面，从护肤品类的海蓝之谜和雅诗兰黛，到香水品类的汤姆福特和勒莱柏，增长都与产品创新密切相关。本土创新能力正在成为重要优势。中国研发团队能够更快响应本地需求，加速产品落地，实现全球品牌与本地市场的结合。</p>\n  <p>在运营端，我们的中国供应链智能运营中心已经投入使用，提升了整体响应能力，包括更快的配送、更丰富的产品选择以及更高的服务标准。在渠道方面，我们持续加码天猫、抖音等高增长平台，同时优化线下零售体验。在中国，全渠道能力至关重要。</p>\n  <p>总体来看，我们通过品牌建设、创新和高效执行，把握关键节点，实现了业绩与市场份额的同步提升。</p>\n  <p><strong>36氪：能否为我们简单介绍一下这一智能运营中心，它的最终目的是什么？</strong></p>\n  <p>司泰峰：这个中心的核心目标就是做全渠道配送。我们在上海做了很大的投资，也做出了很明确的承诺。我们要确保我们能跟上中国消费者的需求——他们要更快的速度、更多的产品选择，以及完美无缺的配送体验。</p>\n  <p>这背后有AI技术的支撑，让我们可以在中心内部不断改进。还有一点我很自豪的——这里是24小时不停运转的，我们叫它\'黑灯工厂\'，可以全天候直接向消费者发货，日处理量的最高峰可以超过40万单。这意味着不管消费者在哪里，我们都能快速响应他们的需求。</p>\n  <p>你可以把这个中心想象成我们整个中国履约网络的\'大脑\'——它让我们的运营更精准、更可靠，也为我们在中国未来的增长打下了坚实的基础。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260407/v2_b50385c51bf0457d95d7ccccd4a7bd34@5922386_oswg11042039oswg5345oswg3007_img_jpg?x-oss-process=image/quality,q_80/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">雅诗兰黛中国供应链智能运营中心</p>\n  <p><strong>36氪：我想多聊一聊\'敏捷性\'这个话题。您提到有款新品——雅诗兰黛冻龄白金蕴能黑钻赋活精华油——从研发到上市只用了15个月，放在整个行业里15个月算快吗？</strong></p>\n  <p>司泰峰：是的，15个月在整个行业里都是很快的速度。因为从洞察到创意，再到产品开发，就在附近的中国创新研发中心，最后还要通过这样的智能运营中心把它铺到市场上——整条链路走下来，每一步都要走。</p>\n  <p>但有一点是我们整个过程中绝对不妥协的——品质。品质，是我们做所有事情的核心。我们可以加快流程，但绝对不能以牺牲产品品质和消费者体验来换。</p>\n  <p><strong>36氪：市场反馈怎么样？有没有达到你们的预期？</strong></p>\n  <p>司泰峰：我们非常满意。创新产品在很大程度上推动了众多品牌的增速——上一季度实现了两位数的增长，市场份额也在持续提升。但我要说，创新不只是产品创新，流程本身也在创新。</p>\n  <p>比如，我们是上海市闵行区首批入选大企业开放创新中心的企业之一，这个模式就是把我们集团内部的资源跟外部优质人才结合起来，实现“1+1=3”，为中国市场创造更好的创新。</p>\n  <p>今天这个智能运营中心本身也是一种创新——它用全新的方式，以更快的速度、更高的精准性，把产品送到全国每一位消费者手里。对于我们来说，创新从产品开始，但不止于产品——供应链、分销网络、制造能力，方方面面都在创新。</p>\n  <p><strong>36氪：听说你们一年内上新产品占比已经从10%升到了19%，目标是到30%。</strong></p>\n  <p>司泰峰：我可以告诉你的是我们一直在赶上市场的速度。尤其在中国市场，每次来中国，我最有感触的就是这里的速度——这个市场的速度，以及消费者对速度的期待，真的让我印象太深了。</p>\n  <p>我们也从中国学到了很多：怎么打破部门壁垒，怎么把一个来自中国的洞察，快速转化成一款产品。而且这不只是“在中国，为中国”，更是“在中国，为世界”——把中国的速度和效率，以及我们品牌的情感与品质传承，一起带给全球消费者。</p>\n  <p><strong>36氪：你判断中国市场目前的增长机会在哪里，是大众化的平价产品还是高端产品？护肤、彩妆、香水和护发中，哪个品类更具潜力？香水业务虽然增长强劲，但可持续性如何？</strong></p>\n  <p>司泰峰：性价比趋势确实在加强，但高端美妆的长期潜力依然显著。我们的品牌组合主要在高端和奢华区间，这仍然是我们的优势所在。</p>\n  <p>具体来说，护肤毫无疑问是最核心的，中国消费者在护肤上已经是全球最懂行的群体之一。彩妆有韧性，香水在奢华区间增速很快，护发也在冒头。最新一季财报，我们在中国高端美妆市场四个品类都实现了份额增长——海蓝之谜、汤姆福特、勒莱柏表现都很突出。</p>\n  <p>奢华香水的增速明显，但我们不会押注单一的品类——消费者偏好变化迅速，我们多元化的品牌组合本身就是为了应对市场变化而存在的。</p>\n  <h3>谈未来：在更大的不确定性里下注</h3>\n  <p><strong>36氪：日上的停运、北京上海机场零售商交接——这在Q2财报里是一个\"过渡期扰动\"。但从更长远的角度看，中国旅游零售渠道的洗牌，对你们来说是威胁还是机会？</strong></p>\n  <p>司泰峰：中国旅游零售市场正在经历结构性变化，这是一个逐步走向成熟的渠道的自然过程。我们正与合作伙伴紧密协作，确保平稳过渡，并为下一阶段做好准备。</p>\n  <p>从更长期来看，我们将其视为重要机会。旅游零售不仅是销售渠道，更是建立品牌、吸引新客以及提供差异化体验的重要平台。我们的策略是高度定制化，而不是统一模式。我们会根据本地需求，与合作伙伴共同制定更合适的方案，这在中国尤为重要，因为消费者变化非常快。</p>\n  <p>中国市场始终是我们的核心战略重点，旅游零售也是其中的重要组成部分。总体而言，我们对中国旅游零售的长期增长和高端化趋势保持信心，也期待与合作伙伴共同推动其下一阶段的发展。</p>\n  <p><strong>36氪：今天全球地缘政治的不确定性会不会改变你对中国市场的判断？</strong></p>\n  <p>司泰峰：首先，我们是一家已经走过80年的公司，在中国也有30多年的历史。这些年，起起伏伏我们见得多了，我们知道怎么去驾驭市场的波动。但有一点是不变的——我们对中国的承诺是绝对不动摇的。我们相信中国市场的长期潜力，我们知道中国消费者喜爱我们的品牌——这是30多年一点一点积累下来的。我们有很好的品牌矩阵，我们会继续在中国认真做下去。</p>\n  <p>面对外部的波动，我们的应对思路始终是一个——尽可能贴近消费者。这就是为什么我们2022年12月在上海建了中国创新研发中心，今天有这个中国供应链智能运营中心的开幕，外面有很多不确定性，但我们整个网络的韧性，就在于我们始终离消费者很近。</p>\n  <p><strong>36氪：集团目标是要把美国工厂生产的产品在中国市场的占比降到10%，雅诗兰黛集团还会如何进一步降低地区性依赖度？</strong></p>\n  <p>司泰峰：我们是一家全球的美妆企业，我们非常注重全球业务的均衡发展。我把集团划分成了四大区域——中国直接向我汇报，这本身就说明了中国在我们战略里的分量。</p>\n  <p>其他三个区域是美洲、欧洲，还有亚太。这体现了我们对\'在中国，为中国\'的承诺，也体现了我们\'在中国，为世界\'的信心。每次来这里，这里的工作方式、创新速度——都不只是让中国市场变得更好，是让全世界都能受益。</p>\n  <p><strong>36氪：集团最近收购了印度奢侈品牌Forest Essentials剩余的股份，外界认为这是在寻找“第二增长引擎”，你怎么看？</strong></p>\n  <p>司泰峰：Forest Essentials是我们合作了18年的品牌，我们一直持有少数股权。印度市场有个转折点——消费者对健康养生、对高端阿育吠陀有越来越强烈的需求。我们想把握这个机会。而且这不只是“在印度，为印度”——健康养生本身就是一个全球趋势，是“在印度，为世界”。</p>', '', '', '', '', '{\'title\': \'对话雅诗兰黛集团总裁兼CEO司泰峰：让一家公司变得更敏捷，这是他的第一年｜New Look专访\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'对话雅诗兰黛集团总裁兼CEO司泰峰：让一家公司变得更敏捷，这是他的第一年｜New Look专访\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3756542711120640?f=rss\'}], \'link\': \'https://36kr.com/p/3756542711120640?f=rss\', \'published\': \'2026-04-13 13:19:17  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=13, tm_hour=5, tm_min=19, tm_sec=17, tm_wday=0, tm_yday=103, tm_isdst=0), \'summary\': \'<p>文｜贺哲馨</p>\\n  <p>编辑｜乔芊</p>\\n  <p>从外表看，司泰峰（Stéphane de La Faverie）并不是那类锋芒毕露的“改革派”。</p>\\n  <p>他多数时候带着温和的笑意，步伐与语速都偏慢——或许带着一点法国人特有的松弛感。你也很难想象，在成为父亲之前，司泰峰是“狂热的风帆冲浪和跳伞爱好者”。</p>\\n  <p>当下消费环境的惊险程度可能不亚于任何冒险运动。但在日前与36氪的专访中，司泰峰展现出一种从容：<strong>“我们是一家80年历史的公司，30多年前就进入中国市场，波动对我们来说不是什么新鲜事，我们的应对思路始终是一个——尽可能贴近消费者。</strong>”</p>\\n  <p>“而且你知道吗，”他接着说，“雅诗兰黛是第一个用中国人作为广告模特的外国美妆品牌。”这句话透露的言外之意是——在市场直觉和动作上，这家公司一向走在前面。</p>\\n  <p>司泰峰所有履历都与美妆有关，在2011年加入雅诗兰黛集团之后，从品牌总经理一路做到全球执行总裁。2025年1月，他接替傅懿德 (Fabrizio Freda），正式成为雅诗兰黛集团总裁兼首席执行官。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260407/v2_0bd034e2772445e191dc2e4028064a1d@5922386_oswg631199oswg2232oswg1388_img_png?x-oss-process=image/quality,q_90/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">雅诗兰黛集团总裁兼首席执行官司泰峰</p>\\n  <p>这份新职位几乎没有过渡期。上任仅一个月，司泰峰就提出了一项重大改革：<strong>雅诗兰黛集团将区域数量整合为四个，以及将损益表的责任从全球品牌部门下放到各个地区。</strong></p>\\n  <p>这一改革让公司的日常运营变得更“精干和快速”，也能最大程度发挥品牌组合在不同地区的优势。而在此之前，雅诗兰黛集团的模式是一个“品牌部门决定全球销售”，对区域市场的灵活响应有所制约。</p>\\n  <p>在司泰峰上任之前，这家集团几乎是传统家族企业的经典样本——拥有许多流传至今的经典产品，也有经过反复验证的成功路径，但一切都中规中矩。“我们相比拉新更擅长留存，”连司泰峰本人也承认，“但如今的消费者需要看到更多新事物。”</p>\\n  <p>他在上任之初承诺一年内将公司推向市场的新品数量增加两倍，最终将创新产品的占比“从10%提升到30%”，如今这一比例增加到了19%。去年上市的雅诗兰黛冻龄白金蕴能黑钻赋活精华油，成为他经常引用的例子，<strong>“我们中国的研发团队仅仅用了15个月就将其从概念变成了产品，这是一个从公司和行业角度都非常罕见的速度。”</strong></p>\\n  <p>与产品节奏同步变化的，是渠道结构。2024年，雅诗兰黛品牌首次登陆Amazon官网，此后一年内，集团已有超过10个品牌入驻这一平台。与此同时，美国百货渠道的占比下降至约30%，这一数字已经低于不少同行。线上渠道的权重被系统性抬升，并进一步延伸至Shopify和TikTok Shop等新兴电商生态，尤其是后者，在北美市场展现出极高的增长率，被视为美容市场下一阶段的重要变量。</p>\\n  <p>敏捷、创新以及以消费者为中心，可以最精简地概括司泰峰上任以来推进的一系列变革。这三个词背后，指向的是一套系统性的逻辑重构：<strong>从品牌驱动转向市场驱动，从全球指令转向区域决策，从守护经典转向主动创造。</strong></p>\\n  <p>自2026财年开始，雅诗兰黛集团对中国大陆市场业绩进行单独披露。Q2中国大陆市场净销售额达9.28亿美元，同比增长13%，增速在集团四大区域市场中位居第一，对集团的营收贡献占比超过20%。</p>\\n  <p>速度更快、电商环境更完善的中国大陆市场，也理所应当成了全新运营体系的前线实验场。</p>\\n  <p>3月26日，位于上海闵行的雅诗兰黛中国供应链智能运营中心正式启用。活动现场，一架无人机悬吊着一件缎带装饰的纸箱落在观礼台旁，象征着第一件由该中心打包的包裹。</p>\\n  <p>过去企业在接到订单后，需先拣货打包包裹，快递公司揽收后集中转运至其中转场按目的地或者线路分拨。如今，该中心将订单履约与快递包裹分拨两大环节打通，订单再完成分拣打包包裹后直接目的地或者线路发运，提升了整体流转效率，消费者可以更快收到所购产品。</p>\\n  <p>对于正在经历调整期的雅诗兰黛集团来说，这类基础设施的变化未必显眼，却直接关系到效率、成本以及对市场变化的反应速度。</p>\\n  <p><strong>“我可以在飞行的同时修理飞机，”司泰峰曾如此形容这份工作，“以当今消费者变化的速度，你必须能够承担一定的风险，而这正是我试图教给这家公司的。”</strong></p>\\n  <p>以下是36氪与司泰峰的专访内容，在保留原意的基础上经过删减。</p>\\n  <h3>谈转型：一次结构性的变革</h3>\\n  <p><strong>36氪：你担任雅诗兰黛集团总裁兼首席执行官已经满一年了，你会如何总结过去一年的工作？</strong></p>\\n  <p>司泰峰：在我一年前出任CEO时，我就意识到要在当下的高端美妆行业中保持竞争力，我们必须更快行动，并以更差异化的方式运营。行业正在变化——消费者连接更紧密，市场节奏明显加快，我们也必须随之调整。</p>\\n  <p>我的首要任务，是在集团长期积累的基础上，优化工作方式、重新聚焦消费者，同时搭建一套支撑下一阶段增长的运营体系。</p>\\n  <p>基于这一思考，我们提出了“Beauty Reimagined（重塑美妆新境）”，希望让公司回到可持续增长轨道，并真正把“以消费者为中心”落到实处。这一战略围绕五个重点展开：扩大消费者覆盖、推动创新、加大消费者投入、实现可持续增长，以及重塑工作方式。</p>\\n  <p>经过一年的推进，无论在工作方式、创新能力还是业绩表现上，我们都已经看到一些积极变化。当然，这仍在过程中，转型不会一蹴而就。</p>\\n  <p><strong>36氪：雅诗兰黛集团的业绩2026财年恢复增长，背后发生了什么？</strong></p>\\n  <p>司泰峰：我们在本财年上半年就已经回到正轨了——第一季度增长了3%，第二季度增长了4%。这次恢复增长其实是一次非常深层的、结构性的变革，我把它定义为公司历史上规模最大的一次运营与领导力转型。</p>\\n  <p>一是我们让组织架构变得更精简了，过去一年做了很多领导层的调整，这些都在我们\\\'重塑美妆新境\\\'（Beauty Reimagined）这个大战略框架下推进的。二是我们给公司每一个人都讲清楚了：我们要做什么样的公司——做全球最好的、以消费者为中心的美妆企业。</p>\\n  <p>我们还做了一个很重要的调整——把盈亏责任从品牌层面放到了区域层面。这样一来，哪个市场有增长机会，我们就能更快去抓住它。中国就是一个很好的例子。过去这一年，我们看到中国明显在复苏，美妆行业势头很好，中国团队也能更快地做出反应。</p>\\n  <p><strong>36氪：PRGP（Profit Recovery and Growth Plan）包含了很多削减成本的内容，可以说削减成本也是复苏关键原因吗？</strong></p>\\n  <p>司泰峰：PRGP不是简单的成本削减。核心是让组织变得更精简、更灵活，从而把更多的钱和精力用在直接面向消费者的地方。这是我们能够加速的一个重要原因——在恢复盈利的同时，我们加大了对消费者的投入。</p>\\n  <p>我们还在推一个东西，我叫它\\\'一个运营模式\\\'（one operating model）——一个团队，一种文化，一套做法。同时我们和全球很多合作伙伴建立了深度合作，比如Shopify、埃森哲、谷歌等等，这些都帮助我们更敏捷、更快速，把更多精力放在创意和创新上——最终，就是推动增长、恢复盈利。</p>\\n  <p>具体说到中国——从宏观层面，我们看到了明显的加速复苏。上一个自然年最后一个季度，我们在中国增长了13%，而且已经连续两个季度在提升市场份额。</p>\\n  <h3>谈中国：在‘第二主场’，敏捷是关键词</h3>\\n  <p><strong>36氪： 你说过\"中国消费者信心仍然低迷\"，但同期中国业务又实现了双位数增长——怎么理解这个矛盾？</strong></p>\\n  <p>司泰峰：我们确实看到中国消费者信心在逐步改善。同时，我们的表现优于高端美妆行业整体。<strong>增长主要来自几个方面：一是持续推出符合消费者需求的创新产品；二是更精准地触达目标人群；三是加大面向消费者的投入，从而带动新客获取。</strong></p>\\n  <p>品牌层面，从护肤品类的海蓝之谜和雅诗兰黛，到香水品类的汤姆福特和勒莱柏，增长都与产品创新密切相关。本土创新能力正在成为重要优势。中国研发团队能够更快响应本地需求，加速产品落地，实现全球品牌与本地市场的结合。</p>\\n  <p>在运营端，我们的中国供应链智能运营中心已经投入使用，提升了整体响应能力，包括更快的配送、更丰富的产品选择以及更高的服务标准。在渠道方面，我们持续加码天猫、抖音等高增长平台，同时优化线下零售体验。在中国，全渠道能力至关重要。</p>\\n  <p>总体来看，我们通过品牌建设、创新和高效执行，把握关键节点，实现了业绩与市场份额的同步提升。</p>\\n  <p><strong>36氪：能否为我们简单介绍一下这一智能运营中心，它的最终目的是什么？</strong></p>\\n  <p>司泰峰：这个中心的核心目标就是做全渠道配送。我们在上海做了很大的投资，也做出了很明确的承诺。我们要确保我们能跟上中国消费者的需求——他们要更快的速度、更多的产品选择，以及完美无缺的配送体验。</p>\\n  <p>这背后有AI技术的支撑，让我们可以在中心内部不断改进。还有一点我很自豪的——这里是24小时不停运转的，我们叫它\\\'黑灯工厂\\\'，可以全天候直接向消费者发货，日处理量的最高峰可以超过40万单。这意味着不管消费者在哪里，我们都能快速响应他们的需求。</p>\\n  <p>你可以把这个中心想象成我们整个中国履约网络的\\\'大脑\\\'——它让我们的运营更精准、更可靠，也为我们在中国未来的增长打下了坚实的基础。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260407/v2_b50385c51bf0457d95d7ccccd4a7bd34@5922386_oswg11042039oswg5345oswg3007_img_jpg?x-oss-process=image/quality,q_80/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">雅诗兰黛中国供应链智能运营中心</p>\\n  <p><strong>36氪：我想多聊一聊\\\'敏捷性\\\'这个话题。您提到有款新品——雅诗兰黛冻龄白金蕴能黑钻赋活精华油——从研发到上市只用了15个月，放在整个行业里15个月算快吗？</strong></p>\\n  <p>司泰峰：是的，15个月在整个行业里都是很快的速度。因为从洞察到创意，再到产品开发，就在附近的中国创新研发中心，最后还要通过这样的智能运营中心把它铺到市场上——整条链路走下来，每一步都要走。</p>\\n  <p>但有一点是我们整个过程中绝对不妥协的——品质。品质，是我们做所有事情的核心。我们可以加快流程，但绝对不能以牺牲产品品质和消费者体验来换。</p>\\n  <p><strong>36氪：市场反馈怎么样？有没有达到你们的预期？</strong></p>\\n  <p>司泰峰：我们非常满意。创新产品在很大程度上推动了众多品牌的增速——上一季度实现了两位数的增长，市场份额也在持续提升。但我要说，创新不只是产品创新，流程本身也在创新。</p>\\n  <p>比如，我们是上海市闵行区首批入选大企业开放创新中心的企业之一，这个模式就是把我们集团内部的资源跟外部优质人才结合起来，实现“1+1=3”，为中国市场创造更好的创新。</p>\\n  <p>今天这个智能运营中心本身也是一种创新——它用全新的方式，以更快的速度、更高的精准性，把产品送到全国每一位消费者手里。对于我们来说，创新从产品开始，但不止于产品——供应链、分销网络、制造能力，方方面面都在创新。</p>\\n  <p><strong>36氪：听说你们一年内上新产品占比已经从10%升到了19%，目标是到30%。</strong></p>\\n  <p>司泰峰：我可以告诉你的是我们一直在赶上市场的速度。尤其在中国市场，每次来中国，我最有感触的就是这里的速度——这个市场的速度，以及消费者对速度的期待，真的让我印象太深了。</p>\\n  <p>我们也从中国学到了很多：怎么打破部门壁垒，怎么把一个来自中国的洞察，快速转化成一款产品。而且这不只是“在中国，为中国”，更是“在中国，为世界”——把中国的速度和效率，以及我们品牌的情感与品质传承，一起带给全球消费者。</p>\\n  <p><strong>36氪：你判断中国市场目前的增长机会在哪里，是大众化的平价产品还是高端产品？护肤、彩妆、香水和护发中，哪个品类更具潜力？香水业务虽然增长强劲，但可持续性如何？</strong></p>\\n  <p>司泰峰：性价比趋势确实在加强，但高端美妆的长期潜力依然显著。我们的品牌组合主要在高端和奢华区间，这仍然是我们的优势所在。</p>\\n  <p>具体来说，护肤毫无疑问是最核心的，中国消费者在护肤上已经是全球最懂行的群体之一。彩妆有韧性，香水在奢华区间增速很快，护发也在冒头。最新一季财报，我们在中国高端美妆市场四个品类都实现了份额增长——海蓝之谜、汤姆福特、勒莱柏表现都很突出。</p>\\n  <p>奢华香水的增速明显，但我们不会押注单一的品类——消费者偏好变化迅速，我们多元化的品牌组合本身就是为了应对市场变化而存在的。</p>\\n  <h3>谈未来：在更大的不确定性里下注</h3>\\n  <p><strong>36氪：日上的停运、北京上海机场零售商交接——这在Q2财报里是一个\"过渡期扰动\"。但从更长远的角度看，中国旅游零售渠道的洗牌，对你们来说是威胁还是机会？</strong></p>\\n  <p>司泰峰：中国旅游零售市场正在经历结构性变化，这是一个逐步走向成熟的渠道的自然过程。我们正与合作伙伴紧密协作，确保平稳过渡，并为下一阶段做好准备。</p>\\n  <p>从更长期来看，我们将其视为重要机会。旅游零售不仅是销售渠道，更是建立品牌、吸引新客以及提供差异化体验的重要平台。我们的策略是高度定制化，而不是统一模式。我们会根据本地需求，与合作伙伴共同制定更合适的方案，这在中国尤为重要，因为消费者变化非常快。</p>\\n  <p>中国市场始终是我们的核心战略重点，旅游零售也是其中的重要组成部分。总体而言，我们对中国旅游零售的长期增长和高端化趋势保持信心，也期待与合作伙伴共同推动其下一阶段的发展。</p>\\n  <p><strong>36氪：今天全球地缘政治的不确定性会不会改变你对中国市场的判断？</strong></p>\\n  <p>司泰峰：首先，我们是一家已经走过80年的公司，在中国也有30多年的历史。这些年，起起伏伏我们见得多了，我们知道怎么去驾驭市场的波动。但有一点是不变的——我们对中国的承诺是绝对不动摇的。我们相信中国市场的长期潜力，我们知道中国消费者喜爱我们的品牌——这是30多年一点一点积累下来的。我们有很好的品牌矩阵，我们会继续在中国认真做下去。</p>\\n  <p>面对外部的波动，我们的应对思路始终是一个——尽可能贴近消费者。这就是为什么我们2022年12月在上海建了中国创新研发中心，今天有这个中国供应链智能运营中心的开幕，外面有很多不确定性，但我们整个网络的韧性，就在于我们始终离消费者很近。</p>\\n  <p><strong>36氪：集团目标是要把美国工厂生产的产品在中国市场的占比降到10%，雅诗兰黛集团还会如何进一步降低地区性依赖度？</strong></p>\\n  <p>司泰峰：我们是一家全球的美妆企业，我们非常注重全球业务的均衡发展。我把集团划分成了四大区域——中国直接向我汇报，这本身就说明了中国在我们战略里的分量。</p>\\n  <p>其他三个区域是美洲、欧洲，还有亚太。这体现了我们对\\\'在中国，为中国\\\'的承诺，也体现了我们\\\'在中国，为世界\\\'的信心。每次来这里，这里的工作方式、创新速度——都不只是让中国市场变得更好，是让全世界都能受益。</p>\\n  <p><strong>36氪：集团最近收购了印度奢侈品牌Forest Essentials剩余的股份，外界认为这是在寻找“第二增长引擎”，你怎么看？</strong></p>\\n  <p>司泰峰：Forest Essentials是我们合作了18年的品牌，我们一直持有少数股权。印度市场有个转折点——消费者对健康养生、对高端阿育吠陀有越来越强烈的需求。我们想把握这个机会。而且这不只是“在印度，为印度”——健康养生本身就是一个全球趋势，是“在印度，为世界”。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'<p>文｜贺哲馨</p>\\n  <p>编辑｜乔芊</p>\\n  <p>从外表看，司泰峰（Stéphane de La Faverie）并不是那类锋芒毕露的“改革派”。</p>\\n  <p>他多数时候带着温和的笑意，步伐与语速都偏慢——或许带着一点法国人特有的松弛感。你也很难想象，在成为父亲之前，司泰峰是“狂热的风帆冲浪和跳伞爱好者”。</p>\\n  <p>当下消费环境的惊险程度可能不亚于任何冒险运动。但在日前与36氪的专访中，司泰峰展现出一种从容：<strong>“我们是一家80年历史的公司，30多年前就进入中国市场，波动对我们来说不是什么新鲜事，我们的应对思路始终是一个——尽可能贴近消费者。</strong>”</p>\\n  <p>“而且你知道吗，”他接着说，“雅诗兰黛是第一个用中国人作为广告模特的外国美妆品牌。”这句话透露的言外之意是——在市场直觉和动作上，这家公司一向走在前面。</p>\\n  <p>司泰峰所有履历都与美妆有关，在2011年加入雅诗兰黛集团之后，从品牌总经理一路做到全球执行总裁。2025年1月，他接替傅懿德 (Fabrizio Freda），正式成为雅诗兰黛集团总裁兼首席执行官。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260407/v2_0bd034e2772445e191dc2e4028064a1d@5922386_oswg631199oswg2232oswg1388_img_png?x-oss-process=image/quality,q_90/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">雅诗兰黛集团总裁兼首席执行官司泰峰</p>\\n  <p>这份新职位几乎没有过渡期。上任仅一个月，司泰峰就提出了一项重大改革：<strong>雅诗兰黛集团将区域数量整合为四个，以及将损益表的责任从全球品牌部门下放到各个地区。</strong></p>\\n  <p>这一改革让公司的日常运营变得更“精干和快速”，也能最大程度发挥品牌组合在不同地区的优势。而在此之前，雅诗兰黛集团的模式是一个“品牌部门决定全球销售”，对区域市场的灵活响应有所制约。</p>\\n  <p>在司泰峰上任之前，这家集团几乎是传统家族企业的经典样本——拥有许多流传至今的经典产品，也有经过反复验证的成功路径，但一切都中规中矩。“我们相比拉新更擅长留存，”连司泰峰本人也承认，“但如今的消费者需要看到更多新事物。”</p>\\n  <p>他在上任之初承诺一年内将公司推向市场的新品数量增加两倍，最终将创新产品的占比“从10%提升到30%”，如今这一比例增加到了19%。去年上市的雅诗兰黛冻龄白金蕴能黑钻赋活精华油，成为他经常引用的例子，<strong>“我们中国的研发团队仅仅用了15个月就将其从概念变成了产品，这是一个从公司和行业角度都非常罕见的速度。”</strong></p>\\n  <p>与产品节奏同步变化的，是渠道结构。2024年，雅诗兰黛品牌首次登陆Amazon官网，此后一年内，集团已有超过10个品牌入驻这一平台。与此同时，美国百货渠道的占比下降至约30%，这一数字已经低于不少同行。线上渠道的权重被系统性抬升，并进一步延伸至Shopify和TikTok Shop等新兴电商生态，尤其是后者，在北美市场展现出极高的增长率，被视为美容市场下一阶段的重要变量。</p>\\n  <p>敏捷、创新以及以消费者为中心，可以最精简地概括司泰峰上任以来推进的一系列变革。这三个词背后，指向的是一套系统性的逻辑重构：<strong>从品牌驱动转向市场驱动，从全球指令转向区域决策，从守护经典转向主动创造。</strong></p>\\n  <p>自2026财年开始，雅诗兰黛集团对中国大陆市场业绩进行单独披露。Q2中国大陆市场净销售额达9.28亿美元，同比增长13%，增速在集团四大区域市场中位居第一，对集团的营收贡献占比超过20%。</p>\\n  <p>速度更快、电商环境更完善的中国大陆市场，也理所应当成了全新运营体系的前线实验场。</p>\\n  <p>3月26日，位于上海闵行的雅诗兰黛中国供应链智能运营中心正式启用。活动现场，一架无人机悬吊着一件缎带装饰的纸箱落在观礼台旁，象征着第一件由该中心打包的包裹。</p>\\n  <p>过去企业在接到订单后，需先拣货打包包裹，快递公司揽收后集中转运至其中转场按目的地或者线路分拨。如今，该中心将订单履约与快递包裹分拨两大环节打通，订单再完成分拣打包包裹后直接目的地或者线路发运，提升了整体流转效率，消费者可以更快收到所购产品。</p>\\n  <p>对于正在经历调整期的雅诗兰黛集团来说，这类基础设施的变化未必显眼，却直接关系到效率、成本以及对市场变化的反应速度。</p>\\n  <p><strong>“我可以在飞行的同时修理飞机，”司泰峰曾如此形容这份工作，“以当今消费者变化的速度，你必须能够承担一定的风险，而这正是我试图教给这家公司的。”</strong></p>\\n  <p>以下是36氪与司泰峰的专访内容，在保留原意的基础上经过删减。</p>\\n  <h3>谈转型：一次结构性的变革</h3>\\n  <p><strong>36氪：你担任雅诗兰黛集团总裁兼首席执行官已经满一年了，你会如何总结过去一年的工作？</strong></p>\\n  <p>司泰峰：在我一年前出任CEO时，我就意识到要在当下的高端美妆行业中保持竞争力，我们必须更快行动，并以更差异化的方式运营。行业正在变化——消费者连接更紧密，市场节奏明显加快，我们也必须随之调整。</p>\\n  <p>我的首要任务，是在集团长期积累的基础上，优化工作方式、重新聚焦消费者，同时搭建一套支撑下一阶段增长的运营体系。</p>\\n  <p>基于这一思考，我们提出了“Beauty Reimagined（重塑美妆新境）”，希望让公司回到可持续增长轨道，并真正把“以消费者为中心”落到实处。这一战略围绕五个重点展开：扩大消费者覆盖、推动创新、加大消费者投入、实现可持续增长，以及重塑工作方式。</p>\\n  <p>经过一年的推进，无论在工作方式、创新能力还是业绩表现上，我们都已经看到一些积极变化。当然，这仍在过程中，转型不会一蹴而就。</p>\\n  <p><strong>36氪：雅诗兰黛集团的业绩2026财年恢复增长，背后发生了什么？</strong></p>\\n  <p>司泰峰：我们在本财年上半年就已经回到正轨了——第一季度增长了3%，第二季度增长了4%。这次恢复增长其实是一次非常深层的、结构性的变革，我把它定义为公司历史上规模最大的一次运营与领导力转型。</p>\\n  <p>一是我们让组织架构变得更精简了，过去一年做了很多领导层的调整，这些都在我们\\\'重塑美妆新境\\\'（Beauty Reimagined）这个大战略框架下推进的。二是我们给公司每一个人都讲清楚了：我们要做什么样的公司——做全球最好的、以消费者为中心的美妆企业。</p>\\n  <p>我们还做了一个很重要的调整——把盈亏责任从品牌层面放到了区域层面。这样一来，哪个市场有增长机会，我们就能更快去抓住它。中国就是一个很好的例子。过去这一年，我们看到中国明显在复苏，美妆行业势头很好，中国团队也能更快地做出反应。</p>\\n  <p><strong>36氪：PRGP（Profit Recovery and Growth Plan）包含了很多削减成本的内容，可以说削减成本也是复苏关键原因吗？</strong></p>\\n  <p>司泰峰：PRGP不是简单的成本削减。核心是让组织变得更精简、更灵活，从而把更多的钱和精力用在直接面向消费者的地方。这是我们能够加速的一个重要原因——在恢复盈利的同时，我们加大了对消费者的投入。</p>\\n  <p>我们还在推一个东西，我叫它\\\'一个运营模式\\\'（one operating model）——一个团队，一种文化，一套做法。同时我们和全球很多合作伙伴建立了深度合作，比如Shopify、埃森哲、谷歌等等，这些都帮助我们更敏捷、更快速，把更多精力放在创意和创新上——最终，就是推动增长、恢复盈利。</p>\\n  <p>具体说到中国——从宏观层面，我们看到了明显的加速复苏。上一个自然年最后一个季度，我们在中国增长了13%，而且已经连续两个季度在提升市场份额。</p>\\n  <h3>谈中国：在‘第二主场’，敏捷是关键词</h3>\\n  <p><strong>36氪： 你说过\"中国消费者信心仍然低迷\"，但同期中国业务又实现了双位数增长——怎么理解这个矛盾？</strong></p>\\n  <p>司泰峰：我们确实看到中国消费者信心在逐步改善。同时，我们的表现优于高端美妆行业整体。<strong>增长主要来自几个方面：一是持续推出符合消费者需求的创新产品；二是更精准地触达目标人群；三是加大面向消费者的投入，从而带动新客获取。</strong></p>\\n  <p>品牌层面，从护肤品类的海蓝之谜和雅诗兰黛，到香水品类的汤姆福特和勒莱柏，增长都与产品创新密切相关。本土创新能力正在成为重要优势。中国研发团队能够更快响应本地需求，加速产品落地，实现全球品牌与本地市场的结合。</p>\\n  <p>在运营端，我们的中国供应链智能运营中心已经投入使用，提升了整体响应能力，包括更快的配送、更丰富的产品选择以及更高的服务标准。在渠道方面，我们持续加码天猫、抖音等高增长平台，同时优化线下零售体验。在中国，全渠道能力至关重要。</p>\\n  <p>总体来看，我们通过品牌建设、创新和高效执行，把握关键节点，实现了业绩与市场份额的同步提升。</p>\\n  <p><strong>36氪：能否为我们简单介绍一下这一智能运营中心，它的最终目的是什么？</strong></p>\\n  <p>司泰峰：这个中心的核心目标就是做全渠道配送。我们在上海做了很大的投资，也做出了很明确的承诺。我们要确保我们能跟上中国消费者的需求——他们要更快的速度、更多的产品选择，以及完美无缺的配送体验。</p>\\n  <p>这背后有AI技术的支撑，让我们可以在中心内部不断改进。还有一点我很自豪的——这里是24小时不停运转的，我们叫它\\\'黑灯工厂\\\'，可以全天候直接向消费者发货，日处理量的最高峰可以超过40万单。这意味着不管消费者在哪里，我们都能快速响应他们的需求。</p>\\n  <p>你可以把这个中心想象成我们整个中国履约网络的\\\'大脑\\\'——它让我们的运营更精准、更可靠，也为我们在中国未来的增长打下了坚实的基础。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260407/v2_b50385c51bf0457d95d7ccccd4a7bd34@5922386_oswg11042039oswg5345oswg3007_img_jpg?x-oss-process=image/quality,q_80/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">雅诗兰黛中国供应链智能运营中心</p>\\n  <p><strong>36氪：我想多聊一聊\\\'敏捷性\\\'这个话题。您提到有款新品——雅诗兰黛冻龄白金蕴能黑钻赋活精华油——从研发到上市只用了15个月，放在整个行业里15个月算快吗？</strong></p>\\n  <p>司泰峰：是的，15个月在整个行业里都是很快的速度。因为从洞察到创意，再到产品开发，就在附近的中国创新研发中心，最后还要通过这样的智能运营中心把它铺到市场上——整条链路走下来，每一步都要走。</p>\\n  <p>但有一点是我们整个过程中绝对不妥协的——品质。品质，是我们做所有事情的核心。我们可以加快流程，但绝对不能以牺牲产品品质和消费者体验来换。</p>\\n  <p><strong>36氪：市场反馈怎么样？有没有达到你们的预期？</strong></p>\\n  <p>司泰峰：我们非常满意。创新产品在很大程度上推动了众多品牌的增速——上一季度实现了两位数的增长，市场份额也在持续提升。但我要说，创新不只是产品创新，流程本身也在创新。</p>\\n  <p>比如，我们是上海市闵行区首批入选大企业开放创新中心的企业之一，这个模式就是把我们集团内部的资源跟外部优质人才结合起来，实现“1+1=3”，为中国市场创造更好的创新。</p>\\n  <p>今天这个智能运营中心本身也是一种创新——它用全新的方式，以更快的速度、更高的精准性，把产品送到全国每一位消费者手里。对于我们来说，创新从产品开始，但不止于产品——供应链、分销网络、制造能力，方方面面都在创新。</p>\\n  <p><strong>36氪：听说你们一年内上新产品占比已经从10%升到了19%，目标是到30%。</strong></p>\\n  <p>司泰峰：我可以告诉你的是我们一直在赶上市场的速度。尤其在中国市场，每次来中国，我最有感触的就是这里的速度——这个市场的速度，以及消费者对速度的期待，真的让我印象太深了。</p>\\n  <p>我们也从中国学到了很多：怎么打破部门壁垒，怎么把一个来自中国的洞察，快速转化成一款产品。而且这不只是“在中国，为中国”，更是“在中国，为世界”——把中国的速度和效率，以及我们品牌的情感与品质传承，一起带给全球消费者。</p>\\n  <p><strong>36氪：你判断中国市场目前的增长机会在哪里，是大众化的平价产品还是高端产品？护肤、彩妆、香水和护发中，哪个品类更具潜力？香水业务虽然增长强劲，但可持续性如何？</strong></p>\\n  <p>司泰峰：性价比趋势确实在加强，但高端美妆的长期潜力依然显著。我们的品牌组合主要在高端和奢华区间，这仍然是我们的优势所在。</p>\\n  <p>具体来说，护肤毫无疑问是最核心的，中国消费者在护肤上已经是全球最懂行的群体之一。彩妆有韧性，香水在奢华区间增速很快，护发也在冒头。最新一季财报，我们在中国高端美妆市场四个品类都实现了份额增长——海蓝之谜、汤姆福特、勒莱柏表现都很突出。</p>\\n  <p>奢华香水的增速明显，但我们不会押注单一的品类——消费者偏好变化迅速，我们多元化的品牌组合本身就是为了应对市场变化而存在的。</p>\\n  <h3>谈未来：在更大的不确定性里下注</h3>\\n  <p><strong>36氪：日上的停运、北京上海机场零售商交接——这在Q2财报里是一个\"过渡期扰动\"。但从更长远的角度看，中国旅游零售渠道的洗牌，对你们来说是威胁还是机会？</strong></p>\\n  <p>司泰峰：中国旅游零售市场正在经历结构性变化，这是一个逐步走向成熟的渠道的自然过程。我们正与合作伙伴紧密协作，确保平稳过渡，并为下一阶段做好准备。</p>\\n  <p>从更长期来看，我们将其视为重要机会。旅游零售不仅是销售渠道，更是建立品牌、吸引新客以及提供差异化体验的重要平台。我们的策略是高度定制化，而不是统一模式。我们会根据本地需求，与合作伙伴共同制定更合适的方案，这在中国尤为重要，因为消费者变化非常快。</p>\\n  <p>中国市场始终是我们的核心战略重点，旅游零售也是其中的重要组成部分。总体而言，我们对中国旅游零售的长期增长和高端化趋势保持信心，也期待与合作伙伴共同推动其下一阶段的发展。</p>\\n  <p><strong>36氪：今天全球地缘政治的不确定性会不会改变你对中国市场的判断？</strong></p>\\n  <p>司泰峰：首先，我们是一家已经走过80年的公司，在中国也有30多年的历史。这些年，起起伏伏我们见得多了，我们知道怎么去驾驭市场的波动。但有一点是不变的——我们对中国的承诺是绝对不动摇的。我们相信中国市场的长期潜力，我们知道中国消费者喜爱我们的品牌——这是30多年一点一点积累下来的。我们有很好的品牌矩阵，我们会继续在中国认真做下去。</p>\\n  <p>面对外部的波动，我们的应对思路始终是一个——尽可能贴近消费者。这就是为什么我们2022年12月在上海建了中国创新研发中心，今天有这个中国供应链智能运营中心的开幕，外面有很多不确定性，但我们整个网络的韧性，就在于我们始终离消费者很近。</p>\\n  <p><strong>36氪：集团目标是要把美国工厂生产的产品在中国市场的占比降到10%，雅诗兰黛集团还会如何进一步降低地区性依赖度？</strong></p>\\n  <p>司泰峰：我们是一家全球的美妆企业，我们非常注重全球业务的均衡发展。我把集团划分成了四大区域——中国直接向我汇报，这本身就说明了中国在我们战略里的分量。</p>\\n  <p>其他三个区域是美洲、欧洲，还有亚太。这体现了我们对\\\'在中国，为中国\\\'的承诺，也体现了我们\\\'在中国，为世界\\\'的信心。每次来这里，这里的工作方式、创新速度——都不只是让中国市场变得更好，是让全世界都能受益。</p>\\n  <p><strong>36氪：集团最近收购了印度奢侈品牌Forest Essentials剩余的股份，外界认为这是在寻找“第二增长引擎”，你怎么看？</strong></p>\\n  <p>司泰峰：Forest Essentials是我们合作了18年的品牌，我们一直持有少数股权。印度市场有个转折点——消费者对健康养生、对高端阿育吠陀有越来越强烈的需求。我们想把握这个机会。而且这不只是“在印度，为印度”——健康养生本身就是一个全球趋势，是“在印度，为世界”。</p>\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-13 13:19:17', '2026-04-14 14:11:31', 1, '{\"summary\": \"本文分享雅诗兰黛在华本地化转型经验，为出海美妆企业的目标市场布局、组织敏捷转型提供参考\", \"abstract\": \"这是36氪对雅诗兰黛集团新任总裁兼CEO司泰峰的上任一周年专访。司泰峰上任后推动集团大规模运营转型，将全球区域整合为四个，把损益责任从全球品牌部下放到区域，推动组织敏捷化、加速产品创新，目前新品占比已从10%提升至19%。雅诗兰黛将中国作为集团转型的前线试验场，加码本土研发与智能供应链建设，中国市场实现双位数增长，增速位居集团四大区域第一。司泰峰表示集团长期看好中国高端美妆市场潜力，同时布局印度等新兴市场拓展新增长空间。\", \"keywords\": [\"雅诗兰黛\", \"高端美妆\", \"本地化运营\", \"组织变革\", \"供应链智能化\", \"新品创新\", \"新兴市场\", \"全渠道运营\"], \"policy_risk\": {\"market_risk\": \"全球地缘政治存在不确定性，中国消费者信心仍有波动，中国旅游零售渠道正经历结构性洗牌，消费者偏好变化快，对企业市场响应能力提出更高要求\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场本地化运营\", \"industry_category\": \"美妆\"}');
INSERT INTO `news` VALUES (411, '诺和诺德宣布与OpenAI建立战略合作伙伴关系', 'https://36kr.com/newsflashes/3766269385818625?f=rss', 'https://36kr.com/feed', '诺和诺德4月14日宣布与OpenAI建立战略合作伙伴关系，此次合作将运用先进的人工智能能力，对复杂数据集进行分析，筛选具有潜力的候选药物，并缩短从基础研究到惠及患者所需的周期。（界面）', '', '', '', '', '{\'title\': \'诺和诺德宣布与OpenAI建立战略合作伙伴关系\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'诺和诺德宣布与OpenAI建立战略合作伙伴关系\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766269385818625?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766269385818625?f=rss\', \'published\': \'2026-04-14 14:07:20  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=6, tm_min=7, tm_sec=20, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'诺和诺德4月14日宣布与OpenAI建立战略合作伙伴关系，此次合作将运用先进的人工智能能力，对复杂数据集进行分析，筛选具有潜力的候选药物，并缩短从基础研究到惠及患者所需的周期。（界面）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'诺和诺德4月14日宣布与OpenAI建立战略合作伙伴关系，此次合作将运用先进的人工智能能力，对复杂数据集进行分析，筛选具有潜力的候选药物，并缩短从基础研究到惠及患者所需的周期。（界面）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 14:07:20', '2026-04-14 14:11:33', 0, '\"\"');
INSERT INTO `news` VALUES (412, '机构：近期住房租金阶段性回升', 'https://36kr.com/newsflashes/3766264886952706?f=rss', 'https://36kr.com/feed', '根据中指研究院对50个重点城市住宅租赁价格的监测，3月一线城市住宅租金集体上涨，其中北上深的环比涨幅都在0.4%左右，幅度在50个城市中排名前三。中指研究院研究主管程威表示，近期住房租金的阶段性回升是季节性效应集中释放的结果，也符合往年同期租金变化的一般规律。展望后续市场走势，随着“返工潮”等季节性效应减退，重点城市住房租赁市场将回归常态运行。（证券时报）', '', '', '', '', '{\'title\': \'机构：近期住房租金阶段性回升\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'机构：近期住房租金阶段性回升\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766264886952706?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766264886952706?f=rss\', \'published\': \'2026-04-14 14:02:45  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=6, tm_min=2, tm_sec=45, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'根据中指研究院对50个重点城市住宅租赁价格的监测，3月一线城市住宅租金集体上涨，其中北上深的环比涨幅都在0.4%左右，幅度在50个城市中排名前三。中指研究院研究主管程威表示，近期住房租金的阶段性回升是季节性效应集中释放的结果，也符合往年同期租金变化的一般规律。展望后续市场走势，随着“返工潮”等季节性效应减退，重点城市住房租赁市场将回归常态运行。（证券时报）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'根据中指研究院对50个重点城市住宅租赁价格的监测，3月一线城市住宅租金集体上涨，其中北上深的环比涨幅都在0.4%左右，幅度在50个城市中排名前三。中指研究院研究主管程威表示，近期住房租金的阶段性回升是季节性效应集中释放的结果，也符合往年同期租金变化的一般规律。展望后续市场走势，随着“返工潮”等季节性效应减退，重点城市住房租赁市场将回归常态运行。（证券时报）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 14:02:45', '2026-04-14 14:11:36', 0, '\"\"');
INSERT INTO `news` VALUES (413, '国务院办公厅关于印发第十次全国深化“放管服”改革电视电话会议重点任务分工方案的通知', 'http://www.gov.cn/zhengce/content/2022-10/26/content_5721739.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院办公厅关于印发第十次全国深化“放管服”改革电视电话会议重点任务分工方案的通知\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院办公厅关于印发第十次全国深化“放管服”改革电视电话会议重点任务分工方案的通知\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-10/26/content_5721739.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-10/26/content_5721739.htm\', \'published\': \'Sat, 30 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=30, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=5, tm_yday=303, tm_isdst=0)}', '2021-10-30 16:00:00', '2026-04-14 14:11:38', 1, '{\"summary\": \"本文为国务院发布的深化放管服改革任务分工通知，可为出海企业把握国内政策方向提供参考\", \"abstract\": \"本文是国务院办公厅发布的第十次全国深化放管服改革电视电话会议重点任务分工方案通知。暂未提供方案具体内容。本次放管服改革或影响出海企业国内相关审批环节，暂无更多具体信息可供参考。\", \"keywords\": [\"放管服改革\", \"国务院\", \"政策通知\", \"行政审批\", \"企业出海\"], \"policy_risk\": {\"market_risk\": \"未提及具体市场/运营风险\", \"policy_compliance\": \"未提及具体政策/合规要点\"}, \"topic_cluster\": \"宏观政策\", \"industry_category\": \"全行业\"}');
INSERT INTO `news` VALUES (414, '少飞又加价，澳洲航空设法应对燃油成本上涨', 'https://36kr.com/newsflashes/3766254174356233?f=rss', 'https://36kr.com/feed', '澳大利亚澳洲航空公司4月14日说，由于中东战事推升燃油成本，该公司将削减澳大利亚国内航班并提高机票价格。澳航在一份声明中说，航空燃油价格近来显著上涨，且价格仍然“极不稳定”。因此，公司将2026财年下半年（2026年1月至6月）燃油成本预期从25亿澳元（1美元约合1.4澳元）上调至31亿至33亿澳元。“鉴于全球燃料供应链持续存在不确定性，公司正密切关注事态发展。”（新华社）', '', '', '', '', '{\'title\': \'少飞又加价，澳洲航空设法应对燃油成本上涨\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'少飞又加价，澳洲航空设法应对燃油成本上涨\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766254174356233?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766254174356233?f=rss\', \'published\': \'2026-04-14 13:51:52  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=5, tm_min=51, tm_sec=52, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'澳大利亚澳洲航空公司4月14日说，由于中东战事推升燃油成本，该公司将削减澳大利亚国内航班并提高机票价格。澳航在一份声明中说，航空燃油价格近来显著上涨，且价格仍然“极不稳定”。因此，公司将2026财年下半年（2026年1月至6月）燃油成本预期从25亿澳元（1美元约合1.4澳元）上调至31亿至33亿澳元。“鉴于全球燃料供应链持续存在不确定性，公司正密切关注事态发展。”（新华社）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'澳大利亚澳洲航空公司4月14日说，由于中东战事推升燃油成本，该公司将削减澳大利亚国内航班并提高机票价格。澳航在一份声明中说，航空燃油价格近来显著上涨，且价格仍然“极不稳定”。因此，公司将2026财年下半年（2026年1月至6月）燃油成本预期从25亿澳元（1美元约合1.4澳元）上调至31亿至33亿澳元。“鉴于全球燃料供应链持续存在不确定性，公司正密切关注事态发展。”（新华社）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 13:51:52', '2026-04-14 14:11:40', 0, '\"\"');
INSERT INTO `news` VALUES (415, '促进个体工商户发展条例', 'http://www.gov.cn/zhengce/content/2022-10/25/content_5721592.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'促进个体工商户发展条例\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'促进个体工商户发展条例\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-10/25/content_5721592.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-10/25/content_5721592.htm\', \'published\': \'Sat, 30 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=30, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=5, tm_yday=303, tm_isdst=0)}', '2021-10-30 16:00:00', '2026-04-14 14:11:41', 0, '\"\"');
INSERT INTO `news` VALUES (416, '雷诺韩国计划到2029年每年推出新车型', 'https://36kr.com/newsflashes/3766236514124549?f=rss', 'https://36kr.com/feed', '据报道，雷诺韩国计划到2029年每年推出新车型，并从2028年起在釜山生产下一代电动车。（财联社）', '', '', '', '', '{\'title\': \'雷诺韩国计划到2029年每年推出新车型\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'雷诺韩国计划到2029年每年推出新车型\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766236514124549?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766236514124549?f=rss\', \'published\': \'2026-04-14 13:33:54  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=5, tm_min=33, tm_sec=54, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'据报道，雷诺韩国计划到2029年每年推出新车型，并从2028年起在釜山生产下一代电动车。（财联社）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'据报道，雷诺韩国计划到2029年每年推出新车型，并从2028年起在釜山生产下一代电动车。（财联社）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 13:33:54', '2026-04-14 14:11:44', 0, '\"\"');
INSERT INTO `news` VALUES (417, '联想助力理想汽车打造的PPAP文档审核智能体正式发布', 'https://36kr.com/newsflashes/3766231859102470?f=rss', 'https://36kr.com/feed', '36氪获悉，近日，联想助力理想汽车打造的行业首个PPAP文档审核智能体正式发布。基于联想ThinkStation PGX AI工作站，该智能体实现了PPAP文档审核效率质的飞跃。ThinkStation PGX基于NVIDIA GB10 Grace Blackwell超级芯片打造，具备1 PetaFLOP（每秒1千万亿次浮点计算）算力与128GB统一内存，能在本地实时运行理想自研的27B大模型，同时支撑多个智能体并行推理。', '', '', '', '', '{\'title\': \'联想助力理想汽车打造的PPAP文档审核智能体正式发布\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'联想助力理想汽车打造的PPAP文档审核智能体正式发布\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766231859102470?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766231859102470?f=rss\', \'published\': \'2026-04-14 13:29:09  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=5, tm_min=29, tm_sec=9, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，近日，联想助力理想汽车打造的行业首个PPAP文档审核智能体正式发布。基于联想ThinkStation PGX AI工作站，该智能体实现了PPAP文档审核效率质的飞跃。ThinkStation PGX基于NVIDIA GB10 Grace Blackwell超级芯片打造，具备1 PetaFLOP（每秒1千万亿次浮点计算）算力与128GB统一内存，能在本地实时运行理想自研的27B大模型，同时支撑多个智能体并行推理。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'36氪获悉，近日，联想助力理想汽车打造的行业首个PPAP文档审核智能体正式发布。基于联想ThinkStation PGX AI工作站，该智能体实现了PPAP文档审核效率质的飞跃。ThinkStation PGX基于NVIDIA GB10 Grace Blackwell超级芯片打造，具备1 PetaFLOP（每秒1千万亿次浮点计算）算力与128GB统一内存，能在本地实时运行理想自研的27B大模型，同时支撑多个智能体并行推理。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 13:29:09', '2026-04-14 14:11:47', 0, '\"\"');
INSERT INTO `news` VALUES (418, '韩国将在周末和节假日为电动汽车充电提供折扣', 'https://36kr.com/newsflashes/3766220726354439?f=rss', 'https://36kr.com/feed', '韩国政府周二表示，从本周开始，周末下午电动汽车充电费用将降低至多15%。（新浪财经）', '', '', '', '', '{\'title\': \'韩国将在周末和节假日为电动汽车充电提供折扣\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'韩国将在周末和节假日为电动汽车充电提供折扣\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766220726354439?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766220726354439?f=rss\', \'published\': \'2026-04-14 13:17:50  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=5, tm_min=17, tm_sec=50, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'韩国政府周二表示，从本周开始，周末下午电动汽车充电费用将降低至多15%。（新浪财经）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'韩国政府周二表示，从本周开始，周末下午电动汽车充电费用将降低至多15%。（新浪财经）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 13:17:50', '2026-04-14 14:11:52', 0, '\"\"');
INSERT INTO `news` VALUES (419, '国务院关于同意在天津、上海、海南、重庆暂时调整实施有关行政法规规定的批复', 'http://www.gov.cn/zhengce/content/2022-10/08/content_5716699.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院关于同意在天津、上海、海南、重庆暂时调整实施有关行政法规规定的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意在天津、上海、海南、重庆暂时调整实施有关行政法规规定的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-10/08/content_5716699.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-10/08/content_5716699.htm\', \'published\': \'Sat, 30 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=30, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=5, tm_yday=303, tm_isdst=0)}', '2021-10-30 16:00:00', '2026-04-14 14:12:05', 1, '{\"summary\": \"本文仅公布国务院在四地调整行政法规的批复标题，无具体内容，可供出海政策方向研究参考\", \"abstract\": \"本文仅公布了国务院批复的标题，未披露具体批复内容。该批复同意在天津、上海、海南、重庆暂时调整实施有关行政法规规定。因缺少具体内容，无法提炼出海相关的具体结论信息。\", \"keywords\": [\"国务院批复\", \"行政法规调整\", \"天津\", \"上海\", \"海南\", \"重庆\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及具体政策/合规内容\"}, \"topic_cluster\": \"政策合规\", \"industry_category\": null}');
