INSERT INTO `news` VALUES (424, '韩国3月ICT出口额达435亿美元，同比增长逾一倍', 'https://36kr.com/newsflashes/3766204472623624?f=rss', 'https://36kr.com/feed', '韩国政府周二公布的数据显示，随着全球人工智能（AI）热潮推动半导体需求强劲增长，韩国3月份信息通信技术（ICT）产品出口额较上年同期增长超过一倍。根据韩国科技信息通信部的数据，上月韩国ICT产品出口额达到435.1亿美元，高于去年同期的205.2亿美元，创历史同月最高。（新浪财经）', '', '', '', '', '{\'title\': \'韩国3月ICT出口额达435亿美元，同比增长逾一倍\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'韩国3月ICT出口额达435亿美元，同比增长逾一倍\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766204472623624?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766204472623624?f=rss\', \'published\': \'2026-04-14 13:01:18  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=5, tm_min=1, tm_sec=18, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'韩国政府周二公布的数据显示，随着全球人工智能（AI）热潮推动半导体需求强劲增长，韩国3月份信息通信技术（ICT）产品出口额较上年同期增长超过一倍。根据韩国科技信息通信部的数据，上月韩国ICT产品出口额达到435.1亿美元，高于去年同期的205.2亿美元，创历史同月最高。（新浪财经）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'韩国政府周二公布的数据显示，随着全球人工智能（AI）热潮推动半导体需求强劲增长，韩国3月份信息通信技术（ICT）产品出口额较上年同期增长超过一倍。根据韩国科技信息通信部的数据，上月韩国ICT产品出口额达到435.1亿美元，高于去年同期的205.2亿美元，创历史同月最高。（新浪财经）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 13:01:18', '2026-04-14 14:12:23', 1, '{\"summary\": \"帮助出海ICT及半导体企业掌握全球半导体市场需求动态，为行业趋势判断提供参考\", \"abstract\": \"韩国科技信息通信部周二发布韩国3月信息通信技术（ICT）产品出口数据。该月韩国ICT出口额达435.1亿美元，同比增长超一倍，创下历史同月出口最高纪录。本次出口大幅增长主要得益于全球人工智能热潮带动半导体需求强劲上涨。\", \"keywords\": [\"韩国ICT出口\", \"半导体\", \"人工智能\", \"AI\", \"出口增长\", \"全球需求\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"半导体、信息通信技术(ICT)\"}');
INSERT INTO `news` VALUES (425, '小米增持墨睿科技公司，后者为石墨烯材料研发商', 'https://36kr.com/newsflashes/3766188201460227?f=rss', 'https://36kr.com/feed', '36氪获悉，爱企查App显示，近日，广东墨睿科技有限公司发生工商变更，新增北京小米智造股权投资基金合伙企业（有限合伙）等为股东，此前，湖北小米长江产业基金合伙企业（有限合伙）已在该公司持股，同时该公司注册资本增至2202.42万元人民币。该公司成立于2015年，经营范围包括新材料技术研发、石墨及碳素制品制造、石墨烯材料销售、石墨及碳素制品销售等。', '', '', '', '', '{\'title\': \'小米增持墨睿科技公司，后者为石墨烯材料研发商\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'小米增持墨睿科技公司，后者为石墨烯材料研发商\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766188201460227?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766188201460227?f=rss\', \'published\': \'2026-04-14 12:52:39  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=4, tm_min=52, tm_sec=39, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，爱企查App显示，近日，广东墨睿科技有限公司发生工商变更，新增北京小米智造股权投资基金合伙企业（有限合伙）等为股东，此前，湖北小米长江产业基金合伙企业（有限合伙）已在该公司持股，同时该公司注册资本增至2202.42万元人民币。该公司成立于2015年，经营范围包括新材料技术研发、石墨及碳素制品制造、石墨烯材料销售、石墨及碳素制品销售等。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'36氪获悉，爱企查App显示，近日，广东墨睿科技有限公司发生工商变更，新增北京小米智造股权投资基金合伙企业（有限合伙）等为股东，此前，湖北小米长江产业基金合伙企业（有限合伙）已在该公司持股，同时该公司注册资本增至2202.42万元人民币。该公司成立于2015年，经营范围包括新材料技术研发、石墨及碳素制品制造、石墨烯材料销售、石墨及碳素制品销售等。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 12:52:39', '2026-04-14 14:12:26', 0, '\"\"');
