INSERT INTO `news` VALUES (427, '随着战略转向，OpenAI的8520亿美元估值遭投资者质疑', 'https://36kr.com/newsflashes/3766176130646790?f=rss', 'https://36kr.com/feed', '据报道，随着OpenAI将战略重心转向企业市场，并着手应对来自Anthropic的竞争，其高达8520亿美元的估值正受到其自身投资者的审视。部分OpenAI投资者透露，尽管该公司正筹备最早于今年进行首次公开​​募股（IPO），但上述战略调整恐使其在面对Anthropic以及势头回升的谷歌时，处于较为脆弱的境地。（界面）', '', '', '', '', '{\'title\': \'随着战略转向，OpenAI的8520亿美元估值遭投资者质疑\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'随着战略转向，OpenAI的8520亿美元估值遭投资者质疑\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766176130646790?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766176130646790?f=rss\', \'published\': \'2026-04-14 12:44:22  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=4, tm_min=44, tm_sec=22, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'据报道，随着OpenAI将战略重心转向企业市场，并着手应对来自Anthropic的竞争，其高达8520亿美元的估值正受到其自身投资者的审视。部分OpenAI投资者透露，尽管该公司正筹备最早于今年进行首次公开\\u200b\\u200b募股（IPO），但上述战略调整恐使其在面对Anthropic以及势头回升的谷歌时，处于较为脆弱的境地。（界面）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'据报道，随着OpenAI将战略重心转向企业市场，并着手应对来自Anthropic的竞争，其高达8520亿美元的估值正受到其自身投资者的审视。部分OpenAI投资者透露，尽管该公司正筹备最早于今年进行首次公开\\u200b\\u200b募股（IPO），但上述战略调整恐使其在面对Anthropic以及势头回升的谷歌时，处于较为脆弱的境地。（界面）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 12:44:22', '2026-04-14 14:12:29', 0, '\"\"');
