INSERT INTO `news` VALUES (436, '离境退税2.0版措施预计4月底前推出', 'https://36kr.com/newsflashes/3766182161974020?f=rss', 'https://36kr.com/feed', '4月14日在第六届消博会期间获悉，离境退税2.0版措施目前正在报批过程中，预计4月底前推出（中证网）', '', '', '', '', '{\'title\': \'离境退税2.0版措施预计4月底前推出\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'离境退税2.0版措施预计4月底前推出\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766182161974020?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766182161974020?f=rss\', \'published\': \'2026-04-14 12:38:36  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=4, tm_min=38, tm_sec=36, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'4月14日在第六届消博会期间获悉，离境退税2.0版措施目前正在报批过程中，预计4月底前推出（中证网）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'4月14日在第六届消博会期间获悉，离境退税2.0版措施目前正在报批过程中，预计4月底前推出（中证网）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 12:38:36', '2026-04-14 14:13:03', 1, '{\"summary\": \"本文披露离境退税2.0版措施预计4月底前推出，帮助跨境消费相关出海企业提前掌握政策动态\", \"abstract\": \"4月14日，该消息在第六届消博会期间对外披露。离境退税2.0版措施目前正处于报批流程中，预计将于4月底前推出。政策升级将利好离境跨境消费相关业务，相关出海企业可关注后续落地进展\", \"keywords\": [\"离境退税\", \"离境退税2.0\", \"财税政策\", \"消博会\", \"跨境消费\", \"出海\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"离境退税2.0版措施正在报批，预计4月底前推出，属于离境消费领域的财税升级政策\"}, \"topic_cluster\": \"财税\", \"industry_category\": \"跨境电商\"}');
INSERT INTO `news` VALUES (437, '千问上线表格Agent：对话直接生成、编辑Excel文件', 'https://36kr.com/newsflashes/3766175978979843?f=rss', 'https://36kr.com/feed', '自去年底升级文档和PPT处理能力后，千问进一步将能力延伸至结构化数据生成。4月14日，千问上线“表格Agent”，支持在对话中直接生成、编辑Excel文件。用户可以要求千问检索信息后生成表格，也可以将多轮对话内容整理为表格，或基于图片、文件生成。系统通常可在1–2分钟内输出可下载的Excel文件，无需二次复制粘贴，并支持通过自然语言进行修改。', '', '', '', '', '{\'title\': \'千问上线表格Agent：对话直接生成、编辑Excel文件\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'千问上线表格Agent：对话直接生成、编辑Excel文件\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766175978979843?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766175978979843?f=rss\', \'published\': \'2026-04-14 12:32:19  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=4, tm_min=32, tm_sec=19, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'自去年底升级文档和PPT处理能力后，千问进一步将能力延伸至结构化数据生成。4月14日，千问上线“表格Agent”，支持在对话中直接生成、编辑Excel文件。用户可以要求千问检索信息后生成表格，也可以将多轮对话内容整理为表格，或基于图片、文件生成。系统通常可在1–2分钟内输出可下载的Excel文件，无需二次复制粘贴，并支持通过自然语言进行修改。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'自去年底升级文档和PPT处理能力后，千问进一步将能力延伸至结构化数据生成。4月14日，千问上线“表格Agent”，支持在对话中直接生成、编辑Excel文件。用户可以要求千问检索信息后生成表格，也可以将多轮对话内容整理为表格，或基于图片、文件生成。系统通常可在1–2分钟内输出可下载的Excel文件，无需二次复制粘贴，并支持通过自然语言进行修改。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 12:32:19', '2026-04-14 14:13:07', 0, '\"\"');
