INSERT INTO `news` VALUES (442, '半日主力资金加仓电子板块，抛售医药生物板块', 'https://36kr.com/newsflashes/3766147624616710?f=rss', 'https://36kr.com/feed', '主力资金早间净流入电子、电力设备、通信等板块，净流出医药生物、交通运输、基础化工等板块。具体到个股来看，沪电股份、工业富联、佰维存储获净流入22.58亿元、20.62亿元、19.51亿元。净流出方面，华工科技、北方稀土、永鼎科技遭抛售11.14亿元、7.56亿元、5.04亿元。（第一财经）', '', '', '', '', '{\'title\': \'半日主力资金加仓电子板块，抛售医药生物板块\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'半日主力资金加仓电子板块，抛售医药生物板块\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766147624616710?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766147624616710?f=rss\', \'published\': \'2026-04-14 12:13:24  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=4, tm_min=13, tm_sec=24, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'主力资金早间净流入电子、电力设备、通信等板块，净流出医药生物、交通运输、基础化工等板块。具体到个股来看，沪电股份、工业富联、佰维存储获净流入22.58亿元、20.62亿元、19.51亿元。净流出方面，华工科技、北方稀土、永鼎科技遭抛售11.14亿元、7.56亿元、5.04亿元。（第一财经）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'主力资金早间净流入电子、电力设备、通信等板块，净流出医药生物、交通运输、基础化工等板块。具体到个股来看，沪电股份、工业富联、佰维存储获净流入22.58亿元、20.62亿元、19.51亿元。净流出方面，华工科技、北方稀土、永鼎科技遭抛售11.14亿元、7.56亿元、5.04亿元。（第一财经）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 12:13:24', '2026-04-14 14:13:15', 0, '\"\"');
INSERT INTO `news` VALUES (443, '国务院关于同意海南藏族自治州建设国家可持续发展议程创新示范区的批复', 'http://www.gov.cn/zhengce/content/2022-07/15/content_5701205.htm', 'https://www.gov.cn/jsonTag/tp/rss.xml\n', '', '', '', '', '', '{\'title\': \'国务院关于同意海南藏族自治州建设国家可持续发展议程创新示范区的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意海南藏族自治州建设国家可持续发展议程创新示范区的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-07/15/content_5701205.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-07/15/content_5701205.htm\', \'published\': \'Mon, 06 Dec 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=12, tm_mday=6, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=0, tm_yday=340, tm_isdst=0)}', '2021-12-06 16:00:00', '2026-04-14 14:13:17', 0, '\"\"');
INSERT INTO `news` VALUES (444, '恒大集团、恒大地产及许家印案一审开庭', 'https://36kr.com/newsflashes/3766153730409225?f=rss', 'https://36kr.com/feed', '2026年4月13日至14日，广东省深圳市中级人民法院对深圳市人民检察院提起公诉的被告单位恒大集团有限公司非法吸收公众存款、集资诈骗、违法发放贷款、欺诈发行证券、违规披露重要信息、单位行贿，被告单位恒大地产集团有限公司欺诈发行证券，被告人许家印非法吸收公众存款、集资诈骗、违法发放贷款、违法运用资金、欺诈发行证券、违规披露重要信息、职务侵占、单位行贿一案进行了公开开庭审理。庭审中，法庭主持控辩双方围绕指控的事实进行了法庭调查及法庭辩论，被告单位、许家印进行了最后陈述。许家印当庭表示认罪悔罪。法庭将择期宣判。（央视新闻）', '', '', '', '', '{\'title\': \'恒大集团、恒大地产及许家印案一审开庭\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'恒大集团、恒大地产及许家印案一审开庭\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766153730409225?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766153730409225?f=rss\', \'published\': \'2026-04-14 12:09:41  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=4, tm_min=9, tm_sec=41, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'2026年4月13日至14日，广东省深圳市中级人民法院对深圳市人民检察院提起公诉的被告单位恒大集团有限公司非法吸收公众存款、集资诈骗、违法发放贷款、欺诈发行证券、违规披露重要信息、单位行贿，被告单位恒大地产集团有限公司欺诈发行证券，被告人许家印非法吸收公众存款、集资诈骗、违法发放贷款、违法运用资金、欺诈发行证券、违规披露重要信息、职务侵占、单位行贿一案进行了公开开庭审理。庭审中，法庭主持控辩双方围绕指控的事实进行了法庭调查及法庭辩论，被告单位、许家印进行了最后陈述。许家印当庭表示认罪悔罪。法庭将择期宣判。（央视新闻）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'2026年4月13日至14日，广东省深圳市中级人民法院对深圳市人民检察院提起公诉的被告单位恒大集团有限公司非法吸收公众存款、集资诈骗、违法发放贷款、欺诈发行证券、违规披露重要信息、单位行贿，被告单位恒大地产集团有限公司欺诈发行证券，被告人许家印非法吸收公众存款、集资诈骗、违法发放贷款、违法运用资金、欺诈发行证券、违规披露重要信息、职务侵占、单位行贿一案进行了公开开庭审理。庭审中，法庭主持控辩双方围绕指控的事实进行了法庭调查及法庭辩论，被告单位、许家印进行了最后陈述。许家印当庭表示认罪悔罪。法庭将择期宣判。（央视新闻）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 12:09:41', '2026-04-14 14:13:19', 0, '\"\"');
