INSERT INTO `news` VALUES (446, '恒指午间休盘涨0.43%，恒生科技指数涨0.17%', 'https://36kr.com/newsflashes/3766146235073029?f=rss', 'https://36kr.com/feed', '36氪获悉，恒指午间休盘涨0.43%，恒生科技指数涨0.17%；耐用消费品、半导体、软件服务板块领涨，泡泡玛特涨超6%，百度集团涨超3%，华虹半导体涨超2%；汽车、医药生物、能源板块走弱，理想汽车、中石化油服跌超2%，百济神州跌超1%；南向资金净买入7.89亿港元。', '', '', '', '', '{\'title\': \'恒指午间休盘涨0.43%，恒生科技指数涨0.17%\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'恒指午间休盘涨0.43%，恒生科技指数涨0.17%\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766146235073029?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766146235073029?f=rss\', \'published\': \'2026-04-14 12:02:03  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=4, tm_min=2, tm_sec=3, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，恒指午间休盘涨0.43%，恒生科技指数涨0.17%；耐用消费品、半导体、软件服务板块领涨，泡泡玛特涨超6%，百度集团涨超3%，华虹半导体涨超2%；汽车、医药生物、能源板块走弱，理想汽车、中石化油服跌超2%，百济神州跌超1%；南向资金净买入7.89亿港元。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'36氪获悉，恒指午间休盘涨0.43%，恒生科技指数涨0.17%；耐用消费品、半导体、软件服务板块领涨，泡泡玛特涨超6%，百度集团涨超3%，华虹半导体涨超2%；汽车、医药生物、能源板块走弱，理想汽车、中石化油服跌超2%，百济神州跌超1%；南向资金净买入7.89亿港元。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 12:02:03', '2026-04-14 14:13:22', 0, '\"\"');
