INSERT INTO `news` VALUES (448, '快看漫画将研发多款AI应用，涉及AI角色互动等', 'https://36kr.com/newsflashes/3766119271449346?f=rss', 'https://36kr.com/feed', '36氪获悉，4月14日，快看漫画内部正在推进不止一款App，而是一组围绕AI能力展开的多款App组成的产品矩阵。该AI应用矩阵可能覆盖多个用户需求与使用场景，涉及AI角色互动、开放世界、破次元陪伴等维度。', '', '', '', '', '{\'title\': \'快看漫画将研发多款AI应用，涉及AI角色互动等\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'快看漫画将研发多款AI应用，涉及AI角色互动等\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766119271449346?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766119271449346?f=rss\', \'published\': \'2026-04-14 11:44:32  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=3, tm_min=44, tm_sec=32, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，4月14日，快看漫画内部正在推进不止一款App，而是一组围绕AI能力展开的多款App组成的产品矩阵。该AI应用矩阵可能覆盖多个用户需求与使用场景，涉及AI角色互动、开放世界、破次元陪伴等维度。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'36氪获悉，4月14日，快看漫画内部正在推进不止一款App，而是一组围绕AI能力展开的多款App组成的产品矩阵。该AI应用矩阵可能覆盖多个用户需求与使用场景，涉及AI角色互动、开放世界、破次元陪伴等维度。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 11:44:32', '2026-04-14 14:13:27', 0, '\"\"');
INSERT INTO `news` VALUES (449, 'A股三大指数午间休盘集体上涨，半导体板块走强', 'https://36kr.com/newsflashes/3766117037326851?f=rss', 'https://36kr.com/feed', '36氪获悉，A股三大指数午间休盘集体上涨，沪指涨0.55%，深成指涨1.36%。创业板指涨2.13%；电脑硬件、半导体、通信设备板块领涨，协创数据涨停，长光华芯涨超17%，联特科技涨超4%；能源、林木、餐饮旅游板块走弱，泰山石油跌超4%，福建金森跌超2%，首旅酒店跌超1%。', '', '', '', '', '{\'title\': \'A股三大指数午间休盘集体上涨，半导体板块走强\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'A股三大指数午间休盘集体上涨，半导体板块走强\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766117037326851?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766117037326851?f=rss\', \'published\': \'2026-04-14 11:32:21  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=3, tm_min=32, tm_sec=21, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，A股三大指数午间休盘集体上涨，沪指涨0.55%，深成指涨1.36%。创业板指涨2.13%；电脑硬件、半导体、通信设备板块领涨，协创数据涨停，长光华芯涨超17%，联特科技涨超4%；能源、林木、餐饮旅游板块走弱，泰山石油跌超4%，福建金森跌超2%，首旅酒店跌超1%。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'36氪获悉，A股三大指数午间休盘集体上涨，沪指涨0.55%，深成指涨1.36%。创业板指涨2.13%；电脑硬件、半导体、通信设备板块领涨，协创数据涨停，长光华芯涨超17%，联特科技涨超4%；能源、林木、餐饮旅游板块走弱，泰山石油跌超4%，福建金森跌超2%，首旅酒店跌超1%。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 11:32:21', '2026-04-14 14:13:30', 0, '\"\"');
INSERT INTO `news` VALUES (450, '报告：欧洲消费者在速卖通的年花费增速达25%', 'https://36kr.com/newsflashes/3766108299936521?f=rss', 'https://36kr.com/feed', '36氪获悉，尼尔森发布《2026出海品牌平台迁移白皮书》指出，品牌出海重心正从亚马逊向以速卖通为首的中国平台迁移。数据显示，欧洲消费者在速卖通的年花费增速达25%；品牌侧，亚马逊GMV下滑4%，速卖通以4%增速领涨“出海四小龙”。30%的欧洲消费者视速卖通为“最有可能挑战亚马逊”的平台，认知度居首。', '', '', '', '', '{\'title\': \'报告：欧洲消费者在速卖通的年花费增速达25%\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'报告：欧洲消费者在速卖通的年花费增速达25%\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766108299936521?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766108299936521?f=rss\', \'published\': \'2026-04-14 11:23:28  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=3, tm_min=23, tm_sec=28, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，尼尔森发布《2026出海品牌平台迁移白皮书》指出，品牌出海重心正从亚马逊向以速卖通为首的中国平台迁移。数据显示，欧洲消费者在速卖通的年花费增速达25%；品牌侧，亚马逊GMV下滑4%，速卖通以4%增速领涨“出海四小龙”。30%的欧洲消费者视速卖通为“最有可能挑战亚马逊”的平台，认知度居首。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'36氪获悉，尼尔森发布《2026出海品牌平台迁移白皮书》指出，品牌出海重心正从亚马逊向以速卖通为首的中国平台迁移。数据显示，欧洲消费者在速卖通的年花费增速达25%；品牌侧，亚马逊GMV下滑4%，速卖通以4%增速领涨“出海四小龙”。30%的欧洲消费者视速卖通为“最有可能挑战亚马逊”的平台，认知度居首。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 11:23:28', '2026-04-14 14:13:56', 1, '{\"summary\": \"本文发布欧洲电商平台最新增长数据，帮助出海品牌把握平台格局变化，为出海销售渠道选择提供参考\", \"abstract\": \"尼尔森发布《2026出海品牌平台迁移白皮书》指出，当前品牌出海重心正从亚马逊向以速卖通为首的中国平台迁移。数据显示，欧洲消费者在速卖通的年花费增速达25%。GMV层面，亚马逊GMV下滑4%，速卖通以4%增速领涨“出海四小龙”。三成欧洲消费者认为速卖通是最有可能挑战亚马逊的平台，其行业认知度居首位。\", \"keywords\": [\"品牌出海\", \"速卖通\", \"亚马逊\", \"欧洲市场\", \"平台迁移\", \"GMV\", \"出海四小龙\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"跨境电商\"}');
INSERT INTO `news` VALUES (451, '沪深京三市成交额突破2万亿', 'https://36kr.com/newsflashes/3766274273379073?f=rss', 'https://36kr.com/feed', '36氪获悉，沪深京三市成交额突破2万亿，较上日此时放量超1600亿。', '', '', '', '', '{\'title\': \'沪深京三市成交额突破2万亿\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'沪深京三市成交额突破2万亿\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766274273379073?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766274273379073?f=rss\', \'published\': \'2026-04-14 14:12:18  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=6, tm_min=12, tm_sec=18, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，沪深京三市成交额突破2万亿，较上日此时放量超1600亿。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'36氪获悉，沪深京三市成交额突破2万亿，较上日此时放量超1600亿。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 14:12:18', '2026-04-14 14:15:24', 0, '\"\"');
INSERT INTO `news` VALUES (452, '国开行一季度发放绿色贷款超1500亿元', 'https://36kr.com/newsflashes/3766283062067968?f=rss', 'https://36kr.com/feed', '记者4月14日从国家开发银行获悉，今年一季度，国开行发放绿色贷款超过1500亿元，全行绿色贷款在全部信贷资产中的占比进一步提升。（新华社）', '', '', '', '', '{\'title\': \'国开行一季度发放绿色贷款超1500亿元\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'国开行一季度发放绿色贷款超1500亿元\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766283062067968?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766283062067968?f=rss\', \'published\': \'2026-04-14 14:21:15  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=6, tm_min=21, tm_sec=15, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'记者4月14日从国家开发银行获悉，今年一季度，国开行发放绿色贷款超过1500亿元，全行绿色贷款在全部信贷资产中的占比进一步提升。（新华社）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'记者4月14日从国家开发银行获悉，今年一季度，国开行发放绿色贷款超过1500亿元，全行绿色贷款在全部信贷资产中的占比进一步提升。（新华社）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 14:21:15', '2026-04-14 14:24:40', 0, '\"\"');
INSERT INTO `news` VALUES (453, '“集市”的终结？当开源 AI 只剩下载：一项 280 万个仓库的实证研究揭示了什么', 'https://www.oschina.net/news/420715', 'https://www.oschina.net/news/rss', '当 Meta 发布 Llama、DeepSeek 开放 R1 权重时，整个技术社区都在欢呼AI 开源时代来了。但一个关键问题被忽略了：把模型权重挂到网上供人下载，就等于&quot;开源&quot;了吗？如果没有人能真正参与到模型的共同开发中，那这种&quot;开源&quot;与免费发放产品试用装之间，究竟有什么区别？ 在传统开源软件（OSS）的黄金年代，Eric Raymond 提出...', '', '', '', '', '{\'title\': \'“集市”的终结？当开源 AI 只剩下载：一项 280 万个仓库的实证研究揭示了什么\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'“集市”的终结？当开源 AI 只剩下载：一项 280 万个仓库的实证研究揭示了什么\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420715\'}], \'link\': \'https://www.oschina.net/news/420715\', \'tags\': [{\'term\': \'综合新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'当 Meta 发布 Llama、DeepSeek 开放 R1 权重时，整个技术社区都在欢呼AI 开源时代来了。但一个关键问题被忽略了：把模型权重挂到网上供人下载，就等于&quot;开源&quot;了吗？如果没有人能真正参与到模型的共同开发中，那这种&quot;开源&quot;与免费发放产品试用装之间，究竟有什么区别？ 在传统开源软件（OSS）的黄金年代，Eric Raymond 提出...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'当 Meta 发布 Llama、DeepSeek 开放 R1 权重时，整个技术社区都在欢呼AI 开源时代来了。但一个关键问题被忽略了：把模型权重挂到网上供人下载，就等于&quot;开源&quot;了吗？如果没有人能真正参与到模型的共同开发中，那这种&quot;开源&quot;与免费发放产品试用装之间，究竟有什么区别？ 在传统开源软件（OSS）的黄金年代，Eric Raymond 提出...\'}, \'published\': \'Tue, 14 Apr 2026 14:19:57 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=6, tm_min=19, tm_sec=57, tm_wday=1, tm_yday=104, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420715\', \'guidislink\': False}', '2026-04-14 14:19:57', '2026-04-14 14:25:11', 0, '\"\"');
INSERT INTO `news` VALUES (454, 'Seedance 2.0全面开放API服务', 'https://36kr.com/newsflashes/3766291549405705?f=rss', 'https://36kr.com/feed', '36氪获悉，火山引擎正式上线Seedance 2.0系列API服务。据介绍，Seedance 2.0支持文字、图片、音频、视频四种模态输入。火山引擎为Seedance 2.0建立了肖像与版权安全标准，覆盖视频生成涉及的各种模态和创作前后的全部流程。', '', '', '', '', '{\'title\': \'Seedance 2.0全面开放API服务\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'Seedance 2.0全面开放API服务\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766291549405705?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766291549405705?f=rss\', \'published\': \'2026-04-14 14:29:53  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=6, tm_min=29, tm_sec=53, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，火山引擎正式上线Seedance 2.0系列API服务。据介绍，Seedance 2.0支持文字、图片、音频、视频四种模态输入。火山引擎为Seedance 2.0建立了肖像与版权安全标准，覆盖视频生成涉及的各种模态和创作前后的全部流程。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'36氪获悉，火山引擎正式上线Seedance 2.0系列API服务。据介绍，Seedance 2.0支持文字、图片、音频、视频四种模态输入。火山引擎为Seedance 2.0建立了肖像与版权安全标准，覆盖视频生成涉及的各种模态和创作前后的全部流程。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 14:29:53', '2026-04-14 14:34:31', 0, '\"\"');
INSERT INTO `news` VALUES (455, '智元发布机器人应用部署平台 Genie Studio Agent', 'https://www.oschina.net/news/420717', 'https://www.oschina.net/news/rss', '智元宣布推出面向具身作业场景的零代码应用平台 —— Genie Studio Agent。一套贯穿机器人从开发到部署、从运行到优化的全生命周期软件基础设施，覆盖VLA模型、强化学习、视觉感知、运动控制、导航规划等核心能力。 平台搭载开箱即用的标准化解决方案，在底层技术SDK基础上，封装了直观的可视化界面与丰富的行业场景模板...', '', '', '', '', '{\'title\': \'智元发布机器人应用部署平台 Genie Studio Agent\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'智元发布机器人应用部署平台 Genie Studio Agent\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420717\'}], \'link\': \'https://www.oschina.net/news/420717\', \'tags\': [{\'term\': \'综合新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'智元宣布推出面向具身作业场景的零代码应用平台 —— Genie Studio Agent。一套贯穿机器人从开发到部署、从运行到优化的全生命周期软件基础设施，覆盖VLA模型、强化学习、视觉感知、运动控制、导航规划等核心能力。 平台搭载开箱即用的标准化解决方案，在底层技术SDK基础上，封装了直观的可视化界面与丰富的行业场景模板...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'智元宣布推出面向具身作业场景的零代码应用平台 —— Genie Studio Agent。一套贯穿机器人从开发到部署、从运行到优化的全生命周期软件基础设施，覆盖VLA模型、强化学习、视觉感知、运动控制、导航规划等核心能力。 平台搭载开箱即用的标准化解决方案，在底层技术SDK基础上，封装了直观的可视化界面与丰富的行业场景模板...\'}, \'published\': \'Tue, 14 Apr 2026 14:27:54 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=6, tm_min=27, tm_sec=54, tm_wday=1, tm_yday=104, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420717\', \'guidislink\': False}', '2026-04-14 14:27:54', '2026-04-14 14:47:36', 0, '\"\"');
