INSERT INTO `news` VALUES (459, '湖南能源集团等在长沙新设先进制造产业基金，出资额50亿元', 'https://36kr.com/newsflashes/3766306348368648?f=rss', 'https://36kr.com/feed', '36氪获悉，爱企查App显示，近日，长沙经济技术开发区先进制造产业基金合伙企业（有限合伙）成立，出资额50亿元人民币，经营范围包括以私募基金从事股权投资、投资管理、资产管理等活动。合伙人信息显示，该企业由湖南能源集团有限公司旗下湖南能源集团湘投私募基金管理有限公司、湖南湘投产业投资基金合伙企业（有限合伙）等共同出资。', '', '', '', '', '{\'title\': \'湖南能源集团等在长沙新设先进制造产业基金，出资额50亿元\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'湖南能源集团等在长沙新设先进制造产业基金，出资额50亿元\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766306348368648?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766306348368648?f=rss\', \'published\': \'2026-04-14 14:44:56  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=6, tm_min=44, tm_sec=56, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，爱企查App显示，近日，长沙经济技术开发区先进制造产业基金合伙企业（有限合伙）成立，出资额50亿元人民币，经营范围包括以私募基金从事股权投资、投资管理、资产管理等活动。合伙人信息显示，该企业由湖南能源集团有限公司旗下湖南能源集团湘投私募基金管理有限公司、湖南湘投产业投资基金合伙企业（有限合伙）等共同出资。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'36氪获悉，爱企查App显示，近日，长沙经济技术开发区先进制造产业基金合伙企业（有限合伙）成立，出资额50亿元人民币，经营范围包括以私募基金从事股权投资、投资管理、资产管理等活动。合伙人信息显示，该企业由湖南能源集团有限公司旗下湖南能源集团湘投私募基金管理有限公司、湖南湘投产业投资基金合伙企业（有限合伙）等共同出资。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 14:44:56', '2026-04-14 14:48:33', 0, '\"\"');
INSERT INTO `news` VALUES (460, '全球首个自动驾驶移动空间路线4月20日试运营', 'https://36kr.com/newsflashes/3766303122735620?f=rss', 'https://36kr.com/feed', '4月20日，全球首个“自动驾驶移动空间”路线——贵阳“奇遇环线”将正式启动试运营。该项目由贵阳高新区企业贵州翰凯斯智能技术有限公司联合合资公司贵州勘设泰宇坦行科技有限公司，在观山湖区启动商业化试点运营。这标志着该企业定义的“自动驾驶移动空间”品类从技术研发迈入城市级商业验证阶段。（贵阳晚报）', '', '', '', '', '{\'title\': \'全球首个自动驾驶移动空间路线4月20日试运营\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'全球首个自动驾驶移动空间路线4月20日试运营\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766303122735620?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766303122735620?f=rss\', \'published\': \'2026-04-14 14:41:39  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=6, tm_min=41, tm_sec=39, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'4月20日，全球首个“自动驾驶移动空间”路线——贵阳“奇遇环线”将正式启动试运营。该项目由贵阳高新区企业贵州翰凯斯智能技术有限公司联合合资公司贵州勘设泰宇坦行科技有限公司，在观山湖区启动商业化试点运营。这标志着该企业定义的“自动驾驶移动空间”品类从技术研发迈入城市级商业验证阶段。（贵阳晚报）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'4月20日，全球首个“自动驾驶移动空间”路线——贵阳“奇遇环线”将正式启动试运营。该项目由贵阳高新区企业贵州翰凯斯智能技术有限公司联合合资公司贵州勘设泰宇坦行科技有限公司，在观山湖区启动商业化试点运营。这标志着该企业定义的“自动驾驶移动空间”品类从技术研发迈入城市级商业验证阶段。（贵阳晚报）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 14:41:39', '2026-04-14 14:48:35', 0, '\"\"');
INSERT INTO `news` VALUES (461, 'BP发布首季交易更新：石油交易表现卓越，净债务预计上升', 'https://36kr.com/newsflashes/3766302044684805?f=rss', 'https://36kr.com/feed', '4月14日，BP发布2026年第一季度交易更新报告。报告显示，BP预计第一季度的石油交易结果将表现“卓越”。财务方面，由于营运资本预计出现40亿至70亿美元的显著增加，公司预计截至一季度末的净债务将从2025年底的220亿美元上升至250亿至270亿美元区间。（界面）', '', '', '', '', '{\'title\': \'BP发布首季交易更新：石油交易表现卓越，净债务预计上升\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'BP发布首季交易更新：石油交易表现卓越，净债务预计上升\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766302044684805?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766302044684805?f=rss\', \'published\': \'2026-04-14 14:40:33  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=6, tm_min=40, tm_sec=33, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'4月14日，BP发布2026年第一季度交易更新报告。报告显示，BP预计第一季度的石油交易结果将表现“卓越”。财务方面，由于营运资本预计出现40亿至70亿美元的显著增加，公司预计截至一季度末的净债务将从2025年底的220亿美元上升至250亿至270亿美元区间。（界面）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'4月14日，BP发布2026年第一季度交易更新报告。报告显示，BP预计第一季度的石油交易结果将表现“卓越”。财务方面，由于营运资本预计出现40亿至70亿美元的显著增加，公司预计截至一季度末的净债务将从2025年底的220亿美元上升至250亿至270亿美元区间。（界面）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 14:40:33', '2026-04-14 14:48:38', 0, '\"\"');
INSERT INTO `news` VALUES (462, '韩3月ICT出口额超435亿美元创新高', 'https://36kr.com/newsflashes/3766301331554821?f=rss', 'https://36kr.com/feed', '受人工智能（AI）热潮及半导体市场景气带动，韩国3月信息通信技术（ICT）产品出口额突破400亿美元，创下历史新高。韩国科学技术信息通信部14日发布的数据显示，3月ICT出口额为435.1亿美元，同比大增112%。ICT出口额连续14个月保持增长，也创下历史新高，在国家出口总额（861.3亿美元）中占比也高达50.5%。（新浪财经）', '', '', '', '', '{\'title\': \'韩3月ICT出口额超435亿美元创新高\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'韩3月ICT出口额超435亿美元创新高\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766301331554821?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766301331554821?f=rss\', \'published\': \'2026-04-14 14:39:50  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=6, tm_min=39, tm_sec=50, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'受人工智能（AI）热潮及半导体市场景气带动，韩国3月信息通信技术（ICT）产品出口额突破400亿美元，创下历史新高。韩国科学技术信息通信部14日发布的数据显示，3月ICT出口额为435.1亿美元，同比大增112%。ICT出口额连续14个月保持增长，也创下历史新高，在国家出口总额（861.3亿美元）中占比也高达50.5%。（新浪财经）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'受人工智能（AI）热潮及半导体市场景气带动，韩国3月信息通信技术（ICT）产品出口额突破400亿美元，创下历史新高。韩国科学技术信息通信部14日发布的数据显示，3月ICT出口额为435.1亿美元，同比大增112%。ICT出口额连续14个月保持增长，也创下历史新高，在国家出口总额（861.3亿美元）中占比也高达50.5%。（新浪财经）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 14:39:50', '2026-04-14 14:49:21', 1, '{\"summary\": \"本文为出海半导体、ICT相关企业提供韩国出口市场最新动态，帮助企业把握全球AI带动的行业需求趋势\", \"abstract\": \"韩国科学技术信息通信部发布了该国3月信息通信技术（ICT）产品的出口数据。受全球人工智能热潮与半导体市场景气带动，韩国3月ICT出口额达到435.1亿美元，同比大增112%，创下历史新高。韩国ICT出口已连续14个月保持增长，本次出口额占韩国全国总出口额的比例高达50.5%。\", \"keywords\": [\"韩国出口\", \"ICT出口\", \"半导体\", \"人工智能\", \"出口增长\", \"信息通信技术\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"半导体、信息通信\"}');
INSERT INTO `news` VALUES (463, '美团发布AI产品“小团健康管家”', 'https://36kr.com/newsflashes/3766298462831360?f=rss', 'https://36kr.com/feed', '36氪获悉，今日，在乌镇健康大会上，美团正式发布聚焦家庭健康管理的AI产品“小团健康管家”和全新付费会员服务“健康卡”。前者提供基础的问病问药、健康咨询服务，还支持家庭健康档案管理和体检报告智能解读。用户在对话中可跳转线上购药、在线问诊或预约线下就医。“健康卡”则提供超千款药品购药返现服务，其中原研药超过300款。', '', '', '', '', '{\'title\': \'美团发布AI产品“小团健康管家”\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'美团发布AI产品“小团健康管家”\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766298462831360?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766298462831360?f=rss\', \'published\': \'2026-04-14 14:36:55  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=6, tm_min=36, tm_sec=55, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，今日，在乌镇健康大会上，美团正式发布聚焦家庭健康管理的AI产品“小团健康管家”和全新付费会员服务“健康卡”。前者提供基础的问病问药、健康咨询服务，还支持家庭健康档案管理和体检报告智能解读。用户在对话中可跳转线上购药、在线问诊或预约线下就医。“健康卡”则提供超千款药品购药返现服务，其中原研药超过300款。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'36氪获悉，今日，在乌镇健康大会上，美团正式发布聚焦家庭健康管理的AI产品“小团健康管家”和全新付费会员服务“健康卡”。前者提供基础的问病问药、健康咨询服务，还支持家庭健康档案管理和体检报告智能解读。用户在对话中可跳转线上购药、在线问诊或预约线下就医。“健康卡”则提供超千款药品购药返现服务，其中原研药超过300款。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 14:36:55', '2026-04-14 14:49:23', 0, '\"\"');
