, 0, '\"\"');
INSERT INTO `news` VALUES (467, '全球最大零食店“零食王国”将于4月17日开业', 'https://36kr.com/newsflashes/3766433899037191?f=rss', 'https://36kr.com/feed-newsflash', '36氪获悉，由鸣鸣很忙集团创建的全球规模最大的沉浸式零食体验空间“零食王国”，将于4月17日在湖南长沙芙蓉广场正式开业。该项目拥有超1.2万㎡的零售与体验空间，汇聚了全球约70个国家和地区的风味、超过6500个国内外品牌及3.5万款商品。', '', '', '', '', '{\'title\': \'全球最大零食店“零食王国”将于4月17日开业\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'全球最大零食店“零食王国”将于4月17日开业\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766433899037191?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766433899037191?f=rss\', \'published\': \'2026-04-14 16:54:41  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=54, tm_sec=41, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，由鸣鸣很忙集团创建的全球规模最大的沉浸式零食体验空间“零食王国”，将于4月17日在湖南长沙芙蓉广场正式开业。该项目拥有超1.2万㎡的零售与体验空间，汇聚了全球约70个国家和地区的风味、超过6500个国内外品牌及3.5万款商品。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'36氪获悉，由鸣鸣很忙集团创建的全球规模最大的沉浸式零食体验空间“零食王国”，将于4月17日在湖南长沙芙蓉广场正式开业。该项目拥有超1.2万㎡的零售与体验空间，汇聚了全球约70个国家和地区的风味、超过6500个国内外品牌及3.5万款商品。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 16:54:41', '2026-04-14 17:00:52', 0, '\"\"');
INSERT INTO `news` VALUES (481, '别只盯着猪价，鸭子的价格，跌得更惨', 'https://36kr.com/p/3766331614393090?f=rss', 'https://36kr.com/feed-article', '<blockquote>\n   <p><strong>有人欢喜，有人愁。</strong></p>\n  </blockquote>\n  <p>猪肉，已经跌破5块钱一斤了，这价格比有些蔬菜还便宜。</p>\n  <p>但你可能想不到的是：<strong>鸭肉，比猪肉还便宜。</strong></p>\n  <p>《2025年水禽产业与技术发展报告》指出，2025年全国毛鸭全年平均价格7.60元/千克，同比下降13.31%。另据卓创资讯检测数据，3月鸭产品综合售价为6941元/吨，环比下跌3.85%。月内整体市场需求表现偏弱，价格端承压明显，整体缺乏明显利好支撑。其还预测4月毛鸭价格整体延续偏弱态势，以低位震荡运行为主。</p>\n  <p>这意味着，一只鸭子养大出栏，卖出的钱刨掉饲料、疫苗、人工、水电，养殖户兜里剩不下几毛钱，甚至还要倒贴。</p>\n  <p>一头猪赔几百块，一只鸭也挣不到几毛钱。养殖户“流血”出货，屠宰企业利润被压成纸片，上游环节正在为这场低价盛宴买单。</p>\n  <p>但产业链的另一头，却是另一番景象。</p>\n  <p>煌上煌、周黑鸭等卤味企业的财报里，净利增长百分之七八十，甚至翻倍。原材料成本降了，毛利率升了，账面上的数据也更好看了。</p>\n  <h2><strong>同样一只鸭子：上游烫手，下游却成了宝</strong></h2>\n  <p>煌上煌(002695.SZ)日前发布的业绩预告显示，2025年，公司归母净利润预计增长73.57%至123.16%。</p>\n  <p><strong>利润大幅增长背后，与原材料成本的红利有关。</strong></p>\n  <p>煌上煌的主要原材料有鸭翅、鸭脖、白条鸭等相关鸭副产品。2025年上半年，这些原料的市场价格处于低位。其中，鸭颈采购均价同比下降38.70%，一公斤便宜了3.77元；鸭翅下降&nbsp;21.35%，一公斤便宜了2.8元；鸭肫下降15.71%，一公斤便宜了3.34元；冻新鸭下降&nbsp;8.92%，一公斤便宜了2.22元。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_3667a98748eb455aa386ec51a5e3b824@5265833_oswg49242oswg666oswg356_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">△图片来源：煌上煌2025年半年报</p>\n  <p>这几块钱的降幅。对于一家年采购量成千上万吨的企业来说，就是真金白银的利润。2025&nbsp;年上半年，主要原材料价格的波动带来生产成本的下降，煌上煌酱卤肉制品业综合毛利率同比提升2.23个百分点。</p>\n  <p>周黑鸭（01458.HK）同样受惠于鸭价红利。年报显示，2025年，周黑鸭的净利同比增长59.60%至1.57亿元。这一年里，公司的整体销量增长14.60%至29977吨，但由于产品原材料成本下降叠加供应链效率优化，公司整体销售成本仅微增1.7%&nbsp;。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_ab2b3df074d14c649a9f1edde0d37bfe@5265833_oswg100051oswg746oswg416_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">△图片来源：周黑鸭2025年年报</p>\n  <p>鸭价红利对于下游企业来说，也是难得的采购窗口。在原材料价格处于低位时加大储备，能够锁定未来一段时间的成本优势。从实际动作来看，一些卤味企业也在有意识地加大采购力度。</p>\n  <p>周黑鸭披露，截至去年底，其经营活动所得现金净额减少至约人民币3.76亿元，主要是因为原材料价格下降，集团基于销量增加的预测考虑，增加了对存货的购买。</p>\n  <p>煌上煌也表示，公司贯彻主要原材料战略储备管理制度，行情低位时加大了采购力度。</p>\n  <p>对以鸭副产品为核心原料的下游餐饮企业来说，鸭货价的低位，无疑是一波成本红利。但这份红利，可能是建立在上游的利润挤压之上。&nbsp;</p>\n  <p>过去一年，肉鸭养殖屠宰端的亏损，已经显现。</p>\n  <p>就拿江苏益客食品(301116.SZ)来看。作为一家布局了肉鸡、肉鸭双产业链的农牧食品企业，益客食品的业务包含了肉禽行业产业链的多个环节，如饲料加工、种鸭原种培育、养殖、鸭/鸡苗孵化、屠宰、深加工、羽绒加工等，提供以鸡、鸭等不同家禽为原料的产品。</p>\n  <p>业绩预告显示，<strong>2025年益客食品的净利润预计亏损2.60亿元至2.90亿元，与2024年的盈利1亿元形成鲜明反差。</strong></p>\n  <p>对此，益客食品表示，这是因为肉鸭产业链屠宰、鸭苗等环节需求不及预期，产品价格降幅大于产品成本降幅，导致毛利大幅缩小。据其透露，2025年，公司的鸭产品毛利同比减少约2.2亿元，鸭苗毛利同比减少约2.7亿元，是整体毛利减少的主因。</p>\n  <p>益客食品不是个例。作为“鸭行业第一股”的华英农业（002321.SZ），长期为火锅、熟食连锁、商超、酒店、食品加工企业、消费者等多类客户供应鸭产品。</p>\n  <p>2025年，这家公司的归母净利润预计亏损4500万元至6500万元，上年还盈利3236.06万元，一年时间由盈转亏。</p>\n  <p>对此，华英农业解释，2025年，受市场价格波动等影响，公司产品毛利率较上年有所下降，部分资产出现减值，同时参股的菏泽益华种禽有限公司因禽苗价格同比大幅回落，确认的投资收益较上年大幅减少。</p>\n  <p>实际上，从去年上半年开始，华英农业就已经显露出疲态。当时公司就说过，肉鸭行业延续“低景气、弱需求”的市场格局，主要产品价格在低位区间波动。正因如此，公司的生鲜冻品销量同增10.95%，但由于市场价格下行，营业收入反降1.39%。</p>\n  <p><strong>卖得多了，赚得却少了——这大概是一些上游企业最扎心的写照。</strong></p>\n  <h2><strong>行业亏损数十亿，拐点还没出现</strong></h2>\n  <p>如果说上游的亏损只是个例，那就太小看这轮周期了。</p>\n  <p>近日，国家水禽产业技术体系产业经济岗位科学家刘灵芝在一场讲座上分析称，2025年我国肉鸭产业遭遇十年未遇的全产业链深度亏损，<strong>从种鸭、孵化、养殖到屠宰、加工全环节普遍陷入经营承压状态，行业亏损规模达数十亿元，创下近十年行业发展低谷。</strong></p>\n  <p>这不是某一家企业的问题，而是整个行业的问题。</p>\n  <p>为什么会出现这种情况？</p>\n  <p><strong>最核心的原因就是：供需的失衡。</strong></p>\n  <p>据国家水禽产业技术体系对全国23个水禽主产省（市、区）水禽生产情况的调查统计，2025年我国商品肉鸭出栏43.82亿只，较2024年增长3.86%。</p>\n  <p><strong>产能飙升，但需求增长的速度并没有跟上，供过于求的局面就不可避免。</strong></p>\n  <p>养殖行业通常有“禽随猪涨”的现象，出于肉类蛋白的替代作用，往往猪肉价格上涨的同时会带动禽肉价格上涨从而全产业链收入上调。如今生猪市场进入低谷期，禽类消费市场也呈现弱势。</p>\n  <p>今年3月底，生猪价格已跌到八年新低，海南等省份甚至不到4元/斤。中国养猪网监测显示，猪价已然跌破5元/斤，4月8日全国生猪（外三元）均价为9.49元/公斤，较前一日下跌0.14元/公斤，较上月下跌0.92元/公斤。</p>\n  <p>猪肉这么便宜，消费者自然会更愿意买猪肉——毕竟都是餐桌上的主流肉类。对肉鸭产业来说，这无疑是雪上加霜。</p>\n  <p>目前来看，鸭产品的价格还处于相对低位。而拐点，也远未出现。</p>\n  <p>据财联社报道，今年1月，山东白羽肉鸭行业资深人士徐高峰表示，2025年肉鸭产品价格低迷，小白条鸭产品在去年6月最低跌破4000元/吨的历史最低价位，加工端亏损现象严重。其认为，种鸭新产能已部分投产，大部分在2026年下半年会陆续出苗。</p>\n  <p>这意味着，未来一段时间内，供给端的压力可能会进一步加大，未来去产能过程较为残酷。</p>\n  <h2><strong>上游主动找出路：补链、出海、求变</strong></h2>\n  <p>产业整体不振的背景下，上游企业也在主动探索新的方向。</p>\n  <p>今年1月，益客食品表示，公司践行“一只鸭（鸡）价值最大化”理念，在禽肉深加工等业务环节持续补链强链，去年建成调理品、宠物食品原料车间各1个，现在建宠物食品原料车间1个，未来随着建成产能的释放及在建项目的落地，禽肉深加工业务规模将进一步扩大。</p>\n  <p>华英农业则把目光投向了更远的地方——海外市场。</p>\n  <p>截至去年上半年，该公司的鸭制产品已出口到日本、韩国、欧盟、加拿大、中国香港和中亚、中东等50多个国家和地区。通过出口和内销的统筹，更大化发挥产品的价值。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_72a1ed0ca68643999bd87d8d9f730612@5265833_oswg126526oswg1080oswg943_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">△图片来源：华英农业官网</p>\n  <p>对于去年上半年的业绩表现，华英农业表示，在市场竞争加剧的背景下，公司通过整合内部资源，借助产能利用率的稳定提升和产品出海力度的加大，保持了收入的基本稳定。其中，食品业务出口实现收入2.03亿元，同比增长6.56%，缓解了内销市场带来的压力。</p>\n  <p>华英农业仍在持续加码海外业务。去年10月，其子公司菏泽华运公司与国际业务部负责人及相关业务人员赴德国观展，拜访了欧洲市场客户，并且新增合作订单，为华英产品欧洲市场销售注入增长动能。</p>\n  <p>从历史经验来看，农产品大多难逃周期宿命，往往会遵循这样的发展规律：产能过剩，亏损，去产能，再回归盈利。肉鸭行业也不例外。</p>\n  <p>拐点何时来？没人能给出确切答案。但可以预见，这场上游流血、下游吃饱的戏码，或许还会再演一阵子。</p>\n  <p>而当鸭肉价格持续处于低位，整个行业离洗牌也就不远了。洗牌之后，活下来的，未必是最大的，但一定是最能扛、最懂变通的那一个。</p>\n  <p class=\"editor-note\">本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/1srDJaUA5GFZAjJsSYsO8A\" rel=\"noopener noreferrer\" target=\"_blank\">“红餐供应链指南”</a>，作者：专注餐饮供应链的，36氪经授权发布。</p>', '', '', '', '', '{\'title\': \'别只盯着猪价，鸭子的价格，跌得更惨\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'别只盯着猪价，鸭子的价格，跌得更惨\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3766331614393090?f=rss\'}], \'link\': \'https://36kr.com/p/3766331614393090?f=rss\', \'published\': \'2026-04-14 16:44:25  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=44, tm_sec=25, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'<blockquote>\\n   <p><strong>有人欢喜，有人愁。</strong></p>\\n  </blockquote>\\n  <p>猪肉，已经跌破5块钱一斤了，这价格比有些蔬菜还便宜。</p>\\n  <p>但你可能想不到的是：<strong>鸭肉，比猪肉还便宜。</strong></p>\\n  <p>《2025年水禽产业与技术发展报告》指出，2025年全国毛鸭全年平均价格7.60元/千克，同比下降13.31%。另据卓创资讯检测数据，3月鸭产品综合售价为6941元/吨，环比下跌3.85%。月内整体市场需求表现偏弱，价格端承压明显，整体缺乏明显利好支撑。其还预测4月毛鸭价格整体延续偏弱态势，以低位震荡运行为主。</p>\\n  <p>这意味着，一只鸭子养大出栏，卖出的钱刨掉饲料、疫苗、人工、水电，养殖户兜里剩不下几毛钱，甚至还要倒贴。</p>\\n  <p>一头猪赔几百块，一只鸭也挣不到几毛钱。养殖户“流血”出货，屠宰企业利润被压成纸片，上游环节正在为这场低价盛宴买单。</p>\\n  <p>但产业链的另一头，却是另一番景象。</p>\\n  <p>煌上煌、周黑鸭等卤味企业的财报里，净利增长百分之七八十，甚至翻倍。原材料成本降了，毛利率升了，账面上的数据也更好看了。</p>\\n  <h2><strong>同样一只鸭子：上游烫手，下游却成了宝</strong></h2>\\n  <p>煌上煌(002695.SZ)日前发布的业绩预告显示，2025年，公司归母净利润预计增长73.57%至123.16%。</p>\\n  <p><strong>利润大幅增长背后，与原材料成本的红利有关。</strong></p>\\n  <p>煌上煌的主要原材料有鸭翅、鸭脖、白条鸭等相关鸭副产品。2025年上半年，这些原料的市场价格处于低位。其中，鸭颈采购均价同比下降38.70%，一公斤便宜了3.77元；鸭翅下降&nbsp;21.35%，一公斤便宜了2.8元；鸭肫下降15.71%，一公斤便宜了3.34元；冻新鸭下降&nbsp;8.92%，一公斤便宜了2.22元。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_3667a98748eb455aa386ec51a5e3b824@5265833_oswg49242oswg666oswg356_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">△图片来源：煌上煌2025年半年报</p>\\n  <p>这几块钱的降幅。对于一家年采购量成千上万吨的企业来说，就是真金白银的利润。2025&nbsp;年上半年，主要原材料价格的波动带来生产成本的下降，煌上煌酱卤肉制品业综合毛利率同比提升2.23个百分点。</p>\\n  <p>周黑鸭（01458.HK）同样受惠于鸭价红利。年报显示，2025年，周黑鸭的净利同比增长59.60%至1.57亿元。这一年里，公司的整体销量增长14.60%至29977吨，但由于产品原材料成本下降叠加供应链效率优化，公司整体销售成本仅微增1.7%&nbsp;。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_ab2b3df074d14c649a9f1edde0d37bfe@5265833_oswg100051oswg746oswg416_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">△图片来源：周黑鸭2025年年报</p>\\n  <p>鸭价红利对于下游企业来说，也是难得的采购窗口。在原材料价格处于低位时加大储备，能够锁定未来一段时间的成本优势。从实际动作来看，一些卤味企业也在有意识地加大采购力度。</p>\\n  <p>周黑鸭披露，截至去年底，其经营活动所得现金净额减少至约人民币3.76亿元，主要是因为原材料价格下降，集团基于销量增加的预测考虑，增加了对存货的购买。</p>\\n  <p>煌上煌也表示，公司贯彻主要原材料战略储备管理制度，行情低位时加大了采购力度。</p>\\n  <p>对以鸭副产品为核心原料的下游餐饮企业来说，鸭货价的低位，无疑是一波成本红利。但这份红利，可能是建立在上游的利润挤压之上。&nbsp;</p>\\n  <p>过去一年，肉鸭养殖屠宰端的亏损，已经显现。</p>\\n  <p>就拿江苏益客食品(301116.SZ)来看。作为一家布局了肉鸡、肉鸭双产业链的农牧食品企业，益客食品的业务包含了肉禽行业产业链的多个环节，如饲料加工、种鸭原种培育、养殖、鸭/鸡苗孵化、屠宰、深加工、羽绒加工等，提供以鸡、鸭等不同家禽为原料的产品。</p>\\n  <p>业绩预告显示，<strong>2025年益客食品的净利润预计亏损2.60亿元至2.90亿元，与2024年的盈利1亿元形成鲜明反差。</strong></p>\\n  <p>对此，益客食品表示，这是因为肉鸭产业链屠宰、鸭苗等环节需求不及预期，产品价格降幅大于产品成本降幅，导致毛利大幅缩小。据其透露，2025年，公司的鸭产品毛利同比减少约2.2亿元，鸭苗毛利同比减少约2.7亿元，是整体毛利减少的主因。</p>\\n  <p>益客食品不是个例。作为“鸭行业第一股”的华英农业（002321.SZ），长期为火锅、熟食连锁、商超、酒店、食品加工企业、消费者等多类客户供应鸭产品。</p>\\n  <p>2025年，这家公司的归母净利润预计亏损4500万元至6500万元，上年还盈利3236.06万元，一年时间由盈转亏。</p>\\n  <p>对此，华英农业解释，2025年，受市场价格波动等影响，公司产品毛利率较上年有所下降，部分资产出现减值，同时参股的菏泽益华种禽有限公司因禽苗价格同比大幅回落，确认的投资收益较上年大幅减少。</p>\\n  <p>实际上，从去年上半年开始，华英农业就已经显露出疲态。当时公司就说过，肉鸭行业延续“低景气、弱需求”的市场格局，主要产品价格在低位区间波动。正因如此，公司的生鲜冻品销量同增10.95%，但由于市场价格下行，营业收入反降1.39%。</p>\\n  <p><strong>卖得多了，赚得却少了——这大概是一些上游企业最扎心的写照。</strong></p>\\n  <h2><strong>行业亏损数十亿，拐点还没出现</strong></h2>\\n  <p>如果说上游的亏损只是个例，那就太小看这轮周期了。</p>\\n  <p>近日，国家水禽产业技术体系产业经济岗位科学家刘灵芝在一场讲座上分析称，2025年我国肉鸭产业遭遇十年未遇的全产业链深度亏损，<strong>从种鸭、孵化、养殖到屠宰、加工全环节普遍陷入经营承压状态，行业亏损规模达数十亿元，创下近十年行业发展低谷。</strong></p>\\n  <p>这不是某一家企业的问题，而是整个行业的问题。</p>\\n  <p>为什么会出现这种情况？</p>\\n  <p><strong>最核心的原因就是：供需的失衡。</strong></p>\\n  <p>据国家水禽产业技术体系对全国23个水禽主产省（市、区）水禽生产情况的调查统计，2025年我国商品肉鸭出栏43.82亿只，较2024年增长3.86%。</p>\\n  <p><strong>产能飙升，但需求增长的速度并没有跟上，供过于求的局面就不可避免。</strong></p>\\n  <p>养殖行业通常有“禽随猪涨”的现象，出于肉类蛋白的替代作用，往往猪肉价格上涨的同时会带动禽肉价格上涨从而全产业链收入上调。如今生猪市场进入低谷期，禽类消费市场也呈现弱势。</p>\\n  <p>今年3月底，生猪价格已跌到八年新低，海南等省份甚至不到4元/斤。中国养猪网监测显示，猪价已然跌破5元/斤，4月8日全国生猪（外三元）均价为9.49元/公斤，较前一日下跌0.14元/公斤，较上月下跌0.92元/公斤。</p>\\n  <p>猪肉这么便宜，消费者自然会更愿意买猪肉——毕竟都是餐桌上的主流肉类。对肉鸭产业来说，这无疑是雪上加霜。</p>\\n  <p>目前来看，鸭产品的价格还处于相对低位。而拐点，也远未出现。</p>\\n  <p>据财联社报道，今年1月，山东白羽肉鸭行业资深人士徐高峰表示，2025年肉鸭产品价格低迷，小白条鸭产品在去年6月最低跌破4000元/吨的历史最低价位，加工端亏损现象严重。其认为，种鸭新产能已部分投产，大部分在2026年下半年会陆续出苗。</p>\\n  <p>这意味着，未来一段时间内，供给端的压力可能会进一步加大，未来去产能过程较为残酷。</p>\\n  <h2><strong>上游主动找出路：补链、出海、求变</strong></h2>\\n  <p>产业整体不振的背景下，上游企业也在主动探索新的方向。</p>\\n  <p>今年1月，益客食品表示，公司践行“一只鸭（鸡）价值最大化”理念，在禽肉深加工等业务环节持续补链强链，去年建成调理品、宠物食品原料车间各1个，现在建宠物食品原料车间1个，未来随着建成产能的释放及在建项目的落地，禽肉深加工业务规模将进一步扩大。</p>\\n  <p>华英农业则把目光投向了更远的地方——海外市场。</p>\\n  <p>截至去年上半年，该公司的鸭制产品已出口到日本、韩国、欧盟、加拿大、中国香港和中亚、中东等50多个国家和地区。通过出口和内销的统筹，更大化发挥产品的价值。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_72a1ed0ca68643999bd87d8d9f730612@5265833_oswg126526oswg1080oswg943_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">△图片来源：华英农业官网</p>\\n  <p>对于去年上半年的业绩表现，华英农业表示，在市场竞争加剧的背景下，公司通过整合内部资源，借助产能利用率的稳定提升和产品出海力度的加大，保持了收入的基本稳定。其中，食品业务出口实现收入2.03亿元，同比增长6.56%，缓解了内销市场带来的压力。</p>\\n  <p>华英农业仍在持续加码海外业务。去年10月，其子公司菏泽华运公司与国际业务部负责人及相关业务人员赴德国观展，拜访了欧洲市场客户，并且新增合作订单，为华英产品欧洲市场销售注入增长动能。</p>\\n  <p>从历史经验来看，农产品大多难逃周期宿命，往往会遵循这样的发展规律：产能过剩，亏损，去产能，再回归盈利。肉鸭行业也不例外。</p>\\n  <p>拐点何时来？没人能给出确切答案。但可以预见，这场上游流血、下游吃饱的戏码，或许还会再演一阵子。</p>\\n  <p>而当鸭肉价格持续处于低位，整个行业离洗牌也就不远了。洗牌之后，活下来的，未必是最大的，但一定是最能扛、最懂变通的那一个。</p>\\n  <p class=\"editor-note\">本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/1srDJaUA5GFZAjJsSYsO8A\" rel=\"noopener noreferrer\" target=\"_blank\">“红餐供应链指南”</a>，作者：专注餐饮供应链的，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<blockquote>\\n   <p><strong>有人欢喜，有人愁。</strong></p>\\n  </blockquote>\\n  <p>猪肉，已经跌破5块钱一斤了，这价格比有些蔬菜还便宜。</p>\\n  <p>但你可能想不到的是：<strong>鸭肉，比猪肉还便宜。</strong></p>\\n  <p>《2025年水禽产业与技术发展报告》指出，2025年全国毛鸭全年平均价格7.60元/千克，同比下降13.31%。另据卓创资讯检测数据，3月鸭产品综合售价为6941元/吨，环比下跌3.85%。月内整体市场需求表现偏弱，价格端承压明显，整体缺乏明显利好支撑。其还预测4月毛鸭价格整体延续偏弱态势，以低位震荡运行为主。</p>\\n  <p>这意味着，一只鸭子养大出栏，卖出的钱刨掉饲料、疫苗、人工、水电，养殖户兜里剩不下几毛钱，甚至还要倒贴。</p>\\n  <p>一头猪赔几百块，一只鸭也挣不到几毛钱。养殖户“流血”出货，屠宰企业利润被压成纸片，上游环节正在为这场低价盛宴买单。</p>\\n  <p>但产业链的另一头，却是另一番景象。</p>\\n  <p>煌上煌、周黑鸭等卤味企业的财报里，净利增长百分之七八十，甚至翻倍。原材料成本降了，毛利率升了，账面上的数据也更好看了。</p>\\n  <h2><strong>同样一只鸭子：上游烫手，下游却成了宝</strong></h2>\\n  <p>煌上煌(002695.SZ)日前发布的业绩预告显示，2025年，公司归母净利润预计增长73.57%至123.16%。</p>\\n  <p><strong>利润大幅增长背后，与原材料成本的红利有关。</strong></p>\\n  <p>煌上煌的主要原材料有鸭翅、鸭脖、白条鸭等相关鸭副产品。2025年上半年，这些原料的市场价格处于低位。其中，鸭颈采购均价同比下降38.70%，一公斤便宜了3.77元；鸭翅下降&nbsp;21.35%，一公斤便宜了2.8元；鸭肫下降15.71%，一公斤便宜了3.34元；冻新鸭下降&nbsp;8.92%，一公斤便宜了2.22元。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_3667a98748eb455aa386ec51a5e3b824@5265833_oswg49242oswg666oswg356_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">△图片来源：煌上煌2025年半年报</p>\\n  <p>这几块钱的降幅。对于一家年采购量成千上万吨的企业来说，就是真金白银的利润。2025&nbsp;年上半年，主要原材料价格的波动带来生产成本的下降，煌上煌酱卤肉制品业综合毛利率同比提升2.23个百分点。</p>\\n  <p>周黑鸭（01458.HK）同样受惠于鸭价红利。年报显示，2025年，周黑鸭的净利同比增长59.60%至1.57亿元。这一年里，公司的整体销量增长14.60%至29977吨，但由于产品原材料成本下降叠加供应链效率优化，公司整体销售成本仅微增1.7%&nbsp;。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_ab2b3df074d14c649a9f1edde0d37bfe@5265833_oswg100051oswg746oswg416_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">△图片来源：周黑鸭2025年年报</p>\\n  <p>鸭价红利对于下游企业来说，也是难得的采购窗口。在原材料价格处于低位时加大储备，能够锁定未来一段时间的成本优势。从实际动作来看，一些卤味企业也在有意识地加大采购力度。</p>\\n  <p>周黑鸭披露，截至去年底，其经营活动所得现金净额减少至约人民币3.76亿元，主要是因为原材料价格下降，集团基于销量增加的预测考虑，增加了对存货的购买。</p>\\n  <p>煌上煌也表示，公司贯彻主要原材料战略储备管理制度，行情低位时加大了采购力度。</p>\\n  <p>对以鸭副产品为核心原料的下游餐饮企业来说，鸭货价的低位，无疑是一波成本红利。但这份红利，可能是建立在上游的利润挤压之上。&nbsp;</p>\\n  <p>过去一年，肉鸭养殖屠宰端的亏损，已经显现。</p>\\n  <p>就拿江苏益客食品(301116.SZ)来看。作为一家布局了肉鸡、肉鸭双产业链的农牧食品企业，益客食品的业务包含了肉禽行业产业链的多个环节，如饲料加工、种鸭原种培育、养殖、鸭/鸡苗孵化、屠宰、深加工、羽绒加工等，提供以鸡、鸭等不同家禽为原料的产品。</p>\\n  <p>业绩预告显示，<strong>2025年益客食品的净利润预计亏损2.60亿元至2.90亿元，与2024年的盈利1亿元形成鲜明反差。</strong></p>\\n  <p>对此，益客食品表示，这是因为肉鸭产业链屠宰、鸭苗等环节需求不及预期，产品价格降幅大于产品成本降幅，导致毛利大幅缩小。据其透露，2025年，公司的鸭产品毛利同比减少约2.2亿元，鸭苗毛利同比减少约2.7亿元，是整体毛利减少的主因。</p>\\n  <p>益客食品不是个例。作为“鸭行业第一股”的华英农业（002321.SZ），长期为火锅、熟食连锁、商超、酒店、食品加工企业、消费者等多类客户供应鸭产品。</p>\\n  <p>2025年，这家公司的归母净利润预计亏损4500万元至6500万元，上年还盈利3236.06万元，一年时间由盈转亏。</p>\\n  <p>对此，华英农业解释，2025年，受市场价格波动等影响，公司产品毛利率较上年有所下降，部分资产出现减值，同时参股的菏泽益华种禽有限公司因禽苗价格同比大幅回落，确认的投资收益较上年大幅减少。</p>\\n  <p>实际上，从去年上半年开始，华英农业就已经显露出疲态。当时公司就说过，肉鸭行业延续“低景气、弱需求”的市场格局，主要产品价格在低位区间波动。正因如此，公司的生鲜冻品销量同增10.95%，但由于市场价格下行，营业收入反降1.39%。</p>\\n  <p><strong>卖得多了，赚得却少了——这大概是一些上游企业最扎心的写照。</strong></p>\\n  <h2><strong>行业亏损数十亿，拐点还没出现</strong></h2>\\n  <p>如果说上游的亏损只是个例，那就太小看这轮周期了。</p>\\n  <p>近日，国家水禽产业技术体系产业经济岗位科学家刘灵芝在一场讲座上分析称，2025年我国肉鸭产业遭遇十年未遇的全产业链深度亏损，<strong>从种鸭、孵化、养殖到屠宰、加工全环节普遍陷入经营承压状态，行业亏损规模达数十亿元，创下近十年行业发展低谷。</strong></p>\\n  <p>这不是某一家企业的问题，而是整个行业的问题。</p>\\n  <p>为什么会出现这种情况？</p>\\n  <p><strong>最核心的原因就是：供需的失衡。</strong></p>\\n  <p>据国家水禽产业技术体系对全国23个水禽主产省（市、区）水禽生产情况的调查统计，2025年我国商品肉鸭出栏43.82亿只，较2024年增长3.86%。</p>\\n  <p><strong>产能飙升，但需求增长的速度并没有跟上，供过于求的局面就不可避免。</strong></p>\\n  <p>养殖行业通常有“禽随猪涨”的现象，出于肉类蛋白的替代作用，往往猪肉价格上涨的同时会带动禽肉价格上涨从而全产业链收入上调。如今生猪市场进入低谷期，禽类消费市场也呈现弱势。</p>\\n  <p>今年3月底，生猪价格已跌到八年新低，海南等省份甚至不到4元/斤。中国养猪网监测显示，猪价已然跌破5元/斤，4月8日全国生猪（外三元）均价为9.49元/公斤，较前一日下跌0.14元/公斤，较上月下跌0.92元/公斤。</p>\\n  <p>猪肉这么便宜，消费者自然会更愿意买猪肉——毕竟都是餐桌上的主流肉类。对肉鸭产业来说，这无疑是雪上加霜。</p>\\n  <p>目前来看，鸭产品的价格还处于相对低位。而拐点，也远未出现。</p>\\n  <p>据财联社报道，今年1月，山东白羽肉鸭行业资深人士徐高峰表示，2025年肉鸭产品价格低迷，小白条鸭产品在去年6月最低跌破4000元/吨的历史最低价位，加工端亏损现象严重。其认为，种鸭新产能已部分投产，大部分在2026年下半年会陆续出苗。</p>\\n  <p>这意味着，未来一段时间内，供给端的压力可能会进一步加大，未来去产能过程较为残酷。</p>\\n  <h2><strong>上游主动找出路：补链、出海、求变</strong></h2>\\n  <p>产业整体不振的背景下，上游企业也在主动探索新的方向。</p>\\n  <p>今年1月，益客食品表示，公司践行“一只鸭（鸡）价值最大化”理念，在禽肉深加工等业务环节持续补链强链，去年建成调理品、宠物食品原料车间各1个，现在建宠物食品原料车间1个，未来随着建成产能的释放及在建项目的落地，禽肉深加工业务规模将进一步扩大。</p>\\n  <p>华英农业则把目光投向了更远的地方——海外市场。</p>\\n  <p>截至去年上半年，该公司的鸭制产品已出口到日本、韩国、欧盟、加拿大、中国香港和中亚、中东等50多个国家和地区。通过出口和内销的统筹，更大化发挥产品的价值。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_72a1ed0ca68643999bd87d8d9f730612@5265833_oswg126526oswg1080oswg943_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">△图片来源：华英农业官网</p>\\n  <p>对于去年上半年的业绩表现，华英农业表示，在市场竞争加剧的背景下，公司通过整合内部资源，借助产能利用率的稳定提升和产品出海力度的加大，保持了收入的基本稳定。其中，食品业务出口实现收入2.03亿元，同比增长6.56%，缓解了内销市场带来的压力。</p>\\n  <p>华英农业仍在持续加码海外业务。去年10月，其子公司菏泽华运公司与国际业务部负责人及相关业务人员赴德国观展，拜访了欧洲市场客户，并且新增合作订单，为华英产品欧洲市场销售注入增长动能。</p>\\n  <p>从历史经验来看，农产品大多难逃周期宿命，往往会遵循这样的发展规律：产能过剩，亏损，去产能，再回归盈利。肉鸭行业也不例外。</p>\\n  <p>拐点何时来？没人能给出确切答案。但可以预见，这场上游流血、下游吃饱的戏码，或许还会再演一阵子。</p>\\n  <p>而当鸭肉价格持续处于低位，整个行业离洗牌也就不远了。洗牌之后，活下来的，未必是最大的，但一定是最能扛、最懂变通的那一个。</p>\\n  <p class=\"editor-note\">本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/1srDJaUA5GFZAjJsSYsO8A\" rel=\"noopener noreferrer\" target=\"_blank\">“红餐供应链指南”</a>，作者：专注餐饮供应链的，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'红餐网\'}], \'author\': \'红餐网\', \'author_detail\': {\'name\': \'红餐网\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'拐点还要等多久？\'}]}', '2026-04-14 16:44:25', '2026-04-14 17:01:37', 1, '{\"summary\": \"本文分析国内肉鸭行业周期现状，可为有意出海拓展市场的农牧食品上游企业提供行业参考，了解出海破局的实践路径\", \"abstract\": \"2025年国内肉鸭行业供过于求价格大跌，上游养殖屠宰全环节亏损数十亿元，陷入十年低谷，下游卤味企业则享受原材料成本红利实现利润大幅增长。行业低迷核心原因是产能增长快于需求，叠加猪价低位消费者更多选择猪肉，进一步挤压肉鸭需求。目前行业拐点尚未到来，未来一段时间供给压力仍将加大，去产能过程残酷。国内肉鸭上游企业主动求变，华英农业通过加码产品出海，拓展五十多个海外市场，对冲了内销市场压力\", \"keywords\": [\"产品出海\", \"肉鸭行业\", \"供需失衡\", \"全产业链亏损\", \"成本红利\", \"行业周期\", \"农牧出海\"], \"policy_risk\": {\"market_risk\": \"国内肉鸭行业供过于求，上游养殖屠宰全环节普遍亏损，猪价低位加剧消费替代压力，未来供给压力仍将持续，内销价格长期低位承压，行业正处于残酷洗牌周期\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察, 供应链\", \"industry_category\": \"农牧食品\"}');
INSERT INTO `news` VALUES (483, '徐少春的金蝶还能飞多久', 'https://36kr.com/p/3766266911158791?f=rss', 'https://36kr.com/feed-article', '<p>徐少春又在喊口号了。</p>\n  <p><strong>“AI将再造一个金蝶“、“五年翻倍”这话听着耳熟不</strong>？</p>\n  <p>三年前他说“云将再造一个金蝶”，结果五年烧穿14亿利润，把过去十几年赚的钱全赔进去，差点把自己烧成了“金蝉”。</p>\n  <h2><strong>从“账海无边”到“亏损无底”</strong></h2>\n  <p>1993年，徐少春从毛阿敏的《思念》里找到灵感，给公司起名“金蝶”。</p>\n  <p>那时候他骑着自行车跑客户，揣着360块钱南下深圳，确实是个狠人。</p>\n  <p>但江湖规矩是：打江山容易，守江山难。转型更难。</p>\n  <p>2020年，金蝶云服务收入占比首次过半，徐少春激动得像是找到了第二春。</p>\n  <p>结果呢？当年归母净利润直接从正3.73亿变成-3.35亿，一口气连亏五年，累计亏掉13.78亿</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_fbce1e0dde0a432199e70a8d96927838@19837264_oswg44478oswg1080oswg494_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">（图源：金蝶 2020 全年业绩公布）</p>\n  <p><strong>传统ERP是“一锤子买卖”，签一单收一单的钱，现金流稳如老狗。</strong></p>\n  <p><strong>云订阅是“分期付款”，收入被拉长到每年每月，但研发、销售、实施的投入却要一次性砸出去。</strong></p>\n  <p><strong>金蝶为了抢市场，销售费用飙到27.26亿，管理费用21.41亿，两项吃掉近50亿，营收才70亿，利润直接被生吞活剥</strong>。</p>\n  <p>这就好比：你原来卖的是现房，一手交钱一手交房；现在改卖期房，还得自己垫资盖楼，客户还都是信用记录堪忧的散户。</p>\n  <p>这生意能做？</p>\n  <h2><strong>“AI再造金蝶”？先问问大模型答不答应</strong></h2>\n  <p>徐少春现在把宝押在AI上，口号喊得震天响。</p>\n  <p>但问题是：AI不是金蝶的护城河，而是它的掘墓人。</p>\n  <p>通用大模型越来越强，企业稍微懂点技术，就能自己做报表、做分析、做流程自动化。</p>\n  <p><strong>金蝶的核心价值：流程封装、数据归集、标准化管理</strong>，</p>\n  <p>正在被AI��速拆解。</p>\n  <p>以前企业买ERP是因为\"不会搞\"，现在AI让“不会搞”变成了“很容易搞”。</p>\n  <p>金蝶的AI更像是PPT生成器。对外宣传“AI嵌入全流程、代码生成率高”，但客户真实反馈是：能用，但不刚需；有亮点，但不值钱。</p>\n  <p>AI没能带来显著溢价，也没拉开与用友、泛微的差距，反而变成了“大家都有的标配”。</p>\n  <p><strong>这就好比：</strong></p>\n  <p><strong>你本来卖的是瑞士军刀，现在别人都在用电动工具，你却在军刀上刻了个“智能芯片”故事讲得越响，越显得没有底牌</strong>。</p>\n  <h2><strong>征信罚单虽小，杀伤力极大</strong></h2>\n  <p>2025年11月，央行深圳分行给金蝶征信开了张4.4万的罚单。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_1fc19a7c88a54ab491ce12f7a39b85c0@19837264_oswg81614oswg912oswg396_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>钱不多，但侮辱性极强。</p>\n  <p><strong>金蝶一直讲“企业数据+信用+金融”的故事，征信是闭环关键一环。</strong></p>\n  <p><strong>现在直接被监管锤“违规”，说明数据治理、合规体系存在漏洞。</strong></p>\n  <p><strong>更麻烦的是，小贷业务被曝疑似出租牌照、通道业务，在监管严打“牌照租借、无序放贷”的背景下，这相当于把最有想象空间的第二增长曲线，做成了高危灰色地带</strong>。</p>\n  <p>徐少春喜欢谈“致良知”，但监管部门显然不认同他的“良知”定义。</p>\n  <p><strong>2025年财报一出，金蝶宣布“扭亏为盈”归母净利润9300万，经调整利润2.32亿</strong>。</p>\n  <p>但这盈利靠的是控费用、砍项目、压缩投入，不是商业模式真正跑通。一旦重新加大投入抢市场，亏损随时卷土重来。</p>\n  <p>所以利好一出，股价不涨反跌，机构纷纷下调目标价。</p>\n  <p>资本市场用脚投票：他们不是看空云与AI，是看空金蝶的战略定力、执行能力和盈利逻辑。</p>\n  <h2><strong>牛刀小结：止血不等于重生</strong></h2>\n  <p>徐少春是个有情怀的人。他砸电脑、砸服务器、砸ERP，三次\"砸\"出自己的转型决心；他谈“致良知”、谈“走正道”、谈“行王道”，确实想做个有价值观的企业家。</p>\n  <p>但商业世界不讲情怀，讲现金流、讲LTV/CAC、讲护城河。</p>\n  <p>金蝶这五年，是把转型当运动，把烧钱当增长，把口号当战略。</p>\n  <p>云与AI都不是错，错的是以为只要切换赛道，就能无视商业常识。</p>\n  <p>中小企业为主的客户结构，决定了高销售费用、低留存、低溢价是长期宿命；封闭的生态体系，与AI时代“开放互通”的大势背道而驰。</p>\n  <p><strong>2025年的“扭亏”，更像一次紧急止血，而非重生。</strong></p>\n  <p><strong>五年烧掉14亿，换来云收入占比82.5%，看似转型成功，实则把自己拖进了盈利难、壁垒弱、风险高的死胡同</strong>。</p>\n  <p>徐少春说还要再干30年。</p>\n  <p>但愿下一个30年，他能少喊点口号，多做点实事。</p>\n  <p>毕竟，蝴蝶飞得过沧海，不是因为口号响亮，而是因为翅膀够硬。</p>\n  <p>本文来自微信公众号“牛刀财经”（ID：niudaocaijing），作者：刘一鸣，36氪经授权发布。</p>', '', '', '', '', '{\'title\': \'徐少春的金蝶还能飞多久\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'徐少春的金蝶还能飞多久\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3766266911158791?f=rss\'}], \'link\': \'https://36kr.com/p/3766266911158791?f=rss\', \'published\': \'2026-04-14 16:44:12  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=44, tm_sec=12, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'<p>徐少春又在喊口号了。</p>\\n  <p><strong>“AI将再造一个金蝶“、“五年翻倍”这话听着耳熟不</strong>？</p>\\n  <p>三年前他说“云将再造一个金蝶”，结果五年烧穿14亿利润，把过去十几年赚的钱全赔进去，差点把自己烧成了“金蝉”。</p>\\n  <h2><strong>从“账海无边”到“亏损无底”</strong></h2>\\n  <p>1993年，徐少春从毛阿敏的《思念》里找到灵感，给公司起名“金蝶”。</p>\\n  <p>那时候他骑着自行车跑客户，揣着360块钱南下深圳，确实是个狠人。</p>\\n  <p>但江湖规矩是：打江山容易，守江山难。转型更难。</p>\\n  <p>2020年，金蝶云服务收入占比首次过半，徐少春激动得像是找到了第二春。</p>\\n  <p>结果呢？当年归母净利润直接从正3.73亿变成-3.35亿，一口气连亏五年，累计亏掉13.78亿</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_fbce1e0dde0a432199e70a8d96927838@19837264_oswg44478oswg1080oswg494_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">（图源：金蝶 2020 全年业绩公布）</p>\\n  <p><strong>传统ERP是“一锤子买卖”，签一单收一单的钱，现金流稳如老狗。</strong></p>\\n  <p><strong>云订阅是“分期付款”，收入被拉长到每年每月，但研发、销售、实施的投入却要一次性砸出去。</strong></p>\\n  <p><strong>金蝶为了抢市场，销售费用飙到27.26亿，管理费用21.41亿，两项吃掉近50亿，营收才70亿，利润直接被生吞活剥</strong>。</p>\\n  <p>这就好比：你原来卖的是现房，一手交钱一手交房；现在改卖期房，还得自己垫资盖楼，客户还都是信用记录堪忧的散户。</p>\\n  <p>这生意能做？</p>\\n  <h2><strong>“AI再造金蝶”？先问问大模型答不答应</strong></h2>\\n  <p>徐少春现在把宝押在AI上，口号喊得震天响。</p>\\n  <p>但问题是：AI不是金蝶的护城河，而是它的掘墓人。</p>\\n  <p>通用大模型越来越强，企业稍微懂点技术，就能自己做报表、做分析、做流程自动化。</p>\\n  <p><strong>金蝶的核心价值：流程封装、数据归集、标准化管理</strong>，</p>\\n  <p>正在被AI��速拆解。</p>\\n  <p>以前企业买ERP是因为\"不会搞\"，现在AI让“不会搞”变成了“很容易搞”。</p>\\n  <p>金蝶的AI更像是PPT生成器。对外宣传“AI嵌入全流程、代码生成率高”，但客户真实反馈是：能用，但不刚需；有亮点，但不值钱。</p>\\n  <p>AI没能带来显著溢价，也没拉开与用友、泛微的差距，反而变成了“大家都有的标配”。</p>\\n  <p><strong>这就好比：</strong></p>\\n  <p><strong>你本来卖的是瑞士军刀，现在别人都在用电动工具，你却在军刀上刻了个“智能芯片”故事讲得越响，越显得没有底牌</strong>。</p>\\n  <h2><strong>征信罚单虽小，杀伤力极大</strong></h2>\\n  <p>2025年11月，央行深圳分行给金蝶征信开了张4.4万的罚单。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_1fc19a7c88a54ab491ce12f7a39b85c0@19837264_oswg81614oswg912oswg396_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>钱不多，但侮辱性极强。</p>\\n  <p><strong>金蝶一直讲“企业数据+信用+金融”的故事，征信是闭环关键一环。</strong></p>\\n  <p><strong>现在直接被监管锤“违规”，说明数据治理、合规体系存在漏洞。</strong></p>\\n  <p><strong>更麻烦的是，小贷业务被曝疑似出租牌照、通道业务，在监管严打“牌照租借、无序放贷”的背景下，这相当于把最有想象空间的第二增长曲线，做成了高危灰色地带</strong>。</p>\\n  <p>徐少春喜欢谈“致良知”，但监管部门显然不认同他的“良知”定义。</p>\\n  <p><strong>2025年财报一出，金蝶宣布“扭亏为盈”归母净利润9300万，经调整利润2.32亿</strong>。</p>\\n  <p>但这盈利靠的是控费用、砍项目、压缩投入，不是商业模式真正跑通。一旦重新加大投入抢市场，亏损随时卷土重来。</p>\\n  <p>所以利好一出，股价不涨反跌，机构纷纷下调目标价。</p>\\n  <p>资本市场用脚投票：他们不是看空云与AI，是看空金蝶的战略定力、执行能力和盈利逻辑。</p>\\n  <h2><strong>牛刀小结：止血不等于重生</strong></h2>\\n  <p>徐少春是个有情怀的人。他砸电脑、砸服务器、砸ERP，三次\"砸\"出自己的转型决心；他谈“致良知”、谈“走正道”、谈“行王道”，确实想做个有价值观的企业家。</p>\\n  <p>但商业世界不讲情怀，讲现金流、讲LTV/CAC、讲护城河。</p>\\n  <p>金蝶这五年，是把转型当运动，把烧钱当增长，把口号当战略。</p>\\n  <p>云与AI都不是错，错的是以为只要切换赛道，就能无视商业常识。</p>\\n  <p>中小企业为主的客户结构，决定了高销售费用、低留存、低溢价是长期宿命；封闭的生态体系，与AI时代“开放互通”的大势背道而驰。</p>\\n  <p><strong>2025年的“扭亏”，更像一次紧急止血，而非重生。</strong></p>\\n  <p><strong>五年烧掉14亿，换来云收入占比82.5%，看似转型成功，实则把自己拖进了盈利难、壁垒弱、风险高的死胡同</strong>。</p>\\n  <p>徐少春说还要再干30年。</p>\\n  <p>但愿下一个30年，他能少喊点口号，多做点实事。</p>\\n  <p>毕竟，蝴蝶飞得过沧海，不是因为口号响亮，而是因为翅膀够硬。</p>\\n  <p>本文来自微信公众号“牛刀财经”（ID：niudaocaijing），作者：刘一鸣，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>徐少春又在喊口号了。</p>\\n  <p><strong>“AI将再造一个金蝶“、“五年翻倍”这话听着耳熟不</strong>？</p>\\n  <p>三年前他说“云将再造一个金蝶”，结果五年烧穿14亿利润，把过去十几年赚的钱全赔进去，差点把自己烧成了“金蝉”。</p>\\n  <h2><strong>从“账海无边”到“亏损无底”</strong></h2>\\n  <p>1993年，徐少春从毛阿敏的《思念》里找到灵感，给公司起名“金蝶”。</p>\\n  <p>那时候他骑着自行车跑客户，揣着360块钱南下深圳，确实是个狠人。</p>\\n  <p>但江湖规矩是：打江山容易，守江山难。转型更难。</p>\\n  <p>2020年，金蝶云服务收入占比首次过半，徐少春激动得像是找到了第二春。</p>\\n  <p>结果呢？当年归母净利润直接从正3.73亿变成-3.35亿，一口气连亏五年，累计亏掉13.78亿</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_fbce1e0dde0a432199e70a8d96927838@19837264_oswg44478oswg1080oswg494_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">（图源：金蝶 2020 全年业绩公布）</p>\\n  <p><strong>传统ERP是“一锤子买卖”，签一单收一单的钱，现金流稳如老狗。</strong></p>\\n  <p><strong>云订阅是“分期付款”，收入被拉长到每年每月，但研发、销售、实施的投入却要一次性砸出去。</strong></p>\\n  <p><strong>金蝶为了抢市场，销售费用飙到27.26亿，管理费用21.41亿，两项吃掉近50亿，营收才70亿，利润直接被生吞活剥</strong>。</p>\\n  <p>这就好比：你原来卖的是现房，一手交钱一手交房；现在改卖期房，还得自己垫资盖楼，客户还都是信用记录堪忧的散户。</p>\\n  <p>这生意能做？</p>\\n  <h2><strong>“AI再造金蝶”？先问问大模型答不答应</strong></h2>\\n  <p>徐少春现在把宝押在AI上，口号喊得震天响。</p>\\n  <p>但问题是：AI不是金蝶的护城河，而是它的掘墓人。</p>\\n  <p>通用大模型越来越强，企业稍微懂点技术，就能自己做报表、做分析、做流程自动化。</p>\\n  <p><strong>金蝶的核心价值：流程封装、数据归集、标准化管理</strong>，</p>\\n  <p>正在被AI��速拆解。</p>\\n  <p>以前企业买ERP是因为\"不会搞\"，现在AI让“不会搞”变成了“很容易搞”。</p>\\n  <p>金蝶的AI更像是PPT生成器。对外宣传“AI嵌入全流程、代码生成率高”，但客户真实反馈是：能用，但不刚需；有亮点，但不值钱。</p>\\n  <p>AI没能带来显著溢价，也没拉开与用友、泛微的差距，反而变成了“大家都有的标配”。</p>\\n  <p><strong>这就好比：</strong></p>\\n  <p><strong>你本来卖的是瑞士军刀，现在别人都在用电动工具，你却在军刀上刻了个“智能芯片”故事讲得越响，越显得没有底牌</strong>。</p>\\n  <h2><strong>征信罚单虽小，杀伤力极大</strong></h2>\\n  <p>2025年11月，央行深圳分行给金蝶征信开了张4.4万的罚单。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_1fc19a7c88a54ab491ce12f7a39b85c0@19837264_oswg81614oswg912oswg396_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>钱不多，但侮辱性极强。</p>\\n  <p><strong>金蝶一直讲“企业数据+信用+金融”的故事，征信是闭环关键一环。</strong></p>\\n  <p><strong>现在直接被监管锤“违规”，说明数据治理、合规体系存在漏洞。</strong></p>\\n  <p><strong>更麻烦的是，小贷业务被曝疑似出租牌照、通道业务，在监管严打“牌照租借、无序放贷”的背景下，这相当于把最有想象空间的第二增长曲线，做成了高危灰色地带</strong>。</p>\\n  <p>徐少春喜欢谈“致良知”，但监管部门显然不认同他的“良知”定义。</p>\\n  <p><strong>2025年财报一出，金蝶宣布“扭亏为盈”归母净利润9300万，经调整利润2.32亿</strong>。</p>\\n  <p>但这盈利靠的是控费用、砍项目、压缩投入，不是商业模式真正跑通。一旦重新加大投入抢市场，亏损随时卷土重来。</p>\\n  <p>所以利好一出，股价不涨反跌，机构纷纷下调目标价。</p>\\n  <p>资本市场用脚投票：他们不是看空云与AI，是看空金蝶的战略定力、执行能力和盈利逻辑。</p>\\n  <h2><strong>牛刀小结：止血不等于重生</strong></h2>\\n  <p>徐少春是个有情怀的人。他砸电脑、砸服务器、砸ERP，三次\"砸\"出自己的转型决心；他谈“致良知”、谈“走正道”、谈“行王道”，确实想做个有价值观的企业家。</p>\\n  <p>但商业世界不讲情怀，讲现金流、讲LTV/CAC、讲护城河。</p>\\n  <p>金蝶这五年，是把转型当运动，把烧钱当增长，把口号当战略。</p>\\n  <p>云与AI都不是错，错的是以为只要切换赛道，就能无视商业常识。</p>\\n  <p>中小企业为主的客户结构，决定了高销售费用、低留存、低溢价是长期宿命；封闭的生态体系，与AI时代“开放互通”的大势背道而驰。</p>\\n  <p><strong>2025年的“扭亏”，更像一次紧急止血，而非重生。</strong></p>\\n  <p><strong>五年烧掉14亿，换来云收入占比82.5%，看似转型成功，实则把自己拖进了盈利难、壁垒弱、风险高的死胡同</strong>。</p>\\n  <p>徐少春说还要再干30年。</p>\\n  <p>但愿下一个30年，他能少喊点口号，多做点实事。</p>\\n  <p>毕竟，蝴蝶飞得过沧海，不是因为口号响亮，而是因为翅膀够硬。</p>\\n  <p>本文来自微信公众号“牛刀财经”（ID：niudaocaijing），作者：刘一鸣，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'牛刀财经\'}], \'author\': \'牛刀财经\', \'author_detail\': {\'name\': \'牛刀财经\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'一场烧掉14亿的自我感动\'}]}', '2026-04-14 16:44:12', '2026-04-14 17:01:40', 0, '\"\"');
INSERT INTO `news` VALUES (484, 'AI短剧合规：不治是乱，治了是坎', 'https://36kr.com/p/3766230003991048?f=rss', 'https://36kr.com/feed-article', '<p>2026年4月，AI短剧《桃花簪》因侵犯肖像权遭遇素人维权，最终被平台全面下架。汉服博主“白菜汉服妆造”发现，该剧未经授权将其个人写真通过AI技术生成角色，容貌、服装完全一致。红果短剧平台迅速执行下架，并对制作方处以暂停上传作品15日的处罚。</p>\n  <p>此事迅速发酵，因AI换脸侵权从明星向普通人蔓延，直接触发了更广泛的舆论反弹。多位艺人接连发布声明维权，中国广播电视社会组织联合会演员委员会4月2日发布严正声明，直指AI换脸、声纹克隆等侵权乱象。</p>\n  <p>本次事件间接掀起了一场针对AI技术滥用边界的行业维权浪潮。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_bfd6246ee35c42398b92ace5ff07bc17@000000_oswg88961oswg1080oswg810_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">画面左侧为AI短剧内角色，右侧为博主 &nbsp;本图来自小红书博主“白菜汉服妆造”主页推文截屏 &nbsp;原帖“红果短剧《桃花簪》Ai侵犯肖像权”，编辑日期为3月31日</p>\n  <p>然而AI短剧的知识产权问题，本质是<strong>技术特性、成本结构和证据规则</strong>三者耦合的产物。以现有的观念讨论“如何合规”并无意义，盲目对AI短剧的“喊打喊杀”也解决不了问题。应该关注的是<strong>行业在既定约束条件下必然走向何处</strong>。</p>\n  <h2><strong>“可识别性”是核心标准，不是“长得像”这么简单</strong></h2>\n  <p>AI生成人脸的面部特征，必然落在人类面部分布的某个坐标上。任何一次生成，在概率上都可能与某个真实存在的人相似。<strong>这是技术必然，也是客观规律</strong>。</p>\n  <p>因此，<strong>仅就面部而言，区分“撞脸”与“盗脸”的分水岭，在于制作方的合理注意义务止于何处</strong>。</p>\n  <p>由于制作方对AI生成面部的具体结果<strong>缺乏精确控制能力</strong>，在非故意的前提下，几乎不可能预判生成结果会与哪张真实人脸相似，也<strong>无法确定</strong>AI在生成过程中是否参照了某个特定人物。</p>\n  <p>只有<strong>包括明星在内的具有一定知名度的公众人物</strong>的面部特征才具备普遍的可识别性，制作方有能力在提示词阶段预判并规避，或在生成后识别并替换。而素人的脸不具备这种普遍可识别性，不在制作方可预判的范围内。</p>\n  <p>要求AI短剧中不出现任何与真实自然人相似的面部，显然是强人所难。<strong>AI短剧合理注意义务的边界，应止于避开具有一定知名度的公众人物或特定的自然人。</strong></p>\n  <h2><strong>提示词的故意与技术巧合</strong></h2>\n  <p>如果说面部相似可以辩解为概率巧合，那么当<strong>服饰、妆造、构图等多个非面部维度</strong>同时锁定时，“随机生成”的抗辩在逻辑上便无法成立。</p>\n  <p><strong>判定故意的真正锚点，应是提示词的意图指向。</strong></p>\n  <p>当提示词为“丹凤眼、鹅蛋脸、清冷气质，唐制齐胸襦裙”时，制作者的意图是指向某一类型，而非特定个人。此时，制作方已尽到合理注意义务，如若生成结果中的面部相似，则应属于技术巧合。</p>\n  <p>但当提示词为<strong>“生成一个像某某某那样的角色”</strong>，或<strong>以特定人的照片作为图生图的输入底板</strong>时，意图便明确指向了特定人的整体视觉身份，构成故意侵权。</p>\n  <p><strong>服饰和妆造的证据意义也同样需要注意</strong>。</p>\n  <p>面部特征是模型基于概率的输出，制作方无法精确控制最终生成的面部具体样貌；<strong>但服饰款式、色彩搭配、妆容风格、光影氛围</strong>——这些元素及其组合是提示词可以相对精确控制的产物。</p>\n  <p>以《桃花簪》为例，被侵权的某博主被复刻的不仅是面部，更是其标志性的绿衣、黑帽等要素。当多个维度同时锁定，所谓“偶然生成”的抗辩在概率层面并不具备说服力。</p>\n  <h2><strong>AI短剧的合规困局：无中间路径，唯有隐蔽规避</strong></h2>\n  <p>前述所有法律边界和技术特征的讨论，最终都绕不开一个核心前提——成本</p>\n  <p>AI短剧本身作为一种低成本的商业模式，<strong>过高的授权费用将打破其固有的商业逻辑，颠覆AI短剧行业存在的合理性</strong>。对于部分AI短剧而言，合规不仅是“增加一点成本”，授权费甚至可能反超制作费，成本结构直接倒挂。</p>\n  <p><strong>此外，短剧的IP影响力相对有限，生命周期短</strong>。一部短剧的热度窗口往往只有数周甚至数天，若仅以“疑似侵权”为由临时下架，待争议澄清时，其商业价值可能已消耗殆尽。<strong>即便最终不构成侵权，下架本身对制作方造成的经济损失也是不可逆的</strong>。</p>\n  <p>在双重影响之下，“逐步规范、循序渐进”的中间状态似乎并不存在。如果严格执行合规标准，大量中小制作群体将难以承受，行业供给端的崩溃近在咫尺；如果维持现状，侵权问题将持续频发、难以遏制。</p>\n  <p><strong>AI短剧行业面临的是一个“进退维谷”的两难抉择。</strong></p>\n  <p>低成本、高产量是这个行业的核心竞争力，真正严格执行合规标准，供给端承受不了，但放任侵权的发生又显然违背法律规定与行业公序良俗。</p>\n  <p><strong>当下最可行的路径，并非一味追求“全面合规”，而是先明确划定AI肖像侵权的清晰红线，确定合理注意的范围</strong>；再结合AI生成技术的实际特性、行业成本现状，制定贴合实际、具备可操作性的规制方案，平衡行业生存与权利保护的边界。</p>\n  <p>本文来自微信公众号 <a href=\"https://mp.weixin.qq.com/s?__biz=MjM5NzU5ODEzNw==&amp;mid=2665452989&amp;idx=1&amp;sn=346af9d1f49301eaac37bbef3b9d48be&amp;chksm=bcc7c2c1d821b4ef646fe735fd559370b4aaed6f9158e62480551dfe89c040a0955f91c5fbb1&amp;scene=0&amp;xtrack=1#rd\" rel=\"noopener noreferrer\" target=\"_blank\">“知产力”（ID：zhichanli）</a>，作者：Edwin，36氪经授权发布。</p>', '', '', '', '', '{\'title\': \'AI短剧合规：不治是乱，治了是坎\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'AI短剧合规：不治是乱，治了是坎\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3766230003991048?f=rss\'}], \'link\': \'https://36kr.com/p/3766230003991048?f=rss\', \'published\': \'2026-04-14 16:43:33  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=43, tm_sec=33, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'<p>2026年4月，AI短剧《桃花簪》因侵犯肖像权遭遇素人维权，最终被平台全面下架。汉服博主“白菜汉服妆造”发现，该剧未经授权将其个人写真通过AI技术生成角色，容貌、服装完全一致。红果短剧平台迅速执行下架，并对制作方处以暂停上传作品15日的处罚。</p>\\n  <p>此事迅速发酵，因AI换脸侵权从明星向普通人蔓延，直接触发了更广泛的舆论反弹。多位艺人接连发布声明维权，中国广播电视社会组织联合会演员委员会4月2日发布严正声明，直指AI换脸、声纹克隆等侵权乱象。</p>\\n  <p>本次事件间接掀起了一场针对AI技术滥用边界的行业维权浪潮。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_bfd6246ee35c42398b92ace5ff07bc17@000000_oswg88961oswg1080oswg810_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">画面左侧为AI短剧内角色，右侧为博主 &nbsp;本图来自小红书博主“白菜汉服妆造”主页推文截屏 &nbsp;原帖“红果短剧《桃花簪》Ai侵犯肖像权”，编辑日期为3月31日</p>\\n  <p>然而AI短剧的知识产权问题，本质是<strong>技术特性、成本结构和证据规则</strong>三者耦合的产物。以现有的观念讨论“如何合规”并无意义，盲目对AI短剧的“喊打喊杀”也解决不了问题。应该关注的是<strong>行业在既定约束条件下必然走向何处</strong>。</p>\\n  <h2><strong>“可识别性”是核心标准，不是“长得像”这么简单</strong></h2>\\n  <p>AI生成人脸的面部特征，必然落在人类面部分布的某个坐标上。任何一次生成，在概率上都可能与某个真实存在的人相似。<strong>这是技术必然，也是客观规律</strong>。</p>\\n  <p>因此，<strong>仅就面部而言，区分“撞脸”与“盗脸”的分水岭，在于制作方的合理注意义务止于何处</strong>。</p>\\n  <p>由于制作方对AI生成面部的具体结果<strong>缺乏精确控制能力</strong>，在非故意的前提下，几乎不可能预判生成结果会与哪张真实人脸相似，也<strong>无法确定</strong>AI在生成过程中是否参照了某个特定人物。</p>\\n  <p>只有<strong>包括明星在内的具有一定知名度的公众人物</strong>的面部特征才具备普遍的可识别性，制作方有能力在提示词阶段预判并规避，或在生成后识别并替换。而素人的脸不具备这种普遍可识别性，不在制作方可预判的范围内。</p>\\n  <p>要求AI短剧中不出现任何与真实自然人相似的面部，显然是强人所难。<strong>AI短剧合理注意义务的边界，应止于避开具有一定知名度的公众人物或特定的自然人。</strong></p>\\n  <h2><strong>提示词的故意与技术巧合</strong></h2>\\n  <p>如果说面部相似可以辩解为概率巧合，那么当<strong>服饰、妆造、构图等多个非面部维度</strong>同时锁定时，“随机生成”的抗辩在逻辑上便无法成立。</p>\\n  <p><strong>判定故意的真正锚点，应是提示词的意图指向。</strong></p>\\n  <p>当提示词为“丹凤眼、鹅蛋脸、清冷气质，唐制齐胸襦裙”时，制作者的意图是指向某一类型，而非特定个人。此时，制作方已尽到合理注意义务，如若生成结果中的面部相似，则应属于技术巧合。</p>\\n  <p>但当提示词为<strong>“生成一个像某某某那样的角色”</strong>，或<strong>以特定人的照片作为图生图的输入底板</strong>时，意图便明确指向了特定人的整体视觉身份，构成故意侵权。</p>\\n  <p><strong>服饰和妆造的证据意义也同样需要注意</strong>。</p>\\n  <p>面部特征是模型基于概率的输出，制作方无法精确控制最终生成的面部具体样貌；<strong>但服饰款式、色彩搭配、妆容风格、光影氛围</strong>——这些元素及其组合是提示词可以相对精确控制的产物。</p>\\n  <p>以《桃花簪》为例，被侵权的某博主被复刻的不仅是面部，更是其标志性的绿衣、黑帽等要素。当多个维度同时锁定，所谓“偶然生成”的抗辩在概率层面并不具备说服力。</p>\\n  <h2><strong>AI短剧的合规困局：无中间路径，唯有隐蔽规避</strong></h2>\\n  <p>前述所有法律边界和技术特征的讨论，最终都绕不开一个核心前提——成本</p>\\n  <p>AI短剧本身作为一种低成本的商业模式，<strong>过高的授权费用将打破其固有的商业逻辑，颠覆AI短剧行业存在的合理性</strong>。对于部分AI短剧而言，合规不仅是“增加一点成本”，授权费甚至可能反超制作费，成本结构直接倒挂。</p>\\n  <p><strong>此外，短剧的IP影响力相对有限，生命周期短</strong>。一部短剧的热度窗口往往只有数周甚至数天，若仅以“疑似侵权”为由临时下架，待争议澄清时，其商业价值可能已消耗殆尽。<strong>即便最终不构成侵权，下架本身对制作方造成的经济损失也是不可逆的</strong>。</p>\\n  <p>在双重影响之下，“逐步规范、循序渐进”的中间状态似乎并不存在。如果严格执行合规标准，大量中小制作群体将难以承受，行业供给端的崩溃近在咫尺；如果维持现状，侵权问题将持续频发、难以遏制。</p>\\n  <p><strong>AI短剧行业面临的是一个“进退维谷”的两难抉择。</strong></p>\\n  <p>低成本、高产量是这个行业的核心竞争力，真正严格执行合规标准，供给端承受不了，但放任侵权的发生又显然违背法律规定与行业公序良俗。</p>\\n  <p><strong>当下最可行的路径，并非一味追求“全面合规”，而是先明确划定AI肖像侵权的清晰红线，确定合理注意的范围</strong>；再结合AI生成技术的实际特性、行业成本现状，制定贴合实际、具备可操作性的规制方案，平衡行业生存与权利保护的边界。</p>\\n  <p>本文来自微信公众号 <a href=\"https://mp.weixin.qq.com/s?__biz=MjM5NzU5ODEzNw==&amp;mid=2665452989&amp;idx=1&amp;sn=346af9d1f49301eaac37bbef3b9d48be&amp;chksm=bcc7c2c1d821b4ef646fe735fd559370b4aaed6f9158e62480551dfe89c040a0955f91c5fbb1&amp;scene=0&amp;xtrack=1#rd\" rel=\"noopener noreferrer\" target=\"_blank\">“知产力”（ID：zhichanli）</a>，作者：Edwin，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>2026年4月，AI短剧《桃花簪》因侵犯肖像权遭遇素人维权，最终被平台全面下架。汉服博主“白菜汉服妆造”发现，该剧未经授权将其个人写真通过AI技术生成角色，容貌、服装完全一致。红果短剧平台迅速执行下架，并对制作方处以暂停上传作品15日的处罚。</p>\\n  <p>此事迅速发酵，因AI换脸侵权从明星向普通人蔓延，直接触发了更广泛的舆论反弹。多位艺人接连发布声明维权，中国广播电视社会组织联合会演员委员会4月2日发布严正声明，直指AI换脸、声纹克隆等侵权乱象。</p>\\n  <p>本次事件间接掀起了一场针对AI技术滥用边界的行业维权浪潮。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_bfd6246ee35c42398b92ace5ff07bc17@000000_oswg88961oswg1080oswg810_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">画面左侧为AI短剧内角色，右侧为博主 &nbsp;本图来自小红书博主“白菜汉服妆造”主页推文截屏 &nbsp;原帖“红果短剧《桃花簪》Ai侵犯肖像权”，编辑日期为3月31日</p>\\n  <p>然而AI短剧的知识产权问题，本质是<strong>技术特性、成本结构和证据规则</strong>三者耦合的产物。以现有的观念讨论“如何合规”并无意义，盲目对AI短剧的“喊打喊杀”也解决不了问题。应该关注的是<strong>行业在既定约束条件下必然走向何处</strong>。</p>\\n  <h2><strong>“可识别性”是核心标准，不是“长得像”这么简单</strong></h2>\\n  <p>AI生成人脸的面部特征，必然落在人类面部分布的某个坐标上。任何一次生成，在概率上都可能与某个真实存在的人相似。<strong>这是技术必然，也是客观规律</strong>。</p>\\n  <p>因此，<strong>仅就面部而言，区分“撞脸”与“盗脸”的分水岭，在于制作方的合理注意义务止于何处</strong>。</p>\\n  <p>由于制作方对AI生成面部的具体结果<strong>缺乏精确控制能力</strong>，在非故意的前提下，几乎不可能预判生成结果会与哪张真实人脸相似，也<strong>无法确定</strong>AI在生成过程中是否参照了某个特定人物。</p>\\n  <p>只有<strong>包括明星在内的具有一定知名度的公众人物</strong>的面部特征才具备普遍的可识别性，制作方有能力在提示词阶段预判并规避，或在生成后识别并替换。而素人的脸不具备这种普遍可识别性，不在制作方可预判的范围内。</p>\\n  <p>要求AI短剧中不出现任何与真实自然人相似的面部，显然是强人所难。<strong>AI短剧合理注意义务的边界，应止于避开具有一定知名度的公众人物或特定的自然人。</strong></p>\\n  <h2><strong>提示词的故意与技术巧合</strong></h2>\\n  <p>如果说面部相似可以辩解为概率巧合，那么当<strong>服饰、妆造、构图等多个非面部维度</strong>同时锁定时，“随机生成”的抗辩在逻辑上便无法成立。</p>\\n  <p><strong>判定故意的真正锚点，应是提示词的意图指向。</strong></p>\\n  <p>当提示词为“丹凤眼、鹅蛋脸、清冷气质，唐制齐胸襦裙”时，制作者的意图是指向某一类型，而非特定个人。此时，制作方已尽到合理注意义务，如若生成结果中的面部相似，则应属于技术巧合。</p>\\n  <p>但当提示词为<strong>“生成一个像某某某那样的角色”</strong>，或<strong>以特定人的照片作为图生图的输入底板</strong>时，意图便明确指向了特定人的整体视觉身份，构成故意侵权。</p>\\n  <p><strong>服饰和妆造的证据意义也同样需要注意</strong>。</p>\\n  <p>面部特征是模型基于概率的输出，制作方无法精确控制最终生成的面部具体样貌；<strong>但服饰款式、色彩搭配、妆容风格、光影氛围</strong>——这些元素及其组合是提示词可以相对精确控制的产物。</p>\\n  <p>以《桃花簪》为例，被侵权的某博主被复刻的不仅是面部，更是其标志性的绿衣、黑帽等要素。当多个维度同时锁定，所谓“偶然生成”的抗辩在概率层面并不具备说服力。</p>\\n  <h2><strong>AI短剧的合规困局：无中间路径，唯有隐蔽规避</strong></h2>\\n  <p>前述所有法律边界和技术特征的讨论，最终都绕不开一个核心前提——成本</p>\\n  <p>AI短剧本身作为一种低成本的商业模式，<strong>过高的授权费用将打破其固有的商业逻辑，颠覆AI短剧行业存在的合理性</strong>。对于部分AI短剧而言，合规不仅是“增加一点成本”，授权费甚至可能反超制作费，成本结构直接倒挂。</p>\\n  <p><strong>此外，短剧的IP影响力相对有限，生命周期短</strong>。一部短剧的热度窗口往往只有数周甚至数天，若仅以“疑似侵权”为由临时下架，待争议澄清时，其商业价值可能已消耗殆尽。<strong>即便最终不构成侵权，下架本身对制作方造成的经济损失也是不可逆的</strong>。</p>\\n  <p>在双重影响之下，“逐步规范、循序渐进”的中间状态似乎并不存在。如果严格执行合规标准，大量中小制作群体将难以承受，行业供给端的崩溃近在咫尺；如果维持现状，侵权问题将持续频发、难以遏制。</p>\\n  <p><strong>AI短剧行业面临的是一个“进退维谷”的两难抉择。</strong></p>\\n  <p>低成本、高产量是这个行业的核心竞争力，真正严格执行合规标准，供给端承受不了，但放任侵权的发生又显然违背法律规定与行业公序良俗。</p>\\n  <p><strong>当下最可行的路径，并非一味追求“全面合规”，而是先明确划定AI肖像侵权的清晰红线，确定合理注意的范围</strong>；再结合AI生成技术的实际特性、行业成本现状，制定贴合实际、具备可操作性的规制方案，平衡行业生存与权利保护的边界。</p>\\n  <p>本文来自微信公众号 <a href=\"https://mp.weixin.qq.com/s?__biz=MjM5NzU5ODEzNw==&amp;mid=2665452989&amp;idx=1&amp;sn=346af9d1f49301eaac37bbef3b9d48be&amp;chksm=bcc7c2c1d821b4ef646fe735fd559370b4aaed6f9158e62480551dfe89c040a0955f91c5fbb1&amp;scene=0&amp;xtrack=1#rd\" rel=\"noopener noreferrer\" target=\"_blank\">“知产力”（ID：zhichanli）</a>，作者：Edwin，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'知产力\'}], \'author\': \'知产力\', \'author_detail\': {\'name\': \'知产力\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'一边是合规呼声高涨，一边是行业现实\'}]}', '2026-04-14 16:43:33', '2026-04-14 17:01:44', 0, '\"\"');
INSERT INTO `news` VALUES (488, '吴清会见马来西亚证券委员会主席拿督穆罕默德·法伊兹·阿兹米', 'https://36kr.com/newsflashes/3766431032115969?f=rss', 'https://36kr.com/feed-newsflash', '36氪获悉，4月9日，中国证监会主席吴清在京会见了马来西亚证券委员会主席拿督穆罕默德·法伊兹·阿兹米（Dato\' Mohammad Faiz Azmi）。双方就当前国际经济金融形势和进一步深化两国资本市场及证券期货监管机构之间务实合作交换了意见。', '', '', '', '', '{\'title\': \'吴清会见马来西亚证券委员会主席拿督穆罕默德·法伊兹·阿兹米\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'吴清会见马来西亚证券委员会主席拿督穆罕默德·法伊兹·阿兹米\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766431032115969?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766431032115969?f=rss\', \'published\': \'2026-04-14 16:51:46  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=51, tm_sec=46, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \"36氪获悉，4月9日，中国证监会主席吴清在京会见了马来西亚证券委员会主席拿督穆罕默德·法伊兹·阿兹米（Dato\' Mohammad Faiz Azmi）。双方就当前国际经济金融形势和进一步深化两国资本市场及证券期货监管机构之间务实合作交换了意见。\", \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \"36氪获悉，4月9日，中国证监会主席吴清在京会见了马来西亚证券委员会主席拿督穆罕默德·法伊兹·阿兹米（Dato\' Mohammad Faiz Azmi）。双方就当前国际经济金融形势和进一步深化两国资本市场及证券期货监管机构之间务实合作交换了意见。\"}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 16:51:46', '2026-04-14 17:01:58', 1, '{\"summary\": \"本文披露中马证券监管机构会面动向，为计划布局马来西亚的出海企业提供投融资环境参考\", \"abstract\": \"4月9日，中国证监会主席吴清在北京会见了马来西亚证券委员会主席。双方就当前国际经济金融形势交换意见，同时探讨深化两国资本市场及监管机构间的务实合作。此次会面释放中马资本市场合作加深的信号，将为两国企业跨境出海投融资提供更有利的基础\", \"keywords\": [\"中马合作\", \"资本市场\", \"证券监管\", \"跨境出海\", \"跨境投融资\", \"务实合作\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"跨境金融合作\", \"industry_category\": \"金融服务\"}');
INSERT INTO `news` VALUES (489, '乘联分会：3月份皮卡市场销售7万辆，同比增长11.7%', 'https://36kr.com/newsflashes/3766428284682758?f=rss', 'https://36kr.com/feed-newsflash', '36氪获悉，乘联分会数据显示，2026年3月份皮卡市场销售7万辆，同比增长11.7%，环比增长72.7%，处于近5年的高位水平。1-3月销量16.1万辆，增长7.6%。2026年3月份皮卡生产为6.8万辆，同比增长9.3%；26年1-3月皮卡生产16.2万辆，增长12.3%。', '', '', '', '', '{\'title\': \'乘联分会：3月份皮卡市场销售7万辆，同比增长11.7%\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'乘联分会：3月份皮卡市场销售7万辆，同比增长11.7%\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766428284682758?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766428284682758?f=rss\', \'published\': \'2026-04-14 16:48:58  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=48, tm_sec=58, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，乘联分会数据显示，2026年3月份皮卡市场销售7万辆，同比增长11.7%，环比增长72.7%，处于近5年的高位水平。1-3月销量16.1万辆，增长7.6%。2026年3月份皮卡生产为6.8万辆，同比增长9.3%；26年1-3月皮卡生产16.2万辆，增长12.3%。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'36氪获悉，乘联分会数据显示，2026年3月份皮卡市场销售7万辆，同比增长11.7%，环比增长72.7%，处于近5年的高位水平。1-3月销量16.1万辆，增长7.6%。2026年3月份皮卡生产为6.8万辆，同比增长9.3%；26年1-3月皮卡生产16.2万辆，增长12.3%。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 16:48:58', '2026-04-14 17:02:00', 0, '\"\"');
INSERT INTO `news` VALUES (491, '深交所将召开深市民企2025年度集体业绩说明会', 'https://36kr.com/newsflashes/3766426418905602?f=rss', 'https://36kr.com/feed-newsflash', '36氪获悉，深交所消息，4月20日，深交所将以“优创新激活力·谱写民企发展新篇章”为主题，组织召开深市民营上市公司集体业绩说明会，邀请英搏尔、金力永磁、强瑞技术、博实结等公司参加。', '', '', '', '', '{\'title\': \'深交所将召开深市民企2025年度集体业绩说明会\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'深交所将召开深市民企2025年度集体业绩说明会\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766426418905602?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766426418905602?f=rss\', \'published\': \'2026-04-14 16:47:04  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=47, tm_sec=4, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，深交所消息，4月20日，深交所将以“优创新激活力·谱写民企发展新篇章”为主题，组织召开深市民营上市公司集体业绩说明会，邀请英搏尔、金力永磁、强瑞技术、博实结等公司参加。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'36氪获悉，深交所消息，4月20日，深交所将以“优创新激活力·谱写民企发展新篇章”为主题，组织召开深市民营上市公司集体业绩说明会，邀请英搏尔、金力永磁、强瑞技术、博实结等公司参加。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 16:47:04', '2026-04-14 17:02:03', 0, '\"\"');
INSERT INTO `news` VALUES (493, '上期所：调整黄金等期货相关合约涨跌停板幅度和交易保证金比例', 'https://36kr.com/newsflashes/3766424039113224?f=rss', 'https://36kr.com/feed-newsflash', '36氪获悉，上海期货交易所发布通知，调整黄金等期货相关合约涨跌停板幅度和交易保证金比例。经研究决定，下述合约自上市时起，涨跌停板幅度和交易保证金比例调整如下：黄金AU2607合约的涨跌停板幅度为17%，套保持仓交易保证金比例为18%，一般持仓交易保证金比例为19%； 白银AG2704合约的涨跌停板幅度为20%，套保持仓交易保证金比例为21%，一般持仓交易保证金比例为22%。', '', '', '', '', '{\'title\': \'上期所：调整黄金等期货相关合约涨跌停板幅度和交易保证金比例\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'上期所：调整黄金等期货相关合约涨跌停板幅度和交易保证金比例\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766424039113224?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766424039113224?f=rss\', \'published\': \'2026-04-14 16:44:39  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=44, tm_sec=39, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，上海期货交易所发布通知，调整黄金等期货相关合约涨跌停板幅度和交易保证金比例。经研究决定，下述合约自上市时起，涨跌停板幅度和交易保证金比例调整如下：黄金AU2607合约的涨跌停板幅度为17%，套保持仓交易保证金比例为18%，一般持仓交易保证金比例为19%； 白银AG2704合约的涨跌停板幅度为20%，套保持仓交易保证金比例为21%，一般持仓交易保证金比例为22%。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'36氪获悉，上海期货交易所发布通知，调整黄金等期货相关合约涨跌停板幅度和交易保证金比例。经研究决定，下述合约自上市时起，涨跌停板幅度和交易保证金比例调整如下：黄金AU2607合约的涨跌停板幅度为17%，套保持仓交易保证金比例为18%，一般持仓交易保证金比例为19%； 白银AG2704合约的涨跌停板幅度为20%，套保持仓交易保证金比例为21%，一般持仓交易保证金比例为22%。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 16:44:39', '2026-04-14 17:02:06', 0, '\"\"');
INSERT INTO `news` VALUES (502, '成立四年冲击上市：思格新能源的增长神速与代价', 'https://36kr.com/p/3766173483840256?f=rss', 'https://36kr.com/feed-article', '<p>从注册成立到港交所挂牌，思格新能源就用了四年，有望成为港股近年来上市速度最快的中国科技企业。</p>\n  <p>4月16日，这家2022年5月才成立的公司将以6656为股票代码在港交所公开交易，IPO市值或将超过800亿港元。首日融资申购倍数超逾61倍，截至目前达到约815倍，预计申购倍数将超过1000倍。</p>\n  <p>四年是什么概念？大多数硬科技创业公司在这个阶段还在烧B轮的钱打磨下一代产品。思格2025年的营收是90亿人民币，净利润29.2亿，毛利率50.1%。2023年这三个数字则分别是5800万、负3.73亿、31.3%。<strong>如果只看增长曲线，这家公司堪称奇迹</strong>。</p>\n  <p>值得注意的是，这样的增长曲线诞生在储能内卷的周期里。同行毛利率普遍在二三十个点之间挣扎，思格的50%要么意味着它找到了一个定价权完全不同的市场位置，要么意味着这个数字背后有一定的“附加条件”。</p>\n  <p>从产品端看，思格做的事情在逻辑上不复杂：把光伏逆变器、储能电池、储能变流器、直流充电模块和能源管理系统塞进同一个箱子，五合一出厂，安装商不需要在现场拼接不同品牌的组件、调试协议兼容性。</p>\n  <p>在它之前，一套户储系统的安装是个需要多品牌适配、现场调试的工程活，思格把它变成了接近即插即用的消费品。这种产品也叫\"可堆叠光储一体机\"，思格按2024年出货量计在这个细分品类做到了全球第一，市场份额28.6%。</p>\n  <p>这套产品在澳大利亚踩中了一个难得的时间窗口，2025年7月，该国政府启动\"廉价家庭电池计划\"，为户储安装提供约三成补贴，半年内16万户家庭装上了电池。思格从拿到澳大利亚CEC认证到2025年3月做到月度市占率第一，只用了六个月，此后连续保持到年底；<strong>到2025年，光这一国市场就贡献了思格42.6%的收入</strong>。</p>\n  <p>但是，即便有着如此亮眼的增长曲线，他们三年的经营现金流依然全部为负，应收账款从3.6亿膨胀到31.6亿，存货从4.8亿堆到21.4亿，让29.2亿净利润没有一分钱变成经营现金。这不意味着增长是假的，只是一个真实的高增长同样需要被追问：<strong>最速上市和超高增长并非免费，要看清楚它的代价是什么</strong>。</p>\n  <h2><strong>01&nbsp; &nbsp;用做手机的思路做户储</strong></h2>\n  <p>营收三年增长超过154倍，质疑这种数字的真实性是最本能的反应。但拆开看，这个增长并不是凭空出现的：产品踩中了行业最突出的痛点，也押中了最合适它发挥市场。</p>\n  <p>思格创始人许映童，是能源圈非常知名的人物。据公开资料，他1999年加入华为，在通信领域工作了十年时间；2015年转岗至华为的光伏部门，2015 年带领华为光伏逆变器业务登顶全球出货量榜首，被称为是“主导华为逆变器七连冠”的核心人物。在他的团队中，有不少人都是电力和光伏行业的老兵。</p>\n  <p>一套传统的户用储能系统需要安装商，在现场拼接不同品牌的逆变器、电池、能量管理系统，调试协议兼容性，花半天时间才能让系统跑起来。这个痛点在国内还好说，换到国外就更加突出，人工成本在发达国家市场是大头，安装又高度依赖熟练人工，这类产品的渠道就很难铺开起量。</p>\n  <p>思格拳头产品SigenStor的做法是把五个环节的适配工作在工厂里完成，交给安装商的是一个开箱即装的成品。招股书披露，该产品的安装调试时间压缩到15分钟，一个安装商一天能覆盖的安装量大幅增加。模块化堆叠设计让用户可以按需扩容，不用一次性买到位，降低了首次购买的决策门槛；而对分销商来说，一个SKU覆盖从小户型到大户型的需求，库存管理的复杂度大幅降低。</p>\n  <p>产品定义对了，渠道扩张速度就大幅加快。SigenStor的出货量从18 MWh到447 MWh再到3947 MWh，分销商从零起步，经过26、92到172家的阶梯。更值得看的不是扩张速度，而是流失率的变化：2024年终止了14家分销商，流失率53.8%，这是一次激烈的渠道筛选；<strong>2025年仅终止9家，流失率降到9.8%</strong>。</p>\n  <p>能够在人生地不熟的海外市场筛选经销商，说明公司在面对下游客户时建立了渠道筛选机制，渠道从\"谁都想进来试试\"过渡到了\"留下来的人能赚钱\"，下游安装商从27家扩张到4887家再到17614家，终端服务网络也在一步步铺开。到2025年，分销收入占比达到97.9%，这套渠道体系已经是思格收入的绝对主力。</p>\n  <p>喂养这套渠道的除了产品定位因素，还有主动的定价策略。产品均价从3.17元/Wh降到2.12元/Wh，两年降了33%，公司通过主动降价换量，叠加大容量配置占比提升拉低了单位瓦时价格。</p>\n  <p>另外一个值得注意的产品特性是，<strong>所有SigenStor设备必须联网注册才能解锁完整功能和十年质保</strong>。这个设计的更深层意义不在销售端，而在售后：每一台激活的设备都是一个持续在线的数据节点，为后续的软件变现铺好了管道。</p>\n  <p>不难看出，华为在C端产品如手机、汽车上的一系列产品定位和运营思路，无论是联网注册、一体化产品还是分销商体系等等，被思格成功借鉴到了户储设备上，成为他们收入快速起量扩张的密码。</p>\n  <p>当然，这套打法跑通了，但需要对它的边界保持清醒。InfoLink 2025年全年数据显示，全球户储系统出货35.11 GWh，思格以约3.95 GWh的出货量跻身全球第五。排在它前面的是<strong>特斯拉、华为、比亚迪和阳光电源</strong>，每一家都是体量和渠道深度远超思格的巨头。</p>\n  <p>思格招股书里强调的\"全球第一\"，限定词是\"可堆叠分布式光储一体机\"这个细分品类里，五合一一体机能否成为户储的主流形态还未知，但产品架构本身并不构成专利壁垒，理论上可被复制。固德威2025年推出的ESA系列就是一个直接的例证，多家澳洲独立评测机构在对比后指出<strong>两款产品在外观、模块规格和内部架构上高度相似</strong>。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_4a3b9fd3b877475c9b73eb25f0f605bf@5065245_oswg493881oswg1052oswg1262_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>目前，公开渠道查不到有关思格和固德威之间进一步的信息，但无论如何，来自竞争对手进攻已然开始，决定思格在上市后表现的关键问题，其实是他们整个业务体系的持续性。</p>\n  <h2><strong>02&nbsp; &nbsp;增长的代价</strong></h2>\n  <p>增长跑出来了，但围绕公司业绩持续性的疑问也跟着浮出水面，最直观的是毛利率。</p>\n  <p>SigenStor毛利率从32.2%升到50.8%，有巨大的进步；只是随着碳酸锂价格在2025年下半年反弹，2026年以来已经稳定在15万元/吨左右，上游电芯厂商长期处于微利状态，传导的压力在积累，幅度和节奏取决于供需格局，不一定是线性的，但无论如何，<strong>成本有可能会面临压力</strong>。</p>\n  <p>与此同时，售价端也不是没有压力：产品均价还在降，招股书披露的分级返利通常低于年度采购额的10%，但返利比例也会随采购层级提升而增加。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_0d415fa4d72041ada65b5ea8640bb3fe@5065245_oswg53997oswg1080oswg557_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>而且，思格账面上赚到的利润，到现在也没变成现金。2025年公司净利润29.2亿，经营现金流负2亿。拆开看并不是利润本身有问题，应收账款增加了28.9亿，存货增加了16.6亿，<strong>合计吞掉了足足35.1亿</strong>。</p>\n  <p>钱卡在了渠道的两头：给下游的账期在变长，应收周转天数从51天拉到70天，回款周期在拉长，应付周转天数从111天压到61天。<strong>上下游同时挤压，29亿利润到了现金流量表上就成了负数</strong>。这还只是已经发生的部分，拨备从123万涨到2.64亿，增长超过200倍。如果这部分拨备是为了质保的话，最早一批设备2023年才交付，到现在运行了也就三年时间，真实的售后成本恐怕还没发生。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_e291526c13ad43fdbe6fc2185db6332c@5065245_oswg133838oswg1080oswg588_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>经营造血能力相对有限，银行借款出了大力。2025年底账上现金11.2亿，但计息银行借款从3.9亿膨胀到17.2亿，其中绝大部分是短期借款，公司已从净现金翻转为净负债5.5亿。加上欠供应商的11.6亿贸易应付，整个思格的运营资金链中，应收撑着资产，借款撑着现金。</p>\n  <p>而吞掉现金最多的那个市场，恰恰也是风险最集中的地方。招股书显示，澳洲2024年已经贡献了15.4%的收入，思格在2025年3月就做到了澳洲月度市占率第一，这些都发生在大规模补贴启动之前。</p>\n  <p>在2025年7月澳洲联邦政府启动\"廉价家庭电池计划\"之后，增长进一步加速，据澳大利亚能源部披露，半年内16万户家庭装上了电池。到2025年底，澳洲收入占比从15.4%跳升到42.6%。2025年12月，政府把预算从23亿澳元扩大到72亿，目标是2030年前让200万澳洲家庭装上电池。</p>\n  <p>但补贴结构正在发生变化，另据澳洲能源部在2026年2月更新的方案，从2026年5月起，单位补贴按电池容量分层递减，0到14kWh维持全额，14到28kWh打六折，28到50kWh只剩一成五。思格主打的是可堆叠大容量系统，模块化设计的卖点就是鼓励用户扩容，而新的补贴结构对14kWh以上的容量段力度明显下降。</p>\n  <p>2025年11月，思格针对SigenStor部分型号发起自愿性产品召回，由ACCC协调公示，原因是交流插头过热隐患。思格在召回后仍保持了澳洲市占率第一，但补贴调整叠加品牌信任冲击，42.6%的单一市场集中度让这个位置的稳固性有所下降。</p>\n  <p>毛利率的支撑在松动，利润还没变成现金，最大的市场正经历补贴调整和品牌修复。这些不是孤立的风险点，它们是同一套高速增长模型的不同侧面。</p>\n  <h2><strong>03&nbsp; &nbsp;结语</strong></h2>\n  <p>有一个小小的引子，由于招股书并未多写，所以在正文中没有展开。前面提到，所有SigenStor设备必须联网注册才能解锁完整功能和质保，如果只把这当作一个产品特性，就低估了它的潜在价值。</p>\n  <p>截至2025年底，思格已经卖出了近4GWh的SigenStor，每一台都是一个持续在线的数据终端。云端BMS实时监测电池健康状态，API对接20多个国家60多家电力公司的动态电价，系统支持与VPP供应商的协议对接。<strong>这意味着思格手里握着一张正在扩张的分布式能源网络，每卖出一台设备，这张网就多一个节点</strong>。</p>\n  <p>招股书对这部分的描述还很克制，用的措辞是\"探索智能mySigen App新变现模式\"。翻译过来就是：管道已经铺好了，变现还需要摸索。潜在的变现路径不难想象：能源调度分成、电力交易撮合等增值服务。这些在能源互联网领域都有可以参照的商业模式，问题只在于思格的终端规模和用户粘性够不够支撑。</p>\n  <p>这就引出了围绕思格最核心的估值分歧：它到底是一家硬件公司，还是一个早期的分布式能源网络。</p>\n  <p>按硬件公司看，50%毛利率是电芯降价窗口叠加品类早期定价权的产物，两个条件都在变化，利润的可持续性是估值锚，而这个锚正在被成本反弹、现金流错配和市场集中度同时施压。按能源网络看，每卖出一台SigenStor就多铺一截管道，设备卖得越多，未来软件变现的基础就越厚。</p>\n  <p>4月16日，思格在港交所正式开始交易，如何给这家公司的资产估值，市场会用行动给出它的回答。</p>\n  <p><strong>声明：本文仅用于学习和交流，不构成投资建议。</strong></p>\n  <p class=\"editor-note\">本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/YBMxjTZVP3Z-z2Tp0q_WOw\" rel=\"noopener noreferrer\" target=\"_blank\">“躺平指数”</a>，作者：躺姐，36氪经授权发布。</p>', '', '', '', '', '{\'title\': \'成立四年冲击上市：思格新能源的增长神速与代价\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'成立四年冲击上市：思格新能源的增长神速与代价\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3766173483840256?f=rss\'}], \'link\': \'https://36kr.com/p/3766173483840256?f=rss\', \'published\': \'2026-04-14 16:35:38  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=35, tm_sec=38, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'<p>从注册成立到港交所挂牌，思格新能源就用了四年，有望成为港股近年来上市速度最快的中国科技企业。</p>\\n  <p>4月16日，这家2022年5月才成立的公司将以6656为股票代码在港交所公开交易，IPO市值或将超过800亿港元。首日融资申购倍数超逾61倍，截至目前达到约815倍，预计申购倍数将超过1000倍。</p>\\n  <p>四年是什么概念？大多数硬科技创业公司在这个阶段还在烧B轮的钱打磨下一代产品。思格2025年的营收是90亿人民币，净利润29.2亿，毛利率50.1%。2023年这三个数字则分别是5800万、负3.73亿、31.3%。<strong>如果只看增长曲线，这家公司堪称奇迹</strong>。</p>\\n  <p>值得注意的是，这样的增长曲线诞生在储能内卷的周期里。同行毛利率普遍在二三十个点之间挣扎，思格的50%要么意味着它找到了一个定价权完全不同的市场位置，要么意味着这个数字背后有一定的“附加条件”。</p>\\n  <p>从产品端看，思格做的事情在逻辑上不复杂：把光伏逆变器、储能电池、储能变流器、直流充电模块和能源管理系统塞进同一个箱子，五合一出厂，安装商不需要在现场拼接不同品牌的组件、调试协议兼容性。</p>\\n  <p>在它之前，一套户储系统的安装是个需要多品牌适配、现场调试的工程活，思格把它变成了接近即插即用的消费品。这种产品也叫\"可堆叠光储一体机\"，思格按2024年出货量计在这个细分品类做到了全球第一，市场份额28.6%。</p>\\n  <p>这套产品在澳大利亚踩中了一个难得的时间窗口，2025年7月，该国政府启动\"廉价家庭电池计划\"，为户储安装提供约三成补贴，半年内16万户家庭装上了电池。思格从拿到澳大利亚CEC认证到2025年3月做到月度市占率第一，只用了六个月，此后连续保持到年底；<strong>到2025年，光这一国市场就贡献了思格42.6%的收入</strong>。</p>\\n  <p>但是，即便有着如此亮眼的增长曲线，他们三年的经营现金流依然全部为负，应收账款从3.6亿膨胀到31.6亿，存货从4.8亿堆到21.4亿，让29.2亿净利润没有一分钱变成经营现金。这不意味着增长是假的，只是一个真实的高增长同样需要被追问：<strong>最速上市和超高增长并非免费，要看清楚它的代价是什么</strong>。</p>\\n  <h2><strong>01&nbsp; &nbsp;用做手机的思路做户储</strong></h2>\\n  <p>营收三年增长超过154倍，质疑这种数字的真实性是最本能的反应。但拆开看，这个增长并不是凭空出现的：产品踩中了行业最突出的痛点，也押中了最合适它发挥市场。</p>\\n  <p>思格创始人许映童，是能源圈非常知名的人物。据公开资料，他1999年加入华为，在通信领域工作了十年时间；2015年转岗至华为的光伏部门，2015 年带领华为光伏逆变器业务登顶全球出货量榜首，被称为是“主导华为逆变器七连冠”的核心人物。在他的团队中，有不少人都是电力和光伏行业的老兵。</p>\\n  <p>一套传统的户用储能系统需要安装商，在现场拼接不同品牌的逆变器、电池、能量管理系统，调试协议兼容性，花半天时间才能让系统跑起来。这个痛点在国内还好说，换到国外就更加突出，人工成本在发达国家市场是大头，安装又高度依赖熟练人工，这类产品的渠道就很难铺开起量。</p>\\n  <p>思格拳头产品SigenStor的做法是把五个环节的适配工作在工厂里完成，交给安装商的是一个开箱即装的成品。招股书披露，该产品的安装调试时间压缩到15分钟，一个安装商一天能覆盖的安装量大幅增加。模块化堆叠设计让用户可以按需扩容，不用一次性买到位，降低了首次购买的决策门槛；而对分销商来说，一个SKU覆盖从小户型到大户型的需求，库存管理的复杂度大幅降低。</p>\\n  <p>产品定义对了，渠道扩张速度就大幅加快。SigenStor的出货量从18 MWh到447 MWh再到3947 MWh，分销商从零起步，经过26、92到172家的阶梯。更值得看的不是扩张速度，而是流失率的变化：2024年终止了14家分销商，流失率53.8%，这是一次激烈的渠道筛选；<strong>2025年仅终止9家，流失率降到9.8%</strong>。</p>\\n  <p>能够在人生地不熟的海外市场筛选经销商，说明公司在面对下游客户时建立了渠道筛选机制，渠道从\"谁都想进来试试\"过渡到了\"留下来的人能赚钱\"，下游安装商从27家扩张到4887家再到17614家，终端服务网络也在一步步铺开。到2025年，分销收入占比达到97.9%，这套渠道体系已经是思格收入的绝对主力。</p>\\n  <p>喂养这套渠道的除了产品定位因素，还有主动的定价策略。产品均价从3.17元/Wh降到2.12元/Wh，两年降了33%，公司通过主动降价换量，叠加大容量配置占比提升拉低了单位瓦时价格。</p>\\n  <p>另外一个值得注意的产品特性是，<strong>所有SigenStor设备必须联网注册才能解锁完整功能和十年质保</strong>。这个设计的更深层意义不在销售端，而在售后：每一台激活的设备都是一个持续在线的数据节点，为后续的软件变现铺好了管道。</p>\\n  <p>不难看出，华为在C端产品如手机、汽车上的一系列产品定位和运营思路，无论是联网注册、一体化产品还是分销商体系等等，被思格成功借鉴到了户储设备上，成为他们收入快速起量扩张的密码。</p>\\n  <p>当然，这套打法跑通了，但需要对它的边界保持清醒。InfoLink 2025年全年数据显示，全球户储系统出货35.11 GWh，思格以约3.95 GWh的出货量跻身全球第五。排在它前面的是<strong>特斯拉、华为、比亚迪和阳光电源</strong>，每一家都是体量和渠道深度远超思格的巨头。</p>\\n  <p>思格招股书里强调的\"全球第一\"，限定词是\"可堆叠分布式光储一体机\"这个细分品类里，五合一一体机能否成为户储的主流形态还未知，但产品架构本身并不构成专利壁垒，理论上可被复制。固德威2025年推出的ESA系列就是一个直接的例证，多家澳洲独立评测机构在对比后指出<strong>两款产品在外观、模块规格和内部架构上高度相似</strong>。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_4a3b9fd3b877475c9b73eb25f0f605bf@5065245_oswg493881oswg1052oswg1262_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>目前，公开渠道查不到有关思格和固德威之间进一步的信息，但无论如何，来自竞争对手进攻已然开始，决定思格在上市后表现的关键问题，其实是他们整个业务体系的持续性。</p>\\n  <h2><strong>02&nbsp; &nbsp;增长的代价</strong></h2>\\n  <p>增长跑出来了，但围绕公司业绩持续性的疑问也跟着浮出水面，最直观的是毛利率。</p>\\n  <p>SigenStor毛利率从32.2%升到50.8%，有巨大的进步；只是随着碳酸锂价格在2025年下半年反弹，2026年以来已经稳定在15万元/吨左右，上游电芯厂商长期处于微利状态，传导的压力在积累，幅度和节奏取决于供需格局，不一定是线性的，但无论如何，<strong>成本有可能会面临压力</strong>。</p>\\n  <p>与此同时，售价端也不是没有压力：产品均价还在降，招股书披露的分级返利通常低于年度采购额的10%，但返利比例也会随采购层级提升而增加。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_0d415fa4d72041ada65b5ea8640bb3fe@5065245_oswg53997oswg1080oswg557_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>而且，思格账面上赚到的利润，到现在也没变成现金。2025年公司净利润29.2亿，经营现金流负2亿。拆开看并不是利润本身有问题，应收账款增加了28.9亿，存货增加了16.6亿，<strong>合计吞掉了足足35.1亿</strong>。</p>\\n  <p>钱卡在了渠道的两头：给下游的账期在变长，应收周转天数从51天拉到70天，回款周期在拉长，应付周转天数从111天压到61天。<strong>上下游同时挤压，29亿利润到了现金流量表上就成了负数</strong>。这还只是已经发生的部分，拨备从123万涨到2.64亿，增长超过200倍。如果这部分拨备是为了质保的话，最早一批设备2023年才交付，到现在运行了也就三年时间，真实的售后成本恐怕还没发生。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_e291526c13ad43fdbe6fc2185db6332c@5065245_oswg133838oswg1080oswg588_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>经营造血能力相对有限，银行借款出了大力。2025年底账上现金11.2亿，但计息银行借款从3.9亿膨胀到17.2亿，其中绝大部分是短期借款，公司已从净现金翻转为净负债5.5亿。加上欠供应商的11.6亿贸易应付，整个思格的运营资金链中，应收撑着资产，借款撑着现金。</p>\\n  <p>而吞掉现金最多的那个市场，恰恰也是风险最集中的地方。招股书显示，澳洲2024年已经贡献了15.4%的收入，思格在2025年3月就做到了澳洲月度市占率第一，这些都发生在大规模补贴启动之前。</p>\\n  <p>在2025年7月澳洲联邦政府启动\"廉价家庭电池计划\"之后，增长进一步加速，据澳大利亚能源部披露，半年内16万户家庭装上了电池。到2025年底，澳洲收入占比从15.4%跳升到42.6%。2025年12月，政府把预算从23亿澳元扩大到72亿，目标是2030年前让200万澳洲家庭装上电池。</p>\\n  <p>但补贴结构正在发生变化，另据澳洲能源部在2026年2月更新的方案，从2026年5月起，单位补贴按电池容量分层递减，0到14kWh维持全额，14到28kWh打六折，28到50kWh只剩一成五。思格主打的是可堆叠大容量系统，模块化设计的卖点就是鼓励用户扩容，而新的补贴结构对14kWh以上的容量段力度明显下降。</p>\\n  <p>2025年11月，思格针对SigenStor部分型号发起自愿性产品召回，由ACCC协调公示，原因是交流插头过热隐患。思格在召回后仍保持了澳洲市占率第一，但补贴调整叠加品牌信任冲击，42.6%的单一市场集中度让这个位置的稳固性有所下降。</p>\\n  <p>毛利率的支撑在松动，利润还没变成现金，最大的市场正经历补贴调整和品牌修复。这些不是孤立的风险点，它们是同一套高速增长模型的不同侧面。</p>\\n  <h2><strong>03&nbsp; &nbsp;结语</strong></h2>\\n  <p>有一个小小的引子，由于招股书并未多写，所以在正文中没有展开。前面提到，所有SigenStor设备必须联网注册才能解锁完整功能和质保，如果只把这当作一个产品特性，就低估了它的潜在价值。</p>\\n  <p>截至2025年底，思格已经卖出了近4GWh的SigenStor，每一台都是一个持续在线的数据终端。云端BMS实时监测电池健康状态，API对接20多个国家60多家电力公司的动态电价，系统支持与VPP供应商的协议对接。<strong>这意味着思格手里握着一张正在扩张的分布式能源网络，每卖出一台设备，这张网就多一个节点</strong>。</p>\\n  <p>招股书对这部分的描述还很克制，用的措辞是\"探索智能mySigen App新变现模式\"。翻译过来就是：管道已经铺好了，变现还需要摸索。潜在的变现路径不难想象：能源调度分成、电力交易撮合等增值服务。这些在能源互联网领域都有可以参照的商业模式，问题只在于思格的终端规模和用户粘性够不够支撑。</p>\\n  <p>这就引出了围绕思格最核心的估值分歧：它到底是一家硬件公司，还是一个早期的分布式能源网络。</p>\\n  <p>按硬件公司看，50%毛利率是电芯降价窗口叠加品类早期定价权的产物，两个条件都在变化，利润的可持续性是估值锚，而这个锚正在被成本反弹、现金流错配和市场集中度同时施压。按能源网络看，每卖出一台SigenStor就多铺一截管道，设备卖得越多，未来软件变现的基础就越厚。</p>\\n  <p>4月16日，思格在港交所正式开始交易，如何给这家公司的资产估值，市场会用行动给出它的回答。</p>\\n  <p><strong>声明：本文仅用于学习和交流，不构成投资建议。</strong></p>\\n  <p class=\"editor-note\">本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/YBMxjTZVP3Z-z2Tp0q_WOw\" rel=\"noopener noreferrer\" target=\"_blank\">“躺平指数”</a>，作者：躺姐，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>从注册成立到港交所挂牌，思格新能源就用了四年，有望成为港股近年来上市速度最快的中国科技企业。</p>\\n  <p>4月16日，这家2022年5月才成立的公司将以6656为股票代码在港交所公开交易，IPO市值或将超过800亿港元。首日融资申购倍数超逾61倍，截至目前达到约815倍，预计申购倍数将超过1000倍。</p>\\n  <p>四年是什么概念？大多数硬科技创业公司在这个阶段还在烧B轮的钱打磨下一代产品。思格2025年的营收是90亿人民币，净利润29.2亿，毛利率50.1%。2023年这三个数字则分别是5800万、负3.73亿、31.3%。<strong>如果只看增长曲线，这家公司堪称奇迹</strong>。</p>\\n  <p>值得注意的是，这样的增长曲线诞生在储能内卷的周期里。同行毛利率普遍在二三十个点之间挣扎，思格的50%要么意味着它找到了一个定价权完全不同的市场位置，要么意味着这个数字背后有一定的“附加条件”。</p>\\n  <p>从产品端看，思格做的事情在逻辑上不复杂：把光伏逆变器、储能电池、储能变流器、直流充电模块和能源管理系统塞进同一个箱子，五合一出厂，安装商不需要在现场拼接不同品牌的组件、调试协议兼容性。</p>\\n  <p>在它之前，一套户储系统的安装是个需要多品牌适配、现场调试的工程活，思格把它变成了接近即插即用的消费品。这种产品也叫\"可堆叠光储一体机\"，思格按2024年出货量计在这个细分品类做到了全球第一，市场份额28.6%。</p>\\n  <p>这套产品在澳大利亚踩中了一个难得的时间窗口，2025年7月，该国政府启动\"廉价家庭电池计划\"，为户储安装提供约三成补贴，半年内16万户家庭装上了电池。思格从拿到澳大利亚CEC认证到2025年3月做到月度市占率第一，只用了六个月，此后连续保持到年底；<strong>到2025年，光这一国市场就贡献了思格42.6%的收入</strong>。</p>\\n  <p>但是，即便有着如此亮眼的增长曲线，他们三年的经营现金流依然全部为负，应收账款从3.6亿膨胀到31.6亿，存货从4.8亿堆到21.4亿，让29.2亿净利润没有一分钱变成经营现金。这不意味着增长是假的，只是一个真实的高增长同样需要被追问：<strong>最速上市和超高增长并非免费，要看清楚它的代价是什么</strong>。</p>\\n  <h2><strong>01&nbsp; &nbsp;用做手机的思路做户储</strong></h2>\\n  <p>营收三年增长超过154倍，质疑这种数字的真实性是最本能的反应。但拆开看，这个增长并不是凭空出现的：产品踩中了行业最突出的痛点，也押中了最合适它发挥市场。</p>\\n  <p>思格创始人许映童，是能源圈非常知名的人物。据公开资料，他1999年加入华为，在通信领域工作了十年时间；2015年转岗至华为的光伏部门，2015 年带领华为光伏逆变器业务登顶全球出货量榜首，被称为是“主导华为逆变器七连冠”的核心人物。在他的团队中，有不少人都是电力和光伏行业的老兵。</p>\\n  <p>一套传统的户用储能系统需要安装商，在现场拼接不同品牌的逆变器、电池、能量管理系统，调试协议兼容性，花半天时间才能让系统跑起来。这个痛点在国内还好说，换到国外就更加突出，人工成本在发达国家市场是大头，安装又高度依赖熟练人工，这类产品的渠道就很难铺开起量。</p>\\n  <p>思格拳头产品SigenStor的做法是把五个环节的适配工作在工厂里完成，交给安装商的是一个开箱即装的成品。招股书披露，该产品的安装调试时间压缩到15分钟，一个安装商一天能覆盖的安装量大幅增加。模块化堆叠设计让用户可以按需扩容，不用一次性买到位，降低了首次购买的决策门槛；而对分销商来说，一个SKU覆盖从小户型到大户型的需求，库存管理的复杂度大幅降低。</p>\\n  <p>产品定义对了，渠道扩张速度就大幅加快。SigenStor的出货量从18 MWh到447 MWh再到3947 MWh，分销商从零起步，经过26、92到172家的阶梯。更值得看的不是扩张速度，而是流失率的变化：2024年终止了14家分销商，流失率53.8%，这是一次激烈的渠道筛选；<strong>2025年仅终止9家，流失率降到9.8%</strong>。</p>\\n  <p>能够在人生地不熟的海外市场筛选经销商，说明公司在面对下游客户时建立了渠道筛选机制，渠道从\"谁都想进来试试\"过渡到了\"留下来的人能赚钱\"，下游安装商从27家扩张到4887家再到17614家，终端服务网络也在一步步铺开。到2025年，分销收入占比达到97.9%，这套渠道体系已经是思格收入的绝对主力。</p>\\n  <p>喂养这套渠道的除了产品定位因素，还有主动的定价策略。产品均价从3.17元/Wh降到2.12元/Wh，两年降了33%，公司通过主动降价换量，叠加大容量配置占比提升拉低了单位瓦时价格。</p>\\n  <p>另外一个值得注意的产品特性是，<strong>所有SigenStor设备必须联网注册才能解锁完整功能和十年质保</strong>。这个设计的更深层意义不在销售端，而在售后：每一台激活的设备都是一个持续在线的数据节点，为后续的软件变现铺好了管道。</p>\\n  <p>不难看出，华为在C端产品如手机、汽车上的一系列产品定位和运营思路，无论是联网注册、一体化产品还是分销商体系等等，被思格成功借鉴到了户储设备上，成为他们收入快速起量扩张的密码。</p>\\n  <p>当然，这套打法跑通了，但需要对它的边界保持清醒。InfoLink 2025年全年数据显示，全球户储系统出货35.11 GWh，思格以约3.95 GWh的出货量跻身全球第五。排在它前面的是<strong>特斯拉、华为、比亚迪和阳光电源</strong>，每一家都是体量和渠道深度远超思格的巨头。</p>\\n  <p>思格招股书里强调的\"全球第一\"，限定词是\"可堆叠分布式光储一体机\"这个细分品类里，五合一一体机能否成为户储的主流形态还未知，但产品架构本身并不构成专利壁垒，理论上可被复制。固德威2025年推出的ESA系列就是一个直接的例证，多家澳洲独立评测机构在对比后指出<strong>两款产品在外观、模块规格和内部架构上高度相似</strong>。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_4a3b9fd3b877475c9b73eb25f0f605bf@5065245_oswg493881oswg1052oswg1262_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>目前，公开渠道查不到有关思格和固德威之间进一步的信息，但无论如何，来自竞争对手进攻已然开始，决定思格在上市后表现的关键问题，其实是他们整个业务体系的持续性。</p>\\n  <h2><strong>02&nbsp; &nbsp;增长的代价</strong></h2>\\n  <p>增长跑出来了，但围绕公司业绩持续性的疑问也跟着浮出水面，最直观的是毛利率。</p>\\n  <p>SigenStor毛利率从32.2%升到50.8%，有巨大的进步；只是随着碳酸锂价格在2025年下半年反弹，2026年以来已经稳定在15万元/吨左右，上游电芯厂商长期处于微利状态，传导的压力在积累，幅度和节奏取决于供需格局，不一定是线性的，但无论如何，<strong>成本有可能会面临压力</strong>。</p>\\n  <p>与此同时，售价端也不是没有压力：产品均价还在降，招股书披露的分级返利通常低于年度采购额的10%，但返利比例也会随采购层级提升而增加。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_0d415fa4d72041ada65b5ea8640bb3fe@5065245_oswg53997oswg1080oswg557_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>而且，思格账面上赚到的利润，到现在也没变成现金。2025年公司净利润29.2亿，经营现金流负2亿。拆开看并不是利润本身有问题，应收账款增加了28.9亿，存货增加了16.6亿，<strong>合计吞掉了足足35.1亿</strong>。</p>\\n  <p>钱卡在了渠道的两头：给下游的账期在变长，应收周转天数从51天拉到70天，回款周期在拉长，应付周转天数从111天压到61天。<strong>上下游同时挤压，29亿利润到了现金流量表上就成了负数</strong>。这还只是已经发生的部分，拨备从123万涨到2.64亿，增长超过200倍。如果这部分拨备是为了质保的话，最早一批设备2023年才交付，到现在运行了也就三年时间，真实的售后成本恐怕还没发生。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_e291526c13ad43fdbe6fc2185db6332c@5065245_oswg133838oswg1080oswg588_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>经营造血能力相对有限，银行借款出了大力。2025年底账上现金11.2亿，但计息银行借款从3.9亿膨胀到17.2亿，其中绝大部分是短期借款，公司已从净现金翻转为净负债5.5亿。加上欠供应商的11.6亿贸易应付，整个思格的运营资金链中，应收撑着资产，借款撑着现金。</p>\\n  <p>而吞掉现金最多的那个市场，恰恰也是风险最集中的地方。招股书显示，澳洲2024年已经贡献了15.4%的收入，思格在2025年3月就做到了澳洲月度市占率第一，这些都发生在大规模补贴启动之前。</p>\\n  <p>在2025年7月澳洲联邦政府启动\"廉价家庭电池计划\"之后，增长进一步加速，据澳大利亚能源部披露，半年内16万户家庭装上了电池。到2025年底，澳洲收入占比从15.4%跳升到42.6%。2025年12月，政府把预算从23亿澳元扩大到72亿，目标是2030年前让200万澳洲家庭装上电池。</p>\\n  <p>但补贴结构正在发生变化，另据澳洲能源部在2026年2月更新的方案，从2026年5月起，单位补贴按电池容量分层递减，0到14kWh维持全额，14到28kWh打六折，28到50kWh只剩一成五。思格主打的是可堆叠大容量系统，模块化设计的卖点就是鼓励用户扩容，而新的补贴结构对14kWh以上的容量段力度明显下降。</p>\\n  <p>2025年11月，思格针对SigenStor部分型号发起自愿性产品召回，由ACCC协调公示，原因是交流插头过热隐患。思格在召回后仍保持了澳洲市占率第一，但补贴调整叠加品牌信任冲击，42.6%的单一市场集中度让这个位置的稳固性有所下降。</p>\\n  <p>毛利率的支撑在松动，利润还没变成现金，最大的市场正经历补贴调整和品牌修复。这些不是孤立的风险点，它们是同一套高速增长模型的不同侧面。</p>\\n  <h2><strong>03&nbsp; &nbsp;结语</strong></h2>\\n  <p>有一个小小的引子，由于招股书并未多写，所以在正文中没有展开。前面提到，所有SigenStor设备必须联网注册才能解锁完整功能和质保，如果只把这当作一个产品特性，就低估了它的潜在价值。</p>\\n  <p>截至2025年底，思格已经卖出了近4GWh的SigenStor，每一台都是一个持续在线的数据终端。云端BMS实时监测电池健康状态，API对接20多个国家60多家电力公司的动态电价，系统支持与VPP供应商的协议对接。<strong>这意味着思格手里握着一张正在扩张的分布式能源网络，每卖出一台设备，这张网就多一个节点</strong>。</p>\\n  <p>招股书对这部分的描述还很克制，用的措辞是\"探索智能mySigen App新变现模式\"。翻译过来就是：管道已经铺好了，变现还需要摸索。潜在的变现路径不难想象：能源调度分成、电力交易撮合等增值服务。这些在能源互联网领域都有可以参照的商业模式，问题只在于思格的终端规模和用户粘性够不够支撑。</p>\\n  <p>这就引出了围绕思格最核心的估值分歧：它到底是一家硬件公司，还是一个早期的分布式能源网络。</p>\\n  <p>按硬件公司看，50%毛利率是电芯降价窗口叠加品类早期定价权的产物，两个条件都在变化，利润的可持续性是估值锚，而这个锚正在被成本反弹、现金流错配和市场集中度同时施压。按能源网络看，每卖出一台SigenStor就多铺一截管道，设备卖得越多，未来软件变现的基础就越厚。</p>\\n  <p>4月16日，思格在港交所正式开始交易，如何给这家公司的资产估值，市场会用行动给出它的回答。</p>\\n  <p><strong>声明：本文仅用于学习和交流，不构成投资建议。</strong></p>\\n  <p class=\"editor-note\">本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/YBMxjTZVP3Z-z2Tp0q_WOw\" rel=\"noopener noreferrer\" target=\"_blank\">“躺平指数”</a>，作者：躺姐，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'躺姐指数\'}], \'author\': \'躺姐指数\', \'author_detail\': {\'name\': \'躺姐指数\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'失血换来的增长，究竟能否持续？\'}]}', '2026-04-14 16:35:38', '2026-04-14 17:02:43', 1, '{\"summary\": \"本文分析了出海户储企业思格新能源高速增长赴港上市的经验与隐藏风险，可为储能出海企业提供战略参考\", \"abstract\": \"成立仅四年的思格新能源即将于4月16日登陆港交所，是近年港股上市速度最快的中国科技企业之一。该公司推出一体化可堆叠光储一体机，解决了海外户储安装痛点，凭借清晰的产品定位快速拓展澳大利亚市场，2025年在该细分品类登顶全球，澳洲市场贡献超四成收入。它借鉴消费电子的产品运营思路实现爆发式增长，但高速增长也伴随着诸多代价。目前公司净利润未转化为正向经营现金流，同时面临上游成本上涨、澳洲补贴政策调整、产品易被复制、单一市场依赖等多重风险，增长的持续性有待市场检验\", \"keywords\": [\"户储出海\", \"光储一体机\", \"澳大利亚市场\", \"港交所IPO\", \"储能\", \"补贴政策\", \"经营现金流\"], \"policy_risk\": {\"market_risk\": \"对澳大利亚单一市场依赖度高，2025年该市场贡献42.6%收入，集中风险高；产品架构不构成专利壁垒，已被竞争对手模仿复制；上游碳酸锂价格反弹，成本存在上涨压力，毛利率支撑松动；净利润未转化为正向经营现金流，上下游资金挤压，公司已从净现金转为净负债，现金流承压；曾因交流插头过热隐患在澳洲发起自愿召回，品牌信任受到一定冲击\", \"policy_compliance\": \"澳大利亚2026年5月起调整户用储能补贴政策，14kWh以上大容量电池补贴力度大幅递减，思格主打大容量可堆叠产品受此政策调整影响\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"新能源储能\"}');
INSERT INTO `news` VALUES (504, '教育AI平台Nectir完成1250万美元融资，已覆盖超过100个校区8万名学生', 'https://36kr.com/p/3766166803513856?f=rss', 'https://36kr.com/feed-article', '<p>今年3月，为学校赋能的教育AI平台Nectir 宣布已完成1250万美元的融资，本轮由Rethink Impact领投。Gingerbread Capital、Strada以及现有投资者也参与了本轮投资。</p>\n  <p><strong>Nectir是专为教育打造的、能节省教师时间、提供7×24小时个性化学习支持并提升教育成果的安全AI基础设施。该平台已覆盖超过100个校区8万名学生。</strong></p>\n  <p>Nectir AI 通过高度个性化的 AI 助手来提升学生的学习体验，这些 AI 助手直接基于教师的课程内容构建，且可即时集成到学校的学习管理系统（LMS）中。</p>\n  <p>Nectir由Kavitta Ghai和Jordan Long创立，灵感源于她们在大学期间所遇到的挑战。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_bcd15f6b3de54f15b2be40448e3aff26@000000_oswg580350oswg1080oswg586_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">Nectir首席执行官兼联合创始人Kavitta Ghai</p>\n  <p>“借助这笔新的资金，我们正在扩展我们的愿景，以满足现代教育环境的需求，”Nectir首席执行官兼联合创始人Kavitta Ghai表示。“在Nectir，我们关注的不是3万名学生的问题，而是为3000万名学生的现实设计解决方案。我们相信教育可及性至关重要，我们的基础设施为每一位学生提供个性化的学习伙伴，确保高质量的AI驱动支持成为一种普遍标准，而非奢侈品。”</p>\n  <p>盖洛普咨询公司数据显示，在应对AI普及带来的挑战的同时，高等教育正面临日益严重的危机，各院校面临着证明自身价值的压力。仅36%的美国民众信任高等教育，而六年前这一比例为48%。</p>\n  <p>与此同时，AI的采用已非常广泛：近90%的大学生使用AI，而那些表示学校允许使用AI的学生，相比学校不允许使用AI的学生，毕业后感到已准备好使用该技术的可能性高出25%。</p>\n  <p>这种准备至关重要：<strong>世界经济论坛预测，到2030年，39%的核心工作技能将发生变化，其中AI素养和分析思维均位列雇主需求增长最快的能力之列。</strong></p>\n  <p>AI本身并非威胁，真正危险的是无结构、无安全、无原则的AI。高等教育需要与教学法、隐私和成果相一致的机构级AI。<strong>Nectir正是为此而构建，通过其AI基础设施，使学校和机构能够安全地大规模部署AI助手。</strong></p>\n  <p>Nectir 为学生、教师和管理员部署定制的AI助手，为教授提供教学支持，为学生提供个性化指导，并为行政团队减轻工作负担、提高效率。</p>\n  <p><strong>Nectir AI 助手基于学校的机构知识构建，以课程内容为基础，并集成到学习管理系统中。</strong></p>\n  <p>该平台不使用学生数据来训练模型，并完全符合FERPA和SOC 2标准。</p>\n  <p><strong>Nectir 已带来可衡量的影响：</strong></p>\n  <p>1）在超过100个校区（从斯坦福大学、社区学院到私立高中）获得8万名学生的信赖。</p>\n  <p>2）与加州社区学院达成的里程碑式协议，使Nectir可供116个校区内的全部210万名学生使用。</p>\n  <p>3）洛杉矶太平洋大学在一项经同行评审的研究中显示，全校GPA提高了7.5%，这使得Nectir成为教育领域极少数拥有独立、已发表的学术成果证明其学习成效的AI基础设施解决方案之一。</p>\n  <p>4）74%的学生表示学习体验得到改善，包括对复杂内容的理解和批判性思维能力提升。</p>\n  <p>5）36%的学生表示学习动力增强。</p>\n  <p><strong>“这是一个7×24小时全天候的系统，所以即使在半夜，学生也能获得准确的反馈，”</strong>查博特学院的Adam Hathaway说。“它也非常可定制。如果你把这问题交给ChatGPT，你会得到截然不同的答案。Nectir AI将学生锁定在一个我能控制的系统内。”</p>\n  <p>Rethink Impact是美国专门用来支持女性主导的科技公司的基金，创始人是Jenny Abramson和Jill Ni。两位创始人提到：“AI在高等教育中的使用非常普遍，并且会持续存在。然而，如果以无结构、无安全、无原则的方式使用，它会带来巨大风险，Nectir的合规平台正在推动更好的学习体验、更强的学生动力，并最终在中学和高等教育中带来更好的成果。这是教育科技创新的最佳典范，我们无比激动能在其下一增长阶段支持这个团队！”</p>\n  <p>本文来自微信公众号 <a href=\"https://mp.weixin.qq.com/s?__biz=MzU1Mjc4NjM4Mg==&amp;mid=2247588264&amp;idx=1&amp;sn=65ecdcbe45a4b45a5ec178c8507f982c&amp;chksm=fa5dde1df10abc8eacb58fe640adbdb095e54571baf7caab7134879de4f3116bf3838c0d19b1&amp;scene=0&amp;xtrack=1#rd\" rel=\"noopener noreferrer\" target=\"_blank\">“多知网”（ID：duozhiwang）</a>，作者：王上，36氪经授权发布。</p>', '', '', '', '', '{\'title\': \'教育AI平台Nectir完成1250万美元融资，已覆盖超过100个校区8万名学生\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'教育AI平台Nectir完成1250万美元融资，已覆盖超过100个校区8万名学生\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3766166803513856?f=rss\'}], \'link\': \'https://36kr.com/p/3766166803513856?f=rss\', \'published\': \'2026-04-14 16:35:09  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=35, tm_sec=9, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'<p>今年3月，为学校赋能的教育AI平台Nectir 宣布已完成1250万美元的融资，本轮由Rethink Impact领投。Gingerbread Capital、Strada以及现有投资者也参与了本轮投资。</p>\\n  <p><strong>Nectir是专为教育打造的、能节省教师时间、提供7×24小时个性化学习支持并提升教育成果的安全AI基础设施。该平台已覆盖超过100个校区8万名学生。</strong></p>\\n  <p>Nectir AI 通过高度个性化的 AI 助手来提升学生的学习体验，这些 AI 助手直接基于教师的课程内容构建，且可即时集成到学校的学习管理系统（LMS）中。</p>\\n  <p>Nectir由Kavitta Ghai和Jordan Long创立，灵感源于她们在大学期间所遇到的挑战。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_bcd15f6b3de54f15b2be40448e3aff26@000000_oswg580350oswg1080oswg586_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">Nectir首席执行官兼联合创始人Kavitta Ghai</p>\\n  <p>“借助这笔新的资金，我们正在扩展我们的愿景，以满足现代教育环境的需求，”Nectir首席执行官兼联合创始人K