INSERT INTO `news` VALUES (540, '恒指收涨0.82%，恒生科技指数涨0.62%', 'https://36kr.com/newsflashes/3766390876717829?f=rss', 'https://36kr.com/feed-newsflash', '36氪获悉，恒指收涨0.82%，恒生科技指数涨0.62%；消费、半导体、房地产板块领涨，中梁控股、兆易创新涨超9%，泡泡玛特涨超6%；电气设备、石油石化、机械板块跌幅居前，正力新能跌超11%，重庆机电、山东墨龙跌超5%；南向资金净流出20.17亿港元。', '', '', '', '', '{\'title\': \'恒指收涨0.82%，恒生科技指数涨0.62%\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'恒指收涨0.82%，恒生科技指数涨0.62%\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766390876717829?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766390876717829?f=rss\', \'published\': \'2026-04-14 16:10:55  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=10, tm_sec=55, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，恒指收涨0.82%，恒生科技指数涨0.62%；消费、半导体、房地产板块领涨，中梁控股、兆易创新涨超9%，泡泡玛特涨超6%；电气设备、石油石化、机械板块跌幅居前，正力新能跌超11%，重庆机电、山东墨龙跌超5%；南向资金净流出20.17亿港元。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'36氪获悉，恒指收涨0.82%，恒生科技指数涨0.62%；消费、半导体、房地产板块领涨，中梁控股、兆易创新涨超9%，泡泡玛特涨超6%；电气设备、石油石化、机械板块跌幅居前，正力新能跌超11%，重庆机电、山东墨龙跌超5%；南向资金净流出20.17亿港元。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 16:10:55', '2026-04-14 17:05:10', 0, '\"\"');
INSERT INTO `news` VALUES (541, '苹果加码iPhone Fold', 'https://36kr.com/newsflashes/3766384882172672?f=rss', 'https://36kr.com/feed-newsflash', '4月14日，尽管折叠屏手机市场近年成长力道趋缓，但消息称苹果已为首款折叠屏手机iPhone Fold加码20%面板库存。（新浪财经）', '', '', '', '', '{\'title\': \'苹果加码iPhone Fold\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'苹果加码iPhone Fold\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766384882172672?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766384882172672?f=rss\', \'published\': \'2026-04-14 16:04:49  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=4, tm_sec=49, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'4月14日，尽管折叠屏手机市场近年成长力道趋缓，但消息称苹果已为首款折叠屏手机iPhone Fold加码20%面板库存。（新浪财经）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'4月14日，尽管折叠屏手机市场近年成长力道趋缓，但消息称苹果已为首款折叠屏手机iPhone Fold加码20%面板库存。（新浪财经）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 16:04:49', '2026-04-14 17:05:13', 0, '\"\"');
INSERT INTO `news` VALUES (542, '我国最大规模科学智能计算集群投入使用', 'https://36kr.com/newsflashes/3766381508379138?f=rss', 'https://36kr.com/feed-newsflash', '今天（14日）我国最大规模科学智能计算集群在位于郑州的国家超算互联网核心节点投入使用。这标志着我国在人工智能驱动科学研究算力基础设施领域实现关键突破，将助力我国抢占人工智能产业应用制高点。（央视新闻）', '', '', '', '', '{\'title\': \'我国最大规模科学智能计算集群投入使用\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'我国最大规模科学智能计算集群投入使用\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766381508379138?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766381508379138?f=rss\', \'published\': \'2026-04-14 16:01:23  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=1, tm_sec=23, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'今天（14日）我国最大规模科学智能计算集群在位于郑州的国家超算互联网核心节点投入使用。这标志着我国在人工智能驱动科学研究算力基础设施领域实现关键突破，将助力我国抢占人工智能产业应用制高点。（央视新闻）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'今天（14日）我国最大规模科学智能计算集群在位于郑州的国家超算互联网核心节点投入使用。这标志着我国在人工智能驱动科学研究算力基础设施领域实现关键突破，将助力我国抢占人工智能产业应用制高点。（央视新闻）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 16:01:23', '2026-04-14 17:05:16', 0, '\"\"');
INSERT INTO `news` VALUES (543, '家电业部分塑料从进口转向国内供应，上游短缺与下游疲软博弈价格涨幅', 'https://36kr.com/newsflashes/3766376097727239?f=rss', 'https://36kr.com/feed-newsflash', '“我最近密集拜访下游终端厂家客户，他们大多数对市场需求持不确定看法。”一家国内塑料供应商的相关负责人袁望（化名）4月14日向记者表示，由于最近中东局势紧张导致塑料等原材料供应紧张、价格大涨，上下游之间正在重新议价。记者从产业链了解到，部分家电所需塑料等原材料近期从进口转向谋求国内供应，国内塑料等化工材料大幅涨价，一些终端品牌与上游谈判，在上游塑料短缺与下游需求疲软之间就价格涨幅进行谈判博弈，预计未来塑料价格、供需关系将重构。（第一财经）', '', '', '', '', '{\'title\': \'家电业部分塑料从进口转向国内供应，上游短缺与下游疲软博弈价格涨幅\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'家电业部分塑料从进口转向国内供应，上游短缺与下游疲软博弈价格涨幅\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766376097727239?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766376097727239?f=rss\', \'published\': \'2026-04-14 15:55:53  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=7, tm_min=55, tm_sec=53, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'“我最近密集拜访下游终端厂家客户，他们大多数对市场需求持不确定看法。”一家国内塑料供应商的相关负责人袁望（化名）4月14日向记者表示，由于最近中东局势紧张导致塑料等原材料供应紧张、价格大涨，上下游之间正在重新议价。记者从产业链了解到，部分家电所需塑料等原材料近期从进口转向谋求国内供应，国内塑料等化工材料大幅涨价，一些终端品牌与上游谈判，在上游塑料短缺与下游需求疲软之间就价格涨幅进行谈判博弈，预计未来塑料价格、供需关系将重构。（第一财经）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'“我最近密集拜访下游终端厂家客户，他们大多数对市场需求持不确定看法。”一家国内塑料供应商的相关负责人袁望（化名）4月14日向记者表示，由于最近中东局势紧张导致塑料等原材料供应紧张、价格大涨，上下游之间正在重新议价。记者从产业链了解到，部分家电所需塑料等原材料近期从进口转向谋求国内供应，国内塑料等化工材料大幅涨价，一些终端品牌与上游谈判，在上游塑料短缺与下游需求疲软之间就价格涨幅进行谈判博弈，预计未来塑料价格、供需关系将重构。（第一财经）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 15:55:53', '2026-04-14 17:05:19', 0, '\"\"');
INSERT INTO `news` VALUES (544, 'IBM 以 1700 万美元与美国司法部达成和解协议', 'https://www.oschina.net/news/420793', 'https://www.oschina.net/news/rss', 'IBM 于上周五与美国司法部达成了一项价值 1700 万美元的和解协议。 此前该公司被指控在招聘和晋升过程中考虑“种族、肤色、国籍或性别”因素，涉嫌实施了“非法的多元化、公平与包容（DEI）做法”。美国司法部还指控 IBM 将政府合同资金用于 DEI 项目，随后又申请报销。 IBM否认有任何不当行为，并表示此次和解并不代表 ...', '', '', '', '', '{\'title\': \'IBM 以 1700 万美元与美国司法部达成和解协议\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'IBM 以 1700 万美元与美国司法部达成和解协议\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420793\'}], \'link\': \'https://www.oschina.net/news/420793\', \'tags\': [{\'term\': \'综合新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'IBM 于上周五与美国司法部达成了一项价值 1700 万美元的和解协议。 此前该公司被指控在招聘和晋升过程中考虑“种族、肤色、国籍或性别”因素，涉嫌实施了“非法的多元化、公平与包容（DEI）做法”。美国司法部还指控 IBM 将政府合同资金用于 DEI 项目，随后又申请报销。 IBM否认有任何不当行为，并表示此次和解并不代表 ...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'IBM 于上周五与美国司法部达成了一项价值 1700 万美元的和解协议。 此前该公司被指控在招聘和晋升过程中考虑“种族、肤色、国籍或性别”因素，涉嫌实施了“非法的多元化、公平与包容（DEI）做法”。美国司法部还指控 IBM 将政府合同资金用于 DEI 项目，随后又申请报销。 IBM否认有任何不当行为，并表示此次和解并不代表 ...\'}, \'published\': \'Tue, 14 Apr 2026 16:52:39 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=52, tm_sec=39, tm_wday=1, tm_yday=104, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420793\', \'guidislink\': False}', '2026-04-14 16:52:39', '2026-04-14 17:05:22', 1, '{\"summary\": \"帮助出海美国的企业了解当地DEI用工及政府资金使用的合规要求，规避用工合规风险\", \"abstract\": \"本文报道IBM因被美国司法部指控存在非法DEI招聘晋升做法、违规使用政府合同资金报销DEI项目，最终以1700万美元与美国司法部达成和解。IBM否认存在任何不当行为，此次和解不代表IBM承认自身过错。该事件为出海美国经营的企业明确了用工与资金使用的合规边界，提供了风险参考。\", \"keywords\": [\"IBM\", \"美国司法部\", \"DEI\", \"用工合规\", \"出海合规\", \"和解协议\", \"政府合同\"], \"policy_risk\": {\"market_risk\": \"出海美国企业在DEI管理、政府项目资金使用环节存在合规风险，违规可能面临罚款处罚\", \"policy_compliance\": \"美国对企业DEI用工做法、政府合同资金使用有明确合规要求，禁止违规将政府合同资金用于DEI项目并申请报销\"}, \"topic_cluster\": \"合规法律\", \"industry_category\": \"科技行业\"}');
INSERT INTO `news` VALUES (545, '赣粤高速：3月车辆通行服务收入为3.51亿元', 'https://36kr.com/newsflashes/3766374650003968?f=rss', 'https://36kr.com/feed-newsflash', '36氪获悉，赣粤高速公告，公司2026年3月份车辆通行服务收入为3.51亿元。', '', '', '', '', '{\'title\': \'赣粤高速：3月车辆通行服务收入为3.51亿元\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'赣粤高速：3月车辆通行服务收入为3.51亿元\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766374650003968?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766374650003968?f=rss\', \'published\': \'2026-04-14 15:54:25  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=7, tm_min=54, tm_sec=25, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，赣粤高速公告，公司2026年3月份车辆通行服务收入为3.51亿元。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'36氪获悉，赣粤高速公告，公司2026年3月份车辆通行服务收入为3.51亿元。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 15:54:25', '2026-04-14 17:05:23', 0, '\"\"');
INSERT INTO `news` VALUES (546, ':fire::fire:最好用的 ORM 框架：xbatis 1.9.9 发布 基于mybatis 的 ORM 框架', 'https://www.oschina.net/news/420786/xbatis-1-9-9-released', 'https://www.oschina.net/news/rss', '1.9.9 - 2026-04-13 1：增加 partialUpdate 精准(局部)修改方法 2：原生updateBatch修改增加null/默认值忽略设置方法 3：LambdaUtil类增加setter/getter Lambda生成方法 4：@ResultCalcField注解支持数据库函数 5：修复exists/notExists中子查询嵌套子查询时，别名一致导致无法上下级引用的问题 6：增加join 子查询的简化...', '', '', '', '', '{\'title\': \':fire::fire:最好用的 ORM 框架：xbatis 1.9.9 发布 基于mybatis 的 ORM 框架\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \':fire::fire:最好用的 ORM 框架：xbatis 1.9.9 发布 基于mybatis 的 ORM 框架\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420786/xbatis-1-9-9-released\'}], \'link\': \'https://www.oschina.net/news/420786/xbatis-1-9-9-released\', \'tags\': [{\'term\': \'软件更新新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'1.9.9 - 2026-04-13 1：增加 partialUpdate 精准(局部)修改方法 2：原生updateBatch修改增加null/默认值忽略设置方法 3：LambdaUtil类增加setter/getter Lambda生成方法 4：@ResultCalcField注解支持数据库函数 5：修复exists/notExists中子查询嵌套子查询时，别名一致导致无法上下级引用的问题 6：增加join 子查询的简化...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'1.9.9 - 2026-04-13 1：增加 partialUpdate 精准(局部)修改方法 2：原生updateBatch修改增加null/默认值忽略设置方法 3：LambdaUtil类增加setter/getter Lambda生成方法 4：@ResultCalcField注解支持数据库函数 5：修复exists/notExists中子查询嵌套子查询时，别名一致导致无法上下级引用的问题 6：增加join 子查询的简化...\'}, \'published\': \'Tue, 14 Apr 2026 16:39:24 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=39, tm_sec=24, tm_wday=1, tm_yday=104, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420786/xbatis-1-9-9-released\', \'guidislink\': False}', '2026-04-14 16:39:24', '2026-04-14 17:05:27', 0, '\"\"');
INSERT INTO `news` VALUES (547, '高德首款具身机器人将亮相', 'https://36kr.com/newsflashes/3766365669802501?f=rss', 'https://36kr.com/feed-newsflash', '从高德获悉，高德首款具身机器人产品将在2026亦庄机器人半马赛事上首次公开亮相。该产品来自高德具身业务部，是一款四足机器人，为阿里巴巴集团推出的首款具身机器人产品。这款机器人将在比赛现场的开放环境下，通过自主感知、决策与交互，完成一系列任务挑战。（上证报）', '', '', '', '', '{\'title\': \'高德首款具身机器人将亮相\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'高德首款具身机器人将亮相\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766365669802501?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766365669802501?f=rss\', \'published\': \'2026-04-14 15:45:17  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=7, tm_min=45, tm_sec=17, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'从高德获悉，高德首款具身机器人产品将在2026亦庄机器人半马赛事上首次公开亮相。该产品来自高德具身业务部，是一款四足机器人，为阿里巴巴集团推出的首款具身机器人产品。这款机器人将在比赛现场的开放环境下，通过自主感知、决策与交互，完成一系列任务挑战。（上证报）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'从高德获悉，高德首款具身机器人产品将在2026亦庄机器人半马赛事上首次公开亮相。该产品来自高德具身业务部，是一款四足机器人，为阿里巴巴集团推出的首款具身机器人产品。这款机器人将在比赛现场的开放环境下，通过自主感知、决策与交互，完成一系列任务挑战。（上证报）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 15:45:17', '2026-04-14 17:05:27', 0, '\"\"');
INSERT INTO `news` VALUES (548, 'LINQ 到 ES|QL：使用 C# 查询 Elasticsearch', 'https://my.oschina.net/u/3343882/blog/19543118', 'https://www.oschina.net/news/rss', '从 v9.3.4 和 v8.19.18 开始，Elasticsearch.NET 客户端包含一个语言集成查询（LINQ）提供程序，可在运行时将 C# LINQ 表达式转换为 Elasticsearch Query Language（ES|QL）查询。你无需手动编写 ES|QL 字符串，而是使用 Where、Select、OrderBy、GroupBy 等标准操作符来构建查询。该提供程序负责处理转换、参数化以及结...', '', '', '', '', '{\'title\': \'LINQ 到 ES|QL：使用 C# 查询 Elasticsearch\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'LINQ 到 ES|QL：使用 C# 查询 Elasticsearch\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://my.oschina.net/u/3343882/blog/19543118\'}], \'link\': \'https://my.oschina.net/u/3343882/blog/19543118\', \'tags\': [{\'term\': \'综合新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'从 v9.3.4 和 v8.19.18 开始，Elasticsearch.NET 客户端包含一个语言集成查询（LINQ）提供程序，可在运行时将 C# LINQ 表达式转换为 Elasticsearch Query Language（ES|QL）查询。你无需手动编写 ES|QL 字符串，而是使用 Where、Select、OrderBy、GroupBy 等标准操作符来构建查询。该提供程序负责处理转换、参数化以及结...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'从 v9.3.4 和 v8.19.18 开始，Elasticsearch.NET 客户端包含一个语言集成查询（LINQ）提供程序，可在运行时将 C# LINQ 表达式转换为 Elasticsearch Query Language（ES|QL）查询。你无需手动编写 ES|QL 字符串，而是使用 Where、Select、OrderBy、GroupBy 等标准操作符来构建查询。该提供程序负责处理转换、参数化以及结...\'}, \'published\': \'Tue, 14 Apr 2026 16:34:58 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=34, tm_sec=58, tm_wday=1, tm_yday=104, tm_isdst=0), \'id\': \'https://my.oschina.net/u/3343882/blog/19543118\', \'guidislink\': False}', '2026-04-14 16:34:58', '2026-04-14 17:05:29', 0, '\"\"');
INSERT INTO `news` VALUES (549, 'Ant Design Pro v6.0.0-beta.4 发布，企业级中后台解决方案', 'https://www.oschina.net/news/420778/ant-design-pro-6-0-0-beta4', 'https://www.oschina.net/news/rss', 'Ant Design Pro v6.0.0-beta.4 现已发布，主要更新内容如下： 新特性 TailwindCSS v4 升级 — 从 TailwindCSS v3 升级到 v4，使用新版配置方式 (#11668) React Query 迁移 — 从 useRequest 迁移到 @tanstack/react-query，提升数据请求和缓存管理能力 (#11665) Cloudflare Worker API — 将 mock API 迁移到 Cloudflare...', '', '', '', '', '{\'title\': \'Ant Design Pro v6.0.0-beta.4 发布，企业级中后台解决方案\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'Ant Design Pro v6.0.0-beta.4 发布，企业级中后台解决方案\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420778/ant-design-pro-6-0-0-beta4\'}], \'link\': \'https://www.oschina.net/news/420778/ant-design-pro-6-0-0-beta4\', \'tags\': [{\'term\': \'软件更新新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'Ant Design Pro v6.0.0-beta.4 现已发布，主要更新内容如下： 新特性 TailwindCSS v4 升级 — 从 TailwindCSS v3 升级到 v4，使用新版配置方式 (#11668) React Query 迁移 — 从 useRequest 迁移到 @tanstack/react-query，提升数据请求和缓存管理能力 (#11665) Cloudflare Worker API — 将 mock API 迁移到 Cloudflare...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'Ant Design Pro v6.0.0-beta.4 现已发布，主要更新内容如下： 新特性 TailwindCSS v4 升级 — 从 TailwindCSS v3 升级到 v4，使用新版配置方式 (#11668) React Query 迁移 — 从 useRequest 迁移到 @tanstack/react-query，提升数据请求和缓存管理能力 (#11665) Cloudflare Worker API — 将 mock API 迁移到 Cloudflare...\'}, \'published\': \'Tue, 14 Apr 2026 16:19:58 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=19, tm_sec=58, tm_wday=1, tm_yday=104, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420778/ant-design-pro-6-0-0-beta4\', \'guidislink\': False}', '2026-04-14 16:19:58', '2026-04-14 17:05:31', 0, '\"\"');
INSERT INTO `news` VALUES (550, 'CREAO AI完成千万美金融资', 'https://36kr.com/newsflashes/3766363299545858?f=rss', 'https://36kr.com/feed-newsflash', '36氪获悉，据Prosperity7消息，CREAO AI完成千万级美金融资，领投方为阿美风险投资（Aramco Ventures）旗下的多元化风投基金Prosperity7 Ventures和经纬创投，并获得过往投资人，包括云启资本、砺思资本、高瓴创投、红杉中国、华业天成资本持续加注。在过去不到一年的时间内，CREAO AI已累积完成超3000万美元融资。', '', '', '', '', '{\'title\': \'CREAO AI完成千万美金融资\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'CREAO AI完成千万美金融资\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766363299545858?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766363299545858?f=rss\', \'published\': \'2026-04-14 15:42:52  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=7, tm_min=42, tm_sec=52, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，据Prosperity7消息，CREAO AI完成千万级美金融资，领投方为阿美风险投资（Aramco Ventures）旗下的多元化风投基金Prosperity7 Ventures和经纬创投，并获得过往投资人，包括云启资本、砺思资本、高瓴创投、红杉中国、华业天成资本持续加注。在过去不到一年的时间内，CREAO AI已累积完成超3000万美元融资。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'36氪获悉，据Prosperity7消息，CREAO AI完成千万级美金融资，领投方为阿美风险投资（Aramco Ventures）旗下的多元化风投基金Prosperity7 Ventures和经纬创投，并获得过往投资人，包括云启资本、砺思资本、高瓴创投、红杉中国、华业天成资本持续加注。在过去不到一年的时间内，CREAO AI已累积完成超3000万美元融资。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 15:42:52', '2026-04-14 17:05:32', 0, '\"\"');
INSERT INTO `news` VALUES (551, 'CopyQ 15.0.0 发布，跨平台剪切板管理工具', 'https://www.oschina.net/news/420751/copyq-15-0-0-released', 'https://www.oschina.net/news/rss', 'CopyQ 是一个剪切板管理工具，可以监控系统剪贴板，并将其内容保存在自定义标签中。保存的剪贴板内容可以在以后直接复制和粘贴到任何应用程序中。 CopyQ 15.0.0 现已发布，更新内容如下： Added 用于 pinned/notes 指示器的颜色和宽度的 CSS 属性。参阅插件指示器。 \nItemPinned { qproperty-pinnedIndicatorColor: rgb...', '', '', '', '', '{\'title\': \'CopyQ 15.0.0 发布，跨平台剪切板管理工具\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'CopyQ 15.0.0 发布，跨平台剪切板管理工具\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420751/copyq-15-0-0-released\'}], \'link\': \'https://www.oschina.net/news/420751/copyq-15-0-0-released\', \'tags\': [{\'term\': \'软件更新新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'CopyQ 是一个剪切板管理工具，可以监控系统剪贴板，并将其内容保存在自定义标签中。保存的剪贴板内容可以在以后直接复制和粘贴到任何应用程序中。 CopyQ 15.0.0 现已发布，更新内容如下： Added 用于 pinned/notes 指示器的颜色和宽度的 CSS 属性。参阅插件指示器。 \\nItemPinned { qproperty-pinnedIndicatorColor: rgb...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'CopyQ 是一个剪切板管理工具，可以监控系统剪贴板，并将其内容保存在自定义标签中。保存的剪贴板内容可以在以后直接复制和粘贴到任何应用程序中。 CopyQ 15.0.0 现已发布，更新内容如下： Added 用于 pinned/notes 指示器的颜色和宽度的 CSS 属性。参阅插件指示器。 \\nItemPinned { qproperty-pinnedIndicatorColor: rgb...\'}, \'published\': \'Tue, 14 Apr 2026 15:29:17 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=7, tm_min=29, tm_sec=17, tm_wday=1, tm_yday=104, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420751/copyq-15-0-0-released\', \'guidislink\': False}', '2026-04-14 15:29:17', '2026-04-14 17:05:33', 0, '\"\"');
INSERT INTO `news` VALUES (552, '吉比特：一季度净利同比预增59%-87%', 'https://36kr.com/newsflashes/3766360223269634?f=rss', 'https://36kr.com/feed-newsflash', '36氪获悉，吉比特公告，预计2026年第一季度实现归属于上市公司股东的净利润4.5亿元-5.3亿元，同比增加59%到87%。', '', '', '', '', '{\'title\': \'吉比特：一季度净利同比预增59%-87%\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'吉比特：一季度净利同比预增59%-87%\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766360223269634?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766360223269634?f=rss\', \'published\': \'2026-04-14 15:39:44  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=7, tm_min=39, tm_sec=44, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'36氪获悉，吉比特公告，预计2026年第一季度实现归属于上市公司股东的净利润4.5亿元-5.3亿元，同比增加59%到87%。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'36氪获悉，吉比特公告，预计2026年第一季度实现归属于上市公司股东的净利润4.5亿元-5.3亿元，同比增加59%到87%。\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 15:39:44', '2026-04-14 17:05:35', 0, '\"\"');
INSERT INTO `news` VALUES (553, 'Seedance 2.0 全面开放 API 服务', 'https://www.oschina.net/news/420732', 'https://www.oschina.net/news/rss', '火山引擎宣布正式上线 Seedance 2.0系列 API 服务，企业和个人用户现在可以调用其视频生成能力，重塑工作流、探索全新的产品形态和应用场景。 Seedance 2.0支持文字、图片、音频、视频四种模态输入。在复杂交互和运动场景下的可用率更高，物理准确度、逼真度、可控性显著增强，更加贴合工业级创作场景的需求。 火山引擎方...', '', '', '', '', '{\'title\': \'Seedance 2.0 全面开放 API 服务\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'Seedance 2.0 全面开放 API 服务\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420732\'}], \'link\': \'https://www.oschina.net/news/420732\', \'tags\': [{\'term\': \'综合新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'火山引擎宣布正式上线 Seedance 2.0系列 API 服务，企业和个人用户现在可以调用其视频生成能力，重塑工作流、探索全新的产品形态和应用场景。 Seedance 2.0支持文字、图片、音频、视频四种模态输入。在复杂交互和运动场景下的可用率更高，物理准确度、逼真度、可控性显著增强，更加贴合工业级创作场景的需求。 火山引擎方...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'火山引擎宣布正式上线 Seedance 2.0系列 API 服务，企业和个人用户现在可以调用其视频生成能力，重塑工作流、探索全新的产品形态和应用场景。 Seedance 2.0支持文字、图片、音频、视频四种模态输入。在复杂交互和运动场景下的可用率更高，物理准确度、逼真度、可控性显著增强，更加贴合工业级创作场景的需求。 火山引擎方...\'}, \'published\': \'Tue, 14 Apr 2026 14:54:39 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=6, tm_min=54, tm_sec=39, tm_wday=1, tm_yday=104, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420732\', \'guidislink\': False}', '2026-04-14 14:54:39', '2026-04-14 17:05:36', 0, '\"\"');
INSERT INTO `news` VALUES (554, '核微反应堆开发商Nuclea Energy申请美股IPO，拟筹资5000万美元', 'https://36kr.com/newsflashes/3766356677444103?f=rss', 'https://36kr.com/feed-newsflash', '致力于为离网市场及数据中心开发核微反应堆的Nuclea Energy于周一向美国证券交易委员会提交申请，拟通过首次公开募股（IPO）筹资最高5000万美元。Nuclea Energy的核心产品为“Morpheus微反应堆”，这是一种可运输、工厂预制、密封堆芯的核反应堆，专为加拿大偏远北极地区和原住民社区、采矿及资源开采、数据中心及关键基础设施、国防与国家安全等场景设计。目前公司仍处于开发阶段，尚未产生任何收入。（新浪财经）', '', '', '', '', '{\'title\': \'核微反应堆开发商Nuclea Energy申请美股IPO，拟筹资5000万美元\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'核微反应堆开发商Nuclea Energy申请美股IPO，拟筹资5000万美元\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3766356677444103?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3766356677444103?f=rss\', \'published\': \'2026-04-14 15:36:08  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=7, tm_min=36, tm_sec=8, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'致力于为离网市场及数据中心开发核微反应堆的Nuclea Energy于周一向美国证券交易委员会提交申请，拟通过首次公开募股（IPO）筹资最高5000万美元。Nuclea Energy的核心产品为“Morpheus微反应堆”，这是一种可运输、工厂预制、密封堆芯的核反应堆，专为加拿大偏远北极地区和原住民社区、采矿及资源开采、数据中心及关键基础设施、国防与国家安全等场景设计。目前公司仍处于开发阶段，尚未产生任何收入。（新浪财经）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'致力于为离网市场及数据中心开发核微反应堆的Nuclea Energy于周一向美国证券交易委员会提交申请，拟通过首次公开募股（IPO）筹资最高5000万美元。Nuclea Energy的核心产品为“Morpheus微反应堆”，这是一种可运输、工厂预制、密封堆芯的核反应堆，专为加拿大偏远北极地区和原住民社区、采矿及资源开采、数据中心及关键基础设施、国防与国家安全等场景设计。目前公司仍处于开发阶段，尚未产生任何收入。（新浪财经）\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 15:36:08', '2026-04-14 17:05:39', 0, '\"\"');
INSERT INTO `news` VALUES (555, '《鞋狗》之后，耐克为什么“跌成狗”了', 'https://36kr.com/p/3766200309580296?f=rss', 'https://36kr.com/feed-article', '<p>耐克这只股票，最近五年真的有点像标题里那个冷笑话。</p>\n  <p>截至2026&nbsp;年&nbsp;4&nbsp;月&nbsp;13&nbsp;日，Nike&nbsp;股价在&nbsp;42&nbsp;美元附近，市值大约 633亿美元。</p>\n  <p>就在&nbsp;3&nbsp;月&nbsp;31&nbsp;日公布最新季度业绩和指引后，市场因为它给出的前景太弱，直接把股价打到了十多年低位附近。</p>\n  <p>库克等大佬个人增持，也没有挡住耐克股价的颓势。</p>\n  <p>问题也已经不是“这季差不差”，而是市场整体开始怀疑：这家曾经几乎代表运动品牌本身的公司，到底还是不是那个熟悉的&nbsp;Nike。</p>\n  <p>如果仔细看财报，你会发现耐克的麻烦不是一天形成的。</p>\n  <p>2025财年，Nike&nbsp;全年营收从&nbsp;514&nbsp;亿美元掉到&nbsp;463&nbsp;亿美元；</p>\n  <p>NIKE Direct&nbsp;从&nbsp;215&nbsp;亿美元降到&nbsp;188&nbsp;亿美元；</p>\n  <p>批发收入也在下滑；毛利率从&nbsp;44.6%&nbsp;降到&nbsp;42.7%；</p>\n  <p>ROIC&nbsp;更是从&nbsp;34.9%&nbsp;掉到&nbsp;20.2%。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_4ab37524e06644fba4cabf6dcc73f418@000000_oswg723200oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>到了2026&nbsp;财年前三季，虽然收入开始有一点企稳迹象，但利润端依旧承压：Q1&nbsp;毛利率&nbsp;42.2%，Q2 40.6%，Q3 40.2%，EPS&nbsp;也一路被压着打。</p>\n  <p>也就是说，耐克是整个经营质量都在变差。</p>\n  <p><strong>这连续的下跌，第一层原因，是耐克过去几年把自己做“偏”了。</strong></p>\n  <p>它原本最强的地方，是产品、品牌、赛事、零售终端、城市文化，一整套系统一起转。</p>\n  <p>但过去几年，耐克明显更迷信DTC，也就是直营和数字化，曾经主动疏远了一部分第三方零售商。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_b1a56232419b436c9b3408cdc9b0c6eb@000000_oswg1043058oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>结果看上去渠道效率更高了，实际上却削弱了品牌在多品牌零售场景里的发现能力、陈列能力和社交扩散能力。</p>\n  <p>连耐克自己现在也承认，过去是“NIKE Direct first offense”，如今要重新回到“整合型市场”，重新修复和批发伙伴的关系。</p>\n  <p>因为大多数消费者本来就不是在耐克自家渠道完成第一次心动的。</p>\n  <p><strong>第二层原因，是它把太多增长押在了“老鞋复用”上。</strong></p>\n  <p>Air Force 1、Dunk、Jordan这些经典款，曾经是印钞机，但印钞机也有被印坏的一天。</p>\n  <p>2024&nbsp;年，耐克在&nbsp;running&nbsp;这个重新升温的大赛道里丢了份额，同时决定减少经典鞋款供给，把资源转回新品开发。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_624021820ea4438b8201e176e6568b5c@000000_oswg859881oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>到2026&nbsp;年，Elliott Hill&nbsp;在电话会上更直接说，耐克这季继续主动清理经典鞋款库存，这一动作单季就对营收造成了大约&nbsp;5&nbsp;个百分点的拖累。</p>\n  <p>而公司此前还说，经典鞋款高峰对应的相关收入，已经被有意压掉了&nbsp;40&nbsp;多亿美元。</p>\n  <p>翻译成人话就是：过去靠老IP、老轮廓、老配色撑起来的繁荣，正在被公司自己拆掉，而新的增长接力棒还没完全跑出来。</p>\n  <p><strong>第三层原因，是中国市场不再是那个“只要品牌够大就能赢”的中国市场了。</strong></p>\n  <p>中国大约占耐克年销售额的15%。但这块市场如今同时叠加了消费降温、本土品牌崛起、耐克自身执行迟缓三重压力。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_a9706855c3444f9a9306ed38310aa140@000000_oswg855291oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>耐克在中国已经连续多个季度下滑，问题不只是“外国品牌不香了”，更在于本地化不够深、库存管理慢、数字和线下执行都偏僵硬。</p>\n  <p>Adidas&nbsp;在中国的一个复苏经验，是把更多产品设计真正做本地化；而耐克则被不少渠道方认为调整还不够深。</p>\n  <p>耐克自己也在最新电话会上承认，中国存在“结构性挑战”和复杂的渠道动态，Q3&nbsp;大中华区收入下滑&nbsp;10%，并预计&nbsp;Q4&nbsp;还会下滑约&nbsp;20%。</p>\n  <p>这意味着中国市场很可能是耐克整个品牌恢复过程中最慢、最难的一块拼图。</p>\n  <p><strong>第四层原因，是耐克的对手们，变快了，也变对了。</strong></p>\n  <p>以前大家总觉得，运动鞋服是耐克和阿迪两强争霸，其他品牌只能吃边角料。</p>\n  <p>但现在不是那个时代了。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_848aca6a9ebd4e2c8a19d9749f9b08a8@000000_oswg832353oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>根据GlobalData&nbsp;的数据，Nike&nbsp;的全球运动服饰市场份额已经从&nbsp;2023&nbsp;年的&nbsp;15.2%&nbsp;掉到&nbsp;2024&nbsp;年的&nbsp;14.1%。</p>\n  <p>而&nbsp;Adidas、New Balance、On、Hoka&nbsp;都在拿份额。</p>\n  <p>更麻烦的是，它们抢走的，恰恰是耐克最该守住的地方：跑步、功能性、专业感、以及年轻消费者对“新鲜感”的期待。</p>\n  <p>耐克之所以不断丢掉货架空间，一个关键原因就是缺少足够能让人眼前一亮的新鞋型，过去&nbsp;Jordan&nbsp;那套神话，如今已经很难原样复制。</p>\n  <p><strong>第五层原因，是这家公司现在一边修复，一边还要扛外部环境的石头。</strong></p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_0b7726fa1bdc4a5b8376f6dede1d1c11@000000_oswg873815oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>耐克财报里几乎每个季度都能看到一个熟悉词：tariffs。2026财年&nbsp;Q1、Q2、Q3，毛利率都明确受到北美更高关税拖累。</p>\n  <p>管理层预计 Q4 毛利率同比降幅为 25 到 75 个基点，其中包含北美关税带来的约 250 个基点拖累。</p>\n  <p>与此同时，中东局势、油价波动、全球贸易保护主义，也都在抬高输入成本、扰乱库存节奏。</p>\n  <p>耐克的问题当然不是关税造成的，但当一家企业本来就在清库存、修渠道、补产品，外部再加一层成本压力，资本市场通常不会给它太多耐心。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_5ddbd799f2be4adba89e98797929bf60@000000_oswg779050oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>所以，耐克为什么会“跌成狗”？</p>\n  <p>因为市场终于不再把它当成一个天然会增长、天然有溢价、天然能把旧故事讲成新故事的品牌神话了。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_f864b0286f884abfbc2dab3cbb0ea2f7@000000_oswg684475oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>它正在从“伟大品牌”被重估成“修复中的大公司”。</p>\n  <p>这两者的估值体系差很多。</p>\n  <p>前者看梦想，看护城河，看文化统治力；后者看库存，看毛利率，看批发修复，看何时止跌，看新品能不能真正跑出来。</p>\n  <p>只要这些数字没有明显拐点，股价就很难靠“Just Do It”&nbsp;回去。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_f1f11d35fc3f430bb2b393dfad074ddf@000000_oswg438902oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>但反过来说，耐克也还没烂到不可逆。&nbsp;</p>\n  <p>最新季度里， Running 业务增长超过 &nbsp;20% ，批发收入同比增长 &nbsp;5% ，管理层也在强调北美和跑步是恢复最快的两个突破口，并计划在今年秋天的 &nbsp;Investor Day &nbsp;给出更完整的长期框架。&nbsp;</p>\n  <p>也就是说，它不是没药了，而是药效还没显现。</p>\n  <p>问题在于，资本市场以前愿意为耐克的传奇预付钱；现在，它只愿意为耐克的兑现买单。</p>\n  <p>说到底，《鞋狗》讲的是创业者如何把一双鞋卖成一个时代的故事。</p>\n  <p>今天资本市场问的却是另一个问题：当一个时代过去了，耐克还能不能重新证明，它卖的不只是鞋，而是下一轮运动消费的标准答案。</p>\n  <p>这是真正让耐克感到不安的地方。</p>\n  <p>本文来自微信公众号 <a href=\"https://mp.weixin.qq.com/s?__biz=MzA3MzE1NjI3MA==&amp;mid=2247505850&amp;idx=1&amp;sn=d6d731e75784d586643ffbcda31e11f7&amp;chksm=9e4dcc0c0e7f900279effaca7fface83b2c31b5df6ca92740aecfb0b244db2c9ebf9e47bd597&amp;scene=0&amp;xtrack=1#rd\" rel=\"noopener noreferrer\" target=\"_blank\">“吴怼怼”（ID：esnql520）</a>，作者：吴怼怼，36氪经授权发布。</p>', '', '', '', '', '{\'title\': \'《鞋狗》之后，耐克为什么“跌成狗”了\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'《鞋狗》之后，耐克为什么“跌成狗”了\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3766200309580296?f=rss\'}], \'link\': \'https://36kr.com/p/3766200309580296?f=rss\', \'published\': \'2026-04-14 15:33:47  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=7, tm_min=33, tm_sec=47, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'<p>耐克这只股票，最近五年真的有点像标题里那个冷笑话。</p>\\n  <p>截至2026&nbsp;年&nbsp;4&nbsp;月&nbsp;13&nbsp;日，Nike&nbsp;股价在&nbsp;42&nbsp;美元附近，市值大约 633亿美元。</p>\\n  <p>就在&nbsp;3&nbsp;月&nbsp;31&nbsp;日公布最新季度业绩和指引后，市场因为它给出的前景太弱，直接把股价打到了十多年低位附近。</p>\\n  <p>库克等大佬个人增持，也没有挡住耐克股价的颓势。</p>\\n  <p>问题也已经不是“这季差不差”，而是市场整体开始怀疑：这家曾经几乎代表运动品牌本身的公司，到底还是不是那个熟悉的&nbsp;Nike。</p>\\n  <p>如果仔细看财报，你会发现耐克的麻烦不是一天形成的。</p>\\n  <p>2025财年，Nike&nbsp;全年营收从&nbsp;514&nbsp;亿美元掉到&nbsp;463&nbsp;亿美元；</p>\\n  <p>NIKE Direct&nbsp;从&nbsp;215&nbsp;亿美元降到&nbsp;188&nbsp;亿美元；</p>\\n  <p>批发收入也在下滑；毛利率从&nbsp;44.6%&nbsp;降到&nbsp;42.7%；</p>\\n  <p>ROIC&nbsp;更是从&nbsp;34.9%&nbsp;掉到&nbsp;20.2%。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_4ab37524e06644fba4cabf6dcc73f418@000000_oswg723200oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>到了2026&nbsp;财年前三季，虽然收入开始有一点企稳迹象，但利润端依旧承压：Q1&nbsp;毛利率&nbsp;42.2%，Q2 40.6%，Q3 40.2%，EPS&nbsp;也一路被压着打。</p>\\n  <p>也就是说，耐克是整个经营质量都在变差。</p>\\n  <p><strong>这连续的下跌，第一层原因，是耐克过去几年把自己做“偏”了。</strong></p>\\n  <p>它原本最强的地方，是产品、品牌、赛事、零售终端、城市文化，一整套系统一起转。</p>\\n  <p>但过去几年，耐克明显更迷信DTC，也就是直营和数字化，曾经主动疏远了一部分第三方零售商。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_b1a56232419b436c9b3408cdc9b0c6eb@000000_oswg1043058oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>结果看上去渠道效率更高了，实际上却削弱了品牌在多品牌零售场景里的发现能力、陈列能力和社交扩散能力。</p>\\n  <p>连耐克自己现在也承认，过去是“NIKE Direct first offense”，如今要重新回到“整合型市场”，重新修复和批发伙伴的关系。</p>\\n  <p>因为大多数消费者本来就不是在耐克自家渠道完成第一次心动的。</p>\\n  <p><strong>第二层原因，是它把太多增长押在了“老鞋复用”上。</strong></p>\\n  <p>Air Force 1、Dunk、Jordan这些经典款，曾经是印钞机，但印钞机也有被印坏的一天。</p>\\n  <p>2024&nbsp;年，耐克在&nbsp;running&nbsp;这个重新升温的大赛道里丢了份额，同时决定减少经典鞋款供给，把资源转回新品开发。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_624021820ea4438b8201e176e6568b5c@000000_oswg859881oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>到2026&nbsp;年，Elliott Hill&nbsp;在电话会上更直接说，耐克这季继续主动清理经典鞋款库存，这一动作单季就对营收造成了大约&nbsp;5&nbsp;个百分点的拖累。</p>\\n  <p>而公司此前还说，经典鞋款高峰对应的相关收入，已经被有意压掉了&nbsp;40&nbsp;多亿美元。</p>\\n  <p>翻译成人话就是：过去靠老IP、老轮廓、老配色撑起来的繁荣，正在被公司自己拆掉，而新的增长接力棒还没完全跑出来。</p>\\n  <p><strong>第三层原因，是中国市场不再是那个“只要品牌够大就能赢”的中国市场了。</strong></p>\\n  <p>中国大约占耐克年销售额的15%。但这块市场如今同时叠加了消费降温、本土品牌崛起、耐克自身执行迟缓三重压力。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_a9706855c3444f9a9306ed38310aa140@000000_oswg855291oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>耐克在中国已经连续多个季度下滑，问题不只是“外国品牌不香了”，更在于本地化不够深、库存管理慢、数字和线下执行都偏僵硬。</p>\\n  <p>Adidas&nbsp;在中国的一个复苏经验，是把更多产品设计真正做本地化；而耐克则被不少渠道方认为调整还不够深。</p>\\n  <p>耐克自己也在最新电话会上承认，中国存在“结构性挑战”和复杂的渠道动态，Q3&nbsp;大中华区收入下滑&nbsp;10%，并预计&nbsp;Q4&nbsp;还会下滑约&nbsp;20%。</p>\\n  <p>这意味着中国市场很可能是耐克整个品牌恢复过程中最慢、最难的一块拼图。</p>\\n  <p><strong>第四层原因，是耐克的对手们，变快了，也变对了。</strong></p>\\n  <p>以前大家总觉得，运动鞋服是耐克和阿迪两强争霸，其他品牌只能吃边角料。</p>\\n  <p>但现在不是那个时代了。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_848aca6a9ebd4e2c8a19d9749f9b08a8@000000_oswg832353oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>根据GlobalData&nbsp;的数据，Nike&nbsp;的全球运动服饰市场份额已经从&nbsp;2023&nbsp;年的&nbsp;15.2%&nbsp;掉到&nbsp;2024&nbsp;年的&nbsp;14.1%。</p>\\n  <p>而&nbsp;Adidas、New Balance、On、Hoka&nbsp;都在拿份额。</p>\\n  <p>更麻烦的是，它们抢走的，恰恰是耐克最该守住的地方：跑步、功能性、专业感、以及年轻消费者对“新鲜感”的期待。</p>\\n  <p>耐克之所以不断丢掉货架空间，一个关键原因就是缺少足够能让人眼前一亮的新鞋型，过去&nbsp;Jordan&nbsp;那套神话，如今已经很难原样复制。</p>\\n  <p><strong>第五层原因，是这家公司现在一边修复，一边还要扛外部环境的石头。</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_0b7726fa1bdc4a5b8376f6dede1d1c11@000000_oswg873815oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>耐克财报里几乎每个季度都能看到一个熟悉词：tariffs。2026财年&nbsp;Q1、Q2、Q3，毛利率都明确受到北美更高关税拖累。</p>\\n  <p>管理层预计 Q4 毛利率同比降幅为 25 到 75 个基点，其中包含北美关税带来的约 250 个基点拖累。</p>\\n  <p>与此同时，中东局势、油价波动、全球贸易保护主义，也都在抬高输入成本、扰乱库存节奏。</p>\\n  <p>耐克的问题当然不是关税造成的，但当一家企业本来就在清库存、修渠道、补产品，外部再加一层成本压力，资本市场通常不会给它太多耐心。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_5ddbd799f2be4adba89e98797929bf60@000000_oswg779050oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>所以，耐克为什么会“跌成狗”？</p>\\n  <p>因为市场终于不再把它当成一个天然会增长、天然有溢价、天然能把旧故事讲成新故事的品牌神话了。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_f864b0286f884abfbc2dab3cbb0ea2f7@000000_oswg684475oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>它正在从“伟大品牌”被重估成“修复中的大公司”。</p>\\n  <p>这两者的估值体系差很多。</p>\\n  <p>前者看梦想，看护城河，看文化统治力；后者看库存，看毛利率，看批发修复，看何时止跌，看新品能不能真正跑出来。</p>\\n  <p>只要这些数字没有明显拐点，股价就很难靠“Just Do It”&nbsp;回去。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_f1f11d35fc3f430bb2b393dfad074ddf@000000_oswg438902oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>但反过来说，耐克也还没烂到不可逆。&nbsp;</p>\\n  <p>最新季度里， Running 业务增长超过 &nbsp;20% ，批发收入同比增长 &nbsp;5% ，管理层也在强调北美和跑步是恢复最快的两个突破口，并计划在今年秋天的 &nbsp;Investor Day &nbsp;给出更完整的长期框架。&nbsp;</p>\\n  <p>也就是说，它不是没药了，而是药效还没显现。</p>\\n  <p>问题在于，资本市场以前愿意为耐克的传奇预付钱；现在，它只愿意为耐克的兑现买单。</p>\\n  <p>说到底，《鞋狗》讲的是创业者如何把一双鞋卖成一个时代的故事。</p>\\n  <p>今天资本市场问的却是另一个问题：当一个时代过去了，耐克还能不能重新证明，它卖的不只是鞋，而是下一轮运动消费的标准答案。</p>\\n  <p>这是真正让耐克感到不安的地方。</p>\\n  <p>本文来自微信公众号 <a href=\"https://mp.weixin.qq.com/s?__biz=MzA3MzE1NjI3MA==&amp;mid=2247505850&amp;idx=1&amp;sn=d6d731e75784d586643ffbcda31e11f7&amp;chksm=9e4dcc0c0e7f900279effaca7fface83b2c31b5df6ca92740aecfb0b244db2c9ebf9e47bd597&amp;scene=0&amp;xtrack=1#rd\" rel=\"noopener noreferrer\" target=\"_blank\">“吴怼怼”（ID：esnql520）</a>，作者：吴怼怼，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>耐克这只股票，最近五年真的有点像标题里那个冷笑话。</p>\\n  <p>截至2026&nbsp;年&nbsp;4&nbsp;月&nbsp;13&nbsp;日，Nike&nbsp;股价在&nbsp;42&nbsp;美元附近，市值大约 633亿美元。</p>\\n  <p>就在&nbsp;3&nbsp;月&nbsp;31&nbsp;日公布最新季度业绩和指引后，市场因为它给出的前景太弱，直接把股价打到了十多年低位附近。</p>\\n  <p>库克等大佬个人增持，也没有挡住耐克股价的颓势。</p>\\n  <p>问题也已经不是“这季差不差”，而是市场整体开始怀疑：这家曾经几乎代表运动品牌本身的公司，到底还是不是那个熟悉的&nbsp;Nike。</p>\\n  <p>如果仔细看财报，你会发现耐克的麻烦不是一天形成的。</p>\\n  <p>2025财年，Nike&nbsp;全年营收从&nbsp;514&nbsp;亿美元掉到&nbsp;463&nbsp;亿美元；</p>\\n  <p>NIKE Direct&nbsp;从&nbsp;215&nbsp;亿美元降到&nbsp;188&nbsp;亿美元；</p>\\n  <p>批发收入也在下滑；毛利率从&nbsp;44.6%&nbsp;降到&nbsp;42.7%；</p>\\n  <p>ROIC&nbsp;更是从&nbsp;34.9%&nbsp;掉到&nbsp;20.2%。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_4ab37524e06644fba4cabf6dcc73f418@000000_oswg723200oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>到了2026&nbsp;财年前三季，虽然收入开始有一点企稳迹象，但利润端依旧承压：Q1&nbsp;毛利率&nbsp;42.2%，Q2 40.6%，Q3 40.2%，EPS&nbsp;也一路被压着打。</p>\\n  <p>也就是说，耐克是整个经营质量都在变差。</p>\\n  <p><strong>这连续的下跌，第一层原因，是耐克过去几年把自己做“偏”了。</strong></p>\\n  <p>它原本最强的地方，是产品、品牌、赛事、零售终端、城市文化，一整套系统一起转。</p>\\n  <p>但过去几年，耐克明显更迷信DTC，也就是直营和数字化，曾经主动疏远了一部分第三方零售商。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_b1a56232419b436c9b3408cdc9b0c6eb@000000_oswg1043058oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>结果看上去渠道效率更高了，实际上却削弱了品牌在多品牌零售场景里的发现能力、陈列能力和社交扩散能力。</p>\\n  <p>连耐克自己现在也承认，过去是“NIKE Direct first offense”，如今要重新回到“整合型市场”，重新修复和批发伙伴的关系。</p>\\n  <p>因为大多数消费者本来就不是在耐克自家渠道完成第一次心动的。</p>\\n  <p><strong>第二层原因，是它把太多增长押在了“老鞋复用”上。</strong></p>\\n  <p>Air Force 1、Dunk、Jordan这些经典款，曾经是印钞机，但印钞机也有被印坏的一天。</p>\\n  <p>2024&nbsp;年，耐克在&nbsp;running&nbsp;这个重新升温的大赛道里丢了份额，同时决定减少经典鞋款供给，把资源转回新品开发。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_624021820ea4438b8201e176e6568b5c@000000_oswg859881oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>到2026&nbsp;年，Elliott Hill&nbsp;在电话会上更直接说，耐克这季继续主动清理经典鞋款库存，这一动作单季就对营收造成了大约&nbsp;5&nbsp;个百分点的拖累。</p>\\n  <p>而公司此前还说，经典鞋款高峰对应的相关收入，已经被有意压掉了&nbsp;40&nbsp;多亿美元。</p>\\n  <p>翻译成人话就是：过去靠老IP、老轮廓、老配色撑起来的繁荣，正在被公司自己拆掉，而新的增长接力棒还没完全跑出来。</p>\\n  <p><strong>第三层原因，是中国市场不再是那个“只要品牌够大就能赢”的中国市场了。</strong></p>\\n  <p>中国大约占耐克年销售额的15%。但这块市场如今同时叠加了消费降温、本土品牌崛起、耐克自身执行迟缓三重压力。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_a9706855c3444f9a9306ed38310aa140@000000_oswg855291oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>耐克在中国已经连续多个季度下滑，问题不只是“外国品牌不香了”，更在于本地化不够深、库存管理慢、数字和线下执行都偏僵硬。</p>\\n  <p>Adidas&nbsp;在中国的一个复苏经验，是把更多产品设计真正做本地化；而耐克则被不少渠道方认为调整还不够深。</p>\\n  <p>耐克自己也在最新电话会上承认，中国存在“结构性挑战”和复杂的渠道动态，Q3&nbsp;大中华区收入下滑&nbsp;10%，并预计&nbsp;Q4&nbsp;还会下滑约&nbsp;20%。</p>\\n  <p>这意味着中国市场很可能是耐克整个品牌恢复过程中最慢、最难的一块拼图。</p>\\n  <p><strong>第四层原因，是耐克的对手们，变快了，也变对了。</strong></p>\\n  <p>以前大家总觉得，运动鞋服是耐克和阿迪两强争霸，其他品牌只能吃边角料。</p>\\n  <p>但现在不是那个时代了。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_848aca6a9ebd4e2c8a19d9749f9b08a8@000000_oswg832353oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>根据GlobalData&nbsp;的数据，Nike&nbsp;的全球运动服饰市场份额已经从&nbsp;2023&nbsp;年的&nbsp;15.2%&nbsp;掉到&nbsp;2024&nbsp;年的&nbsp;14.1%。</p>\\n  <p>而&nbsp;Adidas、New Balance、On、Hoka&nbsp;都在拿份额。</p>\\n  <p>更麻烦的是，它们抢走的，恰恰是耐克最该守住的地方：跑步、功能性、专业感、以及年轻消费者对“新鲜感”的期待。</p>\\n  <p>耐克之所以不断丢掉货架空间，一个关键原因就是缺少足够能让人眼前一亮的新鞋型，过去&nbsp;Jordan&nbsp;那套神话，如今已经很难原样复制。</p>\\n  <p><strong>第五层原因，是这家公司现在一边修复，一边还要扛外部环境的石头。</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_0b7726fa1bdc4a5b8376f6dede1d1c11@000000_oswg873815oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>耐克财报里几乎每个季度都能看到一个熟悉词：tariffs。2026财年&nbsp;Q1、Q2、Q3，毛利率都明确受到北美更高关税拖累。</p>\\n  <p>管理层预计 Q4 毛利率同比降幅为 25 到 75 个基点，其中包含北美关税带来的约 250 个基点拖累。</p>\\n  <p>与此同时，中东局势、油价波动、全球贸易保护主义，也都在抬高输入成本、扰乱库存节奏。</p>\\n  <p>耐克的问题当然不是关税造成的，但当一家企业本来就在清库存、修渠道、补产品，外部再加一层成本压力，资本市场通常不会给它太多耐心。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_5ddbd799f2be4adba89e98797929bf60@000000_oswg779050oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>所以，耐克为什么会“跌成狗”？</p>\\n  <p>因为市场终于不再把它当成一个天然会增长、天然有溢价、天然能把旧故事讲成新故事的品牌神话了。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_f864b0286f884abfbc2dab3cbb0ea2f7@000000_oswg684475oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>它正在从“伟大品牌”被重估成“修复中的大公司”。</p>\\n  <p>这两者的估值体系差很多。</p>\\n  <p>前者看梦想，看护城河，看文化统治力；后者看库存，看毛利率，看批发修复，看何时止跌，看新品能不能真正跑出来。</p>\\n  <p>只要这些数字没有明显拐点，股价就很难靠“Just Do It”&nbsp;回去。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_f1f11d35fc3f430bb2b393dfad074ddf@000000_oswg438902oswg1080oswg602_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>但反过来说，耐克也还没烂到不可逆。&nbsp;</p>\\n  <p>最新季度里， Running 业务增长超过 &nbsp;20% ，批发收入同比增长 &nbsp;5% ，管理层也在强调北美和跑步是恢复最快的两个突破口，并计划在今年秋天的 &nbsp;Investor Day &nbsp;给出更完整的长期框架。&nbsp;</p>\\n  <p>也就是说，它不是没药了，而是药效还没显现。</p>\\n  <p>问题在于，资本市场以前愿意为耐克的传奇预付钱；现在，它只愿意为耐克的兑现买单。</p>\\n  <p>说到底，《鞋狗》讲的是创业者如何把一双鞋卖成一个时代的故事。</p>\\n  <p>今天资本市场问的却是另一个问题：当一个时代过去了，耐克还能不能重新证明，它卖的不只是鞋，而是下一轮运动消费的标准答案。</p>\\n  <p>这是真正让耐克感到不安的地方。</p>\\n  <p>本文来自微信公众号 <a href=\"https://mp.weixin.qq.com/s?__biz=MzA3MzE1NjI3MA==&amp;mid=2247505850&amp;idx=1&amp;sn=d6d731e75784d586643ffbcda31e11f7&amp;chksm=9e4dcc0c0e7f900279effaca7fface83b2c31b5df6ca92740aecfb0b244db2c9ebf9e47bd597&amp;scene=0&amp;xtrack=1#rd\" rel=\"noopener noreferrer\" target=\"_blank\">“吴怼怼”（ID：esnql520）</a>，作者：吴怼怼，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'吴怼怼\'}], \'author\': \'吴怼怼\', \'author_detail\': {\'name\': \'吴怼怼\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'耐克还能不能重新证明自己？\'}]}', '2026-04-14 15:33:47', '2026-04-14 17:05:40', 1, '{\"summary\": \"本文分析耐克近年股价与业绩双下跌的核心原因，为出海运动品牌的战略布局和本地化运营提供经验参考\", \"abstract\": \"本文介绍了耐克近年营收、利润持续下滑，股价跌至十多年低位的经营现状。文章从渠道战略偏差、过度依赖经典鞋款、中国市场表现不佳、竞品冲击、外部环境成本压力五个层面，拆解了耐克业绩下滑的核心原因。文章指出当前资本市场已经将耐克从\\\"伟大品牌\\\"重估为\\\"修复中的大公司\\\"，只有业绩出现明显拐点才能推动估值回升。目前耐克已经开启战略调整，业绩修复的效果仍待时间验证。\", \"keywords\": [\"耐克\", \"股价下跌\", \"DTC\", \"中国市场\", \"关税\", \"运动服饰\", \"本地化\", \"市场份额\"], \"policy_risk\": {\"market_risk\": \"战略过度侧重直营数字化疏远批发渠道、过度依赖经典鞋款导致经营质量下滑；中国市场遭遇消费降温、本土品牌崛起，连续多个季度业绩下滑，存在结构性挑战；多个竞品抢占市场份额，耐克全球运动服饰市场份额持续下降；地缘局势、油价波动扰乱库存节奏，叠加成本压力，资本市场对业绩兑现要求提升，耐克遭遇估值重估\", \"policy_compliance\": \"北美地区关税提升，全球贸易保护主义抬高企业经营成本\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"运动服饰\"}');
INSERT INTO `news` VALUES (556, 'An AI Vibe Coding Horror Story', 'https://www.tobru.ch/an-ai-vibe-coding-horror-story/', 'https://hnrss.org/frontpage', '<p>Article URL: <a href=\"https://www.tobru.ch/an-ai-vibe-coding-horror-story/\">https://www.tobru.ch/an-ai-vibe-coding-horror-story/</a></p>\n<p>Comments URL: <a href=\"https://news.ycombinator.com/item?id=47762901\">https://news.ycombinator.com/item?id=47762901</a></p>\n<p>Points: 10</p>\n<p># Comments: 0</p>', '', '', '', '', '{\'title\': \'An AI Vibe Coding Horror Story\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://hnrss.org/frontpage\', \'value\': \'An AI Vibe Coding Horror Story\'}, \'summary\': \'<p>Article URL: <a href=\"https://www.tobru.ch/an-ai-vibe-coding-horror-story/\">https://www.tobru.ch/an-ai-vibe-coding-horror-story/</a></p>\\n<p>Comments URL: <a href=\"https://news.ycombinator.com/item?id=47762901\">https://news.ycombinator.com/item?id=47762901</a></p>\\n<p>Points: 10</p>\\n<p># Comments: 0</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://hnrss.org/frontpage\', \'value\': \'<p>Article URL: <a href=\"https://www.tobru.ch/an-ai-vibe-coding-horror-story/\">https://www.tobru.ch/an-ai-vibe-coding-horror-story/</a></p>\\n<p>Comments URL: <a href=\"https://news.ycombinator.com/item?id=47762901\">https://news.ycombinator.com/item?id=47762901</a></p>\\n<p>Points: 10</p>\\n<p># Comments: 0</p>\'}, \'published\': \'Tue, 14 Apr 2026 08:35:45 +0000\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=35, tm_sec=45, tm_wday=1, tm_yday=104, tm_isdst=0), \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.tobru.ch/an-ai-vibe-coding-horror-story/\'}], \'link\': \'https://www.tobru.ch/an-ai-vibe-coding-horror-story/\', \'authors\': [{\'name\': \'teichmann\'}], \'author\': \'teichmann\', \'author_detail\': {\'name\': \'teichmann\'}, \'comments\': \'https://news.ycombinator.com/item?id=47762901\', \'id\': \'https://news.ycombinator.com/item?id=47762901\', \'guidislink\': False}', '2026-04-14 08:35:45', '2026-04-14 17:05:42', 0, '\"\"');
INSERT INTO `news` VALUES (557, '世界变了、Linus妥协了？AI代码可以进Linux内核，但出了事人来背', 'https://36kr.com/p/3766159271117570?f=rss', 'https://36kr.com/feed-article', '<blockquote>\n   <p>Linux 给 AI 生成代码“立规矩”：Copilot 可以用，但出了问题人来背。&nbsp;</p>\n  </blockquote>\n  <p>吵了几个月之后，Linus Torvalds 和 Linux 内核维护者终于把 Linux 内核第一套 AI 辅助代码规则定下来了。这套新规很符合 Torvalds 一贯的务实风格：AI 工具可以用，但 Linux 内核对代码质量的高要求一点也不会放松。</p>\n  <p>新指南主要定了三件事。</p>\n  <p><strong>第一，AI 代理不能添加 Signed-off-by 标签</strong></p>\n  <p>只有人类才能合法签署 Linux 内核的开发者来源证明（Developer Certificate of Origin，DCO）。这是确保代码许可合规的法律机制。换句话说，即便你提交的补丁完全由 AI 编写，责任仍然只在你本人，而不是 AI 或其提供方。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_3f2b53ff28fe4c50853fa92bc933c895@000000_oswg29064oswg837oswg220_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p><strong>第二，必须标注 Assisted-by（辅助来源）</strong></p>\n  <p>如果在内核开发过程中用了 AI 工具，就要把来源写清楚，这样大家才能知道 AI 在这次提交里到底参与了多少。相关代码贡献需要按下面这个格式加上 Assisted-by 标签：</p>\n  <p>Assisted-by: AGENT_NAME:MODEL_VERSION [TOOL1] [TOOL2]</p>\n  <p>这里需要把你用了什么模型、什么 Agent、还有哪些辅助工具说清楚。比如 AGENT_NAME 是你用的 AI 工具或者框架名称；MODEL_VERSION 是具体用的模型版本；[TOOL1] [TOOL2] 是可选项，用来写这次还搭配用了哪些专门的分析工具，比如 coccinelle、sparse、smatch、clang-tidy。像 git、gcc、make、编辑器这些日常基础工具，就不用写进去了。</p>\n  <p>比如，如果你用的是 Claude 的 claude-3-opus，同时还配合 coccinelle 和 sparse 做分析，就可以这样写：</p>\n  <p>Assisted-by: Claude:claude-3-opus coccinelle sparse</p>\n  <p><strong>第三，人类承担全部责任</strong></p>\n  <p>把前面几条合起来看，意思其实很明确：AI 可以参与写代码，但责任不能转嫁给 AI。AI 生成的代码有没有经过完整审查，许可证是不是合规，后续如果出了 bug 或安全漏洞，最后都要由提交代码的人来负责。</p>\n  <p>不要试图把有问题的代码偷偷混进内核。2021 年明尼苏达大学的那起事件，就是一个典型的前车之鉴。否则，你基本可以告别 Linux 内核开发者身份，以及任何严肃开源项目的参与机会。</p>\n  <p>那次事件里，明尼苏达大学一组研究人员以安全研究的名义，故意向 Linux 内核提交带有缺陷、甚至可能引入漏洞的补丁，想借此测试社区能不能识别并拦下这些“有问题的修复”。问题不只在于补丁本身有问题，更在于他们事先没有告知社区，而是直接把维护者和开发者当成了实验对象。</p>\n  <p>事情曝光后，Greg Kroah-Hartman 公开批评这种做法浪费社区时间、破坏协作信任，相关提交被集中审查和回滚，明尼苏达大学的后续贡献也被 Linux 社区封禁，成为内核社区至今仍反复引用的反面案例。</p>\n  <h2><strong>1 &nbsp;Claude 已经够强了，但在内核里还只是工具&nbsp;</strong></h2>\n  <p>Assisted-by 标签既是透明机制，也是一个“提醒标记”。它让维护者在不污名化 AI 使用的前提下，对 AI 辅助的补丁进行更严格的审查。</p>\n  <p>这个标签的出现，其实源自一场不小的争议。</p>\n  <p>争议的起点，是 Nvidia 工程师、知名 Linux 内核开发者 Sasha Levin。在 2025 年北美开源峰会上，他分享了自己用 LLM 改进内核的一些实践。</p>\n  <p>他认为 LLM 本质上就是一个参数规模巨大的模式匹配引擎，可以看作一个“超大的状态机”。不同的是，内核里常见的状态机是确定性的，而 LLM 的状态转移是概率性的。给定一段上下文，它会预测“下一个最可能的词”。比如输入“the Linux kernel is written in...”，它几乎一定会输出 “C”，但也存在较小概率输出 “Rust” 或 “Python”。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_dd92c77bf1de4803b9b2cbdae071abf1@000000_oswg29471oswg790oswg347_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>同时，LLM 依赖“上下文窗口”工作，也就是它在回答时能够“记住”的输入文本。<strong>像 Claude 这样的系统，上下文窗口大约在 20 万 token 左右，已经足够覆盖一个完整的内核子系统。</strong></p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_44f9de3263514ef68f83d7d02b236647@000000_oswg39873oswg777oswg431_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>Levin 并不认为 LLM 会取代人类做内核开发。他更愿意把它看作“下一代编译器”。过去开发者写汇编，后来有了高级语言；当时也有人不认可，说“真正的开发者应该自己分配寄存器”。但最终大家还是接受了更高层的工具，生产力也随之提升。LLM 也是类似的演进——它不完美，但已经足够带来效率提升。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_6edbe5727e36499fbbc834854af636a6@000000_oswg28671oswg720oswg182_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>他举了一个例子：Linux 6.15 中合入的一个补丁，署名是他，但代码实际上是由 LLM 完整生成的，连 changelog 也是。Levin 对代码做了审查和测试，但并没有亲自编写。他认为，这类“小而明确”的任务正是 LLM 的强项，但还没到可以让它独立写出一个全新设备驱动的程度。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_39a23283105c4ebb976756ef9ecd3c39@000000_oswg72932oswg893oswg557_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>LLM 在写 commit message 上也很有帮助，而这件事往往比写代码本身更难，尤其对非英语母语的开发者来说。</p>\n  <p>他还展示了补丁中的一段修改。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_38e9110f47604cddad0213975b01c68f@000000_oswg9758oswg294oswg107_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>这里从一个哈希 API 切换到另一个，需要把“大小”改为“2 的幂表示”。LLM 正确理解了这一点，并做了对应修改。它还在补丁后面意识到一个 mask 操作其实是多余的，于是直接删除。Levin 表示，这段代码既正确，也高效。</p>\n  <p>围绕这件事，社区也讨论了更多问题。比如，有人问：会不会因为过度信任 LLM 输出而引入错误？Levin 的回答是：LLM 会出错，人类也会，而且经常会。还有人问代码的许可证问题，他表示自己并没有深入考虑，直觉上认为模型生成的代码是可以使用的。</p>\n  <p>最后也有人问，这套方法能不能用于代码合入前的自动审查。Levin 表示技术上是可行的，但规模太大、成本太高，目前还不现实，不过未来有可能做到。</p>\n  <p>这场风波的一个直接结果是：Levin 本人开始支持建立 AI 使用的透明规则，他提交了第一版提案，也就是后来内核 AI 政策的雏形，最初建议用 Co-developed-by 来标记 AI 参与。</p>\n  <p>随后，无论是线下讨论还是 Linux Kernel Mailing List（LKML）上的交流，都在争论是引入新的 Generated-by 标签，还是复用现有的 Co-developed-by。最终，维护者选择了 Assisted-by，更准确地体现 AI 作为“工具”的角色，而不是“共同作者”。</p>\n  <p>最终选择 Assisted-by 而不是 Generated-by，主要基于三点考虑：</p>\n  <p>第一，更准确。内核开发中 AI 更多用于辅助（代码补全、重构建议、测试生成），而不是完整生成代码；</p>\n  <p>第二，格式一致。它与 Reviewed-by、Tested-by、Co-developed-by 等现有标签保持一致；</p>\n  <p>第三，中性表达。既说明了工具的参与，又不会暗示代码“不可信”或“低一等”。</p>\n  <p>这种务实路线，其实也和 Torvalds 的态度一致。他说：“我不希望内核开发文档变成某种 AI 立场声明。‘世界要完了’和‘AI 会彻底改变软件工程’这两种声音已经够多了。我不希望文档站队。对我来说，它就应该是——AI 只是一个工具。”</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_4024642851ca46028bcbb394e359ca87@000000_oswg97027oswg787oswg578_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <h2><strong>2 &nbsp;一夜之间世界就变了，规则也只能跟着改&nbsp;</strong></h2>\n  <p>这一决策背后，一个很重要的现实变化是，AI 编程助手在内核开发里，突然开始变得“真的有用”了。</p>\n  <p>上个月，Linux 稳定内核维护者 Greg Kroah-Hartman 提到，几个月前，内核社区面对的还主要是所谓的“AI slop”，也就是那些明显不对、质量很低的 AI 生成安全报告。“当时甚至还有点好笑，也不太让人担心。”当然，Linux 内核有很多维护者，对他们来说，这类垃圾报告的压力远没有 cURL 那样大。cURL 的创始人兼主要开发者 Daniel Stenberg 就因为 AI 垃圾报告太多，一度暂停了漏洞赏金。</p>\n  <p>但情况已经变了。Kroah-Hartman 说，大概一个月前，也就是约在 2 月份，某个节点发生了变化，“整个世界都切换了。现在我们收到的，是‘真的’报告了。”</p>\n  <p>而且不只是 Linux。他提到，现在很多开源项目都在收到 AI 生成的报告，而且这些报告是好的、真实的。各大开源项目的安全团队之间一直有非正式的沟通，大家都观察到了同样的变化。换句话说，这已经不是 Linux 一家的问题，而是整个开源安全圈同时遇到的新情况。</p>\n  <p>至于到底发生了什么，没有人说得清。被问到变化的原因时，他说：“我们也不知道。没人知道为什么。可能是很多工具突然变好了，也可能是大家开始认真用这些工具了。看起来是很多不同的团队、不同的公司同时在做这件事。”</p>\n  <p>“这些工具确实挺好用的，我们没法忽视它们：它们已经来了，而且还在变得更强。”</p>\n  <p>北京时间周一，Linus Torvalds 发布了 Linux 内核 7.0。对他来说，这次升级到 7.0 并不意味着什么“重大版本转折”，更多只是版本号走到 x.19 之后，顺手进位到 x.0，避免继续往后编号显得太乱。</p>\n  <p>不过，这次发布说明里还是有一句话格外值得注意。Torvalds 写道，“我怀疑，接下来一段时间，大家大量使用 AI 工具，还会不断帮我们把各种边角问题翻出来，所以这可能会成为一段时间里的‘新常态’。至于会持续多久，还要再看。”</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_09e86e93f44146dfb5701ba805301497@000000_oswg49047oswg597oswg361_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\n  <p>另外，虽然 Linux 内核已经引入了 AI 披露政策，但维护者并不会依赖所谓的 AI 检测工具来识别未披露的 AI 代码。他们依然得依靠老办法：深厚的技术经验、模式识别能力，以及最传统的代码评审。正如 Torvalds 在 2023 年说的：“评判他人的代码，需要一定的品味。”</p>\n  <p>问题就在这里。正如他所说：“讨论 AI 垃圾代码没有意义，因为写这些的人不会主动标注。”难的从来不是明显有问题的垃圾代码，而是那些表面看起来完全正常的补丁：它们符合当前需求，风格一致，可以顺利编译，但内部却埋着细微 bug，或长期维护成本的隐患。</p>\n  <p>因此，这套新政策的执行，并不依赖抓住每一个违规者，而是通过提高违规代价，来约束行为。问问那些曾因为提交劣质补丁而被 Torvalds 当面“教育”的人就知道了。虽然他现在已经比过去温和不少，但你依然不会想站在他的对立面。</p>\n  <p><strong>参考资料：</strong></p>\n  <p>https://docs.kernel.org/process/coding-assistants.html</p>\n  <p>https://www.youtube.com/watch?v=ec7gDUFm2-Q</p>\n  <p>https://lwn.net/Articles/1026558/</p>\n  <p>https://lore.kernel.org/lkml/CAHk-=wg0sdh_OF8zgFD-f6o9yFRK=tDOXhB1JAxfs11W9bX--Q@mail.gmail.com/</p>\n  <p>https://www.theregister.com/2026/04/13/linux_kernel_7_releaseed/</p>\n  <p>本文来自微信公众号 <a href=\"https://mp.weixin.qq.com/s?__biz=MjM5MDE0Mjc4MA==&amp;mid=2651281607&amp;idx=1&amp;sn=4195df78a3eb209ae7ae0073f84edaa9&amp;chksm=bc82ca34489df5e2b6ff26be379c2f84dfdfb13491d2103b8974cb22335cbcda77cc61ef67ac&amp;scene=0&amp;xtrack=1#rd\" rel=\"noopener noreferrer\" target=\"_blank\">“InfoQ”（ID：infoqchina）</a>，作者：Tina，36氪经授权发布。</p>', '', '', '', '', '{\'title\': \'世界变了、Linus妥协了？AI代码可以进Linux内核，但出了事人来背\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'世界变了、Linus妥协了？AI代码可以进Linux内核，但出了事人来背\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3766159271117570?f=rss\'}], \'link\': \'https://36kr.com/p/3766159271117570?f=rss\', \'published\': \'2026-04-14 15:33:36  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=7, tm_min=33, tm_sec=36, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'<blockquote>\\n   <p>Linux 给 AI 生成代码“立规矩”：Copilot 可以用，但出了问题人来背。&nbsp;</p>\\n  </blockquote>\\n  <p>吵了几个月之后，Linus Torvalds 和 Linux 内核维护者终于把 Linux 内核第一套 AI 辅助代码规则定下来了。这套新规很符合 Torvalds 一贯的务实风格：AI 工具可以用，但 Linux 内核对代码质量的高要求一点也不会放松。</p>\\n  <p>新指南主要定了三件事。</p>\\n  <p><strong>第一，AI 代理不能添加 Signed-off-by 标签</strong></p>\\n  <p>只有人类才能合法签署 Linux 内核的开发者来源证明（Developer Certificate of Origin，DCO）。这是确保代码许可合规的法律机制。换句话说，即便你提交的补丁完全由 AI 编写，责任仍然只在你本人，而不是 AI 或其提供方。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_3f2b53ff28fe4c50853fa92bc933c895@000000_oswg29064oswg837oswg220_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p><strong>第二，必须标注 Assisted-by（辅助来源）</strong></p>\\n  <p>如果在内核开发过程中用了 AI 工具，就要把来源写清楚，这样大家才能知道 AI 在这次提交里到底参与了多少。相关代码贡献需要按下面这个格式加上 Assisted-by 标签：</p>\\n  <p>Assisted-by: AGENT_NAME:MODEL_VERSION [TOOL1] [TOOL2]</p>\\n  <p>这里需要把你用了什么模型、什么 Agent、还有哪些辅助工具说清楚。比如 AGENT_NAME 是你用的 AI 工具或者框架名称；MODEL_VERSION 是具体用的模型版本；[TOOL1] [TOOL2] 是可选项，用来写这次还搭配用了哪些专门的分析工具，比如 coccinelle、sparse、smatch、clang-tidy。像 git、gcc、make、编辑器这些日常基础工具，就不用写进去了。</p>\\n  <p>比如，如果你用的是 Claude 的 claude-3-opus，同时还配合 coccinelle 和 sparse 做分析，就可以这样写：</p>\\n  <p>Assisted-by: Claude:claude-3-opus coccinelle sparse</p>\\n  <p><strong>第三，人类承担全部责任</strong></p>\\n  <p>把前面几条合起来看，意思其实很明确：AI 可以参与写代码，但责任不能转嫁给 AI。AI 生成的代码有没有经过完整审查，许可证是不是合规，后续如果出了 bug 或安全漏洞，最后都要由提交代码的人来负责。</p>\\n  <p>不要试图把有问题的代码偷偷混进内核。2021 年明尼苏达大学的那起事件，就是一个典型的前车之鉴。否则，你基本可以告别 Linux 内核开发者身份，以及任何严肃开源项目的参与机会。</p>\\n  <p>那次事件里，明尼苏达大学一组研究人员以安全研究的名义，故意向 Linux 内核提交带有缺陷、甚至可能引入漏洞的补丁，想借此测试社区能不能识别并拦下这些“有问题的修复”。问题不只在于补丁本身有问题，更在于他们事先没有告知社区，而是直接把维护者和开发者当成了实验对象。</p>\\n  <p>事情曝光后，Greg Kroah-Hartman 公开批评这种做法浪费社区时间、破坏协作信任，相关提交被集中审查和回滚，明尼苏达大学的后续贡献也被 Linux 社区封禁，成为内核社区至今仍反复引用的反面案例。</p>\\n  <h2><strong>1 &nbsp;Claude 已经够强了，但在内核里还只是工具&nbsp;</strong></h2>\\n  <p>Assisted-by 标签既是透明机制，也是一个“提醒标记”。它让维护者在不污名化 AI 使用的前提下，对 AI 辅助的补丁进行更严格的审查。</p>\\n  <p>这个标签的出现，其实源自一场不小的争议。</p>\\n  <p>争议的起点，是 Nvidia 工程师、知名 Linux 内核开发者 Sasha Levin。在 2025 年北美开源峰会上，他分享了自己用 LLM 改进内核的一些实践。</p>\\n  <p>他认为 LLM 本质上就是一个参数规模巨大的模式匹配引擎，可以看作一个“超大的状态机”。不同的是，内核里常见的状态机是确定性的，而 LLM 的状态转移是概率性的。给定一段上下文，它会预测“下一个最可能的词”。比如输入“the Linux kernel is written in...”，它几乎一定会输出 “C”，但也存在较小概率输出 “Rust” 或 “Python”。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_dd92c77bf1de4803b9b2cbdae071abf1@000000_oswg29471oswg790oswg347_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>同时，LLM 依赖“上下文窗口”工作，也就是它在回答时能够“记住”的输入文本。<strong>像 Claude 这样的系统，上下文窗口大约在 20 万 token 左右，已经足够覆盖一个完整的内核子系统。</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_44f9de3263514ef68f83d7d02b236647@000000_oswg39873oswg777oswg431_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>Levin 并不认为 LLM 会取代人类做内核开发。他更愿意把它看作“下一代编译器”。过去开发者写汇编，后来有了高级语言；当时也有人不认可，说“真正的开发者应该自己分配寄存器”。但最终大家还是接受了更高层的工具，生产力也随之提升。LLM 也是类似的演进——它不完美，但已经足够带来效率提升。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_6edbe5727e36499fbbc834854af636a6@000000_oswg28671oswg720oswg182_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>他举了一个例子：Linux 6.15 中合入的一个补丁，署名是他，但代码实际上是由 LLM 完整生成的，连 changelog 也是。Levin 对代码做了审查和测试，但并没有亲自编写。他认为，这类“小而明确”的任务正是 LLM 的强项，但还没到可以让它独立写出一个全新设备驱动的程度。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_39a23283105c4ebb976756ef9ecd3c39@000000_oswg72932oswg893oswg557_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>LLM 在写 commit message 上也很有帮助，而这件事往往比写代码本身更难，尤其对非英语母语的开发者来说。</p>\\n  <p>他还展示了补丁中的一段修改。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_38e9110f47604cddad0213975b01c68f@000000_oswg9758oswg294oswg107_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>这里从一个哈希 API 切换到另一个，需要把“大小”改为“2 的幂表示”。LLM 正确理解了这一点，并做了对应修改。它还在补丁后面意识到一个 mask 操作其实是多余的，于是直接删除。Levin 表示，这段代码既正确，也高效。</p>\\n  <p>围绕这件事，社区也讨论了更多问题。比如，有人问：会不会因为过度信任 LLM 输出而引入错误？Levin 的回答是：LLM 会出错，人类也会，而且经常会。还有人问代码的许可证问题，他表示自己并没有深入考虑，直觉上认为模型生成的代码是可以使用的。</p>\\n  <p>最后也有人问，这套方法能不能用于代码合入前的自动审查。Levin 表示技术上是可行的，但规模太大、成本太高，目前还不现实，不过未来有可能做到。</p>\\n  <p>这场风波的一个直接结果是：Levin 本人开始支持建立 AI 使用的透明规则，他提交了第一版提案，也就是后来内核 AI 政策的雏形，最初建议用 Co-developed-by 来标记 AI 参与。</p>\\n  <p>随后，无论是线下讨论还是 Linux Kernel Mailing List（LKML）上的交流，都在争论是引入新的 Generated-by 标签，还是复用现有的 Co-developed-by。最终，维护者选择了 Assisted-by，更准确地体现 AI 作为“工具”的角色，而不是“共同作者”。</p>\\n  <p>最终选择 Assisted-by 而不是 Generated-by，主要基于三点考虑：</p>\\n  <p>第一，更准确。内核开发中 AI 更多用于辅助（代码补全、重构建议、测试生成），而不是完整生成代码；</p>\\n  <p>第二，格式一致。它与 Reviewed-by、Tested-by、Co-developed-by 等现有标签保持一致；</p>\\n  <p>第三，中性表达。既说明了工具的参与，又不会暗示代码“不可信”或“低一等”。</p>\\n  <p>这种务实路线，其实也和 Torvalds 的态度一致。他说：“我不希望内核开发文档变成某种 AI 立场声明。‘世界要完了’和‘AI 会彻底改变软件工程’这两种声音已经够多了。我不希望文档站队。对我来说，它就应该是——AI 只是一个工具。”</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_4024642851ca46028bcbb394e359ca87@000000_oswg97027oswg787oswg578_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <h2><strong>2 &nbsp;一夜之间世界就变了，规则也只能跟着改&nbsp;</strong></h2>\\n  <p>这一决策背后，一个很重要的现实变化是，AI 编程助手在内核开发里，突然开始变得“真的有用”了。</p>\\n  <p>上个月，Linux 稳定内核维护者 Greg Kroah-Hartman 提到，几个月前，内核社区面对的还主要是所谓的“AI slop”，也就是那些明显不对、质量很低的 AI 生成安全报告。“当时甚至还有点好笑，也不太让人担心。”当然，Linux 内核有很多维护者，对他们来说，这类垃圾报告的压力远没有 cURL 那样大。cURL 的创始人兼主要开发者 Daniel Stenberg 就因为 AI 垃圾报告太多，一度暂停了漏洞赏金。</p>\\n  <p>但情况已经变了。Kroah-Hartman 说，大概一个月前，也就是约在 2 月份，某个节点发生了变化，“整个世界都切换了。现在我们收到的，是‘真的’报告了。”</p>\\n  <p>而且不只是 Linux。他提到，现在很多开源项目都在收到 AI 生成的报告，而且这些报告是好的、真实的。各大开源项目的安全团队之间一直有非正式的沟通，大家都观察到了同样的变化。换句话说，这已经不是 Linux 一家的问题，而是整个开源安全圈同时遇到的新情况。</p>\\n  <p>至于到底发生了什么，没有人说得清。被问到变化的原因时，他说：“我们也不知道。没人知道为什么。可能是很多工具突然变好了，也可能是大家开始认真用这些工具了。看起来是很多不同的团队、不同的公司同时在做这件事。”</p>\\n  <p>“这些工具确实挺好用的，我们没法忽视它们：它们已经来了，而且还在变得更强。”</p>\\n  <p>北京时间周一，Linus Torvalds 发布了 Linux 内核 7.0。对他来说，这次升级到 7.0 并不意味着什么“重大版本转折”，更多只是版本号走到 x.19 之后，顺手进位到 x.0，避免继续往后编号显得太乱。</p>\\n  <p>不过，这次发布说明里还是有一句话格外值得注意。Torvalds 写道，“我怀疑，接下来一段时间，大家大量使用 AI 工具，还会不断帮我们把各种边角问题翻出来，所以这可能会成为一段时间里的‘新常态’。至于会持续多久，还要再看。”</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_09e86e93f44146dfb5701ba805301497@000000_oswg49047oswg597oswg361_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>另外，虽然 Linux 内核已经引入了 AI 披露政策，但维护者并不会依赖所谓的 AI 检测工具来识别未披露的 AI 代码。他们依然得依靠老办法：深厚的技术经验、模式识别能力，以及最传统的代码评审。正如 Torvalds 在 2023 年说的：“评判他人的代码，需要一定的品味。”</p>\\n  <p>问题就在这里。正如他所说：“讨论 AI 垃圾代码没有意义，因为写这些的人不会主动标注。”难的从来不是明显有问题的垃圾代码，而是那些表面看起来完全正常的补丁：它们符合当前需求，风格一致，可以顺利编译，但内部却埋着细微 bug，或长期维护成本的隐患。</p>\\n  <p>因此，这套新政策的执行，并不依赖抓住每一个违规者，而是通过提高违规代价，来约束行为。问问那些曾因为提交劣质补丁而被 Torvalds 当面“教育”的人就知道了。虽然他现在已经比过去温和不少，但你依然不会想站在他的对立面。</p>\\n  <p><strong>参考资料：</strong></p>\\n  <p>https://docs.kernel.org/process/coding-assistants.html</p>\\n  <p>https://www.youtube.com/watch?v=ec7gDUFm2-Q</p>\\n  <p>https://lwn.net/Articles/1026558/</p>\\n  <p>https://lore.kernel.org/lkml/CAHk-=wg0sdh_OF8zgFD-f6o9yFRK=tDOXhB1JAxfs11W9bX--Q@mail.gmail.com/</p>\\n  <p>https://www.theregister.com/2026/04/13/linux_kernel_7_releaseed/</p>\\n  <p>本文来自微信公众号 <a href=\"https://mp.weixin.qq.com/s?__biz=MjM5MDE0Mjc4MA==&amp;mid=2651281607&amp;idx=1&amp;sn=4195df78a3eb209ae7ae0073f84edaa9&amp;chksm=bc82ca34489df5e2b6ff26be379c2f84dfdfb13491d2103b8974cb22335cbcda77cc61ef67ac&amp;scene=0&amp;xtrack=1#rd\" rel=\"noopener noreferrer\" target=\"_blank\">“InfoQ”（ID：infoqchina）</a>，作者：Tina，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<blockquote>\\n   <p>Linux 给 AI 生成代码“立规矩”：Copilot 可以用，但出了问题人来背。&nbsp;</p>\\n  </blockquote>\\n  <p>吵了几个月之后，Linus Torvalds 和 Linux 内核维护者终于把 Linux 内核第一套 AI 辅助代码规则定下来了。这套新规很符合 Torvalds 一贯的务实风格：AI 工具可以用，但 Linux 内核对代码质量的高要求一点也不会放松。</p>\\n  <p>新指南主要定了三件事。</p>\\n  <p><strong>第一，AI 代理不能添加 Signed-off-by 标签</strong></p>\\n  <p>只有人类才能合法签署 Linux 内核的开发者来源证明（Developer Certificate of Origin，DCO）。这是确保代码许可合规的法律机制。换句话说，即便你提交的补丁完全由 AI 编写，责任仍然只在你本人，而不是 AI 或其提供方。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_3f2b53ff28fe4c50853fa92bc933c895@000000_oswg29064oswg837oswg220_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p><strong>第二，必须标注 Assisted-by（辅助来源）</strong></p>\\n  <p>如果在内核开发过程中用了 AI 工具，就要把来源写清楚，这样大家才能知道 AI 在这次提交里到底参与了多少。相关代码贡献需要按下面这个格式加上 Assisted-by 标签：</p>\\n  <p>Assisted-by: AGENT_NAME:MODEL_VERSION [TOOL1] [TOOL2]</p>\\n  <p>这里需要把你用了什么模型、什么 Agent、还有哪些辅助工具说清楚。比如 AGENT_NAME 是你用的 AI 工具或者框架名称；MODEL_VERSION 是具体用的模型版本；[TOOL1] [TOOL2] 是可选项，用来写这次还搭配用了哪些专门的分析工具，比如 coccinelle、sparse、smatch、clang-tidy。像 git、gcc、make、编辑器这些日常基础工具，就不用写进去了。</p>\\n  <p>比如，如果你用的是 Claude 的 claude-3-opus，同时还配合 coccinelle 和 sparse 做分析，就可以这样写：</p>\\n  <p>Assisted-by: Claude:claude-3-opus coccinelle sparse</p>\\n  <p><strong>第三，人类承担全部责任</strong></p>\\n  <p>把前面几条合起来看，意思其实很明确：AI 可以参与写代码，但责任不能转嫁给 AI。AI 生成的代码有没有经过完整审查，许可证是不是合规，后续如果出了 bug 或安全漏洞，最后都要由提交代码的人来负责。</p>\\n  <p>不要试图把有问题的代码偷偷混进内核。2021 年明尼苏达大学的那起事件，就是一个典型的前车之鉴。否则，你基本可以告别 Linux 内核开发者身份，以及任何严肃开源项目的参与机会。</p>\\n  <p>那次事件里，明尼苏达大学一组研究人员以安全研究的名义，故意向 Linux 内核提交带有缺陷、甚至可能引入漏洞的补丁，想借此测试社区能不能识别并拦下这些“有问题的修复”。问题不只在于补丁本身有问题，更在于他们事先没有告知社区，而是直接把维护者和开发者当成了实验对象。</p>\\n  <p>事情曝光后，Greg Kroah-Hartman 公开批评这种做法浪费社区时间、破坏协作信任，相关提交被集中审查和回滚，明尼苏达大学的后续贡献也被 Linux 社区封禁，成为内核社区至今仍反复引用的反面案例。</p>\\n  <h2><strong>1 &nbsp;Claude 已经够强了，但在内核里还只是工具&nbsp;</strong></h2>\\n  <p>Assisted-by 标签既是透明机制，也是一个“提醒标记”。它让维护者在不污名化 AI 使用的前提下，对 AI 辅助的补丁进行更严格的审查。</p>\\n  <p>这个标签的出现，其实源自一场不小的争议。</p>\\n  <p>争议的起点，是 Nvidia 工程师、知名 Linux 内核开发者 Sasha Levin。在 2025 年北美开源峰会上，他分享了自己用 LLM 改进内核的一些实践。</p>\\n  <p>他认为 LLM 本质上就是一个参数规模巨大的模式匹配引擎，可以看作一个“超大的状态机”。不同的是，内核里常见的状态机是确定性的，而 LLM 的状态转移是概率性的。给定一段上下文，它会预测“下一个最可能的词”。比如输入“the Linux kernel is written in...”，它几乎一定会输出 “C”，但也存在较小概率输出 “Rust” 或 “Python”。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_dd92c77bf1de4803b9b2cbdae071abf1@000000_oswg29471oswg790oswg347_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>同时，LLM 依赖“上下文窗口”工作，也就是它在回答时能够“记住”的输入文本。<strong>像 Claude 这样的系统，上下文窗口大约在 20 万 token 左右，已经足够覆盖一个完整的内核子系统。</strong></p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_44f9de3263514ef68f83d7d02b236647@000000_oswg39873oswg777oswg431_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>Levin 并不认为 LLM 会取代人类做内核开发。他更愿意把它看作“下一代编译器”。过去开发者写汇编，后来有了高级语言；当时也有人不认可，说“真正的开发者应该自己分配寄存器”。但最终大家还是接受了更高层的工具，生产力也随之提升。LLM 也是类似的演进——它不完美，但已经足够带来效率提升。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_6edbe5727e36499fbbc834854af636a6@000000_oswg28671oswg720oswg182_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>他举了一个例子：Linux 6.15 中合入的一个补丁，署名是他，但代码实际上是由 LLM 完整生成的，连 changelog 也是。Levin 对代码做了审查和测试，但并没有亲自编写。他认为，这类“小而明确”的任务正是 LLM 的强项，但还没到可以让它独立写出一个全新设备驱动的程度。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_39a23283105c4ebb976756ef9ecd3c39@000000_oswg72932oswg893oswg557_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>LLM 在写 commit message 上也很有帮助，而这件事往往比写代码本身更难，尤其对非英语母语的开发者来说。</p>\\n  <p>他还展示了补丁中的一段修改。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_38e9110f47604cddad0213975b01c68f@000000_oswg9758oswg294oswg107_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>这里从一个哈希 API 切换到另一个，需要把“大小”改为“2 的幂表示”。LLM 正确理解了这一点，并做了对应修改。它还在补丁后面意识到一个 mask 操作其实是多余的，于是直接删除。Levin 表示，这段代码既正确，也高效。</p>\\n  <p>围绕这件事，社区也讨论了更多问题。比如，有人问：会不会因为过度信任 LLM 输出而引入错误？Levin 的回答是：LLM 会出错，人类也会，而且经常会。还有人问代码的许可证问题，他表示自己并没有深入考虑，直觉上认为模型生成的代码是可以使用的。</p>\\n  <p>最后也有人问，这套方法能不能用于代码合入前的自动审查。Levin 表示技术上是可行的，但规模太大、成本太高，目前还不现实，不过未来有可能做到。</p>\\n  <p>这场风波的一个直接结果是：Levin 本人开始支持建立 AI 使用的透明规则，他提交了第一版提案，也就是后来内核 AI 政策的雏形，最初建议用 Co-developed-by 来标记 AI 参与。</p>\\n  <p>随后，无论是线下讨论还是 Linux Kernel Mailing List（LKML）上的交流，都在争论是引入新的 Generated-by 标签，还是复用现有的 Co-developed-by。最终，维护者选择了 Assisted-by，更准确地体现 AI 作为“工具”的角色，而不是“共同作者”。</p>\\n  <p>最终选择 Assisted-by 而不是 Generated-by，主要基于三点考虑：</p>\\n  <p>第一，更准确。内核开发中 AI 更多用于辅助（代码补全、重构建议、测试生成），而不是完整生成代码；</p>\\n  <p>第二，格式一致。它与 Reviewed-by、Tested-by、Co-developed-by 等现有标签保持一致；</p>\\n  <p>第三，中性表达。既说明了工具的参与，又不会暗示代码“不可信”或“低一等”。</p>\\n  <p>这种务实路线，其实也和 Torvalds 的态度一致。他说：“我不希望内核开发文档变成某种 AI 立场声明。‘世界要完了’和‘AI 会彻底改变软件工程’这两种声音已经够多了。我不希望文档站队。对我来说，它就应该是——AI 只是一个工具。”</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_4024642851ca46028bcbb394e359ca87@000000_oswg97027oswg787oswg578_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <h2><strong>2 &nbsp;一夜之间世界就变了，规则也只能跟着改&nbsp;</strong></h2>\\n  <p>这一决策背后，一个很重要的现实变化是，AI 编程助手在内核开发里，突然开始变得“真的有用”了。</p>\\n  <p>上个月，Linux 稳定内核维护者 Greg Kroah-Hartman 提到，几个月前，内核社区面对的还主要是所谓的“AI slop”，也就是那些明显不对、质量很低的 AI 生成安全报告。“当时甚至还有点好笑，也不太让人担心。”当然，Linux 内核有很多维护者，对他们来说，这类垃圾报告的压力远没有 cURL 那样大。cURL 的创始人兼主要开发者 Daniel Stenberg 就因为 AI 垃圾报告太多，一度暂停了漏洞赏金。</p>\\n  <p>但情况已经变了。Kroah-Hartman 说，大概一个月前，也就是约在 2 月份，某个节点发生了变化，“整个世界都切换了。现在我们收到的，是‘真的’报告了。”</p>\\n  <p>而且不只是 Linux。他提到，现在很多开源项目都在收到 AI 生成的报告，而且这些报告是好的、真实的。各大开源项目的安全团队之间一直有非正式的沟通，大家都观察到了同样的变化。换句话说，这已经不是 Linux 一家的问题，而是整个开源安全圈同时遇到的新情况。</p>\\n  <p>至于到底发生了什么，没有人说得清。被问到变化的原因时，他说：“我们也不知道。没人知道为什么。可能是很多工具突然变好了，也可能是大家开始认真用这些工具了。看起来是很多不同的团队、不同的公司同时在做这件事。”</p>\\n  <p>“这些工具确实挺好用的，我们没法忽视它们：它们已经来了，而且还在变得更强。”</p>\\n  <p>北京时间周一，Linus Torvalds 发布了 Linux 内核 7.0。对他来说，这次升级到 7.0 并不意味着什么“重大版本转折”，更多只是版本号走到 x.19 之后，顺手进位到 x.0，避免继续往后编号显得太乱。</p>\\n  <p>不过，这次发布说明里还是有一句话格外值得注意。Torvalds 写道，“我怀疑，接下来一段时间，大家大量使用 AI 工具，还会不断帮我们把各种边角问题翻出来，所以这可能会成为一段时间里的‘新常态’。至于会持续多久，还要再看。”</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_09e86e93f44146dfb5701ba805301497@000000_oswg49047oswg597oswg361_img_000?x-oss-process=image/format,jpg/interlace,1\" /></p>\\n  <p>另外，虽然 Linux 内核已经引入了 AI 披露政策，但维护者并不会依赖所谓的 AI 检测工具来识别未披露的 AI 代码。他们依然得依靠老办法：深厚的技术经验、模式识别能力，以及最传统的代码评审。正如 Torvalds 在 2023 年说的：“评判他人的代码，需要一定的品味。”</p>\\n  <p>问题就在这里。正如他所说：“讨论 AI 垃圾代码没有意义，因为写这些的人不会主动标注。”难的从来不是明显有问题的垃圾代码，而是那些表面看起来完全正常的补丁：它们符合当前需求，风格一致，可以顺利编译，但内部却埋着细微 bug，或长期维护成本的隐患。</p>\\n  <p>因此，这套新政策的执行，并不依赖抓住每一个违规者，而是通过提高违规代价，来约束行为。问问那些曾因为提交劣质补丁而被 Torvalds 当面“教育”的人就知道了。虽然他现在已经比过去温和不少，但你依然不会想站在他的对立面。</p>\\n  <p><strong>参考资料：</strong></p>\\n  <p>https://docs.kernel.org/process/coding-assistants.html</p>\\n  <p>https://www.youtube.com/watch?v=ec7gDUFm2-Q</p>\\n  <p>https://lwn.net/Articles/1026558/</p>\\n  <p>https://lore.kernel.org/lkml/CAHk-=wg0sdh_OF8zgFD-f6o9yFRK=tDOXhB1JAxfs11W9bX--Q@mail.gmail.com/</p>\\n  <p>https://www.theregister.com/2026/04/13/linux_kernel_7_releaseed/</p>\\n  <p>本文来自微信公众号 <a href=\"https://mp.weixin.qq.com/s?__biz=MjM5MDE0Mjc4MA==&amp;mid=2651281607&amp;idx=1&amp;sn=4195df78a3eb209ae7ae0073f84edaa9&amp;chksm=bc82ca34489df5e2b6ff26be379c2f84dfdfb13491d2103b8974cb22335cbcda77cc61ef67ac&amp;scene=0&amp;xtrack=1#rd\" rel=\"noopener noreferrer\" target=\"_blank\">“InfoQ”（ID：infoqchina）</a>，作者：Tina，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'极客邦科技InfoQ\'}], \'author\': \'极客邦科技InfoQ\', \'author_detail\': {\'name\': \'极客邦科技InfoQ\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'Linux 给 AI 生成代码“立规矩”：Copilot 可以用，但出了问题人来背。\'}]}', '2026-04-14 15:33:36', '2026-04-14 17:05:42', 0, '\"\"');
