INSERT INTO `news` VALUES (560, 'MOS tech 6502 8-bit microprocessor in pure SQL powered by Postgres', 'https://github.com/lasect/pg_6502', 'https://hnrss.org/frontpage', '<p>Article URL: <a href=\"https://github.com/lasect/pg_6502\">https://github.com/lasect/pg_6502</a></p>\n<p>Comments URL: <a href=\"https://news.ycombinator.com/item?id=47761723\">https://news.ycombinator.com/item?id=47761723</a></p>\n<p>Points: 11</p>\n<p># Comments: 0</p>', '', '', '', '', '{\'title\': \'MOS tech 6502 8-bit microprocessor in pure SQL powered by Postgres\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://hnrss.org/frontpage\', \'value\': \'MOS tech 6502 8-bit microprocessor in pure SQL powered by Postgres\'}, \'summary\': \'<p>Article URL: <a href=\"https://github.com/lasect/pg_6502\">https://github.com/lasect/pg_6502</a></p>\\n<p>Comments URL: <a href=\"https://news.ycombinator.com/item?id=47761723\">https://news.ycombinator.com/item?id=47761723</a></p>\\n<p>Points: 11</p>\\n<p># Comments: 0</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://hnrss.org/frontpage\', \'value\': \'<p>Article URL: <a href=\"https://github.com/lasect/pg_6502\">https://github.com/lasect/pg_6502</a></p>\\n<p>Comments URL: <a href=\"https://news.ycombinator.com/item?id=47761723\">https://news.ycombinator.com/item?id=47761723</a></p>\\n<p>Points: 11</p>\\n<p># Comments: 0</p>\'}, \'published\': \'Tue, 14 Apr 2026 05:46:49 +0000\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=5, tm_min=46, tm_sec=49, tm_wday=1, tm_yday=104, tm_isdst=0), \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://github.com/lasect/pg_6502\'}], \'link\': \'https://github.com/lasect/pg_6502\', \'authors\': [{\'name\': \'adunk\'}], \'author\': \'adunk\', \'author_detail\': {\'name\': \'adunk\'}, \'comments\': \'https://news.ycombinator.com/item?id=47761723\', \'id\': \'https://news.ycombinat