SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ----------------------------
-- Table structure for news
-- ----------------------------
DROP TABLE IF EXISTS `news`;
CREATE TABLE `news`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '标题',
  `url` varchar(1024) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '原始链接',
  `source` varchar(128) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT 'RSS来源',
  `content` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '正文',
  `authors` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '文章作者',
  `keywords` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '关键词',
  `category` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '行业分类',
  `ai_summary` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT 'ai总结',
  `origin_msg` longtext CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '原始数据',
  `published_at` datetime NULL DEFAULT NULL COMMENT '发布时间',
  `created_at` datetime NOT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '爬虫时间',
  `is_policy` tinyint NULL DEFAULT NULL COMMENT '是否为政策类文章',
  `ai_json_output` json NULL COMMENT 'AI提取总结的JSON',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_url`(`url` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 600 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of news
-- ----------------------------
How的赛道。</strong></p>\n  <p><strong>张海波：</strong>那四年里，我们掌握了大量对体育的理解，从初学者到深度爱好者、再到专业运动员的全过程理解，很少有人能看到这个完整的路径。</p>\n  <p>我能感受到那些爱好者对科技产品的渴求，每次交流时他们都非常兴奋。这让我萌生了创业的想法，不再做20多万的高价设备——这类产品很前沿、但用户面有限，只能解决极少数人的痛点。我想做一款广大爱好者买得起用得上的运动科技产品。</p>\n  <p><strong>硬氪：市面上各类体育智能硬件存在鲜明的定位差异，我们该如何理解不同运动场景与产品定位的界定？庞伯特出于哪些考量最终锁定了产品方向？</strong></p>\n  <p><strong>张海波：</strong>通常来讲，我们可以将泛体育划分为四个方向。一种是Sports，即具备完整竞技规则、可开展专业赛事的运动，比如足球、篮球、网球等，这也是庞伯特所瞄准的赛道；第二种叫Recreation，偏向休闲娱乐属性的活动，例如飞镖、飞盘、桌球等，在海外，有些乒乓球场景也可以归属到这一活动品类中，更多用于聚会消遣；三是Outdoor，追求自我突破的户外运动，比如登山、划船等，用户更注重挑战身体极限、刷新个人纪录；第四类是Fitness，即以塑形、体能提升为目标的健身运动。</p>\n  <p>这四个品类不能说不相通，但从面向爱好者的专业化产品角度，界限是分明的。庞伯特做的是Sports，以及部分与Sports相关的Recreation娱乐化呈现，跟Fitness、Outdoor类运动目前没关系。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_aedd8a3132df493b96a4f5bdc8b0562f@6022551_oswg4390912oswg6000oswg3376_img_jpg?x-oss-process=image/quality,q_80/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">庞伯特PACE系列智能网球发球机器人（图源/企业）</p>\n  <p><strong>硬氪：从产品形态上来看，传统发球机出现了几十年，但大多仍停留在机械吐球阶段，用户体验几乎没有革新。庞伯特想解决的核心矛盾是什么？</strong></p>\n  <p><strong>张海波：</strong>运动场景里，用户只有三种状态——纯玩、训练、比赛/对战。三个场景互斥，用户在球场上只能做其中一件事。这也就决定了我们在做产品时要选侧重点。</p>\n  <p>庞伯特专注的是训练场景。<strong>用户真正需要的并不是一个机器对手。</strong>对战本身带有强烈社交属性，即便机器能陪打，用户最终还是会回归人与人之间的对抗。很多人觉得机器人接球很新鲜，但其底层需求并不是 “陪打”，而是 “可以借助机器来辅助自己练习”。练习，才是核心需求。</p>\n  <p>在大众运动里，找对手很容易，甚至不缺免费的伙伴。但好教练却很难得：要么找不到、要么风格不合适、时间难约，成本还高。即便用户每周请一次教练，其余大部分自主训练时间，不管是颠球、空挥、使用发球机还是对墙练习，大家都希望身边能有一个 “教练”。他可以不用一直喂球，但能持续观察、给出实时指导。而这些需求，目前几乎没有产品能够真正满足。</p>\n  <p><strong>硬氪：这些用户画像有什么特点？</strong></p>\n  <p><strong>张海波：</strong>国内外运动人群的训练习惯存在明显差异。<strong>在海外，大多数运动几乎不存在“纯娱乐”的阶段，要么不参与、要么从开始就接受专业教练指导，训练意识普遍更强。</strong>而国内用户往往先从兴趣玩乐切入，再逐步转向系统性训练。</p>\n  <p>这也决定了我们初代产品是主要服务于资深运动爱好者，即面向掌握特定技巧、提想升运动能力的用户。这类人群熟悉运动本身，他们渴望在真实比赛里赢更多球，但缺乏明确的训练目标，需要借助设备辅助练习。</p>\n  <p>对这类用户而言，成本账很容易算清：线下教练课时费即便偏低也要100美元/小时，进阶课程更是高达200至500美元不等。庞伯特的发球机器人价格段覆盖1000–5000美元区间，无论是作为日常辅助训练工具，还是替代部分教练功能的AI Coach（运动AI助教），对长期训练的用户来说都是很高的性价比。</p>\n  <h2><strong>「手-眼-脑」一体化架构</strong></h2>\n  <p><strong>硬氪：从乒乓球到网球、再到匹克球、羽毛球等，庞伯特在运动场景拓展上是如何选择的？</strong></p>\n  <p><strong>张海波：</strong>庞伯特定位是一家做多运动的AI机器人公司。运动本身没有国界，首选乒乓球是因为这项运动我们最熟悉，团队有充足的运动数据和技术积累，能迅速推出产品帮公司起步。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_e55145ec23944fb5a25f2292f08d8324@6022551_oswg171525oswg1918oswg1279_img_jpg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">庞伯特智能乒乓球发球机器人（图源/企业）</p>\n  <p><strong>在第二项运动选择时，我们的标准只有一个——必须是全球化运动。</strong>相比于羽毛球受众主要集中在中国及东南亚地区，棒球偏向美国、日本等单一区域市场，网球具备高度全球化属性。后续我们也会围绕全球化赛道陆续单点突破，包括面向美国的匹克球、欧洲的板式网球及日本市场的棒球等。</p>\n  <p><strong>硬氪：不同运动的动作模式与击球逻辑有明显差异，其背后的算法是否具有可迁移性？</strong></p>\n  <p><strong>张海波：</strong>乒乓球、网球、匹克球、板式网球、羽毛球等均可归为隔网类运动。这类项目底层逻辑高度相通，场地环境相对固定，上网、退台、进攻、防守的技战术框架基本一致，界内界外判定、正反手动作与攻防转换时机等规则也高度相似。</p>\n  <p>但乒乓球是其中最难的场景。它的运动变量复杂，旋转维度、转速差异大，回合节奏极快，攻防转换发生在数百毫秒中。</p>\n  <p>相比之下，网球的旋转变化更少，单回合时长接近2秒，控制难度明显更低。因此，在我们解决了乒乓球的发球控制、视觉感知与AI模型等技术难题后，再切入网球等其他隔网运动时，是能迅速形成降维打击的。</p>\n  <p><strong>硬氪：具体到产品端，AI能力如何体现？</strong></p>\n  <p><strong>张海波：</strong>我们将AI Coach拆解为手、眼、脑三个核心能力模块。“手”对应发球与供球系统，能够精准复刻专业教练的出球线路与旋转；“眼”是视觉感知系统，负责实时捕捉运动场景与动作数据；“脑”则依托大模型实现自然语言交互，对用户击球动作、战术思路进行分析与反馈。</p>\n  <p>具体到实际场景中，AI Coach主要提供两大能力，一是对用户运动能力定级，并制定个性化的训练计划；二是提供实时动作指导与语音反馈。</p>\n  <p>它的训练过程对标真实教练的工作流程，喂球、纠错、喊话、撰写训练报告等，复刻专业人员的教学行为，并增加了设备同步的优势；同时，我们也会防止出现冗余的创新设计分散用户注意力。当用户认为，使用庞伯特的产品能获得与数百元一节的私教课程相近的体验时，这款产品就是成功的。</p>\n  <p><strong>硬氪：“手、眼、脑”三个能力模块在实际训练里，现阶段哪一个技术成熟度最高？</strong></p>\n  <p><strong>张海波：</strong>我们积淀最深厚的还是“手”，也就是发球与供球系统。</p>\n  <p>多球训练是网球、乒乓球、羽毛球等隔网运动里最核心的训练方式。通常我们看到，教练站在固定位置，拿着球筐或球车，给你喂出不同落点的球：左边一个、右边一个、往前一个、底线一个。</p>\n  <p><strong>在这个过程里，教练真正关键的作用其实是不纠结于单次失误，默认动作有效，持续稳定地送出下一球。</strong></p>\n  <p>这个逻辑听起来可能有点反直觉，很多人会觉得AI Coach就该实时纠错<strong>。但事实上，基础训练阶段的“忽略错误”远比“纠正错误”更重要。</strong>训练的本质，是通过固定球路的大量重复形成肌肉记忆，而不是被随机击球打断节奏。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_540d9305fb4d4d4da5a74fcdabc72df5@6022551_oswg4028732oswg2784oswg1568_img_png?x-oss-process=image/quality,q_80/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">庞伯特PACE系列智能网球发球机器人（图源/企业）</p>\n  <p>我们的发球机器人也是按照这个原理设计的，在固定位置按既定线路与节奏稳定出球，不追球、不打乱节奏，帮助用户高效完成成千上万次标准化重复练习。</p>\n  <p>“手”的发球能力是一切智能指导的基础。没有稳定、精准、可重复的供球能力，后续的视觉感知与智能分析也就无从谈起。只有把球喂对、喂稳，用户才能进入有效训练状态，视觉系统捕捉到有意义的动作数据，大模型才能基于正确的上下文进行分析和反馈。</p>\n  <p>所以我们坚持先做“手”，铺开产品，积累球路数据和用户训练行为，再逐步加入“眼”和“脑”的能力并持续迭代。</p>\n  <p><strong>硬氪：从一项运动拓展到另一项运动时，产品定义层面的核心难点是什么？</strong></p>\n  <p><strong>张海波：</strong>每进入一项新的运动，对运动本身的理解至关重要。不同运动挑战的是人的不同极限：网球侧重折返跑动与力量，乒乓球考验瞬时反应和手上细微动作，羽毛球则需要高低切换的协调性和跳跃能力。</p>\n  <p>核心在于，我们要用AI交付什么？AI Coach的脑子、眼睛、手，分别在这项运动中提供哪些能力。</p>\n  <p>以网球发球机器人为例，我们没有选择摄像头，<strong>而是自研了传感器来实时跟踪用户的跑动状态</strong>：因为网球场的跑动范围达几百平方米，教练喂球时，需要根据用户的跑动位置来决定下一个球的时机与落点。这正是我们挖掘出的关键差异点，也是产品能获得用户认可的原因，只是把上一代功能简单放大搬过来是行不通的。本质还是对场景的理解和定义。</p>\n  <p><strong>硬氪：硬件方面的壁垒体现在哪些方面？</strong></p>\n  <p><strong>张海波：</strong>体育赛道的硬件壁垒其实很高，但用户的感知度没有那么强。</p>\n  <p>我们的网球发球机器人采用了定制电机与自研驱动方案，能做到60转的上下旋，高度还原职业选手级别的旋转强度与真实击球弧线，实测球速达到130公里/小时。此前市场上部分产品的实际球速约为80公里/小时。但对普通用户而言，这些参数是抽象的，很难直观感受到差异。</p>\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_ba427c6f6ca7476e9f4d8a6672c6cffc@6022551_oswg1137259oswg1920oswg1802_img_jpg?x-oss-process=image/quality,q_90/format,jpg/interlace,1\" /></p>\n  <p class=\"img-desc\">庞伯特PACE系列智能网球发球机器人（图源/企业）</p>\n  <p><strong>硬氪：考虑到用户运动能力的差异，对“有效训练”“能力提升”的判断标准也不相同。从哪些维度来判断，你们的产品对不同用户都能真正有效？</strong></p>\n  <p><strong>张海波：</strong>用户其实只关心一件事——我能不能涨球？涨球就是练习更高效。</p>\n  <p>过去，庞伯特的平台里已经积累了100万组球路，网球也有超过20万组。数据量大了，我们就能让发球机器人发出的球像真人在发球。具体来说，这种“真人感”体现在它发出的球能匹配用户的当前水平，让TA接起来舒服，但又不会太舒服。</p>\n  <p>在此基础上，我们的AI Coach会在每次练习后，细致地告诉用户进步在哪里、哪里需要改进，比如脚再往前一点、重心再高一点。用户只要跟着练两三天，就能明显看到进步，同样一个球打起来的稳定性会显著变好，这种感知非常直观。</p>\n  <p>用户要的就是这种实实在在的提升，而不是一个花哨的概念。最终落脚点很简单，用了这台机器，运动能力确实在提升。</p>\n  <h2><strong>「把蛋糕做大」</strong></h2>\n  <p><strong>硬氪：这两年市场上出现了很多新形态的发球机器人，比如移动底盘、网兜接球、全自主跑动等，跟庞伯特有哪些区别？</strong></p>\n  <p><strong>张海波：</strong>行业里出现一些结构新颖的产品，初期确实足够吸引眼球。但用户的新鲜感褪去之后，这类产品终究要回答一个核心问题，它是否真的能帮助用户提升运动水平？</p>\n  <p>如果答案是否定的，就无法获得长期使用与复购。市场数据也能印证这一点，不少同类产品的个人用户复购率和活跃度并不高，更多是球馆采购作为体验式项目。</p>\n  <p>因此，在多运动产品矩阵中，我们每开拓一个新的运动品类，首款产品都会坚持从专业训练场景切入，优先服务职业选手与资深爱好者，以稳定可靠的性能、可量化的训练效果，建立核心人群的认可与信任。</p>\n  <p><strong>体育行业的一个鲜明特点是，不存在一款产品能通吃整个市场，它的人群需求是高度分化的。如果第一个产品没有占领这个心智，很快就会被别人取代。</strong></p>\n  <p>不管面向什么市场、用户是哪个年龄段，运动人群的核心诉求始终是专业可靠。就像今天选购网球球拍时，用户更倾向费德勒签名款，因为它代表着权威。这与是否拥有签名无关，而是专业定位本身，就能为用户带来认同感与信任感。&nbsp;</p>\n  <p><strong>硬氪：反映到具体产品与价格布局上，你们采取了怎样的定价策略？</strong></p>\n  <p><strong>张海波：</strong>以乒乓球为例，我们的产品线是从高端往下延伸的。最早做的是10万元级设备，先立住标签；再逐步推出6000多元的中端机型，再到1000多元的大众款，价格不断下探。</p>\n  <p>网球发球机器人也是同样的路径。我们对每一款产品的定位和边界都定义得十分清晰，让不同用户在对应的价位段内，都能获得适配且专业的体验。</p>\n  <p>愿意选择10万元设备的职业选手，看重的是动作还原度与训练真实性；购买5000元价位的深度爱好者，更关注旋转、速度与数据分析能力，希望借助设备持续提升水平；而2000元左右的机型，既能满足初学者练习，也适合家庭休闲与亲子陪伴使用。</p>\n  <p><strong>硬氪：目前来看，整个AI+体育市场的发展速度，跟你创业初期所设想的一致吗？</strong></p>\n  <p><strong>张海波：</strong>我觉得比预期要慢一些，但依旧很开心。过去，各种发球机在专业用户与运动爱好者中的渗透率不足10%，因为传统产品体验不好，技术陈旧、功能单一，几十年没更新过。但到了现在，数字化、AI技术的融入，加上中国成熟的供应链能力，增量空间被彻底打开。</p>\n  <p><strong>硬氪：大量创新公司涌入智能体育硬件赛道，你怎么看待这一波热潮？</strong></p>\n  <p><strong>张海波：以前搞体育创业的人很少，它为什么不能成为科技密度最高的产业之一？</strong>我觉得这个趋势正在发生，最近两年明显多了起来。</p>\n  <p>一个产业的科技密度，本质上是科技人才的密度，这是很重要的指标。体育应该被更多人重视，尤其是被科技圈重视，这样才能通过技术研发的力量催生新方案、提供好产品给用户，形成正向闭环。</p>\n  <p>有越来越多的企业在进入这个行业，这是好事。大家一起拱增量、把蛋糕做大，这是我们一直等的第一个milestone。</p>', '', '', '', '', '{\'title\': \'半年融资近2亿，他要用AI发球机器人解决全球1亿人的训练难题｜硬氪专访\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'半年融资近2亿，他要用AI发球机器人解决全球1亿人的训练难题｜硬氪专访\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3764953900990977?f=rss\'}], \'link\': \'https://36kr.com/p/3764953900990977?f=rss\', \'published\': \'2026-04-14 09:10:00  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=1, tm_min=10, tm_sec=0, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'<p>作者｜黄楠</p>\\n  <p>编辑｜袁斯来</p>\\n  <p>如果你想找庞伯特创始人张海波，大概率得去公司附近的各种球场。</p>\\n  <p>张海波早把自己训练成了各种球类的高手。</p>\\n  <p>2025年10月，公司网球场刚建成不久，他就拎着自家的发球机器人，从零开始学球。见到张海波时，他告诉硬氪，经过半年训练，现在已经打到了NTRP 3.0——相当于普通用户通常要练一两年才能达到的进阶水平。他没请私教，也没有陪练，唯一的老师，就是那台被自己反复击打的发球机器人。</p>\\n  <p>张海波很早就精通乒乓球，他是国内最早一批将强化学习用于乒乓球对打的工程师。早年在上市公司任职期间，他就做出了一套能与人进行“人机对战”的具身机械臂方案。这套系统成本高达20多万元，曾为国家队提供数据分析，甚至能与专业选手抗衡。但张海波很快意识到，能击败人类的机器人是一种景观，不可能成为大众真正需要的产品。</p>\\n  <p>比起用炫酷的demo展示技术上限，张海波更愿意钻进国内外大大小小的球馆，观察那些最挑剔的深度爱好者。</p>\\n  <p>他发现，运动人群真正缺的不是一个机器人对手，而是缺教练、缺陪练、缺高效的自主训练方式。而市场上大部分发球设备多还停留在机械吐球阶段：无节奏、无旋转、无指导，几乎谈不上训练价值。</p>\\n  <p>长期被技术忽略的用户痛点和巨大的行业空白，让张海波下定决心走出实验室。2019年，张海波创立庞伯特，希望以智能发球机器人为载体，为用户提供随时可用、专业稳定的AI Coach（运动助教）。</p>\\n  <p><strong>这条路径很快得到了市场的验证。2024年10月，庞伯特PACE系列智能网球发球机器人上线Kickstarter，众筹金额超270万美元。2025年黑五期间，海外单月销售额突破数千万元；目前公司全球用户已超30万。</strong></p>\\n  <p><strong>硬氪独家获悉，庞伯特日前完成了A轮系列融资、三轮累计近两亿元，神骐资本、明势创投、蓝驰创投、锦秋基金、华创资本等机构集体参投，高鹄资本担任独家财务顾问。</strong></p>\\n  <p>资本的信心源于一条清晰的增长逻辑。根据国际网球联合会（ITF）2024年11月数据，全球网球参与人数达到1.06亿。其中，美国网球活跃用户与教练配比高达800：1，专业教练供给严重不足；在中国，网球正快速成为都市白领与中产家庭的主流运动，但动辄数百元一小时的私教课，把绝大多数初学者挡在门外。而庞伯特希望用AI技术，给出一种解法。</p>\\n  <p><strong>以下是硬氪与庞伯特创始人兼CEO张海波的对谈实录，内容经编辑：</strong></p>\\n  <h2><strong>训练场景下的AI Coach</strong></h2>\\n  <p><strong>硬氪：你最早开始做机器人是在十年前。</strong></p>\\n  <p><strong>张海波：</strong>我做的第一代机器人是一款乒乓球对打机器人，它和目前常见的发球机器人或使用人形机器人打球不同，采用机械臂结构进行人机对打，是一个具备自主判断和决策能力的具身智能系统。</p>\\n  <p>我们从图像中获取信息，输入到模型里，由它控制机械臂把球打到我们期望的位置。这个过程中，乒乓球会旋转，因此我们做了很多关于球怎么飞行、怎么预测、怎么拦截的专利，给国家队也做过不少数据分析。</p>\\n  <p>但我们当时追求的不是产品化，而是更高、更快、更强，要打赢别人，所以设备成本也很高，单台要达到20多万元。</p>\\n  <p><strong>硬氪：体育运动领域是一个高度依赖行业Know\\x1eHow的赛道。</strong></p>\\n  <p><strong>张海波：</strong>那四年里，我们掌握了大量对体育的理解，从初学者到深度爱好者、再到专业运动员的全过程理解，很少有人能看到这个完整的路径。</p>\\n  <p>我能感受到那些爱好者对科技产品的渴求，每次交流时他们都非常兴奋。这让我萌生了创业的想法，不再做20多万的高价设备——这类产品很前沿、但用户面有限，只能解决极少数人的痛点。我想做一款广大爱好者买得起用得上的运动科技产品。</p>\\n  <p><strong>硬氪：市面上各类体育智能硬件存在鲜明的定位差异，我们该如何理解不同运动场景与产品定位的界定？庞伯特出于哪些考量最终锁定了产品方向？</strong></p>\\n  <p><strong>张海波：</strong>通常来讲，我们可以将泛体育划分为四个方向。一种是Sports，即具备完整竞技规则、可开展专业赛事的运动，比如足球、篮球、网球等，这也是庞伯特所瞄准的赛道；第二种叫Recreation，偏向休闲娱乐属性的活动，例如飞镖、飞盘、桌球等，在海外，有些乒乓球场景也可以归属到这一活动品类中，更多用于聚会消遣；三是Outdoor，追求自我突破的户外运动，比如登山、划船等，用户更注重挑战身体极限、刷新个人纪录；第四类是Fitness，即以塑形、体能提升为目标的健身运动。</p>\\n  <p>这四个品类不能说不相通，但从面向爱好者的专业化产品角度，界限是分明的。庞伯特做的是Sports，以及部分与Sports相关的Recreation娱乐化呈现，跟Fitness、Outdoor类运动目前没关系。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_aedd8a3132df493b96a4f5bdc8b0562f@6022551_oswg4390912oswg6000oswg3376_img_jpg?x-oss-process=image/quality,q_80/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">庞伯特PACE系列智能网球发球机器人（图源/企业）</p>\\n  <p><strong>硬氪：从产品形态上来看，传统发球机出现了几十年，但大多仍停留在机械吐球阶段，用户体验几乎没有革新。庞伯特想解决的核心矛盾是什么？</strong></p>\\n  <p><strong>张海波：</strong>运动场景里，用户只有三种状态——纯玩、训练、比赛/对战。三个场景互斥，用户在球场上只能做其中一件事。这也就决定了我们在做产品时要选侧重点。</p>\\n  <p>庞伯特专注的是训练场景。<strong>用户真正需要的并不是一个机器对手。</strong>对战本身带有强烈社交属性，即便机器能陪打，用户最终还是会回归人与人之间的对抗。很多人觉得机器人接球很新鲜，但其底层需求并不是 “陪打”，而是 “可以借助机器来辅助自己练习”。练习，才是核心需求。</p>\\n  <p>在大众运动里，找对手很容易，甚至不缺免费的伙伴。但好教练却很难得：要么找不到、要么风格不合适、时间难约，成本还高。即便用户每周请一次教练，其余大部分自主训练时间，不管是颠球、空挥、使用发球机还是对墙练习，大家都希望身边能有一个 “教练”。他可以不用一直喂球，但能持续观察、给出实时指导。而这些需求，目前几乎没有产品能够真正满足。</p>\\n  <p><strong>硬氪：这些用户画像有什么特点？</strong></p>\\n  <p><strong>张海波：</strong>国内外运动人群的训练习惯存在明显差异。<strong>在海外，大多数运动几乎不存在“纯娱乐”的阶段，要么不参与、要么从开始就接受专业教练指导，训练意识普遍更强。</strong>而国内用户往往先从兴趣玩乐切入，再逐步转向系统性训练。</p>\\n  <p>这也决定了我们初代产品是主要服务于资深运动爱好者，即面向掌握特定技巧、提想升运动能力的用户。这类人群熟悉运动本身，他们渴望在真实比赛里赢更多球，但缺乏明确的训练目标，需要借助设备辅助练习。</p>\\n  <p>对这类用户而言，成本账很容易算清：线下教练课时费即便偏低也要100美元/小时，进阶课程更是高达200至500美元不等。庞伯特的发球机器人价格段覆盖1000–5000美元区间，无论是作为日常辅助训练工具，还是替代部分教练功能的AI Coach（运动AI助教），对长期训练的用户来说都是很高的性价比。</p>\\n  <h2><strong>「手-眼-脑」一体化架构</strong></h2>\\n  <p><strong>硬氪：从乒乓球到网球、再到匹克球、羽毛球等，庞伯特在运动场景拓展上是如何选择的？</strong></p>\\n  <p><strong>张海波：</strong>庞伯特定位是一家做多运动的AI机器人公司。运动本身没有国界，首选乒乓球是因为这项运动我们最熟悉，团队有充足的运动数据和技术积累，能迅速推出产品帮公司起步。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_e55145ec23944fb5a25f2292f08d8324@6022551_oswg171525oswg1918oswg1279_img_jpg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">庞伯特智能乒乓球发球机器人（图源/企业）</p>\\n  <p><strong>在第二项运动选择时，我们的标准只有一个——必须是全球化运动。</strong>相比于羽毛球受众主要集中在中国及东南亚地区，棒球偏向美国、日本等单一区域市场，网球具备高度全球化属性。后续我们也会围绕全球化赛道陆续单点突破，包括面向美国的匹克球、欧洲的板式网球及日本市场的棒球等。</p>\\n  <p><strong>硬氪：不同运动的动作模式与击球逻辑有明显差异，其背后的算法是否具有可迁移性？</strong></p>\\n  <p><strong>张海波：</strong>乒乓球、网球、匹克球、板式网球、羽毛球等均可归为隔网类运动。这类项目底层逻辑高度相通，场地环境相对固定，上网、退台、进攻、防守的技战术框架基本一致，界内界外判定、正反手动作与攻防转换时机等规则也高度相似。</p>\\n  <p>但乒乓球是其中最难的场景。它的运动变量复杂，旋转维度、转速差异大，回合节奏极快，攻防转换发生在数百毫秒中。</p>\\n  <p>相比之下，网球的旋转变化更少，单回合时长接近2秒，控制难度明显更低。因此，在我们解决了乒乓球的发球控制、视觉感知与AI模型等技术难题后，再切入网球等其他隔网运动时，是能迅速形成降维打击的。</p>\\n  <p><strong>硬氪：具体到产品端，AI能力如何体现？</strong></p>\\n  <p><strong>张海波：</strong>我们将AI Coach拆解为手、眼、脑三个核心能力模块。“手”对应发球与供球系统，能够精准复刻专业教练的出球线路与旋转；“眼”是视觉感知系统，负责实时捕捉运动场景与动作数据；“脑”则依托大模型实现自然语言交互，对用户击球动作、战术思路进行分析与反馈。</p>\\n  <p>具体到实际场景中，AI Coach主要提供两大能力，一是对用户运动能力定级，并制定个性化的训练计划；二是提供实时动作指导与语音反馈。</p>\\n  <p>它的训练过程对标真实教练的工作流程，喂球、纠错、喊话、撰写训练报告等，复刻专业人员的教学行为，并增加了设备同步的优势；同时，我们也会防止出现冗余的创新设计分散用户注意力。当用户认为，使用庞伯特的产品能获得与数百元一节的私教课程相近的体验时，这款产品就是成功的。</p>\\n  <p><strong>硬氪：“手、眼、脑”三个能力模块在实际训练里，现阶段哪一个技术成熟度最高？</strong></p>\\n  <p><strong>张海波：</strong>我们积淀最深厚的还是“手”，也就是发球与供球系统。</p>\\n  <p>多球训练是网球、乒乓球、羽毛球等隔网运动里最核心的训练方式。通常我们看到，教练站在固定位置，拿着球筐或球车，给你喂出不同落点的球：左边一个、右边一个、往前一个、底线一个。</p>\\n  <p><strong>在这个过程里，教练真正关键的作用其实是不纠结于单次失误，默认动作有效，持续稳定地送出下一球。</strong></p>\\n  <p>这个逻辑听起来可能有点反直觉，很多人会觉得AI Coach就该实时纠错<strong>。但事实上，基础训练阶段的“忽略错误”远比“纠正错误”更重要。</strong>训练的本质，是通过固定球路的大量重复形成肌肉记忆，而不是被随机击球打断节奏。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_540d9305fb4d4d4da5a74fcdabc72df5@6022551_oswg4028732oswg2784oswg1568_img_png?x-oss-process=image/quality,q_80/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">庞伯特PACE系列智能网球发球机器人（图源/企业）</p>\\n  <p>我们的发球机器人也是按照这个原理设计的，在固定位置按既定线路与节奏稳定出球，不追球、不打乱节奏，帮助用户高效完成成千上万次标准化重复练习。</p>\\n  <p>“手”的发球能力是一切智能指导的基础。没有稳定、精准、可重复的供球能力，后续的视觉感知与智能分析也就无从谈起。只有把球喂对、喂稳，用户才能进入有效训练状态，视觉系统捕捉到有意义的动作数据，大模型才能基于正确的上下文进行分析和反馈。</p>\\n  <p>所以我们坚持先做“手”，铺开产品，积累球路数据和用户训练行为，再逐步加入“眼”和“脑”的能力并持续迭代。</p>\\n  <p><strong>硬氪：从一项运动拓展到另一项运动时，产品定义层面的核心难点是什么？</strong></p>\\n  <p><strong>张海波：</strong>每进入一项新的运动，对运动本身的理解至关重要。不同运动挑战的是人的不同极限：网球侧重折返跑动与力量，乒乓球考验瞬时反应和手上细微动作，羽毛球则需要高低切换的协调性和跳跃能力。</p>\\n  <p>核心在于，我们要用AI交付什么？AI Coach的脑子、眼睛、手，分别在这项运动中提供哪些能力。</p>\\n  <p>以网球发球机器人为例，我们没有选择摄像头，<strong>而是自研了传感器来实时跟踪用户的跑动状态</strong>：因为网球场的跑动范围达几百平方米，教练喂球时，需要根据用户的跑动位置来决定下一个球的时机与落点。这正是我们挖掘出的关键差异点，也是产品能获得用户认可的原因，只是把上一代功能简单放大搬过来是行不通的。本质还是对场景的理解和定义。</p>\\n  <p><strong>硬氪：硬件方面的壁垒体现在哪些方面？</strong></p>\\n  <p><strong>张海波：</strong>体育赛道的硬件壁垒其实很高，但用户的感知度没有那么强。</p>\\n  <p>我们的网球发球机器人采用了定制电机与自研驱动方案，能做到60转的上下旋，高度还原职业选手级别的旋转强度与真实击球弧线，实测球速达到130公里/小时。此前市场上部分产品的实际球速约为80公里/小时。但对普通用户而言，这些参数是抽象的，很难直观感受到差异。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_ba427c6f6ca7476e9f4d8a6672c6cffc@6022551_oswg1137259oswg1920oswg1802_img_jpg?x-oss-process=image/quality,q_90/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">庞伯特PACE系列智能网球发球机器人（图源/企业）</p>\\n  <p><strong>硬氪：考虑到用户运动能力的差异，对“有效训练”“能力提升”的判断标准也不相同。从哪些维度来判断，你们的产品对不同用户都能真正有效？</strong></p>\\n  <p><strong>张海波：</strong>用户其实只关心一件事——我能不能涨球？涨球就是练习更高效。</p>\\n  <p>过去，庞伯特的平台里已经积累了100万组球路，网球也有超过20万组。数据量大了，我们就能让发球机器人发出的球像真人在发球。具体来说，这种“真人感”体现在它发出的球能匹配用户的当前水平，让TA接起来舒服，但又不会太舒服。</p>\\n  <p>在此基础上，我们的AI Coach会在每次练习后，细致地告诉用户进步在哪里、哪里需要改进，比如脚再往前一点、重心再高一点。用户只要跟着练两三天，就能明显看到进步，同样一个球打起来的稳定性会显著变好，这种感知非常直观。</p>\\n  <p>用户要的就是这种实实在在的提升，而不是一个花哨的概念。最终落脚点很简单，用了这台机器，运动能力确实在提升。</p>\\n  <h2><strong>「把蛋糕做大」</strong></h2>\\n  <p><strong>硬氪：这两年市场上出现了很多新形态的发球机器人，比如移动底盘、网兜接球、全自主跑动等，跟庞伯特有哪些区别？</strong></p>\\n  <p><strong>张海波：</strong>行业里出现一些结构新颖的产品，初期确实足够吸引眼球。但用户的新鲜感褪去之后，这类产品终究要回答一个核心问题，它是否真的能帮助用户提升运动水平？</p>\\n  <p>如果答案是否定的，就无法获得长期使用与复购。市场数据也能印证这一点，不少同类产品的个人用户复购率和活跃度并不高，更多是球馆采购作为体验式项目。</p>\\n  <p>因此，在多运动产品矩阵中，我们每开拓一个新的运动品类，首款产品都会坚持从专业训练场景切入，优先服务职业选手与资深爱好者，以稳定可靠的性能、可量化的训练效果，建立核心人群的认可与信任。</p>\\n  <p><strong>体育行业的一个鲜明特点是，不存在一款产品能通吃整个市场，它的人群需求是高度分化的。如果第一个产品没有占领这个心智，很快就会被别人取代。</strong></p>\\n  <p>不管面向什么市场、用户是哪个年龄段，运动人群的核心诉求始终是专业可靠。就像今天选购网球球拍时，用户更倾向费德勒签名款，因为它代表着权威。这与是否拥有签名无关，而是专业定位本身，就能为用户带来认同感与信任感。&nbsp;</p>\\n  <p><strong>硬氪：反映到具体产品与价格布局上，你们采取了怎样的定价策略？</strong></p>\\n  <p><strong>张海波：</strong>以乒乓球为例，我们的产品线是从高端往下延伸的。最早做的是10万元级设备，先立住标签；再逐步推出6000多元的中端机型，再到1000多元的大众款，价格不断下探。</p>\\n  <p>网球发球机器人也是同样的路径。我们对每一款产品的定位和边界都定义得十分清晰，让不同用户在对应的价位段内，都能获得适配且专业的体验。</p>\\n  <p>愿意选择10万元设备的职业选手，看重的是动作还原度与训练真实性；购买5000元价位的深度爱好者，更关注旋转、速度与数据分析能力，希望借助设备持续提升水平；而2000元左右的机型，既能满足初学者练习，也适合家庭休闲与亲子陪伴使用。</p>\\n  <p><strong>硬氪：目前来看，整个AI+体育市场的发展速度，跟你创业初期所设想的一致吗？</strong></p>\\n  <p><strong>张海波：</strong>我觉得比预期要慢一些，但依旧很开心。过去，各种发球机在专业用户与运动爱好者中的渗透率不足10%，因为传统产品体验不好，技术陈旧、功能单一，几十年没更新过。但到了现在，数字化、AI技术的融入，加上中国成熟的供应链能力，增量空间被彻底打开。</p>\\n  <p><strong>硬氪：大量创新公司涌入智能体育硬件赛道，你怎么看待这一波热潮？</strong></p>\\n  <p><strong>张海波：以前搞体育创业的人很少，它为什么不能成为科技密度最高的产业之一？</strong>我觉得这个趋势正在发生，最近两年明显多了起来。</p>\\n  <p>一个产业的科技密度，本质上是科技人才的密度，这是很重要的指标。体育应该被更多人重视，尤其是被科技圈重视，这样才能通过技术研发的力量催生新方案、提供好产品给用户，形成正向闭环。</p>\\n  <p>有越来越多的企业在进入这个行业，这是好事。大家一起拱增量、把蛋糕做大，这是我们一直等的第一个milestone。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'<p>作者｜黄楠</p>\\n  <p>编辑｜袁斯来</p>\\n  <p>如果你想找庞伯特创始人张海波，大概率得去公司附近的各种球场。</p>\\n  <p>张海波早把自己训练成了各种球类的高手。</p>\\n  <p>2025年10月，公司网球场刚建成不久，他就拎着自家的发球机器人，从零开始学球。见到张海波时，他告诉硬氪，经过半年训练，现在已经打到了NTRP 3.0——相当于普通用户通常要练一两年才能达到的进阶水平。他没请私教，也没有陪练，唯一的老师，就是那台被自己反复击打的发球机器人。</p>\\n  <p>张海波很早就精通乒乓球，他是国内最早一批将强化学习用于乒乓球对打的工程师。早年在上市公司任职期间，他就做出了一套能与人进行“人机对战”的具身机械臂方案。这套系统成本高达20多万元，曾为国家队提供数据分析，甚至能与专业选手抗衡。但张海波很快意识到，能击败人类的机器人是一种景观，不可能成为大众真正需要的产品。</p>\\n  <p>比起用炫酷的demo展示技术上限，张海波更愿意钻进国内外大大小小的球馆，观察那些最挑剔的深度爱好者。</p>\\n  <p>他发现，运动人群真正缺的不是一个机器人对手，而是缺教练、缺陪练、缺高效的自主训练方式。而市场上大部分发球设备多还停留在机械吐球阶段：无节奏、无旋转、无指导，几乎谈不上训练价值。</p>\\n  <p>长期被技术忽略的用户痛点和巨大的行业空白，让张海波下定决心走出实验室。2019年，张海波创立庞伯特，希望以智能发球机器人为载体，为用户提供随时可用、专业稳定的AI Coach（运动助教）。</p>\\n  <p><strong>这条路径很快得到了市场的验证。2024年10月，庞伯特PACE系列智能网球发球机器人上线Kickstarter，众筹金额超270万美元。2025年黑五期间，海外单月销售额突破数千万元；目前公司全球用户已超30万。</strong></p>\\n  <p><strong>硬氪独家获悉，庞伯特日前完成了A轮系列融资、三轮累计近两亿元，神骐资本、明势创投、蓝驰创投、锦秋基金、华创资本等机构集体参投，高鹄资本担任独家财务顾问。</strong></p>\\n  <p>资本的信心源于一条清晰的增长逻辑。根据国际网球联合会（ITF）2024年11月数据，全球网球参与人数达到1.06亿。其中，美国网球活跃用户与教练配比高达800：1，专业教练供给严重不足；在中国，网球正快速成为都市白领与中产家庭的主流运动，但动辄数百元一小时的私教课，把绝大多数初学者挡在门外。而庞伯特希望用AI技术，给出一种解法。</p>\\n  <p><strong>以下是硬氪与庞伯特创始人兼CEO张海波的对谈实录，内容经编辑：</strong></p>\\n  <h2><strong>训练场景下的AI Coach</strong></h2>\\n  <p><strong>硬氪：你最早开始做机器人是在十年前。</strong></p>\\n  <p><strong>张海波：</strong>我做的第一代机器人是一款乒乓球对打机器人，它和目前常见的发球机器人或使用人形机器人打球不同，采用机械臂结构进行人机对打，是一个具备自主判断和决策能力的具身智能系统。</p>\\n  <p>我们从图像中获取信息，输入到模型里，由它控制机械臂把球打到我们期望的位置。这个过程中，乒乓球会旋转，因此我们做了很多关于球怎么飞行、怎么预测、怎么拦截的专利，给国家队也做过不少数据分析。</p>\\n  <p>但我们当时追求的不是产品化，而是更高、更快、更强，要打赢别人，所以设备成本也很高，单台要达到20多万元。</p>\\n  <p><strong>硬氪：体育运动领域是一个高度依赖行业Know\\x1eHow的赛道。</strong></p>\\n  <p><strong>张海波：</strong>那四年里，我们掌握了大量对体育的理解，从初学者到深度爱好者、再到专业运动员的全过程理解，很少有人能看到这个完整的路径。</p>\\n  <p>我能感受到那些爱好者对科技产品的渴求，每次交流时他们都非常兴奋。这让我萌生了创业的想法，不再做20多万的高价设备——这类产品很前沿、但用户面有限，只能解决极少数人的痛点。我想做一款广大爱好者买得起用得上的运动科技产品。</p>\\n  <p><strong>硬氪：市面上各类体育智能硬件存在鲜明的定位差异，我们该如何理解不同运动场景与产品定位的界定？庞伯特出于哪些考量最终锁定了产品方向？</strong></p>\\n  <p><strong>张海波：</strong>通常来讲，我们可以将泛体育划分为四个方向。一种是Sports，即具备完整竞技规则、可开展专业赛事的运动，比如足球、篮球、网球等，这也是庞伯特所瞄准的赛道；第二种叫Recreation，偏向休闲娱乐属性的活动，例如飞镖、飞盘、桌球等，在海外，有些乒乓球场景也可以归属到这一活动品类中，更多用于聚会消遣；三是Outdoor，追求自我突破的户外运动，比如登山、划船等，用户更注重挑战身体极限、刷新个人纪录；第四类是Fitness，即以塑形、体能提升为目标的健身运动。</p>\\n  <p>这四个品类不能说不相通，但从面向爱好者的专业化产品角度，界限是分明的。庞伯特做的是Sports，以及部分与Sports相关的Recreation娱乐化呈现，跟Fitness、Outdoor类运动目前没关系。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_aedd8a3132df493b96a4f5bdc8b0562f@6022551_oswg4390912oswg6000oswg3376_img_jpg?x-oss-process=image/quality,q_80/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">庞伯特PACE系列智能网球发球机器人（图源/企业）</p>\\n  <p><strong>硬氪：从产品形态上来看，传统发球机出现了几十年，但大多仍停留在机械吐球阶段，用户体验几乎没有革新。庞伯特想解决的核心矛盾是什么？</strong></p>\\n  <p><strong>张海波：</strong>运动场景里，用户只有三种状态——纯玩、训练、比赛/对战。三个场景互斥，用户在球场上只能做其中一件事。这也就决定了我们在做产品时要选侧重点。</p>\\n  <p>庞伯特专注的是训练场景。<strong>用户真正需要的并不是一个机器对手。</strong>对战本身带有强烈社交属性，即便机器能陪打，用户最终还是会回归人与人之间的对抗。很多人觉得机器人接球很新鲜，但其底层需求并不是 “陪打”，而是 “可以借助机器来辅助自己练习”。练习，才是核心需求。</p>\\n  <p>在大众运动里，找对手很容易，甚至不缺免费的伙伴。但好教练却很难得：要么找不到、要么风格不合适、时间难约，成本还高。即便用户每周请一次教练，其余大部分自主训练时间，不管是颠球、空挥、使用发球机还是对墙练习，大家都希望身边能有一个 “教练”。他可以不用一直喂球，但能持续观察、给出实时指导。而这些需求，目前几乎没有产品能够真正满足。</p>\\n  <p><strong>硬氪：这些用户画像有什么特点？</strong></p>\\n  <p><strong>张海波：</strong>国内外运动人群的训练习惯存在明显差异。<strong>在海外，大多数运动几乎不存在“纯娱乐”的阶段，要么不参与、要么从开始就接受专业教练指导，训练意识普遍更强。</strong>而国内用户往往先从兴趣玩乐切入，再逐步转向系统性训练。</p>\\n  <p>这也决定了我们初代产品是主要服务于资深运动爱好者，即面向掌握特定技巧、提想升运动能力的用户。这类人群熟悉运动本身，他们渴望在真实比赛里赢更多球，但缺乏明确的训练目标，需要借助设备辅助练习。</p>\\n  <p>对这类用户而言，成本账很容易算清：线下教练课时费即便偏低也要100美元/小时，进阶课程更是高达200至500美元不等。庞伯特的发球机器人价格段覆盖1000–5000美元区间，无论是作为日常辅助训练工具，还是替代部分教练功能的AI Coach（运动AI助教），对长期训练的用户来说都是很高的性价比。</p>\\n  <h2><strong>「手-眼-脑」一体化架构</strong></h2>\\n  <p><strong>硬氪：从乒乓球到网球、再到匹克球、羽毛球等，庞伯特在运动场景拓展上是如何选择的？</strong></p>\\n  <p><strong>张海波：</strong>庞伯特定位是一家做多运动的AI机器人公司。运动本身没有国界，首选乒乓球是因为这项运动我们最熟悉，团队有充足的运动数据和技术积累，能迅速推出产品帮公司起步。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_e55145ec23944fb5a25f2292f08d8324@6022551_oswg171525oswg1918oswg1279_img_jpg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">庞伯特智能乒乓球发球机器人（图源/企业）</p>\\n  <p><strong>在第二项运动选择时，我们的标准只有一个——必须是全球化运动。</strong>相比于羽毛球受众主要集中在中国及东南亚地区，棒球偏向美国、日本等单一区域市场，网球具备高度全球化属性。后续我们也会围绕全球化赛道陆续单点突破，包括面向美国的匹克球、欧洲的板式网球及日本市场的棒球等。</p>\\n  <p><strong>硬氪：不同运动的动作模式与击球逻辑有明显差异，其背后的算法是否具有可迁移性？</strong></p>\\n  <p><strong>张海波：</strong>乒乓球、网球、匹克球、板式网球、羽毛球等均可归为隔网类运动。这类项目底层逻辑高度相通，场地环境相对固定，上网、退台、进攻、防守的技战术框架基本一致，界内界外判定、正反手动作与攻防转换时机等规则也高度相似。</p>\\n  <p>但乒乓球是其中最难的场景。它的运动变量复杂，旋转维度、转速差异大，回合节奏极快，攻防转换发生在数百毫秒中。</p>\\n  <p>相比之下，网球的旋转变化更少，单回合时长接近2秒，控制难度明显更低。因此，在我们解决了乒乓球的发球控制、视觉感知与AI模型等技术难题后，再切入网球等其他隔网运动时，是能迅速形成降维打击的。</p>\\n  <p><strong>硬氪：具体到产品端，AI能力如何体现？</strong></p>\\n  <p><strong>张海波：</strong>我们将AI Coach拆解为手、眼、脑三个核心能力模块。“手”对应发球与供球系统，能够精准复刻专业教练的出球线路与旋转；“眼”是视觉感知系统，负责实时捕捉运动场景与动作数据；“脑”则依托大模型实现自然语言交互，对用户击球动作、战术思路进行分析与反馈。</p>\\n  <p>具体到实际场景中，AI Coach主要提供两大能力，一是对用户运动能力定级，并制定个性化的训练计划；二是提供实时动作指导与语音反馈。</p>\\n  <p>它的训练过程对标真实教练的工作流程，喂球、纠错、喊话、撰写训练报告等，复刻专业人员的教学行为，并增加了设备同步的优势；同时，我们也会防止出现冗余的创新设计分散用户注意力。当用户认为，使用庞伯特的产品能获得与数百元一节的私教课程相近的体验时，这款产品就是成功的。</p>\\n  <p><strong>硬氪：“手、眼、脑”三个能力模块在实际训练里，现阶段哪一个技术成熟度最高？</strong></p>\\n  <p><strong>张海波：</strong>我们积淀最深厚的还是“手”，也就是发球与供球系统。</p>\\n  <p>多球训练是网球、乒乓球、羽毛球等隔网运动里最核心的训练方式。通常我们看到，教练站在固定位置，拿着球筐或球车，给你喂出不同落点的球：左边一个、右边一个、往前一个、底线一个。</p>\\n  <p><strong>在这个过程里，教练真正关键的作用其实是不纠结于单次失误，默认动作有效，持续稳定地送出下一球。</strong></p>\\n  <p>这个逻辑听起来可能有点反直觉，很多人会觉得AI Coach就该实时纠错<strong>。但事实上，基础训练阶段的“忽略错误”远比“纠正错误”更重要。</strong>训练的本质，是通过固定球路的大量重复形成肌肉记忆，而不是被随机击球打断节奏。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_540d9305fb4d4d4da5a74fcdabc72df5@6022551_oswg4028732oswg2784oswg1568_img_png?x-oss-process=image/quality,q_80/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">庞伯特PACE系列智能网球发球机器人（图源/企业）</p>\\n  <p>我们的发球机器人也是按照这个原理设计的，在固定位置按既定线路与节奏稳定出球，不追球、不打乱节奏，帮助用户高效完成成千上万次标准化重复练习。</p>\\n  <p>“手”的发球能力是一切智能指导的基础。没有稳定、精准、可重复的供球能力，后续的视觉感知与智能分析也就无从谈起。只有把球喂对、喂稳，用户才能进入有效训练状态，视觉系统捕捉到有意义的动作数据，大模型才能基于正确的上下文进行分析和反馈。</p>\\n  <p>所以我们坚持先做“手”，铺开产品，积累球路数据和用户训练行为，再逐步加入“眼”和“脑”的能力并持续迭代。</p>\\n  <p><strong>硬氪：从一项运动拓展到另一项运动时，产品定义层面的核心难点是什么？</strong></p>\\n  <p><strong>张海波：</strong>每进入一项新的运动，对运动本身的理解至关重要。不同运动挑战的是人的不同极限：网球侧重折返跑动与力量，乒乓球考验瞬时反应和手上细微动作，羽毛球则需要高低切换的协调性和跳跃能力。</p>\\n  <p>核心在于，我们要用AI交付什么？AI Coach的脑子、眼睛、手，分别在这项运动中提供哪些能力。</p>\\n  <p>以网球发球机器人为例，我们没有选择摄像头，<strong>而是自研了传感器来实时跟踪用户的跑动状态</strong>：因为网球场的跑动范围达几百平方米，教练喂球时，需要根据用户的跑动位置来决定下一个球的时机与落点。这正是我们挖掘出的关键差异点，也是产品能获得用户认可的原因，只是把上一代功能简单放大搬过来是行不通的。本质还是对场景的理解和定义。</p>\\n  <p><strong>硬氪：硬件方面的壁垒体现在哪些方面？</strong></p>\\n  <p><strong>张海波：</strong>体育赛道的硬件壁垒其实很高，但用户的感知度没有那么强。</p>\\n  <p>我们的网球发球机器人采用了定制电机与自研驱动方案，能做到60转的上下旋，高度还原职业选手级别的旋转强度与真实击球弧线，实测球速达到130公里/小时。此前市场上部分产品的实际球速约为80公里/小时。但对普通用户而言，这些参数是抽象的，很难直观感受到差异。</p>\\n  <p class=\"image-wrapper\"><img src=\"https://img.36krcdn.com/hsossms/20260413/v2_ba427c6f6ca7476e9f4d8a6672c6cffc@6022551_oswg1137259oswg1920oswg1802_img_jpg?x-oss-process=image/quality,q_90/format,jpg/interlace,1\" /></p>\\n  <p class=\"img-desc\">庞伯特PACE系列智能网球发球机器人（图源/企业）</p>\\n  <p><strong>硬氪：考虑到用户运动能力的差异，对“有效训练”“能力提升”的判断标准也不相同。从哪些维度来判断，你们的产品对不同用户都能真正有效？</strong></p>\\n  <p><strong>张海波：</strong>用户其实只关心一件事——我能不能涨球？涨球就是练习更高效。</p>\\n  <p>过去，庞伯特的平台里已经积累了100万组球路，网球也有超过20万组。数据量大了，我们就能让发球机器人发出的球像真人在发球。具体来说，这种“真人感”体现在它发出的球能匹配用户的当前水平，让TA接起来舒服，但又不会太舒服。</p>\\n  <p>在此基础上，我们的AI Coach会在每次练习后，细致地告诉用户进步在哪里、哪里需要改进，比如脚再往前一点、重心再高一点。用户只要跟着练两三天，就能明显看到进步，同样一个球打起来的稳定性会显著变好，这种感知非常直观。</p>\\n  <p>用户要的就是这种实实在在的提升，而不是一个花哨的概念。最终落脚点很简单，用了这台机器，运动能力确实在提升。</p>\\n  <h2><strong>「把蛋糕做大」</strong></h2>\\n  <p><strong>硬氪：这两年市场上出现了很多新形态的发球机器人，比如移动底盘、网兜接球、全自主跑动等，跟庞伯特有哪些区别？</strong></p>\\n  <p><strong>张海波：</strong>行业里出现一些结构新颖的产品，初期确实足够吸引眼球。但用户的新鲜感褪去之后，这类产品终究要回答一个核心问题，它是否真的能帮助用户提升运动水平？</p>\\n  <p>如果答案是否定的，就无法获得长期使用与复购。市场数据也能印证这一点，不少同类产品的个人用户复购率和活跃度并不高，更多是球馆采购作为体验式项目。</p>\\n  <p>因此，在多运动产品矩阵中，我们每开拓一个新的运动品类，首款产品都会坚持从专业训练场景切入，优先服务职业选手与资深爱好者，以稳定可靠的性能、可量化的训练效果，建立核心人群的认可与信任。</p>\\n  <p><strong>体育行业的一个鲜明特点是，不存在一款产品能通吃整个市场，它的人群需求是高度分化的。如果第一个产品没有占领这个心智，很快就会被别人取代。</strong></p>\\n  <p>不管面向什么市场、用户是哪个年龄段，运动人群的核心诉求始终是专业可靠。就像今天选购网球球拍时，用户更倾向费德勒签名款，因为它代表着权威。这与是否拥有签名无关，而是专业定位本身，就能为用户带来认同感与信任感。&nbsp;</p>\\n  <p><strong>硬氪：反映到具体产品与价格布局上，你们采取了怎样的定价策略？</strong></p>\\n  <p><strong>张海波：</strong>以乒乓球为例，我们的产品线是从高端往下延伸的。最早做的是10万元级设备，先立住标签；再逐步推出6000多元的中端机型，再到1000多元的大众款，价格不断下探。</p>\\n  <p>网球发球机器人也是同样的路径。我们对每一款产品的定位和边界都定义得十分清晰，让不同用户在对应的价位段内，都能获得适配且专业的体验。</p>\\n  <p>愿意选择10万元设备的职业选手，看重的是动作还原度与训练真实性；购买5000元价位的深度爱好者，更关注旋转、速度与数据分析能力，希望借助设备持续提升水平；而2000元左右的机型，既能满足初学者练习，也适合家庭休闲与亲子陪伴使用。</p>\\n  <p><strong>硬氪：目前来看，整个AI+体育市场的发展速度，跟你创业初期所设想的一致吗？</strong></p>\\n  <p><strong>张海波：</strong>我觉得比预期要慢一些，但依旧很开心。过去，各种发球机在专业用户与运动爱好者中的渗透率不足10%，因为传统产品体验不好，技术陈旧、功能单一，几十年没更新过。但到了现在，数字化、AI技术的融入，加上中国成熟的供应链能力，增量空间被彻底打开。</p>\\n  <p><strong>硬氪：大量创新公司涌入智能体育硬件赛道，你怎么看待这一波热潮？</strong></p>\\n  <p><strong>张海波：以前搞体育创业的人很少，它为什么不能成为科技密度最高的产业之一？</strong>我觉得这个趋势正在发生，最近两年明显多了起来。</p>\\n  <p>一个产业的科技密度，本质上是科技人才的密度，这是很重要的指标。体育应该被更多人重视，尤其是被科技圈重视，这样才能通过技术研发的力量催生新方案、提供好产品给用户，形成正向闭环。</p>\\n  <p>有越来越多的企业在进入这个行业，这是好事。大家一起拱增量、把蛋糕做大，这是我们一直等的第一个milestone。</p>\'}, \'source\': {\'title\': \'36氪\'}}', '2026-04-14 09:10:00', '2026-04-14 14:08:30', 1, '{\"summary\": \"本文分享AI运动机器人企业庞伯特的产品策略与出海实践，为运动科技类出海创业者提供参考\", \"abstract\": \"庞伯特由前上市公司工程师张海波创立，瞄准全球运动训练市场专业教练供给不足的痛点，推出搭载AI能力的智能发球机器人，定位大众可负担的AI运动助教。该公司近期完成A轮系列累计近2亿元融资，其网球发球机器人海外众筹、销售表现亮眼，目前全球用户已超30万。庞伯特聚焦全球化隔网类运动赛道，依托乒乓球技术积累降维拓展网球等品类，采用“手-眼-脑”一体化产品架构，优先夯实稳定供球的核心能力。公司采用从高端向大众延伸的产品线布局，认为AI+体育仍有较大增量空间，期待行业参与者共同做大市场。\", \"keywords\": [\"AI发球机器人\", \"出海\", \"智能体育\", \"AI Coach\", \"庞伯特\", \"融资\", \"全球化\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"运动科技\"}');

SET FOREIGN_KEY_CHECKS = 1;
